let _fbFunctions = null;
// Busca um Гәnico documento do Banco via REST
async function fsGetDoc(col, id) {
  if (!FB_READY) return null;
  try {
    const snap = await app.firestore().collection(col).doc(id).get();
    if (!snap.exists) return null;
    return { id: snap.id, ...snap.data() };
  } catch {
    // Fallback REST
    return new Promise(resolve => {
      const url = 'https://firestore.googleapis.com/v1/projects/' + FIREBASE_CONFIG.projectId +
        '/databases/(default)/documents/' + col + '/' + id + '?key=' + FIREBASE_CONFIG.apiKey;
      fetch(url).then(r => r.json()).then(doc => {
        if (!doc.fields) return resolve(null);
        const out = {};
        for (const [k, v] of Object.entries(doc.fields)) {
          if (v.arrayValue) {
            out[k] = (v.arrayValue.values || []).map(item =>
              item.mapValue ? Object.fromEntries(Object.entries(item.mapValue.fields || {}).map(([fk,fv]) => [fk, fv.stringValue ?? fv.integerValue ?? ''])) : item.stringValue ?? ''
            );
          } else {
            out[k] = v.stringValue ?? v.booleanValue ?? v.integerValue ?? null;
          }
        }
        resolve(out);
      }).catch(() => resolve(null));
    });
  }
}

async function getFbFunctions() {
  if (_fbFunctions) return _fbFunctions;
  _fbFunctions = app.functions('us-central1');
  return _fbFunctions;
}
async function callFunction(name, data) {
  const fn = (await getFbFunctions()).httpsCallable(name);
  const r  = await fn(data);
  return r.data;
}
window.callFunction = callFunction; // expГөe globalmente

// в”Җв”Җв”Җ callGenkitFlow вҖ” mapeia flows para Firebase Functions (Gemini) в”Җв”Җ
// Substitui a implementaГ§ГЈo anterior que chamava api.anthropic.com diretamente.
// As functions estГЈo em functions/src/index.js com Gemini via GOOGLE_GENAI_API_KEY.
async function callGenkitFlow(flowName, data) {
  const MAP = {
    'analisarChamado':       'triageChamado',     // triagem automГЎtica (nome real no Firebase)
    'chatbotADSI':           'chatbotADSI',        // assistente IA
    'gerarInsightsExecutivos': 'getInsightsIA',    // dashboard executivo
    'analisarAtivo':         'analisarAtivo',      // anГЎlise de ativo
  };
  const fnName = MAP[flowName] || flowName;
  try {
    return await callFunction(fnName, data);
  } catch (e) {
    console.warn(`[callGenkitFlow] ${flowName} falhou:`, e.message);
    throw e;
  }
}
window.callGenkitFlow = callGenkitFlow;

