// Filtro de tipo ativo para as abas
let _ativoFiltroTipo = '';

function filtrarAtivosPorTipo(tipos, el) {
  _ativoFiltroTipo = tipos;
  // Atualiza tab ativa
  document.querySelectorAll('#ativos-tabs .tab').forEach(t => t.classList.remove('active'));
  if (el) el.classList.add('active');
  else if (event?.currentTarget) event.currentTarget.classList.add('active');
  // Atualiza colunas da tabela de acordo com a aba
  const _isComp = tipos && (tipos.includes('computador') || tipos.includes('notebook') || tipos.includes('desktop') || tipos.includes('workstation'));
  updateAtivosTableForComputadores(_isComp);
  renderAtivos();
}

function renderAtivos() {
  const q      = (document.getElementById('pat-search')?.value || '').toLowerCase();
  const fSt    = document.getElementById('pat-filter-status')?.value || '';
  const tipos  = _ativoFiltroTipo ? _ativoFiltroTipo.split(',') : [];
  const isComp = !!_ativoFiltroTipo && (_ativoFiltroTipo.includes('computador') || _ativoFiltroTipo.includes('notebook') || _ativoFiltroTipo.includes('desktop') || _ativoFiltroTipo.includes('workstation'));
  window._ativosFiltroIsComp = isComp;

  // Atualiza header da tabela
  const thead = document.getElementById('ativos-thead');
  if (thead) {
    thead.innerHTML = `<tr>
      ${isComp ? '<th style="font-size:11px">Computador</th>' : ''}
      <th>PatrimГҙnio</th>${isComp ? '' : '<th>DescriГ§ГЈo</th><th>Tipo</th>'}<th>ГҒrea</th><th>Status</th><th style="font-size:11px">вҸұ Uptime</th>
      ${isComp ? '<th style="font-size:11px">Monitor</th><th style="font-size:11px">S.O.</th><th style="font-size:11px">IP</th><th style="font-size:11px;width:160px">рҹ“Ҡ CPU / RAM / Disco</th>' : ''}
      <th>AГ§Гөes</th>
    </tr>`;
  }

  // Fonte de dados: ativos + impressoras (coleГ§ГЈo separada) quando aba impressoras
  const isImpressoraTab = tipos.length > 0 && tipos.some(t =>
    ['impressora','printer'].includes(t.toLowerCase())
  );
  const _TIPOS_IMP = ['impressora','printer','print','jetdirect','laserjet','inkjet'];
  const fonteDados = isImpressoraTab
    ? [...(STATE.impressorasDisc || []).map(imp => ({
        ...imp,
        tipo: imp.tipo || 'Impressora',
        desc: imp.desc || imp.modelo || imp.nome || imp.ip || '',
        area: imp.area || imp.setor || '',
      }))].filter(imp => {
          const t = (imp.tipo||'').toLowerCase();
          const d = (imp.desc||'').toLowerCase();
          return _TIPOS_IMP.some(k => t.includes(k)) ||
                 d.includes('jetdirect') || d.includes('eeprom') || d.includes('cidate');
        })
    : (STATE.ativos || []);

  const lista = fonteDados.filter(a => {
    if (tipos.length > 0 && !isImpressoraTab) {
      const t = (a.tipo || '').toLowerCase();
      if (!tipos.some(ft => t.includes(ft) || ft.includes(t))) return false;
    }
    if (fSt && a.status !== fSt) return false;
    if (q && !`${a.pat||''} ${a.desc||''} ${a.area||''} ${a.resp||''} ${a.ip||''} ${a.modelo||''}`.toLowerCase().includes(q)) return false;
    return true;
  });

  const colspan = isComp ? '14' : '8';
  document.getElementById('ativos-body').innerHTML = lista.map(a => `
    <tr>
      ${isComp ? (()=>{
        const _hn = hostnameFromAtivo(a);
        const _pp = extractPatrimonioFromHostname(_hn);
        return '<td style="font-family:monospace;font-size:12px;font-weight:600">' + (_hn||'<span style="color:#94A3B8">вҖ”</span>') + '</td>';
      })() : ''}
      <td class="td-mono fw-700" style="color:var(--accent)">${(()=>{
        if (a.pat) return a.pat;
        const _hn2 = hostnameFromAtivo(a);
        const _pp2 = extractPatrimonioFromHostname(_hn2);
        if (_pp2.pat) return _pp2.alerta
          ? '<span style="color:#EF4444;font-weight:700">'+_pp2.pat+' вҡ пёҸ</span>'
          : '<span style="color:#059669;font-weight:700">'+_pp2.pat+'</span>';
        return '<span style="font-size:10px;background:#FEF3C7;color:#92400E;padding:2px 8px;border-radius:10px;font-weight:700;font-family:inherit">Sem PatrimГҙnio</span>';
      })()}</td>
      ${isComp ? '' : `<td style="font-weight:500">${
        a.desc && a.desc !== a.ip
          ? a.desc
          : (a.hostname && a.hostname !== a.ip ? a.hostname : (a.ip ? '<span style="font-family:monospace;font-size:11px;color:var(--g500)">'+a.ip+'</span>' : 'вҖ”'))
      }</td>
      <td><span class="tag">${a.tipo||'вҖ”'}</span></td>`}
      <td>${a.area||'вҖ”'}</td>

      <td>${statusAtivoHtml(a.status)}</td>
      <td style="text-align:center">${(()=>{
        const _ag = (STATE_AGENTS?.list||[]).find(x =>
          (a.ip && x.ip === a.ip) ||
          (a.hostname && (x.hostname||'').toLowerCase() === (a.hostname||'').toLowerCase())
        );
        const _up = _ag?.uptimeH ?? a.uptimeH ?? null;
        if (_up == null) return '<span style="color:var(--g300)">вҖ”</span>';
        if (_up >= 24*30) return '<span style="font-size:11px;font-weight:700;color:#059669">' + Math.floor(_up/24/30) + 'm ' + Math.floor(_up/24%30) + 'd</span>';
        if (_up >= 24)   return '<span style="font-size:11px;font-weight:700;color:#2563EB">' + Math.floor(_up/24) + 'd ' + Math.round(_up%24) + 'h</span>';
        return '<span style="font-size:11px;color:var(--g600)">' + Math.round(_up) + 'h</span>';
      })()}</td>
      ${isComp ? (()=>{
        // Monitor(es) vinculado(s) ao ativo
        const ag = (STATE_AGENTS?.list||[]).find(x =>
          (a.ip && x.ip === a.ip) ||
          (a.hostname && (x.hostname||'').toLowerCase() === (a.hostname||'').toLowerCase())
        );
        const monitores = ag?.monitores?.length
          ? ag.monitores.map(m => escapeHtml(m.nome||m.caption||'Monitor')).join(', ')
          : (a.monitores?.length ? a.monitores.map(m => escapeHtml(m.nome||m.caption||'Monitor')).join(', ') : 'вҖ”');
        const _soRaw = ag?.osNome || ag?.os || ag?.sistemaOp || a.os || a.sistemaOp || a.osName || '';
        const so = escapeHtml(_soRaw ? _soRaw.replace('Microsoft Windows ','Win ').replace('Windows ','Win ') : 'вҖ”');
        const ip = a.ip ? `<span style="font-family:monospace;font-size:11px">${escapeHtml(a.ip)}</span>` : 'вҖ”';
        return `<td style="font-size:11px;max-width:140px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${monitores}">${monitores}</td>
        <td style="font-size:11px;max-width:120px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${so}">${so}</td>
        <td>${ip}</td>`;
      })() : ''}
      ${isComp ? patMetricasHtml(a) : ''}
      <td><div class="flex gap-6">
        <button class="btn btn-ghost btn-xs" onclick="abrirHistorico('${a.pat||a.id}')">рҹ“ң</button>
        <button class="btn btn-ghost btn-xs" onclick="gerarQRCode(${JSON.stringify({id:a.id,pat:a.pat||a.ip||'',desc:a.desc||''})})" title="QR Code">рҹ“ұ</button>
        <button class="btn btn-ghost btn-xs" onclick="analisarAtivoPorIA('${a.pat||a.id}')" title="AnГЎlise IA">рҹӨ–</button>
        <button class="btn btn-secondary btn-xs" onclick="openModal('modal-transferencia')">вҶ”</button>
        ${isComp ? `<button class="btn btn-ghost btn-xs" onclick="patAbrirBusca()" title="Vincular PAT">рҹҸ·пёҸ</button>` : ''}
        ${isComp ? `<button class="btn btn-ghost btn-xs" title="Ver softwares instalados" onclick="(()=>{const _ag=(STATE_AGENTS?.list||[]).find(x=>(a.ip&&x.ip===a.ip)||(a.hostname&&(x.hostname||'').toLowerCase()===(a.hostname||'').toLowerCase()));_ag?swInvVerSoftwaresMaquina(_ag.id):showToast('Agente nГЈo conectado вҖ” sem dados de software','warning')})()">рҹ—ӮпёҸ</button>` : ''}
      </div></td>
    </tr>`).join('') || `<tr><td colspan="${colspan}" style="text-align:center;padding:24px;color:var(--g400)">Nenhum ativo вҖ” ${tipos.length?'tipo: '+_ativoFiltroTipo:'cadastrado'}</td></tr>`;
  nbUpdate('nb-ativos', lista.length);
}


// ============================================================
// HOSTNAME PATRIMГ”NIO EXTRACTOR
// ============================================================
function extractPatrimonioFromHostname(hostname) {
  if (!hostname) return { pat: null, alerta: true };
  // Get trailing numeric digits after the last letter in hostname
  const match = hostname.match(/[a-zA-Z]([0-9]+)$/);
  if (!match) return { pat: null, alerta: true };
  const digits = match[1];
  if (digits.length < 4) return { pat: digits, alerta: true };
  return { pat: digits, alerta: false };
}

function hostnameFromAtivo(a) {
  // Prioridade: campo hostname real > agente local > vazio
  // NUNCA retorna o IP como hostname вҖ” sГЈo campos distintos
  if (a.hostname && a.hostname !== a.ip) return a.hostname;
  // Tenta encontrar via agente pelo IP
  const agent = (window.STATE_AGENTS && STATE_AGENTS.list || [])
    .find(ag => ag.ip === a.ip || ag.ip === a.ipAddress);
  if (agent && agent.hostname && agent.hostname !== a.ip) return agent.hostname;
  return null; // sem hostname вҖ” exibir 'вҖ”' na coluna, nГЈo o IP
}


