function loadRel(tipo) {
  const titles = {
    movimentacoes:'RelatГіrio de MovimentaГ§Гөes', pendencias:'PendГӘncias de MovimentaГ§ГЈo',
    sc:'MГЎquinas em Santa Clara', 'terc-atraso':'Terceirizada вҖ” Atraso (>10 dias)',
    'terc-geral':'Todos os Ativos na Terceirizada', historico:'HistГіrico por Ativo'
  };
  document.getElementById('rel-title').textContent = titles[tipo] || tipo;
  const thead = document.getElementById('rel-thead');
  const tbody = document.getElementById('rel-tbody');
  if (tipo==='movimentacoes') {
    thead.innerHTML='<tr><th>Data</th><th>Tipo</th><th>PatrimГҙnio</th><th>Ativo</th><th>De</th><th>Para</th><th>TГ©cnico</th><th>Status</th></tr>';
    tbody.innerHTML=STATE.movimentacoes.map(m=>`<tr><td class="td-mono">${fmtDate(m.data)}</td><td><span class="tag">${m.tipo}</span></td><td class="td-mono" style="color:var(--accent)">${m.pat}</td><td>${m.ativo}</td><td>${m.de}</td><td>${m.para}</td><td>${m.tecnico}</td><td>${aprovStatusBadge(m.status)}</td></tr>`).join('')||noData(8);
  } else if (tipo==='terc-atraso') {
    const overdue=STATE.terceirizadaAtivos.filter(t=>!t.retornado&&t.diasUteis>10);
    thead.innerHTML='<tr><th>PatrimГҙnio</th><th>Ativo</th><th>Data Envio</th><th>Dias Гҡteis</th><th>TГ©cnico</th><th>Chamado</th></tr>';
    tbody.innerHTML=overdue.map(t=>`<tr style="background:var(--danger-l)"><td class="td-mono" style="color:var(--danger)">${t.pat}</td><td>${t.ativo}</td><td class="td-mono">${fmtDate(t.dataEnvio)}</td><td><span class="badge badge-danger">${t.diasUteis}d</span></td><td>${getTecNome(t.tecnicoTerc)}</td><td class="td-mono">${t.chamadoId}</td></tr>`).join('')||noData(6);
  } else if (tipo==='sc') {
    thead.innerHTML='<tr><th>PatrimГҙnio</th><th>Ativo</th><th>LocalizaГ§ГЈo</th><th>Data Entrada</th><th>ObservaГ§ГЈo</th></tr>';
    tbody.innerHTML=STATE.scAtivos.map(sc=>`<tr><td class="td-mono" style="color:var(--accent)">${sc.pat}</td><td>${sc.ativo}</td><td>рҹ“Қ ${sc.loc}</td><td class="td-mono">${fmtDate(sc.data)}</td><td>${sc.obs||'вҖ”'}</td></tr>`).join('')||noData(5);
  } else if (tipo==='terc-geral') {
    thead.innerHTML='<tr><th>PatrimГҙnio</th><th>Ativo</th><th>Data Envio</th><th>Dias</th><th>TГ©cnico</th><th>Chamado</th><th>Status</th></tr>';
    tbody.innerHTML=STATE.terceirizadaAtivos.map(t=>`<tr><td class="td-mono" style="color:var(--accent)">${t.pat}</td><td>${t.ativo}</td><td class="td-mono">${fmtDate(t.dataEnvio)}</td><td>${t.diasUteis}d</td><td>${getTecNome(t.tecnicoTerc)}</td><td class="td-mono">${t.chamadoId}</td><td>${t.retornado?'<span class="badge badge-success">Retornado</span>':'<span class="badge badge-orange">Na Terceirizada</span>'}</td></tr>`).join('')||noData(7);
  } else {
    thead.innerHTML='<tr><th>RelatГіrio em construГ§ГЈo</th></tr>';
    tbody.innerHTML=`<tr><td style="text-align:center;padding:24px;color:var(--g400)">Em breve...</td></tr>`;
  }
  document.getElementById('rel-result').style.display='';
  document.getElementById('rel-result').scrollIntoView({behavior:'smooth',block:'start'});
}
const noData = n => `<tr><td colspan="${n}" style="text-align:center;padding:24px;color:var(--g400)">Nenhum dado encontrado</td></tr>`;

// ============================================================
// HISTГ“RICO DO ATIVO
// ============================================================
function abrirHistorico(pat) {
  if (!pat||pat==='вҖ”') return showToast('Nenhum patrimГҙnio para exibir', 'danger');
  document.getElementById('hist-patrimonio').textContent = pat;
  const ativo = STATE.ativos.find(a=>a.pat===pat);
  const infoRow = document.getElementById('hist-info-row');
  if (ativo) {
    infoRow.innerHTML = [
      ['Tipo', ativo.tipo], ['DescriГ§ГЈo', ativo.desc],
      ['Status', statusAtivoHtml(ativo.status)], ['LocalizaГ§ГЈo', ativo.loc||'вҖ”'],
      ['Fabricante', ativo.fab||'вҖ”'], ['SГ©rie', ativo.serie||'вҖ”'],
      ['Cadastrado em', fmtDate(ativo.createdAt)],
    ].map(([l,v])=>`<div><div class="text-xs text-muted">${l}</div><div style="font-size:13px;font-weight:600;margin-top:2px">${v}</div></div>`).join('');
  } else { infoRow.innerHTML = '<p class="text-muted">Ativo nГЈo encontrado no cadastro</p>'; }
  const movs = STATE.movimentacoes.filter(m=>m.pat===pat);

  // Busca o ativo para ter hostname e ip disponГӯveis para cruzamento
  const _hn  = ativo ? hostnameFromAtivo(ativo) : '';
  const _ip  = ativo?.ip || '';
  const _id  = ativo?.id || '';

  const chs = (STATE.chamados || []).filter(c => {
    // 1. Campo pat direto
    if (c.pat && c.pat === pat) return true;
    // 2. Ativo vinculado via botГЈo "Vincular Ativo" (ativosVinculados[].pat ou .id ou .docId)
    if (c.ativosVinculados?.some(av =>
      (av.pat  && av.pat  === pat) ||
      (av.id   && av.id   === _id) ||
      (av.docId && av.docId === _id)
    )) return true;
    // 3. Hostname mencionado no tГӯtulo ou descriГ§ГЈo do chamado
    if (_hn && (
      (c.desc  && c.desc.toLowerCase().includes(_hn.toLowerCase())) ||
      (c.titulo && c.titulo.toLowerCase().includes(_hn.toLowerCase()))
    )) return true;
    // 4. IP mencionado no chamado
    if (_ip && (
      (c.desc  && c.desc.includes(_ip)) ||
      (c.titulo && c.titulo.includes(_ip))
    )) return true;
    // 5. movimentacao.patAntigo ou patNovo
    if (c.movimentacao && (
      c.movimentacao.patAntigo === pat ||
      c.movimentacao.patNovo   === pat
    )) return true;
    return false;
  });
  const entries = [
    {dot:'green', title:'Cadastro inicial no sistema', desc:`PatrimГҙnio ${pat} registrado no SYSACK`, time: ativo?fmtDate(ativo.createdAt):'вҖ”'},
    ...chs.map(c=>{
      // Descobre como o chamado foi vinculado ao ativo para mostrar no histГіrico
      const vinculoPat  = c.pat === pat;
      const vinculoAv   = !vinculoPat && c.ativosVinculados?.some(av => av.pat===pat || av.id===_id || av.docId===_id);
      const vinculoNome = !vinculoPat && !vinculoAv && _hn && (c.desc||'').toLowerCase().includes(_hn.toLowerCase());
      const vinculoIp   = !vinculoPat && !vinculoAv && !vinculoNome && _ip && (c.desc||'').includes(_ip);
      const origem = vinculoAv ? ' В· vinculado' : vinculoNome ? ' В· via hostname' : vinculoIp ? ' В· via IP' : '';
      const statusLabel = {aberto:'Aberto',concluido:'ConcluГӯdo',fechado:'Fechado','em-andamento':'Em andamento','aguardando-aprovacao':'Aguard. aprovaГ§ГЈo'}[c.status] || c.status || '';
      return {
        dot: c.status==='concluido'||c.status==='fechado' ? 'green' : c.status==='aguardando-aprovacao' ? 'orange' : 'blue',
        title: `Chamado ${c.id} вҖ” ${tipoLabel(c.tipo)}${origem}`,
        desc: `${statusLabel ? '['+statusLabel+'] ' : ''}${(c.desc||'').slice(0,80)}`,
        time: fmtDate(c.createdAt)
      };
    }),
    ...movs.map(m=>({dot:m.tipo==='Terceirizada'?'orange':m.tipo==='Santa Clara'?'violet':'blue', title:`${m.tipo}: ${m.de} вҶ’ ${m.para}`, desc:`TГ©cnico: ${m.tecnico} В· AprovaГ§ГЈo: ${m.status}`, time:fmtDate(m.data)})),
  ].sort((a,b)=>{ try{ return new Date(b.time||0)-new Date(a.time||0); } catch(e){ return 0; } });
  document.getElementById('hist-timeline').innerHTML = entries.map(e=>`
    <div class="tl-item"><div class="tl-dot ${e.dot}"></div><div class="tl-title">${e.title}</div><div class="tl-desc">${e.desc}</div><div class="tl-time">${e.time}</div></div>`).join('');
  openModal('modal-historico-ativo');
}

function adicionarObsHistorico() {
  const obs = document.getElementById('hist-obs-input').value.trim();
  if (!obs) return;
  const tl = document.getElementById('hist-timeline');
  tl.innerHTML = `<div class="tl-item"><div class="tl-dot gray"></div><div class="tl-title">ObservaГ§ГЈo adicionada</div><div class="tl-desc">${obs}</div><div class="tl-time">agora</div></div>` + tl.innerHTML;
  document.getElementById('hist-obs-input').value = '';
  showToast('ObservaГ§ГЈo adicionada ao histГіrico');
}

// ============================================================
// ATENDER CHAMADO
// ============================================================
function abrirAtendimento(chamadoId) {
  const ch = STATE.chamados.find(c=>c.id===chamadoId);
  if (!ch) return;
  document.getElementById('atender-ch-id').textContent = chamadoId;
  document.getElementById('at-patrimonio').value = ch.pat||'';

  // Preenche a descriГ§ГЈo original do chamado para o tГ©cnico ver
  const descEl = document.getElementById('at-descricao-original');
  const obsEl  = document.getElementById('at-obs-original');
  const nomEl  = document.getElementById('at-solicitante-nome');
  if (nomEl) nomEl.textContent = ch.solicitante
    ? 'рҹ‘Ө ' + ch.solicitante + (ch.area ? ' вҖ” ' + ch.area : '')
    : '';
  if (descEl) descEl.textContent = ch.desc || '';
  if (obsEl)  obsEl.textContent  = ch.obs  ? 'рҹ“қ InformaГ§Гөes adicionais: ' + ch.obs : '';

  // Limpa seГ§Гөes de vГӯnculo
  const existentes = document.getElementById('at-itens-existentes');
  const vinculados = document.getElementById('at-itens-vinculados');
  const resultados = document.getElementById('at-vincular-resultados');
  const buscaEl    = document.getElementById('at-vincular-busca');
  if (existentes) existentes.innerHTML = '';
  if (vinculados)  vinculados.innerHTML  = '';
  if (resultados)  resultados.style.display = 'none';
  // PrГ©-preenche busca com o patrimГҙnio do chamado para facilitar
  if (buscaEl)     buscaEl.value = ch.pat || '';
  if (document.getElementById('at-desc-atendimento'))
    document.getElementById('at-desc-atendimento').value = ch.descAtendimento || '';

  // Monta lista de ativos vinculados:
  // 1) ativosVinculados (array com objetos {pat, id})
  // 2) Fallback: campo pat do chamado (chamados criados antes da funcionalidade)
  let avs = ch.ativosVinculados || [];
  if (!avs.length && ch.pat) {
    // Tenta achar o ativo completo pelo pat
    const ativoEncontrado = (STATE.ativos||[]).find(a =>
      (a.pat||'').toLowerCase() === ch.pat.toLowerCase() ||
      (a.hostname||'').toLowerCase() === ch.pat.toLowerCase() ||
      (a.id||'').toLowerCase() === ch.pat.toLowerCase()
    ) || (STATE.impressorasDisc||[]).find(a =>
      (a.id||'').toLowerCase() === ch.pat.toLowerCase() ||
      (a.ip||'').replace(/\./g,'_') === ch.pat.toLowerCase()
    );
    avs = [{ pat: ch.pat, id: ativoEncontrado?.id || ch.pat, desc: ativoEncontrado?.desc || ativoEncontrado?.hostname || '' }];
  }

  if (existentes && avs.length) {
    existentes.innerHTML = avs.map(av => `
      <div style="display:inline-flex;align-items:center;gap:5px;background:#F0FDF4;border:1px solid #86EFAC;
                  border-radius:6px;padding:4px 10px;font-size:11.5px;font-weight:600;color:#166534">
        рҹ–ҘпёҸ ${escapeHtml(av.pat || av.id || '?')}
        ${av.desc ? `<span style="font-size:10px;font-weight:400;color:#15803D"> вҖ” ${escapeHtml(av.desc)}</span>` : ''}
        <span style="font-size:10px;font-weight:400;color:#15803D;margin-left:2px">(vinculado pelo solicitante)</span>
      </div>`).join('');
  } else if (existentes) {
    existentes.innerHTML = '<span style="font-size:11.5px;color:var(--g400);font-style:italic">Nenhuma mГЎquina vinculada pelo solicitante</span>';
  }

  openModal('modal-atender-chamado');
}


