function abrirMenuUsuario() {
  const u = SESSION_USER || CURRENT_USER;
  if (!u) return;
  const ini = (u.nome||'??').split(' ').map(p=>p[0]).join('').slice(0,2).toUpperCase();
  const el = document.getElementById('perfil-avatar-ini');
  if (el) el.textContent = ini;
  sv('perfil-nome',  u.nome  || 'вҖ”');
  sv('perfil-email', u.email || 'вҖ”');
  sv('perfil-role',  ({admin:'Administrador',gestor:'Gestor',tecnico:'TГ©cnico',viewer:'Visualizador',mdm_admin:'Administrador MDM'})[u.role] || u.role || 'вҖ”');
  // Limpa campos
  ['perfil-senha-atual','perfil-senha-nova','perfil-senha-confirm'].forEach(id => {
    const el = document.getElementById(id); if(el) el.value = '';
  });
  const msg = document.getElementById('perfil-senha-msg');
  if (msg) msg.style.display = 'none';
  openModal('modal-usuario-menu');
}

async function alterarSenha() {
  const atual   = document.getElementById('perfil-senha-atual')?.value || '';
  const nova    = document.getElementById('perfil-senha-nova')?.value || '';
  const confirm = document.getElementById('perfil-senha-confirm')?.value || '';
  const msg     = document.getElementById('perfil-senha-msg');

  function showMsg(txt, ok) {
    msg.textContent = txt;
    msg.style.background = ok ? '#F0FDF4' : '#FEF2F2';
    msg.style.color = ok ? '#166534' : '#991B1B';
    msg.style.border = ok ? '1px solid #86EFAC' : '1px solid #FECACA';
    msg.style.display = '';
  }

  if (!atual)   return showMsg('Informe sua senha atual.', false);
  if (!nova)    return showMsg('Informe a nova senha.', false);
  if (nova.length < 8) return showMsg('A nova senha deve ter pelo menos 8 caracteres.', false);
  if (nova !== confirm) return showMsg('A confirmaГ§ГЈo nГЈo coincide com a nova senha.', false);

  // Valida senha atual
  const hashAtual = await _sha256(atual);
  const u = SESSION_USER || CURRENT_USER;
  const local = LOCAL_USERS[(u?.email||'').toLowerCase()] || LOCAL_USERS[(u?.email||'')];
  if (local?._hash && hashAtual !== local._hash) {
    return showMsg('Senha atual incorreta.', false);
  }

  const hashNova = await _sha256(nova);

  // 1. Atualiza Firebase Auth (se disponГӯvel)
  if (auth?.currentUser) {
    try {
      await auth.currentUser.updatePassword(nova);
      showMsg('вң… Senha alterada com sucesso!', true);
    } catch (e) {
      if (e.code === 'auth/requires-recent-login') {
        showMsg('Por seguranГ§a, faГ§a login novamente antes de alterar a senha.', false);
      } else {
        showMsg('Erro ao alterar no Firebase: ' + e.message, false);
      }
      return;
    }
  }

  // 2. Atualiza no Firestore /users/{uid}
  if (FB_READY && db && u?.uid) {
    try {
      await db.collection('users').doc(u.uid).set({ _hash: hashNova }, { merge: true });
    } catch(e) { console.warn('[Senha] Erro ao salvar no Firestore:', e.message); }
  }

  // 3. Atualiza LOCAL_USERS em memГіria (sessГЈo atual)
  if (local) local._hash = hashNova;

  showMsg('вң… Senha alterada com sucesso! Use a nova senha no prГіximo login.', true);
  setTimeout(() => {
    ['perfil-senha-atual','perfil-senha-nova','perfil-senha-confirm'].forEach(id => {
      const el = document.getElementById(id); if(el) el.value = '';
    });
  }, 2000);
}

function toggleTrocaMaquina(val) {
  const sub = document.getElementById('sub-troca-maquina');
  if (sub) sub.style.display = val === 'sim' ? '' : 'none';
  document.getElementById('ro-troca-sim')?.classList.toggle('checked', val === 'sim');
  document.getElementById('ro-troca-nao')?.classList.toggle('checked', val === 'nao');
  if (val === 'nao') {
    // Limpa seleГ§ГЈo de nova mГЎquina
    document.getElementById('at-nova-maq-busca').value = '';
    document.getElementById('at-nova-maq-selecionada').style.display = 'none';
    document.getElementById('at-nova-maq-resultados').style.display = 'none';
    document.getElementById('at-pat-novo').value = '';
  }
}

// в”Җв”Җ Busca nova mГЎquina no sistema в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
let _atBuscaTimer = null;
function atBuscarNovaMaquina(q, immediate) {
  const res = document.getElementById('at-nova-maq-resultados');
  if (!res) return;
  if (!q || q.length < 2) { res.style.display = 'none'; return; }
  if (immediate) { _atBuscarNovaMaquinaExec(q, res); return; }
  clearTimeout(_atBuscaTimer);
  _atBuscaTimer = setTimeout(() => _atBuscarNovaMaquinaExec(q, res), 180);
}
function _atBuscarNovaMaquinaExec(q, res) {
  const qLow = q.toLowerCase();
  const fontes = STATE.ativos || [];
  const encontrados = fontes.filter(a =>
    (a.pat||'').toLowerCase().includes(qLow) ||
    (a.desc||'').toLowerCase().includes(qLow) ||
    (a.hostname||'').toLowerCase().includes(qLow)
  ).slice(0, 8);

  if (!encontrados.length) {
    res.innerHTML = '<div style="padding:10px 14px;font-size:12px;color:var(--g400)">Nenhuma mГЎquina encontrada вҖ” use o campo abaixo para cadastrar.</div>';
    res.style.display = '';
    return;
  }

  res.innerHTML = encontrados.map(a => `
    <div onclick="atSelecionarNovaMaquina('${a.id}','${escapeHtml(a.pat||'')}','${escapeHtml(a.desc||a.hostname||'')}')"
         style="padding:9px 14px;cursor:pointer;border-bottom:1px solid var(--g100);font-size:12.5px;
                display:flex;gap:10px;align-items:center"
         onmouseover="this.style.background='var(--g50)'" onmouseout="this.style.background=''">
      <span style="font-weight:700;color:var(--accent);min-width:80px">${escapeHtml(a.pat||a.hostname||'')}</span>
      <span style="color:var(--g600)">${escapeHtml(a.desc||a.hostname||'')}</span>
      <span style="color:var(--g400);font-size:11px;margin-left:auto">${a.area||''}</span>
    </div>`).join('');
  res.style.display = '';
}

// в”Җв”Җ Seleciona nova mГЎquina do resultado da busca в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function atSelecionarNovaMaquina(id, pat, desc) {
  document.getElementById('at-nova-maq-busca').value = pat + (desc ? ' вҖ” ' + desc : '');
  document.getElementById('at-nova-maq-resultados').style.display = 'none';
  document.getElementById('at-pat-novo').value = pat;
  const sel = document.getElementById('at-nova-maq-selecionada');
  sel.innerHTML = 'вң… Selecionada: <strong>' + escapeHtml(pat) + '</strong>' + (desc ? ' вҖ” ' + escapeHtml(desc) : '');
  sel.style.display = '';
  // Limpa campos de cadastro manual
  document.getElementById('at-nova-maq-pat').value = '';
  document.getElementById('at-nova-maq-desc').value = '';
}

// в”Җв”Җ Registra nova mГЎquina no sistema в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
async function atRegistrarNovaMaquina() {
  const pat  = document.getElementById('at-nova-maq-pat')?.value?.trim();
  const desc = document.getElementById('at-nova-maq-desc')?.value?.trim();
  const serie = document.getElementById('at-nova-maq-serie')?.value?.trim();
  if (!pat)  return showToast('Informe o patrimГҙnio da nova mГЎquina', 'danger');
  if (!desc) return showToast('Informe a descriГ§ГЈo da nova mГЎquina', 'danger');

  // Verifica se jГЎ existe
  const existe = (STATE.ativos||[]).find(a => (a.pat||'').toLowerCase() === pat.toLowerCase());
  if (existe) {
    atSelecionarNovaMaquina(existe.id, existe.pat, existe.desc||existe.hostname||'');
    showToast('MГЎquina jГЎ existe no sistema вҖ” selecionada automaticamente', 'info');
    return;
  }

  const novo = {
    pat, desc, serie: serie||'', tipo: 'workstation',
    status: 'ativo', fonte: 'manual', area: '',
    createdAt: new Date().toISOString(),
    createdBy: CURRENT_USER?.nome || '',
  };

  const id = await fsAdd('ativos', novo);
  if (id) {
    novo.id = id;
    if (!STATE.ativos) STATE.ativos = [];
    STATE.ativos.unshift(novo);
    atSelecionarNovaMaquina(id, pat, desc);
    showToast('вң… MГЎquina ' + pat + ' registrada no sistema!', 'success');
    document.getElementById('at-nova-maq-pat').value = '';
    document.getElementById('at-nova-maq-desc').value = '';
    document.getElementById('at-nova-maq-serie').value = '';
  }
}

function toggleMudouLugar(val) {
  const sub = document.getElementById('sub-mudou-lugar');
  if (!sub) return;

  document.getElementById('ro-nao')?.classList.toggle('checked', val === 'nao');
  document.getElementById('ro-sim')?.classList.toggle('checked', val === 'sim');

  if (val === 'nao') {
    sub.style.display = 'none';
    sub.innerHTML = ''; // libera memГіria
    return;
  }

  // Lazy render: sГі injeta o HTML pesado quando usuГЎrio escolhe "sim"
  if (!sub.dataset.rendered) {
    sub.dataset.rendered = '1';
    sub.innerHTML = _renderMovimentacaoHTML();
    // Popula select de tГ©cnicos da terceirizada
    const sel = document.getElementById('at-tecnico-terc');
    if (sel && STATE.tecnicos) {
      const terc = STATE.tecnicos.filter(t => t.empresa === 'terceirizada');
      sel.innerHTML = '<option value="">Selecione...</option>' +
        terc.map(t => `<option value="${t.id}">${escapeHtml(t.nome)}</option>`).join('');
    }
  }
  sub.style.display = '';
}

