function chToggleMovimentacao(checked) {
  document.getElementById('ch-mov-campos').style.display = checked ? '' : 'none';
  if (checked) {
    // Popula tГ©cnicos Empresa Terceirizada
    const sel = document.getElementById('ch-tecnico-mindworks');
    if (sel && sel.options.length <= 1) {
      const terceirizada = (STATE.tecnicos || []).filter(t =>
        (t.empresa || '').toLowerCase().includes('mind') ||
        (t.empresa || '').toLowerCase().includes('tercei')
      );
      if (terceirizada.length) {
        terceirizada.forEach(t => {
          const opt = document.createElement('option');
          opt.value = t.id; opt.textContent = t.nome + ' вҖ” ' + (t.empresa || 'Empresa Terceirizada');
          sel.appendChild(opt);
        });
      } else {
        // Placeholder caso nГЈo haja tГ©cnicos cadastrados
        const opt = document.createElement('option');
        opt.value = 'empresa-terceirizada-1'; opt.textContent = 'TГ©cnico Empresa Terceirizada (cadastrar em TГ©cnicos)';
        sel.appendChild(opt);
      }
    }
    document.getElementById('ch-data-recolhimento').value =
      new Date().toISOString().split('T')[0];
  }
}

function chToggleDestino(val) {
  ['mindworks','santa-clara','reutilizada','leilao'].forEach(d => {
    const el = document.getElementById('ch-dest-' + d);
    if (el) el.style.display = val === d ? '' : 'none';
  });
}

function chToggleNomenclatura(val) {
  const el = document.getElementById('ch-reut-nome-campo');
  if (el) el.style.display = val === 'sim' ? '' : 'none';
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// CHAMADO вҖ” Para quem Г©? (eu / outro empregado)
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

// Estado do empregado selecionado para "outro"
let _chEmpSelecionado = null;
let _chPqTimer = null;

function chToggleParaQuem(val) {
  const buscaBox = document.getElementById('ch-pq-busca-box');
  const labelEu  = document.getElementById('ch-pq-label-eu');
  const labelOut = document.getElementById('ch-pq-label-outro');

  if (val === 'outro') {
    if (buscaBox) buscaBox.style.display = '';
    if (labelEu)  { labelEu.style.borderColor  = 'var(--g200)'; labelEu.style.background  = '#fff';            labelEu.style.color  = 'var(--g600)'; }
    if (labelOut) { labelOut.style.borderColor = 'var(--accent)'; labelOut.style.background = 'var(--accent-l)'; labelOut.style.color = 'var(--accent)'; }
    setTimeout(() => document.getElementById('ch-pq-busca')?.focus(), 80);
  } else {
    if (buscaBox) buscaBox.style.display = 'none';
    if (labelEu)  { labelEu.style.borderColor  = 'var(--accent)'; labelEu.style.background  = 'var(--accent-l)'; labelEu.style.color  = 'var(--accent)'; }
    if (labelOut) { labelOut.style.borderColor = 'var(--g200)';   labelOut.style.background = '#fff';             labelOut.style.color = 'var(--g600)'; }
    chLimparEmpregado();
    // Restaura os campos do painel lateral para o usuГЎrio logado
    _chPreencherSolicitanteLogado();
  }
}

function chBuscarEmpregado(q) {
  clearTimeout(_chPqTimer);
  const res = document.getElementById('ch-pq-resultados');
  if (!q || q.length < 2) { if (res) res.style.display = 'none'; return; }
  _chPqTimer = setTimeout(() => _chExecBusca(q), 200);
}

function _chExecBusca(q) {
  const res = document.getElementById('ch-pq-resultados');
  if (!res) return;
  const qL  = q.toLowerCase();
  const emps = (STATE.empregados || []).filter(e =>
    (e.nome   || '').toLowerCase().includes(qL) ||
    (e.mat    || '').toLowerCase().includes(qL) ||
    (e.login  || '').toLowerCase().includes(qL) ||
    (e.email  || '').toLowerCase().includes(qL) ||
    (e.setor  || '').toLowerCase().includes(qL)
  ).slice(0, 12);

  if (!emps.length) {
    res.innerHTML = '<div style="padding:10px 14px;font-size:12px;color:var(--g400)">Nenhum empregado encontrado</div>';
    res.style.display = '';
    return;
  }

  res.innerHTML = emps.map(e => {
    const ini = (e.nome||'?').split(' ').slice(0,2).map(p=>p[0]).join('').toUpperCase();
    const info = [e.mat, e.setor||e.lotacao, e.ramal ? 'Ramal '+e.ramal : ''].filter(Boolean).join(' В· ');
    return `<div onclick="chSelecionarEmpregado(${JSON.stringify(e).replace(/"/g,'&quot;')})"
      style="padding:9px 14px;cursor:pointer;border-bottom:1px solid var(--g100);display:flex;gap:10px;align-items:center"
      onmouseover="this.style.background='var(--g50)'" onmouseout="this.style.background=''">
      <div style="width:32px;height:32px;border-radius:50%;background:var(--accent);color:#fff;display:flex;
                  align-items:center;justify-content:center;font-size:11px;font-weight:700;flex-shrink:0">${ini}</div>
      <div style="flex:1;min-width:0">
        <div style="font-weight:600;font-size:12.5px">${escapeHtml(e.nome||'вҖ”')}</div>
        <div style="font-size:11px;color:var(--g400)">${escapeHtml(info)}</div>
      </div>
      <div style="font-size:11px;color:var(--g500);flex-shrink:0">${escapeHtml(e.email||'')}</div>
    </div>`;
  }).join('');
  res.style.display = '';
}

function chSelecionarEmpregado(emp) {
  _chEmpSelecionado = emp;

  // Card de confirmaГ§ГЈo
  const card = document.getElementById('ch-pq-selecionado');
  const av   = document.getElementById('ch-pq-av');
  const nm   = document.getElementById('ch-pq-nome');
  const inf  = document.getElementById('ch-pq-info');
  if (card) card.style.display = '';
  if (av)   av.textContent = (emp.nome||'?').split(' ').slice(0,2).map(p=>p[0]).join('').toUpperCase();
  if (nm)   nm.textContent = emp.nome || 'вҖ”';
  if (inf)  inf.textContent = [
    emp.mat    ? 'Mat. ' + emp.mat       : '',
    emp.setor  || emp.lotacao            || '',
    emp.ramal  ? 'Ramal ' + emp.ramal    : '',
    emp.email  || '',
  ].filter(Boolean).join(' В· ');

  // Fecha dropdown e limpa busca
  const busca = document.getElementById('ch-pq-busca');
  const res   = document.getElementById('ch-pq-resultados');
  if (busca) busca.value = '';
  if (res)   res.style.display = 'none';

  // Preenche os campos do painel lateral com dados do empregado selecionado
  _chPreencherSolicitante(emp);

  // Atualiza bolha "Criado por" para mostrar quem vai ser atendido
  const bolha = document.getElementById('ch-bolha-requerente');
  if (bolha) bolha.textContent = emp.nome || 'вҖ”';
  const ini = document.getElementById('ch-bolha-iniciais');
  if (ini) ini.textContent = (emp.nome||'?').split(' ').slice(0,2).map(p=>p[0]).join('').toUpperCase();
}

function chLimparEmpregado() {
  _chEmpSelecionado = null;
  const card  = document.getElementById('ch-pq-selecionado');
  const busca = document.getElementById('ch-pq-busca');
  if (card)  card.style.display = 'none';
  if (busca) { busca.value = ''; busca.focus(); }
}

function _chPreencherSolicitante(emp) {
  // Preenche campos do painel lateral com dados do empregado
  const setV = (id, val) => { const el = document.getElementById(id); if (el) el.value = val || ''; };
  setV('ch-solicitante',  emp.nome   || '');
  setV('ch-sol-matricula', emp.mat   || emp.matricula || '');
  setV('ch-sol-ramal',    emp.ramal  || emp.telefone  || '');
  // LocalizaГ§ГЈo = setor/ГЎrea do empregado
  const locEl = document.getElementById('ch-localizacao');
  if (locEl && (emp.setor || emp.lotacao)) {
    // Tenta encontrar a opГ§ГЈo correspondente
    const opts = Array.from(locEl.options);
    const match = opts.find(o =>
      o.value === (emp.setor||emp.lotacao) ||
      o.text.includes(emp.setor||emp.lotacao)
    );
    if (match) locEl.value = match.value;
  }
}

function _chPreencherSolicitanteLogado() {
  // Restaura os dados do usuГЎrio logado nos campos do painel
  const emp = _chEmpLogado();
  if (emp) _chPreencherSolicitante(emp);
}

function _chEmpLogado() {
  if (!CURRENT_USER) return null;
  return (STATE.empregados || []).find(e =>
    e.email === CURRENT_USER.email ||
    e.login === CURRENT_USER.login ||
    e.uid   === CURRENT_USER.uid
  ) || null;
}

// Fecha dropdown ao clicar fora
document.addEventListener('click', e => {
  if (!e.target.closest('#ch-pq-busca') && !e.target.closest('#ch-pq-resultados')) {
    const res = document.getElementById('ch-pq-resultados');
    if (res) res.style.display = 'none';
  }
});

// Reset do seletor ao abrir o modal
const _origOpenModal = window.openModal;
window.openModal = function(id) {
  _origOpenModal?.(id);
  if (id === 'modal-novo-chamado') {
    // Reset para "para mim mesmo"
    _chEmpSelecionado = null;
    const radios = document.querySelectorAll('input[name="ch-para-quem"]');
    radios.forEach(r => { r.checked = r.value === 'eu'; });
    chToggleParaQuem('eu');
    // Popula ГЎreas com dados reais do organograma
    setTimeout(popularSelectsArea, 50);
  }
};

async function salvarChamado() {
  // Evita duplo clique
  const btnSalvar = document.getElementById('btn-salvar-chamado');
  if (btnSalvar?._salvando) return;
  if (btnSalvar) { btnSalvar._salvando = true; btnSalvar.disabled = true; btnSalvar.innerHTML = 'вҸі Salvando...'; }

  try {
    await _salvarChamadoInterno();
  } finally {
    if (btnSalvar) { btnSalvar._salvando = false; btnSalvar.disabled = false; btnSalvar.innerHTML = 'рҹ’ҫ Salvar Chamado'; }
  }
}

async function _salvarChamadoInterno() {
  const titulo = document.getElementById('ch-titulo')?.value?.trim();
  const sol    = document.getElementById('ch-solicitante')?.value?.trim();
  const desc   = document.getElementById('ch-descricao')?.value?.trim();
  if (!titulo) return showToast('Preencha o tГӯtulo do chamado', 'danger');
  if (!sol)    return showToast('Informe o requerente', 'danger');
  if (!desc)   return showToast('Preencha a descriГ§ГЈo do chamado', 'danger');
  const id = await gerarIdChamado();
  // Dados de movimentaГ§ГЈo de mГЎquina
  const temMovimentacao = document.getElementById('ch-movimentacao')?.checked;
  const movimentacao = temMovimentacao ? {
    patAntigo:         document.getElementById('ch-pat-antigo')?.value?.trim()  || '',
    patNovo:           document.getElementById('ch-pat-novo')?.value?.trim()    || '',
    destino:           document.getElementById('ch-destino-maquina')?.value     || '',
    tecnicoTerceirizada:  document.getElementById('ch-tecnico-mindworks')?.value   || '',
    dataRecolhimento:  document.getElementById('ch-data-recolhimento')?.value   || '',
    prazoTerceirizada:    parseInt(document.getElementById('ch-prazo-empresa-terceirizada')?.value || '10'),
    scLocal:           document.getElementById('ch-sc-local')?.value?.trim()    || '',
    reutLocal:         document.getElementById('ch-reut-local')?.value?.trim()  || '',
    reutNomenclatura:  document.getElementById('ch-reut-nomenclatura')?.value   || 'nao',
    reutNome:          document.getElementById('ch-reut-nome')?.value?.trim()   || '',
    reutTipoUso:       document.getElementById('ch-reut-tipo-uso')?.value       || '',
    status:            'pendente-aprovacao', // sempre exige aprovaГ§ГЈo do gestor
    aprovadoPor:       null,
    aprovadoEm:        null,
  } : null;

  // ValidaГ§Гөes de movimentaГ§ГЈo
  if (temMovimentacao) {
    if (!movimentacao.destino) return showToast('Selecione o destino da mГЎquina antiga', 'warning');
    if (movimentacao.destino === 'mindworks' && !movimentacao.tecnicoTerceirizada)
      return showToast('Selecione o tГ©cnico da Empresa Terceirizada', 'warning');
    if (movimentacao.destino === 'santa-clara' && !movimentacao.scLocal)
      return showToast('Informe o local de armazenamento em Santa Clara', 'warning');
    if (movimentacao.destino === 'reutilizada' && !movimentacao.reutLocal)
      return showToast('Informe o novo local de uso', 'warning');
  }

  // Coleta ativos vinculados via botГЈo "Vincular Ativo"
  const ativosVinculados = Array.from(
    document.querySelectorAll('#ch-itens-vinculados [data-ativo-id]')
  ).map(el => ({
    id:    el.dataset.ativoId    || '',
    pat:   el.dataset.ativoPat   || '',
    docId: el.dataset.ativoDocId || '',
  }));

  // в”Җв”Җ Regra: status de encerramento exige ao menos um ativo vinculado в”Җв”Җв”Җв”Җв”Җв”Җ
  const statusSelecionado = document.getElementById('ch-status')?.value || 'novo';
  const STATUS_ENCERRAMENTO = ['solucionado', 'fechado', 'concluido'];
  if (STATUS_ENCERRAMENTO.includes(statusSelecionado) && !ativosVinculados.length) {
    // Destaca a seГ§ГЈo de itens associados
    const itensBox = document.querySelector('.ch-itens-section, #ch-itens-box');
    if (itensBox) {
      itensBox.style.outline = '2px solid var(--danger)';
      itensBox.style.borderRadius = '8px';
      setTimeout(() => { itensBox.style.outline = ''; itensBox.style.borderRadius = ''; }, 4000);
    }
    // Scrolla atГ© a seГ§ГЈo de itens
    document.getElementById('ch-patrimonio')?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    return showToast('вҡ пёҸ Para encerrar o chamado Г© obrigatГіrio vincular ao menos um ativo', 'danger', 6000);
  }

  // Coleta smartphones vinculados via botГЈo "Vincular Smartphone"
  const smartphonesVinculados = Array.from(
    document.querySelectorAll('#ch-itens-vinculados [data-sm-id]')
  ).map(el => ({
    id:   el.dataset.smId   || '',
    pat:  el.dataset.smPat  || '',
    imei: el.dataset.smImei || '',
  }));

  // Determina solicitante: o prГіprio usuГЎrio ou empregado selecionado
  const paraOutro    = document.querySelector('input[name="ch-para-quem"]:checked')?.value === 'outro';
  const empSol       = paraOutro ? _chEmpSelecionado : _chEmpLogado();

  const solicitanteInfo = empSol ? {
    solicitanteId:     empSol.id    || '',
    solicitante:       empSol.nome  || sol,
    solicitanteMat:    empSol.mat   || empSol.matricula || '',
    solicitanteEmail:  empSol.email || '',
    solicitanteRamal:  empSol.ramal || empSol.telefone  || '',
    solicitanteCelular:empSol.celular|| '',
    solicitanteArea:   empSol.setor || empSol.lotacao   || '',
    solicitanteLogin:  empSol.login || '',
  } : {
    solicitanteId:    CURRENT_USER?.uid   || '',
    solicitante:      CURRENT_USER?.nome  || sol,
    solicitanteMat:   document.getElementById('ch-sol-matricula')?.value?.trim() || '',
    solicitanteRamal: document.getElementById('ch-sol-ramal')?.value?.trim()     || '',
    solicitanteEmail: CURRENT_USER?.email || '',
    solicitanteArea:  document.getElementById('ch-localizacao')?.value           || '',
  };

  // Registra quem abriu o chamado (pode ser diferente do solicitante)
  const abertoPor = {
    uid:   CURRENT_USER?.uid   || '',
    nome:  CURRENT_USER?.nome  || '',
    email: CURRENT_USER?.email || '',
    role:  CURRENT_USER?.role  || '',
  };

  const novo = {
    id,
    tipo:     document.getElementById('ch-tipo')?.value || 'incidente',
    area:     document.getElementById('ch-area')?.value || 'TI',
    localizacaoDetalhe: document.getElementById('ch-localizacao-detalhe')?.value?.trim() || '',
    tecnico:  document.getElementById('ch-tecnico')?.value || '',
    pat: document.getElementById('ch-pat-antigo')?.value?.trim()
      || (ativosVinculados[0]?.pat)
      || document.getElementById('ch-patrimonio')?.value || '',
    ativosVinculados,
    smartphonesVinculados,
    desc:     titulo + (desc ? '\n' + desc : ''),
    obs:      document.getElementById('ch-obs')?.value || '',
    status:   temMovimentacao ? 'aguardando-aprovacao' : 'aberto',
    prioridade: document.getElementById('ch-prioridade')?.value || 'media',
    categoria:  document.getElementById('ch-categoria')?.value  || '',
    origem:     document.getElementById('ch-origem')?.value     || 'portal',
    movimentacao,
    temMovimentacao: !!temMovimentacao,
    // Solicitante (para quem Г© o chamado)
    ...solicitanteInfo,
    // Quem abriu o chamado
    abertoPor,
    abertoPorNome: abertoPor.nome,
    aberturaPropria: !paraOutro, // true = abriu para si mesmo
    createdAt: new Date(),
  };
  if (!STATE.chamados) STATE.chamados = [];
  STATE.chamados.unshift(novo);
  fsAdd('chamados', novo, STATE.chamados);

  // Se tem movimentaГ§ГЈo: cria aprovaГ§ГЈo pendente e notifica gestor
  if (temMovimentacao && movimentacao) {
    const aprov = {
      id:          await gerarIdAprovacao(),
      chamadoId:   id,
      tipo:        'MovimentaГ§ГЈo de MГЎquina',
      pat:         movimentacao.patAntigo || novo.pat,
      descricao:   `Chamado ${id}: ${titulo}`,
      destino:     movimentacao.destino,
      detalhes:    movimentacao,
      solicitanteId: CURRENT_USER?.uid || '',
      solicitante:   CURRENT_USER?.nome || sol,
      status:        'pendente',
      createdAt:     new Date().toISOString(),
    };
    if (!STATE.aprovacoes) STATE.aprovacoes = [];
    STATE.aprovacoes.unshift(aprov);
    fsAdd('aprovacoes', aprov);
    nbUpdate('nb-aprov', (STATE.aprovacoes||[]).filter(a=>a.status==='pendente').length);
    showToast(`вң“ Chamado ${id} aberto вҖ” aguardando aprovaГ§ГЈo do gestor para movimentaГ§ГЈo.`, 'warning', 6000);
    goPage('aprovacoes');
  } else {
    showToast(`вң“ Chamado ${id} aberto com sucesso!`);
  }

  closeModal('modal-novo-chamado');
  renderChamados();
  renderDashboard();

  // Vincula chamado ao histГіrico de cada smartphone vinculado
  if (FB_READY && novo.smartphonesVinculados?.length) {
    const histSm = {
      tipo:      'chamado',
      chamadoId: novo.id,
      titulo:    novo.desc?.split('\n')[0] || novo.id,
      status:    novo.status,
      tecnico:   novo.tecnico || '',
      data:      new Date().toISOString(),
      criadoPor: CURRENT_USER?.nome || CURRENT_USER?.email || '',
    };
    for (const sv of novo.smartphonesVinculados) {
      if (!sv.id) continue;
      try {
        await db.collection('smartphones').doc(sv.id).collection('historico').add(histSm);
        console.log(`[Chamado] Vinculado ao smartphone ${sv.pat}`);
      } catch (e) {
        console.warn('[Chamado] Falha ao vincular ao smartphone:', e.message);
      }
    }
  }

  // Vincula chamado ao histГіrico de cada ativo vinculado
  if (FB_READY && novo.ativosVinculados?.length) {
    const hist = {
      tipo:      'chamado',
      chamadoId: novo.id,
      titulo:    novo.desc?.split('\n')[0] || novo.id,
      status:    novo.status,
      tecnico:   novo.tecnico || '',
      data:      new Date().toISOString(),
      criadoPor: CURRENT_USER?.nome || CURRENT_USER?.email || '',
    };
    for (const av of novo.ativosVinculados) {
      const docId = av.docId || av.id;
      if (!docId) continue;
      try {
        // Tenta nas coleГ§Гөes possГӯveis (sem GET extra вҖ” escreve direto na mais provГЎvel)
        // O Firestore aceita add em subcoleГ§ГЈo mesmo se o doc pai nГЈo existir no Гӯndice
        let escrito = false;
        for (const col of ['ativos','impressoras','switches','firewalls']) {
          try {
            const ref = db.collection(col).doc(docId);
            const snap = await ref.get();
            if (snap.exists) {
              await ref.collection('historico').add(hist);
              console.log(`[Chamado] вң“ HistГіrico escrito: ${av.pat} em ${col}`);
              escrito = true;
              break;
            }
          } catch(_) {}
        }
        // Se nГЈo achou em nenhuma coleГ§ГЈo, escreve em 'ativos' mesmo assim
        if (!escrito) {
          await db.collection('ativos').doc(docId).collection('historico').add(hist);
          console.log(`[Chamado] вң“ HistГіrico escrito (fallback ativos): ${av.pat || docId}`);
        }
      } catch (e) {
        console.warn('[Chamado] Falha ao vincular ao ativo:', e.message);
      }
    }
  }

  // Exibe confirmaГ§ГЈo com nГәmero do chamado em tela + dispara e-mail
  exibirConfirmacaoChamado(novo);
  // Envia e-mail de confirmaГ§ГЈo via Cloud Function
  if (FB_READY && novo.id && !novo.id.startsWith('offline_')) {
    callFunction('enviarConfirmacaoChamado', {
      chamadoId:  novo.id,
      titulo:     novo.desc?.split('\n')[0] || novo.id,
      solicitante: novo.solicitante,
      prioridade:  novo.prioridade,
      email:       CURRENT_USER?.email || '',
    }).catch(err => console.warn('[Email] Falha ao enviar confirmaГ§ГЈo:', err.message));
  }
}

