// LOGIN & AUTENTICAГҮГғO
// ============================================================

// UsuГЎrios locais (fallback quando Banco Auth nГЈo estГЎ disponГӯvel)
// Em produГ§ГЈo: use APENAS Banco Auth + Banco /users
// Fallback local para dev/offline вҖ” em produГ§ГЈo usa Banco Auth exclusivamente
// A senha abaixo Г© apenas para teste local em file:// вҖ” nГЈo Г© usada em produГ§ГЈo
// Fallback local вҖ” usado quando Firebase Auth nГЈo estГЎ acessГӯvel (ex: rede corporativa)
// Senhas armazenadas como SHA-256. Para gerar: sha256('suasenha')
function _sha256(str) {
  // SHA-256 simplificado via SubtleCrypto (async) вҖ” usado sГі no fallback
  return crypto.subtle.digest('SHA-256', new TextEncoder().encode(str))
    .then(b => Array.from(new Uint8Array(b)).map(x=>x.toString(16).padStart(2,'0')).join(''));
}

// в”Җв”Җ AutenticaГ§ГЈo AD (Active Directory CESAN via vservho091) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Endpoint do servidor auth-ad.js rodando no vservho091
// Configure o IP/DNS externo (ou VPN) do servidor
const AD_AUTH_URL     = 'http://vservho091:3080/auth/ad';
const AD_AUTH_ENABLED = false; // вҶҗ mude para true quando vservho091 tiver porta exposta
// DuraГ§ГЈo do token JWT (primeira autenticaГ§ГЈo)
const AD_TOKEN_DAYS   = 30;    // token vГЎlido 30 dias para suportar uso offline

async function _autenticarAD(login, senha) {
  if (!AD_AUTH_ENABLED) return null;
  const loginNorm = login.toLowerCase().replace('@cesan.com.br','').trim();

  try {
    // 1. Valida credenciais no AD
    const resp = await Promise.race([
      fetch(AD_AUTH_URL, {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ login: loginNorm, senha }),
      }),
      new Promise((_,r) => setTimeout(() => r(new Error('ad/timeout')), 10000)),
    ]);

    if (!resp.ok) {
      const err = await resp.json().catch(()=>({}));
      if (resp.status === 401) throw new Error('auth/wrong-password');
      throw new Error(err.error || 'ad/error');
    }

    const adData = await resp.json();
    const u = adData.usuario;

    // 2. Verifica se o usuГЎrio tem permissГЈo no SYSACK
    // Busca em /users pelo login ou email
    let sysackUser = null;
    try {
      if (FB_READY && db) {
        const snapLogin = await db.collection('users')
          .where('login', '==', loginNorm).limit(1).get();
        if (!snapLogin.empty) sysackUser = { id: snapLogin.docs[0].id, ...snapLogin.docs[0].data() };

        if (!sysackUser) {
          const snapEmail = await db.collection('users')
            .where('email', '==', u.email || loginNorm + '@cesan.com.br').limit(1).get();
          if (!snapEmail.empty) sysackUser = { id: snapEmail.docs[0].id, ...snapEmail.docs[0].data() };
        }
      }
    } catch(dbErr) {
      console.warn('[AD] Erro ao buscar permissГЈo SYSACK:', dbErr.message);
    }

    // 3. UsuГЎrio nГЈo liberado no SYSACK
    if (!sysackUser) {
      throw new Error('ad/sem-permissao');
    }

    // 4. UsuГЎrio bloqueado
    if (sysackUser.bloqueado === true) {
      throw new Error('ad/bloqueado');
    }

    // 5. Monta perfil final: dados do AD + perfil/permissГөes do SYSACK
    // O role vem do SYSACK (nГЈo do AD), garantindo controle centralizado
    const resultado = {
      token:   adData.token,
      usuario: {
        uid:         sysackUser.id,
        login:       loginNorm,
        email:       u.email    || sysackUser.email || loginNorm + '@cesan.com.br',
        nome:        u.nome     || sysackUser.nome  || loginNorm,
        mat:         u.mat      || sysackUser.mat   || '',
        setor:       u.setor    || sysackUser.setor || '',
        cargo:       u.cargo    || sysackUser.cargo || '',
        // Role e permissГөes VГҠM DO SYSACK (nГЈo do AD)
        role:        sysackUser.role        || 'viewer',
        permissions: sysackUser.permissions || permissionsForRole(sysackUser.role || 'viewer'),
        fonte:       'ad',
        adToken:     adData.token,
        sysackId:    sysackUser.id,
      }
    };

    // 6. Atualiza Гәltimo acesso no Firestore
    db?.collection('users').doc(sysackUser.id).update({
      lastLogin:    new Date(),
      lastLoginAD:  new Date(),
      ultimoLogin:  new Date().toISOString(),
    }).catch(() => {});

    return resultado;

  } catch(e) {
    if (['auth/wrong-password','ad/sem-permissao','ad/bloqueado'].includes(e.message)) throw e;
    console.warn('[AD Auth]', e.message);
    return null; // AD indisponГӯvel вҶ’ fallback Firebase/local
  }
}

