let SESSION_USER = null;  // usuГЎrio logado na sessГЈo atual

// в”Җв”Җв”Җ Verifica sessГЈo salva (lembrar acesso) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function checkSavedSession() {
  try {
    const saved = localStorage.getItem('at_session');
    if (!saved) return false;
    const session = JSON.parse(saved);
    if (!session || !session.uid || !session.nome) return false;
    // Valida expiraГ§ГЈo (24h)
    const age = Date.now() - (session.savedAt || 0);
    if (age > 24 * 3600 * 1000) { localStorage.removeItem('at_session'); return false; }
    // Valida que a role salva Г© um valor legГӯtimo (evita adulteraГ§ГЈo do localStorage)
    const VALID_ROLES = ['admin','gestor','tecnico','mdm_admin','viewer'];
    if (!VALID_ROLES.includes(session.role)) { localStorage.removeItem('at_session'); return false; }
    loginSuccess(session, false);
    return true;
  } catch { return false; }
}

// в”Җв”Җв”Җ Login principal в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// в”Җв”Җ Tenta autenticar no Firebase em background apГіs login local в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Fica retentando a cada 30s atГ© conseguir вҖ” quando conseguir, ativa os
// listeners protegidos (chamados, aprovacoes, etc.) que precisam de token Firebase
function _tentarFirebaseAuthBackground(email, senha, tentativa = 1) {
  if (!auth || !email || !senha) return;
  if (auth.currentUser) {
    // JГЎ autenticado вҖ” garante que listeners protegidos estГЈo ativos
    if (!window._protectedListenersAtivos) {
      console.log('[Auth] Firebase Auth jГЎ ativo вҖ” iniciando listeners protegidos');
      startProtectedListeners();
    }
    return;
  }

  auth.signInWithEmailAndPassword(email, senha)
    .then(cred => {
      console.log('[Auth] Firebase Auth obtido em background вң“ вҖ” ativando listeners protegidos');
      if (!window._protectedListenersAtivos) {
        startProtectedListeners();
      }
      // Recarrega dados que podem estar desatualizados
      setTimeout(() => {
        if (typeof renderChamados === 'function' && isPageActive('chamados')) renderChamados();
        if (typeof renderDashboard === 'function') renderDashboard();
      }, 1000);
    })
    .catch(err => {
      const naoExiste = err.code === 'auth/user-not-found' || err.code === 'auth/wrong-password' ||
                        err.code === 'auth/invalid-credential' || (err.message||'').includes('400');
      if (naoExiste) {
        if (auth && !auth.currentUser) {
          auth.signInAnonymously()
            .then(() => { if (!window._protectedListenersAtivos) startProtectedListeners(); })
            .catch(e => console.warn('[Auth] signInAnonymously falhou:', e.message));
        }
        return;
      }
      const maxTentativas = 20;
      if (tentativa < maxTentativas) {
        const delay = Math.min(30000, tentativa * 5000);
        setTimeout(() => _tentarFirebaseAuthBackground(email, senha, tentativa + 1), delay);
      }
    });
}

async function fazerLogin() {
  // Evita duplo disparo (form submit + onclick)
  if (window._loginEmAndamento) return;
  window._loginEmAndamento = true;
  try { await _fazerLoginInterno(); } finally { window._loginEmAndamento = false; }
}

async function _fazerLoginInterno() {
  // emailRaw = o que o usuГЎrio digitou (ex: 'admin' ou 'ana.penha')
  // emailNorm = normalizado com @ (ex: 'ana.penha@cesan.com.br')
  const emailRaw  = (document.getElementById('login-email')?.value || '').trim();
  const senha     = document.getElementById('login-senha')?.value || '';
  const emailNorm = emailRaw.includes('@') ? emailRaw : emailRaw + '@cesan.com.br';

  // в”Җв”Җ Tenta AD primeiro (se configurado e acessГӯvel) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  if (AD_AUTH_ENABLED) {
    try {
      const loginAD  = emailNorm.replace('@cesan.com.br','');
      const adResult = await _autenticarAD(loginAD, senha);
      if (adResult) {
        const u = adResult.usuario;
        const user = {
          uid:         u.login,
          email:       u.email || emailNorm,
          nome:        u.nome  || loginAD,
          avatar:      (u.nome||loginAD).split(' ').slice(0,2).map(w=>w[0]).join('').toUpperCase(),
          role:        _roleParaAD(u.grupos || []),
          permissions: permissionsForRole(_roleParaAD(u.grupos || [])),
          mat:         u.mat   || '',
          setor:       u.setor || '',
          fonte:       'ad',
          adToken:     adResult.token,
        };
        loginSuccess(user, false);
        console.log('[Auth] вң“ Autenticado via AD:', u.nome);
        return;
      }
    } catch(e) {
      if (e.message === 'auth/wrong-password') {
        showToast('Login ou senha incorretos. Verifique suas credenciais de rede.', 'danger', 5000);
        const btn = document.getElementById('btn-login');
        if (btn) { btn.disabled = false; btn.textContent = 'Entrar'; }
        return;
      }
      if (e.message === 'ad/sem-permissao') {
        // Mostra modal de "aguardando liberaГ§ГЈo"
        _mostrarModalSemPermissao(emailNorm);
        const btn = document.getElementById('btn-login');
        if (btn) { btn.disabled = false; btn.textContent = 'Entrar'; }
        return;
      }
      if (e.message === 'ad/bloqueado') {
        showToast('Seu acesso ao SYSACK estГЎ bloqueado. Contate o TI.', 'danger', 7000);
        const btn = document.getElementById('btn-login');
        if (btn) { btn.disabled = false; btn.textContent = 'Entrar'; }
        return;
      }
      // AD indisponГӯvel вҖ” continua para Firebase/local
      console.warn('[Auth] AD indisponГӯvel, usando Firebase/local');
    }
  }

  clearLoginError();
  if (!emailRaw || !senha) return showLoginError('Preencha o e-mail e a senha.');

  setLoginLoading(true);

  // в”Җв”Җ Tentativa 1: Banco Auth (timeout 3s вҖ” rede pode bloquear) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  if (FB_READY && auth) {
    try {
      const cred   = await Promise.race([
        auth.signInWithEmailAndPassword(emailNorm, senha),
        new Promise((_, rej) => setTimeout(() => rej(new Error('auth/timeout')), 3000)),
      ]);
      const fbUser = cred.user;

      // 1. Tenta custom claims (token JWT вҖ” mais seguro, nГЈo pode ser alterado pelo cliente)
      let claimsRole = null;
      try {
        const idTokenResult = await fbUser.getIdTokenResult(true); // forГ§a refresh
        claimsRole = idTokenResult.claims?.role || null;
        if (claimsRole) console.log('[Auth] Role via custom claim:', claimsRole);
      } catch (_) {}

      // 2. Fallback: busca perfil no Banco /users/{uid}
      let profile = { nome: fbUser.displayName || emailNorm, role: claimsRole || 'viewer', uid: fbUser.uid };
      try {
        const snap = await fsGet('users', fbUser.uid);
        if (snap) {
          Object.assign(profile, snap);
          // Custom claim tem prioridade sobre Banco (mais seguro)
          if (claimsRole) profile.role = claimsRole;
        }
      } catch (_) {}

      // 3b. Se role ainda Г© viewer, tenta LOCAL_USERS pelo email (fallback seguro)
      if (!claimsRole && (profile.role === 'viewer' || !profile.role)) {
        const localUser = LOCAL_USERS[emailNorm] || LOCAL_USERS[emailRaw] ||
          Object.values(LOCAL_USERS).find(u => u.email === emailNorm || u.email === emailRaw);
        if (localUser?.role && localUser.role !== 'viewer') {
          profile.role = localUser.role;
          profile.permissions = localUser.permissions || permissionsForRole(localUser.role);
          console.log('[Auth] Role corrigido via LOCAL_USERS:', profile.role);
          // Atualiza no Firestore para corrigir para o futuro
          try {
            if (FB_READY && db) {
              await db.collection('users').doc(fbUser.uid).set(
                { role: profile.role, email: emailNorm, nome: profile.nome, updatedAt: new Date() },
                { merge: true }
              );
            }
          } catch(_) {}
        }
      }

      // 3. Garante que viewer nГЈo acessa admin mesmo se Banco for adulterado
      const VALID_ROLES = ['admin','gestor','tecnico','mdm_admin','viewer'];
      if (!VALID_ROLES.includes(profile.role)) profile.role = 'viewer';
      const user = {
        uid:    fbUser.uid,
        email:  fbUser.email,
        nome:   profile.nome || fbUser.displayName || emailNorm,
        avatar: (profile.nome || fbUser.displayName || '?').split(' ').map(w => w[0]).slice(0,2).join('').toUpperCase(),
        role:   profile.role || 'viewer',
        permissions: permissionsForRole(profile.role || 'viewer'),
      };
      loginSuccess(user, true);
      return;
    } catch (err) {
      // SГі loga se nГЈo for erro de credencial invГЎlida
      const credErrors = ['auth/user-not-found','auth/wrong-password','auth/invalid-credential','auth/invalid-email'];
      if (err?.message === 'auth/timeout') {
        console.warn('[Auth] Timeout вҖ” Firebase Auth bloqueado (ad-blocker?). Tentando autenticaГ§ГЈo local...');
      } else if (err?.code && !credErrors.includes(err.code)) {
        console.warn('[Auth] Banco error:', err?.code, err?.message);
        if (err.code === 'auth/network-request-failed') {
          console.warn('[Auth] PossГӯvel bloqueio por extensГЈo (ad-blocker). Tentando autenticaГ§ГЈo local...');
        }
      }
    }
  }

  // в”Җв”Җ Tentativa 2: fallback local (usado quando Firebase Auth nГЈo estГЎ acessГӯvel) в”Җв”Җ
  const local = LOCAL_USERS[emailRaw.toLowerCase()] ||
                LOCAL_USERS[emailNorm.toLowerCase()] ||
                LOCAL_USERS[emailRaw];
  console.log('[Auth] Fallback local вҖ” usuario encontrado:', !!local, '| email:', emailRaw);
  // Valida senha via SHA-256 (async) ou senha plain text legado
  let senhaOk = false;
  if (local) {
    if (local._hash) {
      try {
        const hash = await _sha256(senha);
        console.log('[Auth] Hash calculado:', hash.slice(0,16), '| esperado:', local._hash.slice(0,16), '| match:', hash === local._hash);
        senhaOk = (hash === local._hash);
      } catch(e) { console.error('[Auth] _sha256 erro:', e); senhaOk = false; }
    } else if (local.password) {
      const senhaNorm = senha.replace(/0/g, 'o').replace(/O/g, 'o');
      const localPass = local.password.replace(/0/g, 'o').replace(/O/g, 'o');
      senhaOk = (local.password === senha || localPass === senhaNorm);
    }
  }
  console.log('[Auth] senhaOk:', senhaOk);
  if (local && senhaOk) {
    const user = {
      uid:         local.uid,
      email:       local.email,
      nome:        local.nome,
      avatar:      local.avatar,
      role:        local.role,
      permissions: local.permissions || permissionsForRole(local.role),
    };

    // Tenta obter Custom Token da Function вҖ” autentica com token real, seguro
    // Se a Function estiver disponГӯvel, obtГ©m token com role correta
    // Se nГЈo (bloqueado/offline), o app funciona com listeners via poll
    if (FB_READY && auth) {
      try {
        const resp = await Promise.race([
          fetch('https://us-central1-sysack-829e2.cloudfunctions.net/gerarCustomToken', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ uid: local.uid, email: local.email, role: local.role }),
          }),
          new Promise((_, rej) => setTimeout(() => rej(new Error('timeout')), 4000)),
        ]);
        if (resp.ok) {
          const { token } = await resp.json();
          if (token) {
            await auth.signInWithCustomToken(token);
            console.log('[Auth] Custom Token OK вҖ” Firestore autenticado com role:', local.role);
          }
        }
      } catch(e) {
        console.warn('[Auth] Custom Token indisponГӯvel:', e.message, 'вҖ” tentando signInAnonymously');
        try {
          if (auth && !auth.currentUser) {
            await auth.signInAnonymously();
            if (!window._protectedListenersAtivos) startProtectedListeners();
          }
        } catch(e2) { console.warn('[Auth] signInAnonymously falhou:', e2.message); }
      }
    }

    loginSuccess(user, true);

    // Tenta autenticar no Firebase em background (pode estar bloqueado pelo ad-blocker)
    // Quando conseguir, os listeners protegidos serГЈo ativados automaticamente
    _tentarFirebaseAuthBackground(emailNorm, senha);
    return;
  }

  setLoginLoading(false);
  showLoginError('UsuГЎrio ou senha incorretos.');
  document.getElementById('login-email')?.classList.add('error');
  document.getElementById('login-senha')?.classList.add('error');
}

function permissionsForRole(role) {
  const map = {
    admin:     { canApprove:true, canDeleteAssets:true, canWipeDevice:true, canGeolocate:true, canViewAudit:true, canExecDashboard:true },
    gestor:    { canApprove:true, canDeleteAssets:false, canWipeDevice:true, canGeolocate:true, canViewAudit:true, canExecDashboard:true },
    tecnico:   { canApprove:false, canDeleteAssets:false, canWipeDevice:false, canGeolocate:false, canViewAudit:false, canExecDashboard:false },
    mdm_admin: { canApprove:false, canDeleteAssets:false, canWipeDevice:true, canGeolocate:true, canViewAudit:false, canExecDashboard:false },
    viewer:    { canApprove:false, canDeleteAssets:false, canWipeDevice:false, canGeolocate:false, canViewAudit:false, canExecDashboard:false },
  };
  return map[role] || map.viewer;
}

function loginSuccess(user, showWelcome = true) {
  SESSION_USER = user;
  // Atualiza CURRENT_USER global
  Object.assign(CURRENT_USER, user);

  // Atualiza UI
  const av = document.getElementById('tb-user-avatar');
  if (av) { av.childNodes[0].textContent = user.avatar || user.nome[0]; }
  const nameEl = document.getElementById('tb-user-name-label');
  if (nameEl) nameEl.textContent = user.nome;
  const roleEl = document.getElementById('tb-user-role-label');
  if (roleEl) roleEl.textContent = user.role;
  document.getElementById('tb-user-name-wrap')?.style?.setProperty('display','block');

  // Atualiza sidebar user
  const uname = document.querySelector('.u-name');
  if (uname) uname.textContent = user.nome;
  const urole = document.querySelector('.u-role');
  if (urole) urole.textContent = user.role.charAt(0).toUpperCase() + user.role.slice(1) + ' В· SYSACK';
  const uav = document.querySelector('.u-avatar');
  if (uav) uav.textContent = user.avatar || user.nome[0];

  // Esconde login, mostra app
  setLoginLoading(false);
  document.getElementById('login-page')?.classList.add('hidden');

  if (showWelcome) {
    const hora = new Date().getHours();
    const saud = hora < 12 ? 'Bom dia' : hora < 18 ? 'Boa tarde' : 'Boa noite';
    showToast(`${saud}, ${user.nome.split(' ')[0]}! рҹ‘Ӣ Bem-vindo ao SYSACK.`, 'success');
  }
  auditLog('LOGIN', 'auth', user.uid, 'user', { nome: user.nome, role: user.role });

  // Inicia listeners do Firestore APГ“S o usuГЎrio estar autenticado
  function _iniciarListeners() {
    startFirestoreListeners();      // pГәblicos (ativos, switches, empregados)
    startProtectedListeners();      // protegidos (chamados, aprovacoes, etc.)
    verificarConfigSeguranca?.();
    iniciarWatcherIP?.();
    iniciarWatcherAlertasIA?.();
    startAgentsListener();
    // Mostra "GestГЈo de Contas" no menu apenas para admins
    const navUsuarios = document.getElementById('nav-usuarios');
    if (navUsuarios) navUsuarios.style.display = isAdmin() ? '' : 'none';
    document.dispatchEvent(new Event('sysack-login'));
  }

  if (FB_READY && db) {
    // Firebase jГЎ pronto вҖ” inicia listeners imediatamente
    setTimeout(_iniciarListeners, 300);
  } else {
    // Firebase ainda inicializando вҖ” aguarda e tenta de novo
    console.log('[Banco] Aguardando Firebase para iniciar listeners...');
    const _maxTentativas = 20;
    let _tentativa = 0;
    const _intervalo = setInterval(() => {
      _tentativa++;
      if (FB_READY && db) {
        clearInterval(_intervalo);
        console.log(`[Banco] Firebase pronto apГіs ${_tentativa} tentativas вҖ” iniciando listeners`);
        _iniciarListeners();
      } else if (_tentativa >= _maxTentativas) {
        clearInterval(_intervalo);
        console.warn('[Banco] Timeout aguardando Firebase вҖ” listeners nГЈo iniciados');
      }
    }, 300);
  }
}

// в”Җв”Җв”Җ Logout в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function confirmarLogout() {
  if (!confirm('Deseja sair do sistema?')) return;
  fazerLogout();
}

async function fazerLogout() {
  auditLog('LOGOUT', 'auth', CURRENT_USER.uid, 'user', {});
  localStorage.removeItem('at_session');
  SESSION_USER = null;
  if (FB_READY && auth) {
    try { await auth.signOut?.(); } catch (_) {}
  }
  // Volta para login
  document.getElementById('login-page')?.classList.remove('hidden');
  // Limpa campos
  const em = document.getElementById('login-email');
  const pw = document.getElementById('login-senha');
  if (em) em.value = ''; if (pw) pw.value = '';
  clearLoginError();
}

// в”Җв”Җв”Җ Esqueci a senha в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
async function esqueciSenha() {
  const emailRaw = document.getElementById('login-email')?.value?.trim();
  if (!emailRaw) { showLoginError('Digite seu e-mail ou usuГЎrio no campo acima.'); return; }
  // Normaliza antes de enviar ao Banco
  const email = emailRaw.includes('@') ? emailRaw : emailRaw + '@adsi.com.br';
  if (FB_READY && auth) {
    try {
      await auth.sendPasswordResetEmail(email);
      clearLoginError();
      showToast(`вңүпёҸ E-mail de recuperaГ§ГЈo enviado para ${email}`, 'success');
    } catch (err) {
      showLoginError('Erro ao enviar e-mail: ' + (err.message || err.code));
    }
  } else {
    showLoginError('Reset de senha requer conexГЈo com Banco. Contate o administrador.');
  }
}

// в”Җв”Җв”Җ Helpers UI в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function showLoginError(msg) {
  const box = document.getElementById('login-error-box');
  if (!box) return;
  box.textContent = 'рҹ”’ ' + msg;
  box.classList.add('show');
}
function clearLoginError() {
  const box = document.getElementById('login-error-box');
  box?.classList.remove('show');
  document.getElementById('login-email')?.classList.remove('error');
  document.getElementById('login-senha')?.classList.remove('error');
}
function setLoginLoading(on) {
  const btn = document.getElementById('login-btn');
  if (!btn) return;
  btn.disabled = on;
  btn.classList.toggle('loading', on);
}
function toggleSenha() {
  const inp = document.getElementById('login-senha');
  const btn = document.getElementById('toggle-pw-btn');
  if (!inp) return;
  const isText = inp.type === 'text';
  inp.type = isText ? 'password' : 'text';
  if (btn) btn.textContent = isText ? 'рҹ‘ҒпёҸ' : 'рҹҷҲ';
}
function showUserMenu() {
  // Simples toggle para exibir info вҖ” pode ser expandido
  const wrap = document.getElementById('tb-user-name-wrap');
  if (!wrap) return;
  const visible = wrap.style.display !== 'none' && wrap.style.display !== '';
  wrap.style.display = visible ? 'none' : 'block';
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// SEGURANГҮA вҖ” SanitizaГ§ГЈo de HTML (previne XSS)
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
function setButtonLoading(btn, loading, label) {
  if (!btn) return;
  if (loading) {
    btn.dataset.origText = btn.textContent;
    btn.disabled = true;
    btn.innerHTML = '<span class="spinner" style="width:14px;height:14px;border-width:2px;margin-right:6px"></span>' + (label || 'Salvando...');
  } else {
    btn.disabled = false;
    btn.textContent = btn.dataset.origText || label || 'Salvar';
  }
}

function escapeHtml(str) {
  if (str === null || str === undefined) return '';
  return String(str)
    .replace(/&/g,  '&amp;')
    .replace(/</g,  '&lt;')
    .replace(/>/g,  '&gt;')
    .replace(/"/g,  '&quot;')
    .replace(/'/g,  '&#39;')
    .replace(/\//g, '&#x2F;');
}
// Alias curto para uso em template literals de innerHTML
const esc = escapeHtml;


// Sanitiza um objeto inteiro вҖ” protege todos os campos string
function sanitizeObj(obj) {
  const out = {};
  for (const [k, v] of Object.entries(obj || {})) {
    out[k] = typeof v === 'string' ? escapeHtml(v) : v;
  }
  return out;
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// MOBILE вҖ” Sidebar drawer + responsivo
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
function toggleSidebar() {
  const sidebar = document.querySelector('.sidebar');
  const overlay = document.getElementById('sidebar-overlay');
  if (!sidebar) return;
  const isOpen = sidebar.classList.toggle('open');
  if (overlay) overlay.classList.toggle('open', isOpen);
  document.body.style.overflow = isOpen ? 'hidden' : '';
}

function closeSidebar() {
  const sidebar = document.querySelector('.sidebar');
  const overlay = document.getElementById('sidebar-overlay');
  sidebar?.classList.remove('open');
  overlay?.classList.remove('open');
  document.body.style.overflow = '';
}

// Fecha sidebar ao navegar (mobile)
document.addEventListener('DOMContentLoaded', () => {
  document.querySelectorAll('.nav-i').forEach(el => {
    el.addEventListener('click', () => {
      if (window.innerWidth <= 768) closeSidebar();
    });
  });
  // Fecha ao pressionar ESC
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape') {
      // Close topmost open modal
      const openModals = document.querySelectorAll('.modal-overlay[style*="flex"], .modal-overlay.open');
      if (openModals.length) {
        const last = openModals[openModals.length - 1];
        last.style.display = 'none';
        last.classList.remove('open');
        return;
      }
      // Close AI panel
      if (document.getElementById('ai-panel')?.style.display !== 'none') {
        closeAIPanel();
        return;
      }
      closeSidebar();
    }
  });
  // Atalho Ctrl+K вҖ” busca global
  document.addEventListener('keydown', e => {
    if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
      e.preventDefault();
      const search = document.getElementById('tb-search-input') ||
                     document.querySelector('.tb-search input');
      if (search) { search.focus(); search.select(); }
    }
  });

  // Swipe para fechar (mobile)
  let touchStartX = 0;
  document.addEventListener('touchstart', e => {
    touchStartX = e.changedTouches[0].screenX;
  }, { passive: true });
  document.addEventListener('touchend', e => {
    const dx = e.changedTouches[0].screenX - touchStartX;
    if (dx < -60) closeSidebar();          // swipe left вҶ’ fecha
    if (dx > 60 && window.innerWidth <= 768) { // swipe right вҶ’ abre
      document.querySelector('.sidebar')?.classList.add('open');
      document.getElementById('sidebar-overlay')?.classList.add('open');
    }
  }, { passive: true });
});

// в”Җв”Җ DEBOUNCE вҖ” evita excesso de queries nos campos de busca в”Җв”Җ
function debounce(fn, ms = 300) {
  let timer;
  return function(...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), ms);
  };
}
const _debouncedSearch = debounce((fn) => fn(), 250);

// в”Җв”Җ DARK/LIGHT THEME в”Җв”Җ
function toggleTheme() {
  const root = document.documentElement;
  const isDark = root.getAttribute('data-theme') === 'dark';
  const newTheme = isDark ? 'light' : 'dark';
  root.setAttribute('data-theme', newTheme);
  localStorage.setItem('at-theme', newTheme);
  const btn = document.getElementById('theme-toggle-btn');
  if (btn) btn.textContent = newTheme === 'dark' ? 'вҳҖпёҸ' : 'рҹҢҷ';
  // Update sidebar brand
  const sidebar = document.querySelector('.sidebar');
  if (sidebar) sidebar.style.background = newTheme === 'dark' ? '#0A0F1E' : 'var(--brand)';
}

function initTheme() {
  const saved = localStorage.getItem('at-theme') || 'light';
  document.documentElement.setAttribute('data-theme', saved);
  const btn = document.getElementById('theme-toggle-btn');
  if (btn) btn.textContent = saved === 'dark' ? 'вҳҖпёҸ' : 'рҹҢҷ';
}

// в”Җв”Җ SIDEBAR GROUP TOGGLE в”Җв”Җ
function toggleSbGroup(id) {
  const grp = document.getElementById(id);
  if (!grp) return;
  const chevId = 'chev-' + id;
  const chev = document.getElementById(chevId);
  const collapsed = grp.classList.toggle('collapsed');
  if (chev) chev.style.transform = collapsed ? 'rotate(-90deg)' : '';
}

// в”Җв”Җ ATORES (chips) в”Җв”Җ
const _atores = { requerente: [], observador: [], tecnico: [], grupo: [] };

function adicionarAtor(tipo) {
  let val = '', label = '';
  if (tipo === 'requerente') { val = document.getElementById('ch-solicitante')?.value?.trim(); label = val; }
  if (tipo === 'observador')  { val = document.getElementById('ch-observador')?.value?.trim(); label = val; }
  if (tipo === 'tecnico') {
    const sel = document.getElementById('ch-tecnico');
    val = sel?.value; label = sel?.options[sel.selectedIndex]?.text;
  }
  if (tipo === 'grupo') {
    const sel = document.getElementById('ch-grupo');
    val = sel?.value; label = sel?.options[sel.selectedIndex]?.text;
  }
  if (!val || !label || label.startsWith('вҖ”')) return showToast('Selecione ou informe o valor', 'danger');
  if (_atores[tipo].find(a => a.val === val)) return showToast('JГЎ adicionado', 'warning');
  _atores[tipo].push({ val, label });
  renderAtorChips(tipo);
  atualizarContadorAtores();
}

function removerAtor(tipo, val) {
  if (!SESSION_USER || !["admin", "gestor", "tecnico"].includes(SESSION_USER.role)) {
    showToast('вӣ” Acesso restrito: remover ator.', 'error');
    return;
  }

  _atores[tipo] = _atores[tipo].filter(a => a.val !== val);
  renderAtorChips(tipo);
  atualizarContadorAtores();
}

function renderAtorChips(tipo) {
  const containerId = tipo === 'tecnico' || tipo === 'grupo' ? 'atribuido-chips' : tipo + '-chips';
  const container = document.getElementById(containerId);
  if (!container) return;
  // Only clear the chips for this tipo within the container вҖ” rebuild all
  if (tipo === 'tecnico' || tipo === 'grupo') {
    const all = [...(_atores.tecnico||[]), ...(_atores.grupo||[])];
    container.innerHTML = all.map(a => {
      const isTec = _atores.tecnico.find(t => t.val === a.val);
      const icon = isTec ?
        '<svg width="11" height="11" viewBox="0 0 16 16" fill="none"><circle cx="8" cy="5.5" r="3" stroke="currentColor" stroke-width="1.5"/><path d="M2 14c0-3 2.5-5 6-5s6 2 6 5" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg>' :
        '<svg width="11" height="11" viewBox="0 0 16 16" fill="none"><circle cx="5" cy="5" r="2.5" stroke="currentColor" stroke-width="1.4"/><circle cx="11" cy="5" r="2.5" stroke="currentColor" stroke-width="1.4"/><path d="M1 14c0-2.5 1.8-4 4-4h6c2.2 0 4 1.5 4 4" stroke="currentColor" stroke-width="1.4" stroke-linecap="round"/></svg>';
      const remTipo = isTec ? 'tecnico' : 'grupo';
      return `<div class="ator-chip">${icon} ${a.label} <span class="chip-remove" onclick="removerAtor('${remTipo}','${a.val}')">вң•</span></div>`;
    }).join('');
  } else {
    container.innerHTML = _atores[tipo].map(a =>
      `<div class="ator-chip"><svg width="11" height="11" viewBox="0 0 16 16" fill="none"><circle cx="8" cy="5.5" r="3" stroke="currentColor" stroke-width="1.5"/><path d="M2 14c0-3 2.5-5 6-5s6 2 6 5" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg> ${a.label} <span class="ator-num" style="margin-left:4px">0</span> <span class="chip-remove" onclick="removerAtor('${tipo}','${a.val}')">вң•</span></div>`
    ).join('');
  }
}

function atualizarContadorAtores() {
  const total = Object.values(_atores).reduce((s, arr) => s + arr.length, 0);
  const el = document.getElementById('atores-count');
  if (el) el.textContent = total;
}

// в”Җв”Җ VINCULAR CHAMADO RELACIONADO в”Җв”Җ
function vincularChamadoRelacionado() {
  const input = document.getElementById('ch-rel-input');
  const val = input?.value?.trim();
  if (!val) return showToast('Informe o nГәmero do chamado', 'danger');
  const ch = STATE.chamados?.find(c => c.id === val || c.id === 'CH-' + val);
  const list = document.getElementById('ch-rel-list');
  if (list) {
    list.insertAdjacentHTML('beforeend', `
      <div class="ch-rel-row">
        <span class="ch-rel-tipo">Relacionado</span>
        <span class="ch-rel-id">${ch ? ch.id : val}</span>
        <span style="flex:1;font-size:12px;color:var(--g600)">${ch ? ch.desc?.slice(0,50) : 'Chamado externo'}</span>
        <span style="cursor:pointer;color:var(--g400);font-size:11px" onclick="this.parentElement.remove()">вң•</span>
      </div>`);
    // update count
    const cnt = document.getElementById('itens-ch-count');
    if (cnt) cnt.textContent = parseInt(cnt.textContent||0) + 1;
  }
  if (input) input.value = '';
  showToast(`вң“ Chamado ${val} vinculado como relacionado`);
}

