function atualizarPrioridadeColor(sel) {
  const colors = {
    'muito-baixa':'#F0FFF4','baixa':'#F0FFF4','media':'#FFFBEB','alta':'#FFF7ED','muito-alta':'#FEF2F2','urgente':'#FEF2F2'
  };
  const textColors = {
    'muito-baixa':'#065F46','baixa':'#065F46','media':'#92400E','alta':'#9A3412','muito-alta':'#991B1B','urgente':'#7F1D1D'
  };
  sel.style.background = colors[sel.value]||'';
  sel.style.color = textColors[sel.value]||'';
  sel.style.fontWeight = '700';
}


// в”Җв”Җ Sugere ativos pelo histГіrico de login do usuГЎrio (Гәltimos 5 dias) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
async function sugerirAtivosPorHistorico() {
  const emp = _empregadoLogado();
  if (!emp) return showToast('UsuГЎrio nГЈo identificado no sistema', 'warning');

  showToast('рҹ”Қ Buscando seus computadores recentes...', 'info', 2000);

  // Busca ativos onde o emp.mat aparece em usuarios_historico nos Гәltimos 5 dias
  const cincoAtras = new Date(Date.now() - 5 * 24 * 60 * 60 * 1000).toISOString();
  let candidatos = [];

  try {
    if (FB_READY && auth?.currentUser) {
      // Usa Cloud Function que jГЎ existe para histГіrico de usuГЎrios
      // Busca todos os ativos onde esse empregado logou recentemente
      const data = await Promise.race([
        callFunction('getAtivosDoUsuario', { mat: emp.mat, desde: cincoAtras }),
        new Promise((_, r) => setTimeout(() => r(new Error('timeout')), 6000)),
      ]);
      candidatos = data?.ativos || [];
    }
  } catch (e) {
    console.warn('[Sugerir] Cloud Function indisponГӯvel, usando STATE.ativos:', e.message);
  }

  // Fallback: busca em STATE.ativos pelo campo resp/matriculaResp
  if (!candidatos.length) {
    candidatos = (STATE.ativos || []).filter(a =>
      (a.matriculaResp || a.responsavelMat || a.resp || '').toLowerCase()
        .includes((emp.mat || '').toLowerCase())
    ).slice(0, 10);
  }

  if (!candidatos.length) {
    showToast('Nenhum computador encontrado nos Гәltimos 5 dias', 'warning');
    return;
  }

  _exibirSeletorVinculo('computador', candidatos, (selecionados) => {
    selecionados.forEach(ativo => {
      // Reutiliza a lГіgica existente de vincular
      const container = document.getElementById('ch-itens-vinculados');
      if (!container || container.querySelector(`[data-ativo-id="${ativo.id}"]`)) return;
      const label = `${ativo.pat || ativo.hostname} вҖ” ${ativo.desc || ''}`.trim();
      container.insertAdjacentHTML('beforeend', `
        <div data-ativo-id="${ativo.id}" data-ativo-pat="${ativo.pat||''}" data-ativo-doc-id="${ativo.id}"
             style="display:inline-flex;align-items:center;gap:5px;background:var(--accent-l);border:1px solid #93C5FD;border-radius:6px;padding:4px 10px;font-size:11.5px;font-weight:600;color:var(--accent)">
          рҹ–ҘпёҸ ${escapeHtml(label)}
          <span style="cursor:pointer;color:var(--g400);margin-left:3px" onclick="this.parentElement.remove()">вң•</span>
        </div>`);
    });
    showToast(`вң“ ${selecionados.length} ativo(s) vinculado(s)!`);
  });
}

// в”Җв”Җ Sugere smartphones vinculados ao empregado logado в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function sugerirSmartphonesPorEmpregado() {
  const emp = _empregadoLogado();
  if (!emp) return showToast('UsuГЎrio nГЈo identificado no sistema', 'warning');

  const sms = (STATE.smartphones || []).filter(s =>
    (s.empMat  || '').toLowerCase() === (emp.mat   || '').toLowerCase() ||
    (s.empNome || '').toLowerCase() === (emp.nome  || '').toLowerCase()
  );

  if (!sms.length) {
    showToast(`Nenhum smartphone vinculado a ${emp.nome}`, 'warning');
    return;
  }

  _exibirSeletorVinculo('smartphone', sms, (selecionados) => {
    selecionados.forEach(sm => {
      const container = document.getElementById('ch-itens-vinculados');
      if (!container || container.querySelector(`[data-sm-id="${sm.id}"]`)) return;
      const label = `${sm.marca} ${sm.modelo} (${sm.pat})${sm.empNome && sm.empNome !== 'вҖ”' ? ' вҖ” ' + sm.empNome : ''}`;
      container.insertAdjacentHTML('beforeend', `
        <div data-sm-id="${sm.id}" data-sm-pat="${sm.pat||''}" data-sm-imei="${sm.imei1||''}"
             style="display:inline-flex;align-items:center;gap:5px;background:#F0FDF4;border:1px solid #86EFAC;border-radius:6px;padding:4px 10px;font-size:11.5px;font-weight:600;color:#166534">
          рҹ“ұ ${escapeHtml(label)}
          <span style="cursor:pointer;color:var(--g400);margin-left:3px" onclick="this.parentElement.remove()">вң•</span>
        </div>`);
    });
    showToast(`вң“ ${selecionados.length} smartphone(s) vinculado(s)!`);
  });
}

// в”Җв”Җ Helper: retorna o empregado correspondente ao usuГЎrio logado в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function _empregadoLogado() {
  if (!CURRENT_USER) return null;
  const emailLogin = (CURRENT_USER.email || '').toLowerCase();
  const loginPart  = emailLogin.split('@')[0];
  return (STATE.empregados || []).find(e =>
    (e.email || '').toLowerCase() === emailLogin ||
    (e.login || '').toLowerCase() === loginPart  ||
    (e.login || '').toLowerCase() === emailLogin
  ) || (CURRENT_USER.nome ? { nome: CURRENT_USER.nome, mat: '', email: emailLogin } : null);
}

// в”Җв”Җ Helper: exibe modal de seleГ§ГЈo de ativos/smartphones в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function _exibirSeletorVinculo(tipo, itens, onConfirm) {
  const isPhone = tipo === 'smartphone';
  const titulo  = isPhone
    ? `рҹ“ұ Smartphones vinculados a vocГӘ`
    : `рҹ–ҘпёҸ Computadores recentes (Гәltimos 5 dias)`;

  const linhas = itens.map((item, i) => {
    const label = isPhone
      ? `${item.marca} ${item.modelo} вҖ” PAT: ${item.pat} вҖ” IMEI: ${item.imei1||'вҖ”'}`
      : `${item.pat || item.hostname} вҖ” ${item.desc || item.nome || ''} вҖ” ${item.area || ''}`;
    return `
      <label style="display:flex;align-items:center;gap:10px;padding:10px 12px;border-radius:8px;
             border:1px solid var(--g200);margin-bottom:8px;cursor:pointer;background:#fff;
             transition:background .15s" onmouseover="this.style.background='var(--g50)'"
             onmouseout="this.style.background='#fff'">
        <input type="checkbox" data-idx="${i}" style="width:16px;height:16px;accent-color:var(--accent)"
               ${itens.length === 1 ? 'checked' : ''}>
        <span style="font-size:12.5px;font-weight:600;color:var(--g700)">${escapeHtml(label)}</span>
      </label>`;
  }).join('');

  const pergunta = isPhone
    ? `O chamado Г© referente a qual smartphone?`
    : `O chamado Г© referente a qual computador?`;

  const html = `
    <div id="modal-sugerir-vinculo" style="position:fixed;inset:0;z-index:10100;display:flex;
         align-items:center;justify-content:center;background:rgba(0,0,0,.45)">
      <div style="background:#fff;border-radius:14px;padding:24px;width:480px;max-width:95vw;
                  max-height:80vh;display:flex;flex-direction:column;box-shadow:0 24px 64px rgba(0,0,0,.18)">
        <div style="font-size:14px;font-weight:700;color:var(--g800);margin-bottom:6px">${titulo}</div>
        <div style="font-size:12px;color:var(--g500);margin-bottom:16px">${pergunta}</div>
        <div style="overflow-y:auto;flex:1;margin-bottom:16px">${linhas}</div>
        <div style="display:flex;gap:8px;justify-content:flex-end">
          <button class="btn btn-ghost btn-sm"
                  onclick="document.getElementById('modal-sugerir-vinculo').remove()">
            Cancelar
          </button>
          <button class="btn btn-primary btn-sm" onclick="_confirmarSeletorVinculo()">
            вң“ Vincular Selecionados
          </button>
        </div>
      </div>
    </div>`;

  document.body.insertAdjacentHTML('beforeend', html);

  // Guarda referГӘncia para o callback
  window._seletorVinculoItens    = itens;
  window._seletorVinculoCallback = onConfirm;
}

function _confirmarSeletorVinculo() {
  const modal = document.getElementById('modal-sugerir-vinculo');
  if (!modal) return;
  const checks  = modal.querySelectorAll('input[type=checkbox]:checked');
  const indices = Array.from(checks).map(c => parseInt(c.dataset.idx));
  const selecionados = indices.map(i => window._seletorVinculoItens[i]).filter(Boolean);
  modal.remove();
  if (!selecionados.length) return showToast('Nenhum item selecionado', 'warning');
  window._seletorVinculoCallback?.(selecionados);
}

let _vinculoTimer = null;
function vincularAtivoAoChamado() {
  clearTimeout(_vinculoTimer);
  _vinculoTimer = setTimeout(_vincularAtivoAoChamadoExec, 200);
}
function _vincularAtivoAoChamadoExec() {
  const input = document.getElementById('ch-patrimonio');
  const q     = (input?.value || '').trim();
  if (q.length < 2) { 
    const res = document.getElementById('ch-patrimonio-resultados');
    if (res) res.style.display = 'none';
    return; 
  }

  const fontes = [
    ...(STATE.ativos       || []),
    ...(STATE.switches     || []),
    ...(STATE.impressorasDisc || []),
    ...(STATE.firewallsDisc   || []),
  ];
  const qLow = q.toLowerCase();
  const encontrados = fontes.filter(a =>
    (a.pat||'').toLowerCase().includes(qLow) ||
    (a.desc||'').toLowerCase().includes(qLow) ||
    (a.hostname||'').toLowerCase().includes(qLow) ||
    (a.nome||'').toLowerCase().includes(qLow)
  ).slice(0, 10);

  // Garante que o dropdown existe
  let res = document.getElementById('ch-patrimonio-resultados');
  if (!res) {
    res = document.createElement('div');
    res.id = 'ch-patrimonio-resultados';
    res.style.cssText = 'border:1px solid var(--g200);border-radius:8px;max-height:180px;overflow-y:auto;background:#fff;margin-top:4px;box-shadow:0 4px 12px rgba(0,0,0,.1)';
    input.parentElement.insertAdjacentElement('afterend', res);
  }

  if (!encontrados.length) {
    res.innerHTML = '<div style="padding:10px 14px;font-size:12px;color:var(--g400)">Nenhum ativo encontrado.</div>';
    res.style.display = '';
    return;
  }

  res.innerHTML = encontrados.map(a => `
    <div onclick="chSelecionarAtivo('${escapeHtml(a.id)}','${escapeHtml(a.pat||a.hostname||'')}','${escapeHtml(a.desc||a.hostname||'')}','${escapeHtml(a.id)}')"
         style="padding:9px 14px;cursor:pointer;border-bottom:1px solid var(--g100);font-size:12.5px;display:flex;gap:10px;align-items:center"
         onmouseover="this.style.background='var(--g50)'" onmouseout="this.style.background=''">
      <span style="font-weight:700;color:var(--accent);min-width:90px">${escapeHtml(a.pat||a.hostname||'вҖ”')}</span>
      <span style="color:var(--g700)">${escapeHtml(a.desc||a.hostname||'')}</span>
      <span style="color:var(--g400);font-size:11px;margin-left:auto">${escapeHtml(a.area||'')}</span>
    </div>`).join('');
  res.style.display = '';
}

function chSelecionarAtivo(id, pat, desc, docId) {
  const container = document.getElementById('ch-itens-vinculados');
  if (!container) return;
  if (container.querySelector(`[data-ativo-id="${id}"]`)) {
    showToast('Ativo jГЎ vinculado', 'warning'); return;
  }
  const label = `${pat}${desc ? ' вҖ” ' + desc : ''}`;
  container.insertAdjacentHTML('beforeend', `
    <div data-ativo-id="${escapeHtml(id)}" data-ativo-pat="${escapeHtml(pat)}" data-ativo-doc-id="${escapeHtml(docId)}"
         style="display:inline-flex;align-items:center;gap:5px;background:var(--accent-l);border:1px solid #93C5FD;border-radius:6px;padding:4px 10px;font-size:11.5px;font-weight:600;color:var(--accent)">
      рҹ–ҘпёҸ ${escapeHtml(label)}
      <span style="cursor:pointer;color:var(--g400);margin-left:3px" onclick="this.parentElement.remove();_chSincronizarPainelItens()">вң•</span>
    </div>`);
  const res = document.getElementById('ch-patrimonio-resultados');
  if (res) res.style.display = 'none';
  const input = document.getElementById('ch-patrimonio');
  if (input) input.value = '';
  showToast(`вң“ ${pat} vinculado!`);

  // Sincroniza com o painel direito de itens
  _chSincronizarPainelItens();

  // Preenche tipo de item automaticamente baseado no ativo
  const ativo = [...(STATE.ativos||[]), ...(STATE.impressorasDisc||[])].find(a => a.id === id || a.pat === pat);
  if (ativo) {
    const tipoMap = {
      'computador':'computador','desktop':'computador','workstation':'computador',
      'notebook':'notebook','laptop':'notebook',
      'monitor':'monitor',
      'impressora':'impressora','printer':'impressora',
      'smartphone':'smartphone','celular':'smartphone',
      'switch':'switch','router':'switch',
      'servidor':'servidor','server':'servidor',
    };
    const tipoAtivo = (ativo.tipo||'').toLowerCase();
    const tipoMapeado = Object.entries(tipoMap).find(([k]) => tipoAtivo.includes(k))?.[1] || '';
    const selTipo = document.getElementById('ch-item-tipo');
    if (selTipo && tipoMapeado) selTipo.value = tipoMapeado;

    // Preenche tambГ©m o PAT no campo do painel direito
    const patInput = document.getElementById('ch-patrimonio-modal');
    if (patInput && !patInput.value) patInput.value = pat;
  }
}

// Sincroniza ch-itens-vinculados (esquerda) вҶ’ ch-itens-vinculados-panel (direita)
function _chSincronizarPainelItens() {
  const panel = document.getElementById('ch-itens-vinculados-panel');
  const countEl = document.getElementById('itens-ch-count');
  const source = document.getElementById('ch-itens-vinculados');
  if (!panel || !source) return;

  const itens = Array.from(source.querySelectorAll('[data-ativo-id]'));
  if (countEl) countEl.textContent = itens.length;

  panel.innerHTML = itens.map(el => {
    const pat  = el.dataset.ativoPat   || '';
    const id   = el.dataset.ativoId    || '';
    const docId= el.dataset.ativoDocId || '';
    const txt  = el.textContent.replace('вң•','').trim();
    return `
    <div style="display:flex;align-items:center;gap:6px;padding:6px 8px;background:var(--accent-l);
                border:1px solid #93C5FD;border-radius:8px;font-size:12px;font-weight:600;color:var(--accent)">
      рҹ–ҘпёҸ <span style="flex:1">${escapeHtml(txt)}</span>
      <span style="cursor:pointer;color:var(--g400);font-size:11px"
            onclick="document.querySelector('#ch-itens-vinculados [data-ativo-id=\'${escapeHtml(id)}\']')?.remove();_chSincronizarPainelItens()">вң•</span>
    </div>`;
  }).join('');
}

function vincularSmartphone() {
  const input = document.getElementById('ch-smartphone-busca');
  const q     = (input?.value || '').trim().toLowerCase();
  if (!q) return showToast('Informe o login, matrГӯcula ou IMEI do smartphone', 'danger');

  const sms = STATE.smartphones || [];

  // Busca exata primeiro: empMat, imei1, imei2, pat
  let sm = sms.find(s =>
    (s.empMat  || '').toLowerCase() === q ||
    (s.imei1   || '').toLowerCase() === q ||
    (s.imei2   || '').toLowerCase() === q ||
    (s.pat     || '').toLowerCase() === q
  );

  // Busca parcial: nome do empregado, login AD, modelo
  if (!sm) {
    sm = sms.find(s =>
      (s.empNome   || '').toLowerCase().includes(q) ||
      (s.empLogin  || '').toLowerCase().includes(q) ||
      (s.empMat    || '').toLowerCase().includes(q) ||
      (s.modelo    || '').toLowerCase().includes(q) ||
      ((s.marca||'')+' '+(s.modelo||'')).toLowerCase().includes(q)
    );
  }

  if (!sm) {
    showToast(`"${input.value}" nГЈo encontrado вҖ” tente login, matrГӯcula ou IMEI`, 'danger');
    return;
  }

  const container = document.getElementById('ch-itens-vinculados');
  if (!container) return;

  // Evita duplicata
  if (container.querySelector(`[data-sm-id="${sm.id}"]`)) {
    showToast('Smartphone jГЎ vinculado', 'warning');
    return;
  }

  const label = `${sm.marca} ${sm.modelo} (${sm.pat})${sm.empNome && sm.empNome !== 'вҖ”' ? ' вҖ” ' + sm.empNome : ''}`;
  container.insertAdjacentHTML('beforeend', `
    <div data-sm-id="${sm.id}" data-sm-pat="${sm.pat||''}" data-sm-imei="${sm.imei1||''}"
         style="display:inline-flex;align-items:center;gap:5px;background:#F0FDF4;border:1px solid #86EFAC;border-radius:6px;padding:4px 10px;font-size:11.5px;font-weight:600;color:#166534">
      рҹ“ұ ${escapeHtml(label)}
      <span style="cursor:pointer;color:var(--g400);margin-left:3px" onclick="this.parentElement.remove()">вң•</span>
    </div>`);

  input.value = '';
  showToast(`вң“ Smartphone ${sm.marca} ${sm.modelo} (${sm.empNome || sm.pat}) vinculado!`);
}

