async function salvarAtendimento() {
  const chamadoId = document.getElementById('atender-ch-id').textContent.trim();
  const ch = (STATE.chamados || []).find(c => c.id === chamadoId);
  if (!ch) return showToast('Chamado nГЈo encontrado', 'danger');

  const diagnostico = document.getElementById('at-diagnostico')?.value || '';
  if (!diagnostico) return showToast('Selecione o diagnГіstico', 'danger');

  // Coleta descriГ§ГЈo do atendimento
  const descAtendimento = document.querySelector('#modal-atender-chamado textarea')?.value?.trim() || '';

  // Coleta ativos vinculados (seГ§ГЈo tГ©cnico)
  const ativosVinculadosTec = Array.from(
    document.querySelectorAll('#at-itens-vinculados [data-ativo-id]')
  ).map(el => ({
    id:    el.dataset.ativoId    || '',
    pat:   el.dataset.ativoPat   || '',
    docId: el.dataset.ativoDocId || '',
  }));

  // Mescla com ativos jГЎ salvos no chamado
  const ativosExistentes = ch.ativosVinculados || [];
  const ativosFinais = [...ativosExistentes];
  for (const av of ativosVinculadosTec) {
    if (!ativosFinais.some(e => e.id === av.id)) ativosFinais.push(av);
  }

  const mudouLugar = document.querySelector('input[name="mudou-lugar"]:checked')?.value === 'sim';
  const destino    = document.getElementById('at-destino-antigo')?.value || '';

  // в”Җв”Җ Regra: nenhum chamado pode ser encerrado sem ativo vinculado в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  const ativosFinaisCheck = [...(ch.ativosVinculados || [])];
  for (const av of ativosVinculadosTec) {
    if (!ativosFinaisCheck.some(e => e.id === av.id)) ativosFinaisCheck.push(av);
  }
  // "Salvar Atendimento" nГЈo encerra, mas se o diagnГіstico indica conclusГЈo avisa
  if (!ativosFinaisCheck.length) {
    // Bloco vermelho no modal
    const vincBox = document.getElementById('at-itens-existentes');
    if (vincBox) {
      vincBox.insertAdjacentHTML('afterend',
        '<div id="at-alerta-ativo" style="color:var(--danger);font-size:12px;font-weight:600;margin-top:6px">' +
        'вҡ пёҸ Vincule ao menos um ativo antes de salvar o atendimento.</div>');
      setTimeout(() => document.getElementById('at-alerta-ativo')?.remove(), 4000);
    }
    return showToast('вҡ пёҸ ObrigatГіrio: vincule ao menos um ativo ao chamado', 'danger', 5000);
  }

  const agora = new Date();
  const update = {
    status:           mudouLugar ? 'aguardando-aprovacao' : 'em-atendimento',
    diagnostico,
    descAtendimento,
    ativosVinculados: ativosFinais,
    atualizadoEm:     agora,
    tecnicoResponsavel: CURRENT_USER?.uid || '',
  };

  // Registra pat do primeiro ativo se nГЈo havia
  if (!ch.pat && ativosFinais.length) update.pat = ativosFinais[0].pat || '';

  // Registra histГіrico em TODOS os ativos vinculados (existentes + adicionados pelo tГ©cnico)
  if (FB_READY && db && ativosFinais.length) {
    const histEntry = {
      evento:      'chamado-atendido',
      chamadoId,
      titulo:      ch.desc?.split('\n')[0] || chamadoId,
      diagnostico: diagnostico,
      tecnico:     CURRENT_USER?.nome || CURRENT_USER?.uid || 'TГ©cnico',
      data:        agora,
      obs:         descAtendimento || `Atendimento do chamado ${chamadoId}`,
    };
    for (const av of ativosFinais) {
      const docId = av.docId || av.id;
      if (!docId) continue;
      try {
        let escrito = false;
        for (const col of ['ativos','impressoras','switches','firewalls']) {
          try {
            const snap = await db.collection(col).doc(docId).get();
            if (snap.exists) {
              const entrada = { ...histEntry,
                evento: ativosVinculadosTec.some(a=>(a.docId||a.id)===docId)
                  ? 'chamado-vinculado-tecnico' : 'chamado-atendido'
              };
              await db.collection(col).doc(docId).collection('historico').add(entrada);
              console.log(`[Atendimento] вң“ HistГіrico escrito: ${av.pat||docId} em ${col}`);
              escrito = true; break;
            }
          } catch(_) {}
        }
        if (!escrito) {
          await db.collection('ativos').doc(docId).collection('historico').add(histEntry);
        }
      } catch(e) { console.warn('[atendimento] histГіrico ativo:', e.message); }
    }
  }

  // Salva no Firestore
  try {
    await fsUpdate('chamados', chamadoId, update);
    // Atualiza STATE local
    Object.assign(ch, update);
    showToast('вң“ Atendimento salvo com sucesso!', 'success');
  } catch(e) {
    showToast('Erro ao salvar: ' + e.message, 'danger');
    return;
  }

  // Fluxo de movimentaГ§ГЈo
  if (mudouLugar && destino === 'terceirizada') {
    const aprov = {
      id: await gerarIdAprovacao(),
      chamadoId,
      tipo: 'Envio para Terceirizada',
      pat: ch.pat || 'вҖ”',
      ativo: ch.desc || 'вҖ”',
      solicitante: CURRENT_USER?.nome || 'TГ©cnico',
      data: agora,
      status: 'pendente',
      obs: '',
    };
    if (!STATE.aprovacoes) STATE.aprovacoes = [];
    STATE.aprovacoes.unshift(aprov);
    if (FB_READY && db) await db.collection('aprovacoes').add(aprov).catch(() => {});
    showToast('вҸі Enviado para aprovaГ§ГЈo do gestor', 'warning');
  }

  closeModal('modal-atender-chamado');
  renderChamados();
  renderDashboard();
}

// в”Җв”Җ Vincular ativo durante atendimento (tГ©cnico) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
let _atVincTimer = null;
function atVincularAtivo(immediate) {
  if (immediate) { _atVincularAtivoExec(); return; }
  clearTimeout(_atVincTimer);
  _atVincTimer = setTimeout(_atVincularAtivoExec, 220);
}
function _atVincularAtivoExec() {
  const input = document.getElementById('at-vincular-busca');
  const q     = (input?.value || '').trim();
  const res   = document.getElementById('at-vincular-resultados');
  if (!res) return;

  const fontes = [...(STATE.ativos||[]), ...(STATE.switches||[]), ...(STATE.impressorasDisc||[])];

  // Campo vazio вҶ’ mostra primeiros 12 ativos para o tГ©cnico escolher
  let encontrados;
  if (q.length < 2) {
    encontrados = fontes.slice(0, 12);
  } else {
    const qLow = q.toLowerCase();
    encontrados = fontes.filter(a =>
      (a.pat||'').toLowerCase().includes(qLow) ||
      (a.desc||'').toLowerCase().includes(qLow) ||
      (a.hostname||'').toLowerCase().includes(qLow) ||
      (a.nome||'').toLowerCase().includes(qLow)
    ).slice(0, 12);
  }

  if (!encontrados.length) {
    res.innerHTML = '<div style="padding:10px 14px;font-size:12px;color:var(--g400)">Nenhum ativo encontrado.</div>';
    res.style.display = '';
    return;
  }

  const header = q.length < 2
    ? '<div style="padding:6px 14px;font-size:11px;color:var(--g500);border-bottom:1px solid var(--g100);font-style:italic">Mostrando primeiros ativos вҖ” digite para filtrar</div>'
    : '';

  res.innerHTML = header + encontrados.map(a => {
    const pat  = escapeHtml(a.pat||a.hostname||'вҖ”');
    const desc = escapeHtml(a.desc||a.hostname||'');
    const area = escapeHtml(a.area||'');
    const id   = escapeHtml(a.id);
    const patRaw = escapeHtml(a.pat||a.hostname||'');
    const descRaw= escapeHtml(a.desc||a.hostname||'');
    return `<div onclick="atConfirmarVincularAtivo('${id}','${patRaw}','${descRaw}','${id}')"
         style="padding:9px 14px;cursor:pointer;border-bottom:1px solid var(--g100);font-size:12.5px;display:flex;gap:10px;align-items:center"
         onmouseover="this.style.background='var(--g50)'" onmouseout="this.style.background=''">
      <span style="font-weight:700;color:var(--accent);min-width:90px">${pat}</span>
      <span style="color:var(--g700);flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${desc}</span>
      <span style="color:var(--g400);font-size:11px;flex-shrink:0">${area}</span>
    </div>`;
  }).join('');
  res.style.display = '';
}
function atConfirmarVincularAtivo(id, pat, desc, docId) {
  const container = document.getElementById('at-itens-vinculados');
  if (!container) return;
  if (container.querySelector(`[data-ativo-id="${id}"]`)) {
    showToast('Ativo jГЎ vinculado', 'warning');
    return;
  }
  const label = `${pat} вҖ” ${desc}`.trim().replace(/ вҖ” $/, '');
  container.insertAdjacentHTML('beforeend', `
    <div data-ativo-id="${escapeHtml(id)}" data-ativo-pat="${escapeHtml(pat)}" data-ativo-doc-id="${escapeHtml(docId)}"
         style="display:inline-flex;align-items:center;gap:5px;background:var(--accent-l);border:1px solid #93C5FD;border-radius:6px;padding:4px 10px;font-size:11.5px;font-weight:600;color:var(--accent)">
      рҹ–ҘпёҸ ${escapeHtml(label)}
      <span style="cursor:pointer;color:var(--g400);margin-left:3px" onclick="this.parentElement.remove()">вң•</span>
    </div>`);
  // Fecha dropdown e limpa busca
  document.getElementById('at-vincular-resultados').style.display = 'none';
  document.getElementById('at-vincular-busca').value = '';
  showToast(`вң“ ${pat} vinculado ao chamado`);
}

