// Cache de populateSelects вҖ” evita reprocessar a cada openModal
let _populateSelectsDone = false;
function _resetPopulateCache() { _populateSelectsDone = false; }

function openModal(id) {
  if (!_populateSelectsDone) { populateSelects(); _populateSelectsDone = true; }
  const el = document.getElementById(id);
  if (el) el.classList.add('open');
  if (id === 'modal-novo-chamado') {
    const now = new Date();
    const iso = now.toISOString().slice(0,16);
    const abEl = document.getElementById('ch-data-abertura');
    if (abEl) abEl.value = iso;
    const bolhaNow = document.getElementById('ch-bolha-now');
    if (bolhaNow) bolhaNow.textContent = now.toLocaleString('pt-BR');
    // PrГ©-preenche requerente com o empregado correspondente ao usuГЎrio logado
    const solEl = document.getElementById('ch-solicitante');
    if (solEl && !solEl.value && CURRENT_USER) {
      // Tenta achar o empregado pelo email ou login (sAMAccountName)
      const emailLogin = (CURRENT_USER.email || '').toLowerCase();
      const loginPart  = emailLogin.split('@')[0]; // ex: "ana.penha"
      const emp = (STATE.empregados || []).find(e =>
        (e.email || '').toLowerCase() === emailLogin ||
        (e.login || '').toLowerCase() === loginPart  ||
        (e.login || '').toLowerCase() === emailLogin
      );
      if (emp) {
        solEl.value = emp.nome || CURRENT_USER.nome || '';
        // PrГ©-preenche email do requerente
        const emailEl = document.getElementById('ch-sol-email');
        if (emailEl) emailEl.value = emp.email || CURRENT_USER.email || '';
        // PrГ©-preenche matrГӯcula e ramal do requerente
        const matEl   = document.getElementById('ch-sol-matricula');
        const ramalEl = document.getElementById('ch-sol-ramal');
        if (matEl)   matEl.value   = emp.mat   || '';
        if (ramalEl) ramalEl.value = emp.ramal || emp.telefone || '';
        // PrГ©-preenche ГЎrea baseado na sigla organizacional do empregado
        const areaEl = document.getElementById('ch-area');
        const _siglaEmp = _siglaDoEmpregado(emp);
        if (areaEl && _siglaEmp) {
          _popularSelectArea(areaEl, _siglaEmp);
        }
        // PrГ©-preenche localizaГ§ГЈo com a ГЎrea/setor do empregado
        _preencherLocalizacao(emp);
        console.log(`[Chamado] Requerente identificado: ${emp.nome} (${emp.mat}) вҖ” ${emp.setor || emp.lotacao}`);
      } else {
        solEl.value = CURRENT_USER.nome || CURRENT_USER.email || '';
        const emailEl = document.getElementById('ch-sol-email');
        if (emailEl) emailEl.value = CURRENT_USER.email || '';
      }
      atualizarIniciais();
    }
    const sel = document.getElementById('ch-tecnico');
    if (sel && STATE.tecnicos) {
      sel.innerHTML = '<option value="">вҖ” Selecione o tГ©cnico вҖ”</option>' +
        STATE.tecnicos.filter(t=>t.empresa==='adsi').map(t=>`<option value="${t.id}">${t.nome}</option>`).join('');
    }
  }
}
function closeModal(id) {
  // Reset lazy-rendered sections
  if (id === 'modal-atender-chamado') {
    const sub = document.getElementById('sub-mudou-lugar');
    if (sub) { sub.innerHTML = ''; delete sub.dataset.rendered; sub.style.display = 'none'; }
    document.querySelectorAll('input[name="mudou-lugar"]').forEach(r => r.checked = false);
    document.getElementById('ro-nao')?.classList.remove('checked');
    document.getElementById('ro-sim')?.classList.remove('checked');
  }
  const el = document.getElementById(id);
  if (el) el.classList.remove('open');
}

/**
 * Retorna a sigla organizacional (ex: A-DSI) de um empregado.
 *
 * O AD da CESAN guarda em `department` (вҶ’ emp.setor) o local fГӯsico
 * (ex: "Rui Barbosa"), e a sigla da gerГӘncia fica na OU do DN do LDAP.
 * O agente salva essa sigla em `emp.lotacao` quando `department` estГЎ vazio,
 * e tambГ©m em `orgUnidades` como coleГ§ГЈo separada.
 *
 * EstratГ©gia:
 * 1. Se emp.lotacao parece uma sigla (contГ©m hГӯfen ou Г© maiГәscula curta), usa ela
 * 2. Busca em orgUnidades pela matrГӯcula do empregado
 * 3. Fallback: emp.setor
 */
function _siglaDoEmpregado(emp) {
  if (!emp) return '';

  // 1. emp.lotacao pode jГЎ ser a sigla (A-DSI, E-DCA, etc.) quando vem do DN
  const lotacao = emp.lotacao || '';
  const isSigla = /^[A-Z][-][A-Z]/.test(lotacao) || // A-DSI, E-DCA...
                  (/^[A-Z]{1,2}-/.test(lotacao) && lotacao.length <= 10);
  if (isSigla) return lotacao;

  // 2. Busca em orgUnidades pela matrГӯcula
  if (emp.mat) {
    const unidade = (STATE.orgUnidades || []).find(u =>
      (u.empregados || []).some(e =>
        e.mat === emp.mat || e.login === emp.login
      )
    );
    if (unidade?.sigla) return unidade.sigla;
  }

  // 3. Fallback: setor (pode ser o local fГӯsico, mas Г© o que temos)
  return emp.setor || emp.lotacao || '';
}

/**
 * Preenche o select de localizaГ§ГЈo com a ГЎrea/setor do empregado.
 * Popula dinamicamente a partir do STATE.orgUnidades e empregados,
 * e seleciona a unidade correspondente ao empregado.
 */
function _preencherLocalizacao(emp) {
  const locEl = document.getElementById('ch-localizacao');
  if (!locEl) return;

  // Coleta localizaГ§Гөes Гәnicas: prefer orgUnidades (tem nome completo)
  const locais = new Map(); // sigla вҶ’ nome completo

  (STATE.orgUnidades || []).forEach(u => {
    if (u.sigla) locais.set(u.sigla, u.nome || u.sigla);
  });

  // Complementa com setores dos empregados se orgUnidades vazio
  if (locais.size === 0) {
    (STATE.empregados || []).forEach(e => {
      const s = e.setor || e.lotacao || e.area;
      if (s) locais.set(s, s);
    });
  }

  // Determina a localizaГ§ГЈo do empregado
  const setorEmp = _siglaDoEmpregado(emp);

  // ReconstrГіi opГ§Гөes
  locEl.innerHTML = '<option value="">вҖ” Selecione вҖ”</option>';
  [...locais.entries()].sort((a,b) => a[0].localeCompare(b[0])).forEach(([sigla, nome]) => {
    const opt = document.createElement('option');
    opt.value = sigla;
    opt.textContent = nome !== sigla ? `${sigla} вҖ” ${nome}` : sigla;
    if (sigla === setorEmp) opt.selected = true;
    locEl.appendChild(opt);
  });

  // Se o setor do empregado nГЈo estava na lista, adiciona
  if (setorEmp && !locais.has(setorEmp)) {
    const opt = document.createElement('option');
    opt.value = setorEmp;
    opt.textContent = setorEmp;
    opt.selected = true;
    locEl.appendChild(opt);
  }

  locEl.value = setorEmp || '';

  // Limpa o campo de detalhamento
  const detalheEl = document.getElementById('ch-localizacao-detalhe');
  if (detalheEl) detalheEl.value = '';
}

/**
 * Popula o select de ГЎrea com os setores Гәnicos dos empregados e
 * define o valor atual. Garante que o setor do empregado apareГ§a
 * mesmo que nГЈo estivesse nas opГ§Гөes fixas do HTML.
 */
function _popularSelectArea(selectEl, setorAtual) {
  if (!selectEl) return;

  // Coleta setores Гәnicos dos empregados (usa orgUnidades se disponГӯvel)
  const setores = new Set();

  // Tenta primeiro pegar do organograma (siglas como A-DSI, A-GTIвҖҰ)
  (STATE.orgUnidades || []).forEach(u => { if (u.sigla) setores.add(u.sigla); });

  // Complementa com setores dos empregados
  (STATE.empregados || []).forEach(e => {
    if (e.setor)   setores.add(e.setor);
    if (e.lotacao) setores.add(e.lotacao);
    if (e.area)    setores.add(e.area);
  });

  // Se nГЈo tiver dados ainda, mantГ©m as opГ§Гөes estГЎticas do HTML
  if (setores.size === 0) {
    if (setorAtual) {
      // Adiciona pelo menos o setor do usuГЎrio atual
      const exists = selectEl.querySelector(`option[value="${CSS.escape(setorAtual)}"]`);
      if (!exists) {
        const opt = document.createElement('option');
        opt.value = setorAtual;
        opt.textContent = setorAtual;
        selectEl.appendChild(opt);
      }
    }
    selectEl.value = setorAtual || '';
    return;
  }

  // ReconstrГіi as opГ§Гөes
  const atualVal = selectEl.value || setorAtual;
  selectEl.innerHTML = '<option value="">вҖ” Selecione вҖ”</option>';
  [...setores].sort().forEach(s => {
    const opt = document.createElement('option');
    opt.value = s;
    opt.textContent = s;
    if (s === atualVal) opt.selected = true;
    selectEl.appendChild(opt);
  });

  // Se o valor atual nГЈo estava na lista, adiciona
  if (setorAtual && !setores.has(setorAtual)) {
    const opt = document.createElement('option');
    opt.value = setorAtual;
    opt.textContent = setorAtual;
    opt.selected = true;
    selectEl.appendChild(opt);
  }

  selectEl.value = setorAtual || atualVal || '';
}

// ============================================================
// TOAST
// ============================================================
function _fixToastPosition() {
  const t = document.getElementById('toast');
  if (!t) return;
  t.style.position  = 'fixed';
  t.style.top       = '16px';
  t.style.right     = '20px';
  t.style.bottom    = '';
  t.style.zIndex    = '99999';
}

function showToast(msg, type='success', duration=2500) {
  _fixToastPosition();
  const container = document.getElementById('toast');
  const t = document.createElement('div');
  const c = {success:['#0F172A','#10B981','#fff'], danger:['#FEF2F2','#DC2626','#991B1B'], warning:['#FFFBEB','#D97706','#92400E'], info:['#EFF6FF','#2563EB','#1E40AF']};
  const [bg,accent,text] = c[type]||c.success;
  const icon = type==='success'?'вң“':type==='danger'?'вң•':type==='warning'?'вҡ ':'в„№';
  t.style.cssText=`background:${bg};color:${text};padding:11px 18px;border-radius:10px;font-size:13px;font-weight:600;box-shadow:0 20px 48px rgba(0,0,0,.14);display:flex;gap:8px;align-items:center;pointer-events:all;border:1px solid ${accent}33;animation:fadeUp .25s ease;font-family:'Inter',sans-serif;max-width:380px`;
  t.innerHTML=`<span style="color:${accent};font-size:16px">${icon}</span><span>${msg}</span>`;
  container.appendChild(t);
  setTimeout(()=>{ t.style.opacity='0'; t.style.transform='translateY(-8px)'; t.style.transition='all .3s ease'; setTimeout(()=>t.remove(),300); }, duration);
}

