function fmtDatetime(d) {
  if (!d) return 'вҖ”';
  const dt = d instanceof Date ? d : new Date(d);
  if (isNaN(dt)) return 'вҖ”';
  return dt.toLocaleDateString('pt-BR') + ' ' + dt.toLocaleTimeString('pt-BR', {hour:'2-digit',minute:'2-digit'});
}

