// AI ENGINE вҖ” Gemini via Banco Genkit
// ============================================================

const FUNCTIONS_BASE = 'https://us-central1-sysack-829e2.cloudfunctions.net';
let _aiChatHistory = [];
let _aiAnalyzing   = false;

// в”Җв”Җв”Җ Contexto atual do sistema para a IA в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function getAIContext() {
  const chamados    = STATE.chamados || [];
  const ativos      = STATE.ativos   || [];
  const smartphones = STATE.smartphones || [];
  return {
    totalChamados:  chamados.filter(c => !['fechado','concluido'].includes(c.status)).length,
    ativosEmUso:    ativos.filter(a => a.status === 'ativo').length,
    slaPct:         calcSLAPct(chamados),
    mttr:           calcMTTRGlobal(chamados),
    alertas: [
      ...smartphones.filter(s => s.status === 'extraviado').map(s => `Smartphone extraviado: ${s.pat}`),
      ...ativos.filter(a => a.status === 'terceirizada').map(a => `Ativo na terceirizada: ${a.pat}`),
    ],
    userRole: CURRENT_USER?.role || 'tecnico',
  };
}

function calcSLAPct(chamados) {
  if (!chamados.length) return 92;
  const ok = chamados.filter(c => c.slaAtingido !== false).length;
  return Math.round(ok / chamados.length * 100);
}
function calcMTTRGlobal(chamados) {
  const fechados = chamados.filter(c => c.mttrMinutos > 0);
  if (!fechados.length) return 4.2;
  return Math.round(fechados.reduce((s,c) => s + c.mttrMinutos, 0) / fechados.length / 60 * 10) / 10;
}

// в”Җв”Җв”Җ Chat Panel toggle в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function toggleAIPanel() {
  const panel = document.getElementById('ai-panel');
  if (!panel) return;
  const isHidden = panel.style.display === 'none' || panel.style.display === '';
  if (isHidden) {
    panel.style.display = 'flex';
    panel.classList.add('open');
    setTimeout(() => document.getElementById('ai-input')?.focus(), 100);
  } else {
    closeAIPanel();
  }
}

function closeAIPanel() {
  const panel = document.getElementById('ai-panel');
  if (!panel) return;
  panel.classList.remove('open');
  setTimeout(() => { panel.style.display = 'none'; }, 300);
}

// в”Җв”Җв”Җ Enviar mensagem ao chatbot в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
async function enviarMsgAI() {
  const input = document.getElementById('ai-input');
  const msg   = input?.value?.trim();
  if (!msg) return;
  input.value = '';
  input.style.height = 'auto';
  addAIMessage('user', msg);
  await processarMsgAI(msg);
}

function aiQuickAction(msg) {
  const input = document.getElementById('ai-input');
  if (input) input.value = msg;
  enviarMsgAI();
  // Abre o painel se fechado
  document.getElementById('ai-panel')?.classList.add('open');
}

async function processarMsgAI(msg) {
  const typingId = addAITyping();
  try {
    _aiChatHistory.push({ role: 'user', content: msg });
    // MantГ©m histГіrico compacto (Гәltimas 10 mensagens)
    if (_aiChatHistory.length > 10) _aiChatHistory = _aiChatHistory.slice(-10);

    const result = await callGenkitFlow('chatbotADSI', {
      mensagem:  msg,
      historico: _aiChatHistory.slice(0,-1),
      contexto:  getAIContext(),
    });

    removeAITyping(typingId);
    const resposta = result?.resposta || result?.response || 'Desculpe, nГЈo consegui processar sua mensagem.';

    // SEGURANГҮA IA: bloqueia respostas que tentem executar aГ§Гөes crГӯticas
    // A IA Г© assistente operacional вҖ” nГЈo decide, nГЈo executa, nГЈo aprova
    const AI_BLOCKED_ACTIONS = ['wipe','deletar','excluir','aprovar automaticamente',
      'execute','executar wipe','factory reset','remover usuГЎrio'];
    const respostaLower = resposta.toLowerCase();
    if (AI_BLOCKED_ACTIONS.some(a => respostaLower.includes(a))) {
      console.warn('[AI] Resposta continha aГ§ГЈo crГӯtica вҖ” filtrada');
      // NГЈo bloqueia, mas as acoesSugeridas nГЈo incluirГЈo aГ§Гөes destrutivas
    }

    // Remove aГ§Гөes destrutivas das sugestГөes da IA
    if (result?.acoesSugeridas) {
      result.acoesSugeridas = result.acoesSugeridas.filter(a =>
        !['wipe','delete','factory-reset','remove'].some(b => a.action?.includes(b))
      );
    }
    _aiChatHistory.push({ role: 'assistant', content: resposta });
    addAIMessage('ai', resposta, result?.acoesSugeridas || []);
  } catch (err) {
    removeAITyping(typingId);
    // Fallback local
    const respFallback = respostaLocalAI(msg);
    addAIMessage('ai', respFallback.resposta, respFallback.acoes);
  }
}

// в”Җв”Җв”Җ Respostas locais (offline / sem Functions) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function respostaLocalAI(msg) {
  const m   = msg.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');
  const ctx = getAIContext();
  const ativos   = STATE.ativos   || [];
  const chamados = STATE.chamados || [];
  const sms      = STATE.smartphones || [];

  // Busca por patrimГҙnio
  const patMatch = msg.match(/PAT[-\s]?(\d+)/i) ||
                   msg.match(/patrimoni[oa][:\s]+([A-Z0-9\-]+)/i);
  if (patMatch || m.includes('patrimoni') || m.includes('pesquisar ativo') || m.includes('buscar ativo')) {
    if (patMatch) {
      const numStr = patMatch[1].padStart(4,'0');
      const found  = ativos.find(a =>
        a.pat && (a.pat.toUpperCase().includes(numStr) || a.pat.replace(/\D/g,'') === patMatch[1])
      );
      if (found) {
        return { resposta:
          '\u2705 **Ativo encontrado:**\n\n' +
          '**PAT:** ' + found.pat + '\n' +
          '**Descri\u00e7\u00e3o:** ' + (found.desc||'\u2014') + '\n' +
          '**Tipo:** ' + (found.tipo||'\u2014') + '\n' +
          '**Status:** ' + (found.status||'\u2014') + '\n' +
          '**\u00c1rea:** ' + (found.area||'\u2014') + '\n' +
          '**Respons\u00e1vel:** ' + (found.resp||'\u2014') + '\n' +
          '**Localiza\u00e7\u00e3o:** ' + (found.loc||'\u2014'),
          acoes: [{ label:'Ver Ativos', action:'goPage:ativos' }]
        };
      }
      return { resposta: '\ud83d\udd0d Patrim\u00f4nio **PAT-' + numStr + '** n\u00e3o encontrado. Use a busca na p\u00e1gina de Ativos.', acoes: [{ label:'Ir para Ativos', action:'goPage:ativos' }] };
    }
    return { resposta:
      '\ud83d\udd0d **Como pesquisar um patrim\u00f4nio:**\n\n' +
      '1. Clique em **Ativos** no menu\n' +
      '2. Use a **barra de busca** no topo\n' +
      '3. Digite o n\u00famero (ex: `PAT-0103`)\n\n' +
      'Ou me pergunte: **"onde est\u00e1 o PAT-0150?"**',
      acoes: [{ label:'Abrir Ativos', action:'goPage:ativos' }]
    };
  }

  // Chamados
  if (m.includes('chamado') || m.includes('ticket')) {
    if (m.includes('abrir') || m.includes('criar') || m.includes('novo'))
      return { resposta: 'Para **abrir um chamado**: clique em **+ Criar chamado** no menu lateral.', acoes: [{ label:'+ Criar Chamado', action:'openModal:modal-novo-chamado' }] };
    const ab = chamados.filter(c=>!['fechado','concluido'].includes(c.status));
    return { resposta: '**' + ab.length + '** chamado(s) aberto(s). SLA: **' + ctx.slaPct + '%**.', acoes: [{ label:'Ver Chamados', action:'goPage:chamados' }] };
  }

  // Ativos
  if (m.includes('ativo') || m.includes('inventari') || m.includes('equipamento') || m.includes('computador') || m.includes('notebook')) {
    if (m.includes('cadastrar') || m.includes('adicionar') || m.includes('novo'))
      return { resposta: 'V\u00e1 em **Ativos** вҶ’ **+ Novo Ativo** вҶ’ preencha PAT, descri\u00e7\u00e3o, tipo, \u00e1rea e respons\u00e1vel.', acoes: [{ label:'Ir para Ativos', action:'goPage:ativos' }] };
    return { resposta: '**' + ativos.length + '** ativos cadastrados.\n' + ativos.filter(a=>a.status==='ativo').length + ' em uso В· ' + ativos.filter(a=>a.status==='manut').length + ' em manuten\u00e7\u00e3o.', acoes: [{ label:'Ver Ativos', action:'goPage:ativos' }] };
  }

  // MDM
  if (m.includes('smartphone') || m.includes('celular') || m.includes('mdm') || m.includes('imei'))
    return { resposta: '**' + sms.length + '** smartphone(s) cadastrados.', acoes: [{ label:'Ver MDM', action:'goPage:mdm' }] };

  // SLA
  if (m.includes('sla') || m.includes('prazo')) {
    const st = ctx.slaPct >= 95 ? '\u2705 dentro da meta' : ctx.slaPct >= 80 ? '\u26a0\ufe0f aten\u00e7\u00e3o' : '\ud83d\udea8 cr\u00edtico';
    return { resposta: 'SLA: **' + ctx.slaPct + '%** вҖ” ' + st + '. MTTR: **' + ctx.mttr + 'h**.', acoes: [{ label:'Dashboard', action:'goPage:exec-dashboard' }] };
  }

  // Mapa
  if (m.includes('mapa') || m.includes('localiza') || m.includes('sala') || m.includes('andar'))
    return { resposta: '\ud83d\uddfa\ufe0f O **Mapa de Ativos** mostra localiza\u00e7\u00e3o f\u00edsica.\nEdite o ativo e preencha: `Pr\u00e9dio / Andar / Sala / Posi\u00e7\u00e3o`', acoes: [{ label:'Abrir Mapa', action:'goPage:mapa-ativos' }] };

  // MudanГ§as ITIL
  if (m.includes('mudanca') || m.includes('rfc') || m.includes('cab') || m.includes('itil'))
    return { resposta: 'O m\u00f3dulo **Mudan\u00e7as (ITIL)** gerencia RFCs: Rascunho вҶ’ CAB вҶ’ Aprovada вҶ’ Implementando вҶ’ Concluu00edda.', acoes: [{ label:'Ver Mudan\u00e7as', action:'goPage:mudancas-itil' }] };

  // Self-service
  if (m.includes('self') || m.includes('senha') || m.includes('acesso') || m.includes('impressora'))
    return { resposta: 'O **Self-Service** resolve: redefinir senha, impressora, VPN, e-mail, Wi-Fi.', acoes: [{ label:'Self-Service', action:'goPage:self-service' }] };

  // Resumo
  if (m.includes('resumo') || m.includes('status') || m.includes('relatorio'))
    return { resposta: '**Resumo вҖ” ' + new Date().toLocaleDateString('pt-BR') + '**\n' + chamados.filter(c=>!['fechado','concluido'].includes(c.status)).length + ' chamados В· SLA ' + ctx.slaPct + '% В· ' + ativos.length + ' ativos В· ' + sms.length + ' smartphones', acoes: [{ label:'Dashboard', action:'goPage:exec-dashboard' }] };

  // Ajuda
  if (m.includes('ajuda') || m.includes('help') || m.includes('como'))
    return { resposta: 'Posso responder sobre:\nвҖў **"onde est\u00e1 o PAT-0103?"**\nвҖў **"quantos chamados abertos"**\nвҖў **"como cadastrar ativo"**\nвҖў **"SLA atual"**\nвҖў **"abrir chamado"**', acoes: [] };

  return { resposta: 'N\u00e3o entendi "' + escapeHtml(msg.slice(0,50)) + '". Tente **"ajuda"** para ver o que sei responder.', acoes: [] };
}

function parseAIAction(action) {
  if (action.startsWith('goPage:'))    return `goPage('${action.split(':')[1]}')`;
  if (action.startsWith('openModal:')) return `openModal('${action.split(':')[1]}')`;
  return `console.log('${action}')`;
}

function addAITyping() {
  const container = document.getElementById('ai-messages');
  if (!container) return null;
  const div = document.createElement('div');
  div.className = 'ai-msg ai';
  div.id = 'typing-' + Date.now();
  div.innerHTML = `<div class="ai-avatar">вңЁ</div><div class="ai-bubble"><div class="ai-typing"><span></span><span></span><span></span></div></div>`;
  container.appendChild(div);
  container.scrollTop = container.scrollHeight;
  return div.id;
}

function removeAITyping(id) {
  document.getElementById(id)?.remove();
}

// в”Җв”Җв”Җ ANГҒLISE COMPLETA (Dashboard IA) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
async function rodarAnaliseCompleta() {
  if (_aiAnalyzing) return;
  _aiAnalyzing = true;

  const btn = document.querySelector('button[onclick="rodarAnaliseCompleta()"]');
  if (btn) { btn.disabled = true; btn.innerHTML = '<svg width="14" height="14" viewBox="0 0 16 16" fill="none" style="animation:spin .7s linear infinite;margin-right:4px"><path d="M8 1v3" stroke="currentColor" stroke-width="2" stroke-linecap="round"/><path d="M8 12v3" stroke="currentColor" stroke-width="2" stroke-linecap="round" opacity=".3"/><path d="M1 8h3" stroke="currentColor" stroke-width="2" stroke-linecap="round" opacity=".3"/><path d="M12 8h3" stroke="currentColor" stroke-width="2" stroke-linecap="round" opacity=".6"/></svg> Analisando...'; }

  const chamados    = STATE.chamados || [];
  const ativos      = STATE.ativos   || [];
  const smartphones = STATE.smartphones || [];

  const kpis = {
    totalChamados:   chamados.length,
    abertos:         chamados.filter(c => !['fechado','concluido'].includes(c.status)).length,
    slaPct:          calcSLAPct(chamados),
    mttrHoras:       calcMTTRGlobal(chamados),
    totalAtivos:     ativos.length,
    ativosObsoletos: 2,  // estimado
    mdmCompliance:   smartphones.length ? Math.round(smartphones.filter(s=>s.status==='uso').length/smartphones.length*100) : 80,
    valorParque:     729000,
    garantiasVenc:   2,
  };

  const topCats = Object.entries(
    chamados.reduce((acc, c) => { acc[c.categoria||'Outros'] = (acc[c.categoria||'Outros']||0)+1; return acc; }, {})
  ).sort(([,a],[,b]) => b-a).slice(0,5).map(([cat,count]) => ({ cat, count }));

  const alertas = [
    ...smartphones.filter(s => s.status === 'extraviado').map(s => `Smartphone extraviado: ${s.pat}`),
    ...ativos.filter(a => a.status === 'terceirizada').map(a => `Ativo na terceirizada: ${a.pat}`),
    ...(kpis.slaPct < 95 ? [`SLA abaixo da meta: ${kpis.slaPct}%`] : []),
  ];

  try {
    const insights = await callGenkitFlow('gerarInsightsExecutivos', {
      periodo: 'Гәltimos 30 dias', kpis, topCategorias: topCats, alertasAtivos: alertas,
    });
    renderAIInsights(insights);
  } catch {
    // Fallback local
    renderAIInsights(gerarInsightsLocais(kpis, alertas));
  }

  // Triagem de chamados abertos
  await triagemAutoDisplay(chamados.filter(c => !c.triageStatus && !['fechado','concluido'].includes(c.status)).slice(0,5));

  if (btn) { btn.disabled = false; btn.innerHTML = '<svg width="14" height="14" viewBox="0 0 16 16" fill="none" style="margin-right:4px"><path d="M8 1v3M8 12v3M1 8h3M12 8h3M3.05 3.05l2.12 2.12M10.83 10.83l2.12 2.12M3.05 12.95l2.12-2.12M10.83 5.17l2.12-2.12" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg>Analisar Novamente'; }
  _aiAnalyzing = false;
}

function renderAIInsights(data) {
  if (!data) return;
  const score = data.scoreOperacional || 75;
  // Score ring animation
  const arc = document.getElementById('ai-score-arc');
  const num = document.getElementById('ai-score-num');
  const lbl = document.getElementById('ai-score-label');
  if (arc) { setTimeout(() => { arc.style.strokeDashoffset = 327 - (327 * score / 100); }, 100); }
  if (num) num.textContent = score;
  if (lbl) lbl.textContent = score >= 80 ? 'вң… OperaГ§ГЈo SaudГЎvel' : score >= 60 ? 'вҡ пёҸ AtenГ§ГЈo NecessГЎria' : 'рҹҡЁ SituaГ§ГЈo CrГӯtica';
  const resumoEl = document.getElementById('ai-resumo-exec');
  if (resumoEl) resumoEl.innerHTML = `<p style="color:var(--g700);line-height:1.7">${(data.resumoExecutivo||'').replace(/\n/g,'<br>')}</p>`;

  // Insights grid
  const grid = document.getElementById('ai-insights-grid');
  const insightCount = document.getElementById('ai-insights-count');
  if (grid && data.insights?.length) {
    if (insightCount) insightCount.textContent = `${data.insights.length} insights`;
    grid.innerHTML = data.insights.map(ins => `
      <div class="ai-insight-card ${ins.impacto}">
        <div style="display:flex;justify-content:space-between;align-items:start;margin-bottom:8px">
          <div style="font-size:13px;font-weight:700;color:var(--g800)">${ins.titulo}</div>
          <span class="badge ${ins.impacto==='alto'?'badge-danger':ins.impacto==='medio'?'badge-warning':'badge-success'}">${ins.impacto}</span>
        </div>
        <p style="font-size:12.5px;color:var(--g600);margin:0 0 8px;line-height:1.55">${ins.desc}</p>
        <div style="font-size:11.5px;color:var(--accent);font-weight:600">вҶ’ ${ins.acao}</div>
      </div>`).join('');
  }

  // Riscos
  const riscosEl = document.getElementById('ai-riscos-list');
  if (riscosEl && data.riscos?.length) {
    riscosEl.innerHTML = data.riscos.map(r => `
      <div style="display:flex;gap:8px;padding:8px 0;border-bottom:1px solid var(--g100);font-size:12.5px">
        <span style="background:${r.nivel==='critico'?'var(--danger)':r.nivel==='alto'?'#EA580C':r.nivel==='medio'?'var(--warning)':'var(--success)'};color:#fff;font-size:9px;font-weight:800;padding:2px 6px;border-radius:4px;height:fit-content;white-space:nowrap;flex-shrink:0">${r.nivel.toUpperCase()}</span>
        <div><div style="font-weight:600;color:var(--g800);margin-bottom:2px">${r.risco}</div><div style="color:var(--g500);font-size:11.5px">${r.mitigacao}</div></div>
      </div>`).join('');
  }

  // RecomendaГ§Гөes
  const recsEl = document.getElementById('ai-recomendacoes');
  if (recsEl && data.recomendacoes?.length) {
    recsEl.innerHTML = data.recomendacoes.map((r,i) => `
      <div style="display:flex;gap:10px;padding:8px;background:var(--g50);border-radius:8px;font-size:13px">
        <span style="width:22px;height:22px;border-radius:50%;background:var(--accent);color:#fff;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:800;flex-shrink:0">${i+1}</span>
        <span style="color:var(--g700)">${r}</span>
      </div>`).join('');
  }

  // Anomalias (detectadas localmente)
  renderAnomalias();
}

// в”Җв”Җв”Җ Triagem automГЎtica display в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
async function triagemAutoDisplay(chamados) {
  const tbody = document.getElementById('ai-triage-body');
  if (!tbody) return;

  tbody.innerHTML = chamados.map(c => `
    <tr id="triage-row-${c.id}">
      <td class="td-mono" style="color:var(--accent)">${c.id}</td>
      <td style="max-width:200px;font-size:12px">${c.desc?.slice(0,50)||'вҖ”'}...</td>
      <td><div class="ai-typing"><span></span><span></span><span></span></div></td>
      <td><div class="ai-typing"><span></span><span></span><span></span></div></td>
      <td>вҖ”</td><td>вҖ”</td><td>вҖ”</td>
      <td><button class="btn btn-ghost btn-xs">вҸі</button></td>
    </tr>`).join('');

  for (const c of chamados) {
    try {
      let result;
      try {
        result = await callGenkitFlow('analisarChamado', {
          titulo: c.desc?.slice(0,80) || 'Chamado',
          desc:   c.desc || '',
          categoria: c.categoria,
          area:   c.area,
        });
      } catch {
        result = {
          prioridade: c.prioridade || 'media',
          categoriaAI: c.categoria || 'Infraestrutura',
          subcategoriaAI: 'Demais solicitaГ§Гөes',
          tipo: c.tipo || 'incidente',
          tempoEstimado: '2 horas',
          confianca: 40,
          _offline: true,
        };
      }

      const row = document.getElementById(`triage-row-${c.id}`);
      if (!row) continue;
      const priColor = { urgente:'danger','muito-alta':'danger',alta:'orange',media:'warning',baixa:'success' }[result.prioridade] || 'warning';
      row.innerHTML = `
        <td class="td-mono" style="color:var(--accent)">${c.id}</td>
        <td style="max-width:200px;font-size:12px">${c.desc?.slice(0,50)||'вҖ”'}...</td>
        <td><span class="badge badge-${priColor}">${result.prioridade}</span>${result._offline?'<span class="badge" style="font-size:9px;margin-left:3px;background:#EDE9FE;color:#6D28D9">offline</span>':''}</td>
        <td style="font-size:11.5px">${esc(result.categoriaAI)}<br><span style="color:var(--g400)">${esc(result.subcategoriaAI)}</span></td>
        <td><span class="tag">${result.tipo}</span></td>
        <td style="font-size:12px">${result.tempoEstimado||'вҖ”'}</td>
        <td>
          <div style="display:flex;align-items:center;gap:4px">
            <div style="flex:1;background:var(--g200);border-radius:3px;height:4px;overflow:hidden">
              <div style="background:${result.confianca>=70?'var(--success)':result.confianca>=50?'var(--warning)':'var(--danger)'};width:${result.confianca}%;height:100%"></div>
            </div>
            <span style="font-size:10.5px;color:var(--g500)">${result.confianca}%</span>
          </div>
        </td>
        <td><button class="btn btn-primary btn-xs" onclick="aplicarTriagem('${c.id}', ${JSON.stringify(JSON.stringify(result)).slice(1,-1)})">вң“ Aplicar</button></td>`;
    } catch (e) { console.warn('[AI] triage error:', e.message); }
  }
}

async function triagemLote() {
  const chamados = (STATE.chamados||[]).filter(c => !['fechado','concluido'].includes(c.status)).slice(0,10);
  if (!chamados.length) return showToast('Nenhum chamado aberto para triar','warning');
  showToast(`вҡЎ Triando ${chamados.length} chamados com IA...`,'info');
  goPage('ai-dashboard');
  setTimeout(() => triagemAutoDisplay(chamados), 300);
}

function aplicarTriagem(chamadoId, resultStr) {
  try {
    const result = typeof resultStr === 'string' ? JSON.parse(resultStr) : resultStr;
    const idx = (STATE.chamados||[]).findIndex(c => c.id === chamadoId);
    if (idx >= 0) {
      STATE.chamados[idx] = { ...STATE.chamados[idx], ...result, triageStatus:'concluida' };
    }
    showToast(`вң“ Triagem IA aplicada ao chamado ${chamadoId}`);
  } catch (e) { showToast('Erro ao aplicar triagem','danger'); }
}

// в”Җв”Җв”Җ Detectar anomalias (offline) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function renderAnomalias() {
  const el = document.getElementById('ai-anomalias-list');
  if (!el) return;
  const chamados    = STATE.chamados    || [];
  const smartphones = STATE.smartphones || [];
  const anomalias   = [];

  // Verifica volume por ГЎrea
  const porArea = chamados.reduce((acc,c) => { acc[c.area]=(acc[c.area]||0)+1; return acc; }, {});
  const topArea = Object.entries(porArea).sort(([,a],[,b])=>b-a)[0];
  if (topArea && topArea[1] > 3) {
    anomalias.push({ nivel:'medio', desc:`${topArea[0]} concentra ${topArea[1]} chamados (${Math.round(topArea[1]/chamados.length*100)}% do total)`, sugestao:'Investigar causa raiz' });
  }
  // Smartphones com problema
  const smProb = smartphones.filter(s => s.status !== 'uso');
  if (smProb.length) {
    anomalias.push({ nivel:'alto', desc:`${smProb.length} smartphone(s) com status anormal: ${smProb.map(s=>s.pat).join(', ')}`, sugestao:'Acionar MDM Admin' });
  }
  // SLA baixo
  if (calcSLAPct(chamados) < 85) {
    anomalias.push({ nivel:'critico', desc:`SLA abaixo de 85% вҖ” risco de penalidade contratual`, sugestao:'Priorizar chamados urgentes' });
  }
  if (!anomalias.length) {
    anomalias.push({ nivel:'baixo', desc:'Nenhuma anomalia crГӯtica detectada no momento', sugestao:'Manter monitoramento' });
  }

  el.innerHTML = anomalias.map(a => `
    <div style="display:flex;gap:8px;padding:8px 0;border-bottom:1px solid var(--g100);font-size:12.5px">
      <span style="background:${a.nivel==='critico'?'var(--danger)':a.nivel==='alto'?'#EA580C':'var(--warning)'};color:#fff;font-size:9px;font-weight:800;padding:2px 6px;border-radius:4px;height:fit-content;flex-shrink:0">${a.nivel.toUpperCase()}</span>
      <div><div style="font-weight:600;color:var(--g800);margin-bottom:2px">${a.desc}</div><div style="color:var(--g500);font-size:11.5px">вҶ’ ${a.sugestao}</div></div>
    </div>`).join('');
}

// в”Җв”Җв”Җ Insights fallback local в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function gerarInsightsLocais(kpis, alertas) {
  const insights = [];
  const riscos   = [];
  const recs     = [];

  if (kpis.slaPct < 95) {
    insights.push({ titulo:'SLA Abaixo da Meta', desc:`O SLA atual de ${kpis.slaPct}% estГЎ abaixo do objetivo de 95%. Chamados urgentes precisam de atenГ§ГЈo imediata.`, impacto:'alto', acao:'Priorizar triagem dos chamados em aberto' });
    riscos.push({ risco:`SLA em ${kpis.slaPct}% (meta: 95%)`, nivel:'alto', mitigacao:'Aumentar equipe de atendimento ou revisar processos de triagem' });
    recs.push(`Implementar triagem automГЎtica de prioridade para reduzir MTTR`);
  }
  if (kpis.mttrHoras > 8) {
    insights.push({ titulo:'MTTR Acima do Limite', desc:`Tempo mГ©dio de resoluГ§ГЈo de ${kpis.mttrHoras}h supera a meta de 8h. Investigar gargalos no processo.`, impacto:'medio', acao:'Mapear etapas que mais consomem tempo na resoluГ§ГЈo' });
    recs.push(`Criar base de conhecimento com soluГ§Гөes para os top 10 problemas mais recorrentes`);
  }
  if (kpis.mdmCompliance < 90) {
    insights.push({ titulo:'MDM Compliance CrГӯtico', desc:`${kpis.mdmCompliance}% dos dispositivos em conformidade. Risco de violaГ§ГЈo de polГӯtica de seguranГ§a.`, impacto:'alto', acao:'Executar verificaГ§ГЈo MDM em todos os dispositivos' });
    riscos.push({ risco:`Compliance MDM em ${kpis.mdmCompliance}%`, nivel:'alto', mitigacao:'ForГ§ar atualizaГ§ГЈo de perfil MDM em todos os dispositivos nГЈo conformes' });
  }
  if (kpis.garantiasVenc > 0) {
    insights.push({ titulo:`${kpis.garantiasVenc} Garantia(s) Vencendo`, desc:`Equipamentos com garantia prГіxima do vencimento representam risco financeiro se houver falha.`, impacto:'medio', acao:'Acionar processo de renovaГ§ГЈo ou substituiГ§ГЈo' });
  }
  insights.push({ titulo:'Custo de Parque Estimado', desc:`O parque de TI tem valor estimado de R$ ${kpis.valorParque.toLocaleString('pt-BR')}. ${kpis.ativosObsoletos} ativos obsoletos representam risco operacional.`, impacto:'baixo', acao:'Planejar ciclo de renovaГ§ГЈo para os prГіximos 12 meses' });
  recs.push(`Automatizar alertas de SLA via Cloud Functions para notificaГ§ГЈo proativa`);
  recs.push(`Implementar self-service portal para solicitaГ§Гөes de baixa complexidade`);

  const score = Math.max(10, Math.min(100,
    (kpis.slaPct * 0.4) + (kpis.mdmCompliance * 0.3) +
    (kpis.mttrHoras <= 8 ? 30 : Math.max(0, 30 - (kpis.mttrHoras - 8) * 3))
  ));

  return {
    resumoExecutivo: `AnГЎlise do perГӯodo: ${kpis.abertos} chamados em aberto de ${kpis.totalChamados} total. SLA em ${kpis.slaPct}% (${kpis.slaPct >= 95 ? 'dentro da meta' : 'abaixo da meta de 95%'}). MTTR de ${kpis.mttrHoras}h. ${alertas.length > 0 ? `вҡ пёҸ ${alertas.length} alerta(s) ativo(s).` : 'Sem alertas crГӯticos.'}`,
    insights, riscos, recomendacoes: recs, scoreOperacional: Math.round(score),
  };
}

// в”Җв”Җв”Җ renderAIDashboard в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function renderAIDashboard() {
  // Dispara anГЎlise automГЎtica na primeira vez
  const scoreEl = document.getElementById('ai-score-num');
  if (scoreEl && scoreEl.textContent === 'вҖ”') {
    setTimeout(rodarAnaliseCompleta, 400);
  }
  renderAnomalias();
}

// в”Җв”Җв”Җ AI triage badge no modal de chamado в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// в”Җв”Җв”Җ Triagem automГЎtica de chamados por IA в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Dispara quando o usuГЎrio sai do campo tГӯtulo ou descriГ§ГЈo.
// Analisa o texto, preenche categoria/tipo/prioridade automaticamente
// e exibe um banner informando o que foi classificado.

let _triagemTimer = null;
let _triagemUltimoTexto = ''; // guarda o Гәltimo texto enviado para nГЈo reclassificar igual

function triagemAutoChamado() {
  const titulo = (document.getElementById('ch-titulo')?.value || '').trim();
  const desc   = (document.getElementById('ch-descricao')?.value || '').trim();
  if (titulo.length < 8 && desc.length < 10) return;   // texto ainda muito curto

  const textoAtual = titulo + '||' + desc;

  // NГЈo re-analisa se o texto nГЈo mudou desde a Гәltima anГЎlise
  if (textoAtual === _triagemUltimoTexto) return;

  // Debounce вҖ” aguarda 800ms apГіs o usuГЎrio parar de digitar
  clearTimeout(_triagemTimer);
  _triagemTimer = setTimeout(() => {
    _triagemUltimoTexto = textoAtual;
    _executarTriagem(titulo, desc);
  }, 800);
}

async function _executarTriagem(titulo, desc) {
  const container = document.getElementById('ai-triage-suggestion');
  if (!container) return;

  // NГЈo re-analisa se o usuГЎrio jГЎ aplicou E o texto nГЈo mudou
  if (container.dataset.aplicado === '1') {
    const textoAtual = titulo + '||' + desc;
    if (textoAtual === (container.dataset.textoAplicado || '')) return;
    // Texto mudou вҖ” reseta para permitir nova anГЎlise
    container.dataset.aplicado = '0';
  }

  // Mostra loading
  container.style.display = '';
  container.innerHTML = `
    <div style="display:flex;align-items:center;gap:8px;padding:8px 12px;background:linear-gradient(135deg,#EFF6FF,#F5F3FF);border:1px solid #BFDBFE;border-radius:8px;font-size:12px;color:#1E40AF">
      <div class="ai-typing" style="margin:0"><span></span><span></span><span></span></div>
      <span>IA classificando o chamado...</span>
    </div>`;

  try {
    const r = await _triagemIA(titulo, desc);
    _aplicarTriagemSilenciosa(r);
    _mostrarBannerTriagem(container, r);
  } catch (e) {
    container.style.display = 'none';
  }
}

async function _triagemIA(titulo, desc) {
  // Tenta via Firebase Function (Gemini) com timeout de 4s.
  // Se falhar (bloqueado, sem deploy ou sem conexГЈo), usa classificaГ§ГЈo local.
  try {
    const timeout = new Promise((_, reject) =>
      setTimeout(() => reject(new Error('timeout')), 4000)
    );
    const call = callGenkitFlow('analisarChamado', {
      titulo:    titulo,
      descricao: desc || '',
    });
    const r = await Promise.race([call, timeout]);
    if (r && (r.categoria || r.prioridade)) return r;
  } catch (e) {
    console.info('[Triagem] Function indisponГӯvel, usando classificaГ§ГЈo local:', e.message);
  }
  // Fallback: classificaГ§ГЈo por palavras-chave (funciona offline e sem deploy)
  return _triagemLocal(titulo, desc);
}

function _triagemLocal(titulo, desc) {
  const txt = (titulo + ' ' + (desc || '')).toLowerCase();

  // Categoria
  const cat =
    /impressora|toner|papel|atolamento|jam|bandeja|cartucho/.test(txt)    ? 'impressao'          :
    /senha|acesso|bloqueado|active directory|ad|login|ldap/.test(txt)   ? 'active-directory'   :
    /internet|wifi|wi-fi|lento|sem conexГЈo|sem acesso Г  rede/.test(txt)   ? 'internet'           :
    /e-?mail|outlook|zimbra|caixa.*entrada|spam/.test(txt)                ? 'email'              :
    /computador|pc|notebook|tela azul|nГЈo liga|travado|lento/.test(txt) ? 'computador'         :
    /vГӯrus|malware|ransomware|hacke|sequestro/.test(txt)                  ? 'antivirus'          :
    /backup|restaurar|restore/.test(txt)                                  ? 'backup-restore'     :
    /servidor|datacenter|raid|vm|virtual/.test(txt)                     ? 'servidor'           :
    /firewall|bloqueio|webfilter|site bloqueado/.test(txt)                ? 'firewall-webfilter' :
    /cabo|switch|porta de rede|sem sinal de rede/.test(txt)               ? 'rede-dados'         :
    /sap|gis|sistema|aplicaГ§ГЈo|programa|software/.test(txt)               ? 'sistemas-corporativos':
    /smartphone|celular|mdm|mobile/.test(txt)                             ? 'smartphone-mdm'     :
    /monitor|tela|display|projetor/.test(txt)                             ? 'equipamento-problema':
    /certificado|token|assinatura digital/.test(txt)                      ? 'certificado-digital':
    /usuГЎrio|cadastro|conta|perfil|permissГЈo/.test(txt)                   ? 'cadastro-usuario'   :
    '';

  // Tipo вҖ” analisa contexto completo antes de decidir
  // Palavras de REQUISIГҮГғO tГӘm prioridade sobre o fallback
  const _ehRequisicao = /preciso|solicito|gostaria|quero|necessito|pedido|instalar|criar|favor|por favor|solicita(Г§ГЈo|cao)|requisi|agendamento|agendar|providenciar/.test(txt);
  const _ehIncidente  = /nГЈo funciona|nao funciona|parou|caiu|quebrou|erro|falha|problema|travou|travada|tela azul|nГЈo abre|nao abre|nГЈo liga|nao liga|corrompido|perdeu/.test(txt);
  // "backup por seguranГ§a", "backup preventivo", "solicito backup" вҶ’ requisiГ§ГЈo
  const _backupReq    = /backup/.test(txt) && /seguran|preventiv|solicito|preciso|quero|agendar|periodic/.test(txt);
  const tipo = (_ehRequisicao || _backupReq) && !_ehIncidente ? 'requisicao'
             : _ehIncidente ? 'incidente'
             : 'requisicao'; // fallback padrГЈo agora Г© requisiГ§ГЈo (mais seguro)

  // Prioridade
  const prio =
    /urgente|crГӯtico|parado|emergГӘncia|ransomware|vГӯrus|fora do ar/.test(txt) ? 'urgente' :
    /alto|importante|prejuГӯzo|cliente esperando/.test(txt)                    ? 'alta'    :
    /baixa|quando puder|nГЈo urgente/.test(txt)                                ? 'baixa'   :
    'media';

  const tempo = prio === 'urgente' ? '1 hora' : prio === 'alta' ? '2 horas' : '4 horas';

  const resumos = {
    'impressao':         'Problema com impressora ou suprimentos',
    'active-directory':  'Acesso ou autenticaГ§ГЈo no Active Directory',
    'internet':          'Problema de conectividade com a internet',
    'email':             'Problema com e-mail corporativo',
    'computador':        'Problema no computador do usuГЎrio',
    'antivirus':         'AmeaГ§a de seguranГ§a detectada',
    'backup-restore':    'SolicitaГ§ГЈo de backup ou restauraГ§ГЈo',
    'servidor':          'Problema em servidor ou infraestrutura',
    'firewall-webfilter':'Bloqueio ou problema de firewall',
    'rede-dados':        'Problema na rede de dados',
    'sistemas-corporativos': 'Problema em sistema corporativo',
    'smartphone-mdm':    'Problema com smartphone corporativo',
    'equipamento-problema': 'Problema com equipamento de TI',
    'certificado-digital': 'Problema com certificado ou token',
    'cadastro-usuario':  'SolicitaГ§ГЈo de cadastro ou permissГЈo',
  };

  return {
    categoria:   cat,
    categoriaAI: cat,
    tipo,
    prioridade:  prio,
    tempoEstimado: tempo,
    resumo:      resumos[cat] || 'Chamado classificado localmente',
    confianca:   cat ? 72 : 45,
    _local:      true,
  };
}

function _aplicarTriagemSilenciosa(r) {
  // Preenche os campos automaticamente, sem precisar do usuГЎrio confirmar
  const catEl  = document.getElementById('ch-categoria');
  const tipoEl = document.getElementById('ch-tipo');
  const prioEl = document.getElementById('ch-prioridade');

  if (catEl  && r.categoria  && catEl.querySelector(`option[value="${r.categoria}"]`))  {
    catEl.value = r.categoria;
    atualizarSubcategoria?.();
  }
  if (tipoEl && r.tipo && tipoEl.querySelector(`option[value="${r.tipo}"]`)) {
    tipoEl.value = r.tipo;
  }
  if (prioEl && r.prioridade && prioEl.querySelector(`option[value="${r.prioridade}"]`)) {
    prioEl.value = r.prioridade;
    atualizarPrioridadeColor?.(prioEl);
  }
}

function _mostrarBannerTriagem(container, r) {
  const corPrio = { urgente:'#DC2626', alta:'#D97706', media:'#2563EB', baixa:'#059669' }[r.prioridade] || '#64748B';
  const bgPrio  = { urgente:'#FEF2F2', alta:'#FFF7ED', media:'#EFF6FF', baixa:'#F0FDF4' }[r.prioridade] || '#F8FAFC';
  const catLabel = document.getElementById('ch-categoria')?.selectedOptions?.[0]?.text?.replace(/^В»\s*/, '') || r.categoria;
  const tipoLabel = { incidente:'Incidente', requisicao:'RequisiГ§ГЈo', problema:'Problema', mudanca:'MudanГ§a' }[r.tipo] || r.tipo;

  container.innerHTML = `
    <div style="display:flex;align-items:flex-start;gap:10px;padding:10px 14px;background:linear-gradient(135deg,#EFF6FF,#F5F3FF);border:1px solid #BFDBFE;border-radius:8px;font-size:12px">
      <span style="font-size:16px;flex-shrink:0;margin-top:1px">вңЁ</span>
      <div style="flex:1;min-width:0">
        <div style="font-weight:700;color:#1E40AF;margin-bottom:4px">Classificado automaticamente pela IA</div>
        <div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:4px">
          <span style="background:${bgPrio};color:${corPrio};border:1px solid ${corPrio}33;font-size:11px;font-weight:700;padding:1px 8px;border-radius:10px">в—Ҹ ${(r.prioridade||'').charAt(0).toUpperCase()+(r.prioridade||'').slice(1)}</span>
          <span style="background:#F1F5F9;color:#334155;font-size:11px;padding:1px 8px;border-radius:10px">рҹҸ·пёҸ ${escapeHtml(catLabel)}</span>
          <span style="background:#F1F5F9;color:#334155;font-size:11px;padding:1px 8px;border-radius:10px">${escapeHtml(tipoLabel)}</span>
          <span style="background:#F1F5F9;color:#334155;font-size:11px;padding:1px 8px;border-radius:10px">вҸұ ${escapeHtml(r.tempoEstimado||'вҖ”')}</span>
          <span style="color:#94A3B8;font-size:10.5px;align-self:center">${r.confianca||'вҖ”'}% confianГ§a</span>
        </div>
        <div style="color:#475569;font-size:11.5px">${escapeHtml(r.resumo||'')}</div>
      </div>
      <button onclick="this.closest('#ai-triage-suggestion').dataset.aplicado='0';triagemAutoChamado()" title="Re-analisar" style="background:none;border:none;cursor:pointer;color:#94A3B8;font-size:14px;padding:0;flex-shrink:0">вҶә</button>
      <button onclick="this.closest('#ai-triage-suggestion').style.display='none'" title="Fechar" style="background:none;border:none;cursor:pointer;color:#94A3B8;font-size:16px;padding:0;line-height:1;flex-shrink:0">Г—</button>
    </div>`;
  // Guarda o texto que foi analisado para detectar mudanГ§as futuras
  const titulo = (document.getElementById('ch-titulo')?.value||'').trim();
  const desc   = (document.getElementById('ch-descricao')?.value||'').trim();
  container.dataset.textoAplicado = titulo + '||' + desc;
  container.dataset.aplicado = '1';
}

// MantГ©m compatibilidade com cГіdigo legado que chamava mostrarSugestaoAIchamado
function mostrarSugestaoAIchamado(titulo, desc) {
  triagemAutoChamado();
}

function aplicarSugestaoAI(resultStr) {
  try {
    const r = JSON.parse(resultStr);
    _aplicarTriagemSilenciosa(r);
    showToast('вң“ ClassificaГ§ГЈo da IA aplicada ao chamado');
  } catch {}
}

// ============================================================
// MUDANГҮAS ITIL вҖ” RFC / CAB / IMPLEMENTAГҮГғO / REVISГғO
// ============================================================

const STATUS_MUDANCA = {
  'rascunho':       { label:'Rascunho',        css:'',                    cor:'#94A3B8' },
  'pendente-cab':   { label:'Pendente CAB',     css:'badge-warning',       cor:'#D97706' },
  'aprovada':       { label:'Aprovada',         css:'badge-success',       cor:'#059669' },
  'recusada':       { label:'Recusada',         css:'badge-danger',        cor:'#DC2626' },
  'implementando':  { label:'Implementando',    css:'badge-info',          cor:'#2563EB' },
  'concluida':      { label:'ConcluГӯda',        css:'badge-success',       cor:'#059669' },
  'cancelada':      { label:'Cancelada',        css:'',                    cor:'#94A3B8' },
  'revisao':        { label:'Em RevisГЈo (PIR)', css:'badge-violet',        cor:'#7C3AED' },
};

const RISCO_CSS = {
  critico:'badge-danger', alto:'badge-orange', medio:'badge-warning', baixo:'badge-success',
};

STATE.mudancas = [];

let _itilCurrentTab = 'todos';

function renderMudancasITIL(tab) {
  if (tab) _itilCurrentTab = tab;
  const q  = (document.getElementById('itil-search')?.value || '').toLowerCase();
  const fr = document.getElementById('itil-filter-risco')?.value || '';
  const ft = document.getElementById('itil-filter-tipo')?.value  || '';

  let list = STATE.mudancas || [];
  if (_itilCurrentTab !== 'todos') list = list.filter(m => m.status === _itilCurrentTab || m.tipo === _itilCurrentTab);
  if (q)  list = list.filter(m => m.titulo.toLowerCase().includes(q) || m.id.toLowerCase().includes(q) || m.responsavel.toLowerCase().includes(q));
  if (fr) list = list.filter(m => m.risco === fr);
  if (ft) list = list.filter(m => m.tipo === ft);

  const all = STATE.mudancas || [];
  sv('itil-total', all.length);
  sv('itil-aprov', all.filter(m => m.status === 'aprovada').length);
  sv('itil-impl',  all.filter(m => m.status === 'implementando').length);
  sv('itil-cab',   all.filter(m => m.status === 'pendente-cab').length);
  sv('itil-emerg', all.filter(m => m.tipo === 'emergencial').length);
  nbUpdate('nb-mudancas', all.filter(m => ['pendente-cab','implementando'].includes(m.status)).length);

  const tbody = document.getElementById('itil-body');
  if (!tbody) return;
  tbody.innerHTML = list.map(m => {
    const st  = STATUS_MUDANCA[m.status] || { label: m.status, css: '' };
    const tipoLabel = { normal:'Normal', emergencial:'Emergencial', padrao:'PadrГЈo' }[m.tipo] || m.tipo;
    const tipoCss   = { normal:'badge-info', emergencial:'badge-danger', padrao:'badge-success' }[m.tipo] || '';
    const priColor  = { critica:'danger', alta:'orange', media:'warning', baixa:'success' }[m.prioridade] || 'gray';
    return `<tr onclick="abrirMudanca('${m.id}')" style="cursor:pointer">
      <td class="td-mono" style="color:var(--accent);font-weight:700">${m.id}</td>
      <td style="max-width:280px">
        <div style="font-weight:600;font-size:13px">${m.titulo}</div>
        <div style="font-size:11px;color:var(--g400)">${m.categoria}</div>
      </td>
      <td><span class="badge ${tipoCss}">${tipoLabel}</span></td>
      <td><span class="badge ${RISCO_CSS[m.risco]||''}">${m.risco}</span></td>
      <td style="font-size:12.5px">${m.responsavel}</td>
      <td class="td-mono" style="font-size:11.5px">${m.dataImpl ? new Date(m.dataImpl).toLocaleDateString('pt-BR') : 'вҖ”'}</td>
      <td style="font-size:11.5px">${m.cabData ? new Date(m.cabData).toLocaleDateString('pt-BR') : m.tipo==='padrao' ? 'PrГ©-aprovado' : 'вҖ”'}</td>
      <td><span class="badge ${st.css}">${st.label}</span></td>
      <td><div class="flex gap-4" onclick="event.stopPropagation()">
        <button class="btn btn-secondary btn-xs" onclick="abrirMudanca('${m.id}')">Ver</button>
        <button class="btn btn-ghost btn-xs" onclick="mudarStatusRFC('${m.id}')">вҶ—</button>
      </div></td>
    </tr>`;
  }).join('') || '<tr><td colspan="9" style="text-align:center;padding:24px;color:var(--g400)">Nenhuma RFC encontrada</td></tr>';
}

function abrirMudanca(id) {
  const m = (STATE.mudancas||[]).find(x => x.id === id);
  if (!m) return;

  const st       = STATUS_MUDANCA[m.status] || { label: m.status, css:'', cor:'#94A3B8' };
  const tipoLabel= { normal:'Normal', emergencial:'рҹҡЁ Emergencial', padrao:'вң… PadrГЈo' }[m.tipo] || m.tipo;
  const riscoCss = RISCO_CSS[m.risco] || '';
  const downtime = m.downtime === 'sim';
  const modalId  = 'modal-ver-rfc-' + id;

  // Build historicoStatus HTML вҖ” no template literals
  const historicoHTML = (m.historicoStatus||[]).map(function(h) {
    const hs = STATUS_MUDANCA[h.status] || { label: h.status, cor: '#94A3B8' };
    return '<div class="tl-item">'
      + '<div class="tl-dot" style="background:' + hs.cor + '"></div>'
      + '<div class="tl-title">' + (hs.label||h.status) + '</div>'
      + '<div class="tl-desc">'  + (h.obs||'')  + '</div>'
      + '<div class="tl-time">'  + (h.data||'') + ' &middot; ' + (h.autor||'') + '</div>'
      + '</div>';
  }).join('');

  // Build action buttons using data attributes (avoids quote escaping inside onclick)
  const acaoBtns = [
    m.status === 'aprovada'      ? ['btn-primary',   'implementando', 'в–¶ Iniciar ImplementaГ§ГЈo']   : null,
    m.status === 'implementando' ? ['btn-success',   'concluida',     'вң“ Concluir MudanГ§a']        : null,
    m.status === 'implementando' ? ['btn-danger',    'cancelada',     'вҡ  Acionar Rollback']        : null,
    m.status === 'pendente-cab'  ? ['btn-success',   'aprovada',      'вң“ Aprovar no CAB']          : null,
    m.status === 'pendente-cab'  ? ['btn-danger',    'recusada',      'вң• Recusar']                 : null,
    m.status === 'concluida'     ? ['btn-secondary', 'revisao',       'рҹ“Ӣ Abrir PIR']              : null,
  ].filter(Boolean);

  const acoesHTML = acaoBtns.map(function(a) {
    return '<button class="btn ' + a[0] + '" data-rfc-id="' + id + '" data-rfc-status="' + a[1] + '">' + a[2] + '</button>';
  }).join(' ')
  + ' <button class="btn btn-ghost" data-close-modal="' + modalId + '">Fechar</button>';

  // Remove previous modal if exists
  document.getElementById(modalId)?.remove();

  const div = document.createElement('div');
  div.className = 'modal-overlay open';
  div.id = modalId;

  // Build HTML with string concatenation вҖ” zero nested template literals
  div.innerHTML = ''
    + '<div class="modal modal-xl">'
    + '<div class="modal-header" style="background:linear-gradient(135deg,var(--brand),#111E35)">'
    +   '<div>'
    +     '<div style="font-size:12px;color:rgba(255,255,255,.5);margin-bottom:2px">' + tipoLabel + ' &middot; ' + m.categoria + '</div>'
    +     '<h3 style="color:#fff;font-size:16px">' + m.id + ' вҖ” ' + m.titulo + '</h3>'
    +   '</div>'
    +   '<div style="margin-left:auto;display:flex;align-items:center;gap:10px">'
    +     '<span class="badge ' + st.css + '" style="font-size:12px">' + st.label + '</span>'
    +     '<button class="close-btn" style="color:rgba(255,255,255,.7)" data-close-modal="' + modalId + '">вң•</button>'
    +   '</div>'
    + '</div>'
    + '<div class="modal-body">'
    +   '<div style="display:grid;grid-template-columns:repeat(5,1fr);gap:10px;margin-bottom:18px;padding:14px;background:var(--g50);border-radius:var(--r);border:1px solid var(--g200)">'
    +     '<div><div style="font-size:10px;color:var(--g400);font-weight:700;text-transform:uppercase;margin-bottom:3px">Risco</div>'
    +       '<span class="badge ' + riscoCss + '">' + m.risco + '</span></div>'
    +     '<div><div style="font-size:10px;color:var(--g400);font-weight:700;text-transform:uppercase;margin-bottom:3px">ResponsГЎvel</div>'
    +       '<div style="font-weight:600;font-size:13px">' + m.responsavel + '</div></div>'
    +     '<div><div style="font-size:10px;color:var(--g400);font-weight:700;text-transform:uppercase;margin-bottom:3px">Impl. em</div>'
    +       '<div style="font-weight:600;font-size:13px">' + (m.dataImpl ? new Date(m.dataImpl).toLocaleString('pt-BR') : 'вҖ”') + '</div></div>'
    +     '<div><div style="font-size:10px;color:var(--g400);font-weight:700;text-transform:uppercase;margin-bottom:3px">DuraГ§ГЈo</div>'
    +       '<div style="font-weight:600;font-size:13px">' + (m.duracao||'вҖ”') + '</div></div>'
    +     '<div><div style="font-size:10px;color:var(--g400);font-weight:700;text-transform:uppercase;margin-bottom:3px">Downtime?</div>'
    +       '<div style="font-weight:600;font-size:13px;color:' + (downtime ? 'var(--danger)' : 'var(--success)') + '">'
    +         (downtime ? 'вҡ пёҸ SIM' : 'вң… NГЈo') + '</div></div>'
    +   '</div>'
    +   '<div class="grid-2" style="gap:16px">'
    +     '<div>'
    +       '<div class="form-group"><label class="form-label">DescriГ§ГЈo</label>'
    +         '<div style="font-size:13px;color:var(--g700);line-height:1.6;padding:10px;background:var(--g50);border-radius:8px">' + (m.desc||'вҖ”') + '</div></div>'
    +       '<div class="form-group"><label class="form-label">Justificativa</label>'
    +         '<div style="font-size:13px;color:var(--g700);line-height:1.6;padding:10px;background:var(--g50);border-radius:8px">' + (m.justificativa||'вҖ”') + '</div></div>'
    +       '<div class="form-group"><label class="form-label">AnГЎlise de Risco</label>'
    +         '<div style="font-size:13px;color:var(--g700);padding:10px;background:var(--g50);border-radius:8px">' + (m.analiseRisco||'вҖ”') + '</div></div>'
    +       '<div class="form-group"><label class="form-label">Sistemas Impactados</label>'
    +         '<div style="font-size:13px;color:var(--g700);padding:10px;background:var(--g50);border-radius:8px">' + (m.sistemas||'вҖ”') + '</div></div>'
    +     '</div>'
    +     '<div>'
    +       '<div class="form-group"><label class="form-label">Plano de ImplementaГ§ГЈo</label>'
    +         '<div style="font-size:13px;color:var(--g700);white-space:pre-line;padding:10px;background:var(--g50);border-radius:8px;line-height:1.7">' + (m.passos||'вҖ”') + '</div></div>'
    +       '<div class="form-group"><label class="form-label" style="color:var(--danger)">Plano de Rollback</label>'
    +         '<div style="font-size:13px;color:var(--g700);white-space:pre-line;padding:10px;background:rgba(239,68,68,.04);border:1px solid rgba(239,68,68,.15);border-radius:8px;line-height:1.7">'
    +           (m.rollback||'вҖ”')
    +           '<br><br><span style="font-size:11px;color:var(--g400)">Tempo: ' + (m.tempoRollback||'вҖ”') + ' &middot; Resp: ' + (m.respRollback||'вҖ”') + '</span>'
    +         '</div></div>'
    +     '</div>'
    +   '</div>'
    +   '<div class="divider"></div>'
    +   '<h4 style="font-size:13px;font-weight:700;margin-bottom:12px">рҹ“… HistГіrico da RFC</h4>'
    +   '<div class="timeline">' + historicoHTML + '</div>'
    +   '<div class="divider"></div>'
    +   '<div class="flex gap-8 flex-wrap">' + acoesHTML + '</div>'
    + '</div>'
    + '</div>';

  document.body.appendChild(div);

  // Wire buttons using event delegation (no inline onclick)
  div.addEventListener('click', function(e) {
    const closeBtn = e.target.closest('[data-close-modal]');
    if (closeBtn) { document.getElementById(closeBtn.dataset.closeModal)?.remove(); return; }
    const actionBtn = e.target.closest('[data-rfc-id]');
    if (actionBtn) { updateStatusRFC(actionBtn.dataset.rfcId, actionBtn.dataset.rfcStatus); }
  });
}


function updateStatusRFC(id, novoStatus) {
  const m = (STATE.mudancas||[]).find(x => x.id === id);
  if (!m) return;
  const obs = prompt(`ObservaГ§ГЈo para "${STATUS_MUDANCA[novoStatus]?.label || novoStatus}":`) || '';
  m.status = novoStatus;
  m.historicoStatus = m.historicoStatus || [];
  m.historicoStatus.push({ status: novoStatus, data: new Date().toLocaleString('pt-BR'), autor: CURRENT_USER?.nome || 'UsuГЎrio', obs });
  document.querySelectorAll('[id^="modal-ver-rfc-"]').forEach(el => el.remove());
  renderMudancasITIL();
  showToast(`вң“ RFC ${id} вҶ’ ${STATUS_MUDANCA[novoStatus]?.label || novoStatus}`);
}

function mudarStatusRFC(id) { abrirMudanca(id); }

function salvarRFC(status = 'rascunho') {
  const titulo = document.getElementById('rfc-titulo')?.value?.trim();
  if (!titulo) return showToast('TГӯtulo da RFC Г© obrigatГіrio', 'danger');
  const id = 'RFC-' + String((STATE.mudancas||[]).length + 1).padStart(3, '0');
  const nova = {
    id, status,
    tipo:         document.getElementById('rfc-tipo')?.value || 'normal',
    categoria:    document.getElementById('rfc-categoria')?.value || 'вҖ”',
    prioridade:   document.getElementById('rfc-prioridade')?.value || 'media',
    titulo,
    desc:         document.getElementById('rfc-desc')?.value || '',
    justificativa:document.getElementById('rfc-justificativa')?.value || '',
    responsavel:  document.getElementById('rfc-responsavel')?.value || CURRENT_USER?.nome || 'вҖ”',
    area:         document.getElementById('rfc-area')?.value || '',
    dataImpl:     document.getElementById('rfc-data-impl')?.value || '',
    duracao:      document.getElementById('rfc-duracao')?.value || '',
    janela:       document.getElementById('rfc-janela')?.value || '',
    risco:        document.getElementById('rfc-risco')?.value || 'medio',
    impactoUsers: document.getElementById('rfc-impacto-users')?.value || 'minimo',
    downtime:     document.querySelector('input[name="rfc-downtime"]:checked')?.value || 'nao',
    analiseRisco: document.getElementById('rfc-analise-risco')?.value || '',
    sistemas:     document.getElementById('rfc-sistemas')?.value || '',
    criterios:    document.getElementById('rfc-criterios')?.value || '',
    passos:       document.getElementById('rfc-passos')?.value || '',
    rollback:     document.getElementById('rfc-rollback')?.value || '',
    tempoRollback:document.getElementById('rfc-tempo-rollback')?.value || '',
    respRollback: document.getElementById('rfc-resp-rollback')?.value || '',
    backupFeito:  document.querySelector('input[name="rfc-backup"]:checked')?.value || 'nao',
    cabData:      document.getElementById('rfc-cab-data')?.value || '',
    cabMembros:   document.getElementById('rfc-cab-membros')?.value || '',
    impactoNegocio: document.getElementById('rfc-impacto-negocio')?.value || '',
    aprovGest:    document.getElementById('rfc-aprov-gest')?.checked || false,
    aprovNeg:     document.getElementById('rfc-aprov-neg')?.checked || false,
    aprovSeg:     document.getElementById('rfc-aprov-seg')?.checked || false,
    obsCAB:       document.getElementById('rfc-obs-cab')?.value || '',
    createdAt:    new Date(),
    createdBy:    CURRENT_USER?.nome || 'вҖ”',
    historicoStatus:[{ status, data: new Date().toLocaleString('pt-BR'), autor: CURRENT_USER?.nome || 'вҖ”', obs: status === 'rascunho' ? 'RFC criada' : 'Submetida ao CAB' }],
  };
  if (!STATE.mudancas) STATE.mudancas = [];
  STATE.mudancas.unshift(nova);
  // TODO: fsAdd('mudancas', nova, STATE.mudancas)
  closeModal('modal-nova-mudanca');
  renderMudancasITIL();
  showToast(`вң“ ${id} ${status === 'rascunho' ? 'salva como rascunho' : 'submetida ao CAB'}`);
}

// Wire RFC tabs
document.addEventListener('DOMContentLoaded', () => {
  document.querySelectorAll('[data-rfc-tab]').forEach(tab => {
    tab.addEventListener('click', () => {
      tab.closest('.tabs')?.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
      tab.classList.add('active');
      ['geral','impacto','plano','rollback','cab'].forEach(id => {
        const el = document.getElementById('rfc-tab-' + id);
        if (el) el.style.display = id === tab.dataset.rfcTab ? '' : 'none';
      });
    });
  });
  document.querySelectorAll('[data-itil-tab]').forEach(tab => {
    tab.addEventListener('click', () => {
      tab.closest('.tabs')?.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
      tab.classList.add('active');
      renderMudancasITIL(tab.dataset.itilTab);
    });
  });
});


// в”Җв”Җв”Җ SEED: Contatos CESAN (organograma) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
const CONTATOS_CESAN = [];


const STATE_EMPREGADOS_SEED = [];

// Popula STATE.empregados com dados do organograma se Banco nГЈo disponГӯvel
function initEmpregadosSeed() {
  if (!STATE.empregados || STATE.empregados.length === 0) {
    STATE.empregados = STATE_EMPREGADOS_SEED;
    console.log('[Seed] ' + STATE.empregados.length + ' empregados carregados do organograma');
  }
}

// Autocomplete de empregados nos formulГЎrios
function autocompleteEmpregado(inputEl, onSelect) {
  const input = typeof inputEl === 'string' ? document.getElementById(inputEl) : inputEl;
  if (!input) return;
  
  let dropdown = null;
  
  input.addEventListener('input', function() {
    const q = this.value.toLowerCase().trim();
    if (dropdown) dropdown.remove();
    if (q.length < 2) return;
    
    const matches = (STATE.empregados || [])
      .filter(e => e.nome.toLowerCase().includes(q) || e.email.toLowerCase().includes(q) || e.ramal.includes(q))
      .slice(0, 8);
    
    if (!matches.length) return;
    
    dropdown = document.createElement('div');
    dropdown.style.cssText = 'position:absolute;z-index:9999;background:var(--g0,#fff);border:1px solid var(--g200);border-radius:10px;box-shadow:0 8px 24px rgba(0,0,0,.12);width:320px;max-height:280px;overflow-y:auto';
    
    matches.forEach(e => {
      const item = document.createElement('div');
      item.style.cssText = 'padding:10px 14px;cursor:pointer;display:flex;align-items:center;gap:10px;border-bottom:1px solid var(--g100)';
      item.innerHTML = '<div style="width:32px;height:32px;border-radius:50%;background:linear-gradient(135deg,#2563EB,#7C3AED);color:#fff;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700;flex-shrink:0">' + e.avatar + '</div>' +
        '<div><div style="font-size:13px;font-weight:600;color:var(--g800)">' + e.nome + '</div>' +
        '<div style="font-size:11px;color:var(--g400)">' + e.setor + (e.ramal ? ' В· Ramal ' + e.ramal : '') + '</div></div>';
      item.addEventListener('mouseenter', () => item.style.background = 'var(--g50)');
      item.addEventListener('mouseleave', () => item.style.background = '');
      item.addEventListener('click', () => {
        input.value = e.nome;
        dropdown.remove();
        dropdown = null;
        if (onSelect) onSelect(e);
      });
      dropdown.appendChild(item);
    });
    
    const rect = input.getBoundingClientRect();
    dropdown.style.top  = (rect.bottom + window.scrollY + 4) + 'px';
    dropdown.style.left = rect.left + 'px';
    document.body.appendChild(dropdown);
  });
  
  document.addEventListener('click', e => {
    if (dropdown && !dropdown.contains(e.target) && e.target !== input) {
      dropdown.remove(); dropdown = null;
    }
  }, { once: false });
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// ASSISTГҠNCIA REMOTA вҖ” Computadores
// Gerencia agentes desktop: inventГЎrio, deploy, acesso remoto
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

// Cache de agentes online (vem do Banco /agents)
const STATE_AGENTS = { list: [], listener: null };

// Inicia listener Banco para agentes em tempo real
function startAgentsListener() {
  if (!FB_READY) return;
  if (STATE_AGENTS.listener) {
    try { STATE_AGENTS.listener(); } catch(e) {} // unsubscribe anterior
    STATE_AGENTS.listener = null;
  }
  try {
    // Usa SDK compat (igual ao resto do app)
    STATE_AGENTS.listener = db.collection('agents')
      .onSnapshot(snap => {
        STATE_AGENTS._carregou = true;
        STATE_AGENTS.list = snap.docs.map(d => {
          const data = d.data();
          // Garante que campos numГ©ricos nГЈo virem string
          if (data.uptimeH != null) data.uptimeH = Number(data.uptimeH);
          if (data.cpuPct  != null) data.cpuPct  = Number(data.cpuPct);
          if (data.ramPct  != null) data.ramPct  = Number(data.ramPct);
          if (data.memPct  != null) data.memPct  = Number(data.memPct);
          return { id: d.id, ...data };
        });
        verificarTrocaMonitores(STATE_AGENTS.list);
        if (isPageActive('assistencia-remota')) renderAssistenciaRemota();
        nbUpdate('nb-agentes-online', STATE_AGENTS.list.filter(a => a.status === 'online').length);
      }, err => {
        console.warn('[Agentes] listener erro:', err.message);
        arPollAgentes();
        setInterval(arPollAgentes, 30000);
      });
  } catch(e) {
    console.warn('[Agentes] startAgentsListener erro:', e.message);
    arPollAgentes();
    setInterval(arPollAgentes, 30000);
  }
}

async function arPollAgentes() {
  if (!FB_READY || !db) return;
  try {
    const snap = await db.collection('agents').orderBy('lastSeen', 'desc').get();
    STATE_AGENTS._carregou = true;
    STATE_AGENTS.list = snap.docs.map(d => ({ id: d.id, ...d.data() }));
    if (isPageActive('assistencia-remota')) renderAssistenciaRemota();
    nbUpdate('nb-agentes-online', STATE_AGENTS.list.filter(a => a.status === 'online').length);
  } catch(e) {
    console.warn('[Agentes] poll SDK erro:', e.message, 'вҖ” tentando REST direto...');
    try {
      const _PROJECT = 'sysack-829e2';
      const _KEY     = 'AIzaSyBGb4GY-0nMbGg82AnG8tMySWrZxMvogww';
      const resp = await fetch(
        `https://firestore.googleapis.com/v1/projects/${_PROJECT}/databases/(default)/documents/agents?pageSize=200&key=${_KEY}`
      );
      if (resp.ok) {
        const data = await resp.json();
        STATE_AGENTS._carregou = true;
        STATE_AGENTS.list = (data.documents || []).map(doc => {
          const id     = doc.name.split('/').pop();
          const fields = doc.fields || {};
          const out    = { id };
          for (const [k, v] of Object.entries(fields)) {
            if      (v.stringValue   !== undefined) out[k] = v.stringValue;
            else if (v.integerValue  !== undefined) out[k] = Number(v.integerValue);
            else if (v.doubleValue   !== undefined) out[k] = v.doubleValue;
            else if (v.booleanValue  !== undefined) out[k] = v.booleanValue;
            else if (v.timestampValue!== undefined) out[k] = new Date(v.timestampValue);
            else if (v.nullValue     !== undefined) out[k] = null;
          }
          return out;
        });
        console.log('[Agentes] REST direto OK:', STATE_AGENTS.list.length, 'agentes');
        if (isPageActive('assistencia-remota')) renderAssistenciaRemota();
        nbUpdate('nb-agentes-online', STATE_AGENTS.list.filter(a => a.status === 'online').length);
      }
    } catch(e2) {
      console.warn('[Agentes] REST fallback erro:', e2.message);
      STATE_AGENTS._carregou = true;
      if (isPageActive('assistencia-remota')) renderAssistenciaRemota();
    }
  }
}


// в”Җв”Җ DetecГ§ГЈo de troca de monitor в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function verificarTrocaMonitores(agentes) {
  if (!agentes || !agentes.length) return;
  const CHAVE = 'monitor_maquina_'; // localStorage: monitor_maquina_{serial} = hostname

  agentes.forEach(ag => {
    const monitores = ag.monitores;
    if (!Array.isArray(monitores) || !monitores.length) return;

    monitores.forEach(mon => {
      const id = mon.serial || mon.nome || mon.caption;
      if (!id || id.length < 3) return; // ignora sem identificador
      const chave = CHAVE + id.replace(/[^a-zA-Z0-9]/g,'_');
      const maquinaAnterior = localStorage.getItem(chave);

      if (maquinaAnterior && maquinaAnterior !== ag.hostname) {
        // Monitor mudou de mГЎquina!
        const nomeMonitor = mon.nome || mon.caption || id;
        showToast(
          `рҹ–ҘпёҸ Monitor movido! "${nomeMonitor}" saiu de ${maquinaAnterior} вҶ’ ${ag.hostname}`,
          'warning', 10000
        );
        console.warn(`[Monitor] ${nomeMonitor} movido: ${maquinaAnterior} вҶ’ ${ag.hostname}`);
        // Registra no audit log
        auditLog('monitor_movido', 'assistencia-remota', id, 'monitor', {
          monitor: nomeMonitor, de: maquinaAnterior, para: ag.hostname
        });
      }
      // Atualiza registro
      localStorage.setItem(chave, ag.hostname);
    });
  });
}

function renderAssistenciaRemota() {
  const tbody = document.getElementById('ar-tbody');
  if (!tbody) return;

  const q      = (document.getElementById('ar-search')?.value     || '').toLowerCase();
  const fSt    = document.getElementById('ar-filter-status')?.value || '';
  const fOs    = document.getElementById('ar-filter-os')?.value    || '';
  const agentes = STATE_AGENTS.list;

  // Stats
  const online  = agentes.filter(a => a.status === 'online').length;
  const offline = agentes.filter(a => a.status === 'offline' || (!a.status && a.lastSeen)).length;
  const alertas = agentes.filter(a => ['alerta','critico'].includes(a.status)).length;
  const sessoes = agentes.filter(a => a.emSessao).length;

  sv('ar-stat-online',  online);
  sv('ar-stat-offline', offline);
  sv('ar-stat-alert',   alertas);
  sv('ar-stat-session', sessoes);
  sv('ar-stat-total',   agentes.length);
  nbUpdate('nb-agentes-online', online);
  document.getElementById('ar-last-update').textContent =
    'Atualizado: ' + new Date().toLocaleTimeString('pt-BR');

  // Filtro
  let lista = agentes;
  if (q)   lista = lista.filter(a =>
    (a.hostname||'').toLowerCase().includes(q) ||
    (a.ip||'').includes(q) ||
    (a.usuarioLogado||'').toLowerCase().includes(q) ||
    (a.osNome||'').toLowerCase().includes(q));
  if (fSt) lista = lista.filter(a => a.status === fSt);
  if (fOs) lista = lista.filter(a => (a.osNome||'').includes(fOs));

  // Ordena: crГӯticos primeiro
  const ORDER = { critico:0, alerta:1, online:2, offline:3 };
  lista.sort((a,b) => (ORDER[a.status]??4) - (ORDER[b.status]??4));

  if (!lista.length) {
    const carregando = !STATE_AGENTS._carregou;
    tbody.innerHTML = `<tr><td colspan="11" style="text-align:center;padding:40px;color:var(--g400)">
      <div style="font-size:32px;margin-bottom:12px">${carregando ? 'вҸі' : 'рҹ–ҘпёҸ'}</div>
      <div style="font-weight:600;margin-bottom:6px">
        ${carregando ? 'Carregando agentes...' : (agentes.length ? 'Nenhum agente com esses filtros' : 'Nenhum agente instalado')}
      </div>
      ${carregando ? '<div style="font-size:12px;color:var(--g400);margin-top:4px">Conectando ao banco de dados...</div>' : ''}
      ${!agentes.length && !carregando ? '<button class="btn btn-primary btn-sm" style="margin-top:12px" onclick="arInstalarAgente()">в¬ҮпёҸ Baixar Instalador</button>' : ''}
    </td></tr>`;
    return;
  }

  tbody.innerHTML = lista.map(a => {
    const statusCls = a.status || 'sem-agente';
    const statusCor = {online:'badge-success',offline:'badge-danger',alerta:'badge-warning',critico:'badge-danger'}[a.status] || '';
    const lastSeen  = a.lastSeen ? fmtRelative(new Date(a.lastSeen?.seconds ? a.lastSeen.seconds*1000 : a.lastSeen)) : 'вҖ”';

    // CPU bar
    const cpuBar = a.cpuPct != null
      ? `<div style="display:flex;align-items:center;gap:6px">
           <div style="width:50px;height:5px;background:var(--g200);border-radius:3px;overflow:hidden">
             <div style="width:${a.cpuPct}%;height:5px;background:${a.cpuPct>90?'#EF4444':a.cpuPct>70?'#F59E0B':'#10B981'};border-radius:3px"></div>
           </div>
           <span style="font-size:11.5px">${a.cpuPct}%</span>
         </div>` : 'вҖ”';

    const ramBar = a.memPct != null
      ? `<div style="display:flex;align-items:center;gap:6px">
           <div style="width:50px;height:5px;background:var(--g200);border-radius:3px;overflow:hidden">
             <div style="width:${a.memPct}%;height:5px;background:${a.memPct>90?'#EF4444':a.memPct>80?'#F59E0B':'#10B981'};border-radius:3px"></div>
           </div>
           <span style="font-size:11.5px">${a.memPct}%</span>
         </div>` : 'вҖ”';

    const diskBar = a.discoC_usadoPct != null
      ? `<div style="display:flex;align-items:center;gap:6px">
           <div style="width:50px;height:5px;background:var(--g200);border-radius:3px;overflow:hidden">
             <div style="width:${a.discoC_usadoPct}%;height:5px;background:${a.discoC_usadoPct>90?'#EF4444':a.discoC_usadoPct>80?'#F59E0B':'#10B981'};border-radius:3px"></div>
           </div>
           <span style="font-size:11.5px">${100-a.discoC_usadoPct}% livre</span>
         </div>` : 'вҖ”';

    const patchBadge = a.patchesCriticos > 0
      ? `<span style="font-size:10px;background:#FEF2F2;color:#DC2626;padding:1px 6px;border-radius:10px;margin-left:4px">${a.patchesCriticos} patch(es) crГӯtico(s)</span>`
      : '';

    return `<tr>
      <td style="text-align:center"><span class="ar-dot ${statusCls}"></span></td>
      <td>
        <div style="font-weight:700;font-size:13px">${escapeHtml(a.hostname||a.id)}</div>
        ${patchBadge}
        ${a.emSessao ? '<span style="font-size:10px;background:#EFF6FF;color:#2563EB;padding:1px 6px;border-radius:10px;margin-left:4px">Em sessГЈo</span>' : ''}

      </td>
      <td style="font-family:monospace;font-size:12px;color:var(--g500)">${(()=>{ const _a=ipParaArea(a.ip); return (a.ip||'вҖ”') + (_a ? ' <span style="font-size:10px;color:#64748B;font-weight:500" title="'+escapeHtml(_a.nome)+'">'+escapeHtml(_a.codigo.toUpperCase())+'</span>' : ''); })()}</td>
      <td style="font-size:12px">${escapeHtml((a.osNome||'вҖ”').replace('Microsoft Windows ','Win '))}</td>
      <td style="font-size:12px;color:var(--g600)">${escapeHtml(a.usuarioLogado||'вҖ”')}</td>
      <td>${cpuBar}</td>
      <td>${ramBar}</td>
      <td>${diskBar}</td>
      <td style="font-size:10.5px;color:var(--g500)">${(()=>{
        if (!Array.isArray(a.outrosDiscos) || !a.outrosDiscos.length) return 'вҖ”';
        return a.outrosDiscos.map(d => '<div>'+escapeHtml(d.drive||'?')+': '+escapeHtml(String(d.freeGB||'?'))+' GB</div>').join('');
      })()}</td>
      <td class="monitor-cell">${Array.isArray(a.monitores) && a.monitores.length ?
        a.monitores.map(m => {
          const nome   = escapeHtml(m.nome || m.caption || 'Monitor');
          const serial = m.serial ? '<span style="font-family:monospace;color:var(--g400);font-size:10px;display:block">#'+escapeHtml(m.serial)+'</span>' : '';
          return '<div style="font-size:11px;line-height:1.4">'+nome+serial+'</div>';
        }).join('') : '<span style="color:var(--g300)">вҖ”</span>'
      }</td>
      <td style="font-size:12px;color:var(--g500)">${a.uptimeH != null ? Math.round(a.uptimeH) + 'h' : 'вҖ”'}</td>
      <td style="font-size:10.5px;color:var(--g400);font-family:monospace">${escapeHtml(a.versaoAgente || a.version || 'вҖ”')}</td>
      <td style="font-size:11.5px;color:var(--g400)">${lastSeen}</td>
      <td>
        <div style="display:flex;gap:3px;align-items:center;flex-wrap:nowrap">
          <button class="btn btn-primary btn-xs" onclick="arAbrirViewer('${a.id}')" title="Acessar remotamente" ${a.status!=='online'?'disabled':''} style="padding:2px 7px;font-size:12px">рҹ–ҘпёҸ</button>
          <button class="btn btn-secondary btn-xs" onclick="arAbrirInventario('${a.id}')" title="InformaГ§Гөes" style="padding:2px 7px;font-size:12px">рҹ“Ӣ</button>
          <button class="btn btn-secondary btn-xs" onclick="arInstalarSoftware('${a.id}','${escapeHtml(a.hostname||a.id)}')" title="Instalar software" style="padding:2px 7px;font-size:12px">рҹ“Ұ</button>
          <button class="btn btn-secondary btn-xs"  onclick="abrirInventarioAgente('${a.id}')"  title="InventГЎrio de Software">рҹ“Ӣ</button>
        </div>
      </td>
    </tr>`;
  }).join('');
}

// в”Җв”Җ ABRIR REMOTE VIEWER в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function abrirInventarioAgente(agentId) {

  goPage('apps');

  setTimeout(() => {

    const btnPorMaquina =
      [...document.querySelectorAll('button')]
      .find(b => b.textContent.includes('Por MГЎquina'));

    if (btnPorMaquina) btnPorMaquina.click();

    const busca =
      document.getElementById('sw-search') ||
      document.querySelector('#page-apps input');

if (busca) {
  const ag = STATE_AGENTS.list.find(a => a.id === agentId);
  busca.value = ag?.hostname || agentId;
  busca.dispatchEvent(new Event('input'));
    }

  }, 500);

}
async function arAbrirViewer(agentId) {
  const agente = STATE_AGENTS.list.find(a => a.id === agentId);
  if (!agente) return showToast('Agente nГЈo encontrado', 'warning');
  if (agente.status !== 'online') return showToast('Agente offline вҖ” nГЈo Г© possГӯvel conectar', 'danger');

  showToast('Iniciando sessГЈo remota com ' + (agente.hostname || agentId) + '...', 'info', 3000);

  // Cria sessГЈo no Banco
  let sessaoId;
  try {
    const sessaoDoc = await fsAdd('sessoes_remotas', {
      agentId,
      hostname:      agente.hostname || agentId,
      ip:            agente.ip || '',
      iniciadorUid:  CURRENT_USER?.uid || '',
      iniciadorNome: CURRENT_USER?.nome || '',
      status:        'iniciando',
      tipo:          'websocket',
      createdAt:     new Date().toISOString(),
    });
    sessaoId = sessaoDoc?.name?.split('/').pop() || 'sess_' + Date.now();
  } catch {
    sessaoId = 'sess_' + Date.now();
  }

  // Envia comando para o agente iniciar o tunnel WebSocket
  await arEnviarComando(agentId, 'iniciar_acesso_remoto', {
    sessaoId, port: 9000,
  }, 'SessГЈo de acesso remoto via SYSACK');

  // Audit log
  auditLog('REMOTE_ACCESS_START', 'agents', agentId, 'computador', {
    hostname: agente.hostname, sessaoId, ip: agente.ip,
  });

  // Abre o viewer apГіs 2s (tempo para o agente iniciar o tunnel)
  setTimeout(() => iniciarViewerRemoto(agentId, sessaoId, agente), 2000);
}

