// Inicia listener quando o usuГЎrio faz login
function initAgentsListener() {
  // Carrega tabela de redes CESAN do Banco e verifica IPs dos ativos
  carregarRedesCesan().then(() => setTimeout(verificarTodosIPs, 8000));
  if (FB_READY) startAgentsListener();
}

// Garante que os agentes estГЈo carregados ao abrir a pГЎgina
// Chamado toda vez que a pГЎgina de assistГӘncia remota Г© acessada
let _arEnsureTimer = null;
function _arEnsureLoaded() {
  if (!FB_READY || !db) return;

  // Se jГЎ carregou E tem dados reais, nГЈo precisa recarregar
  if (STATE_AGENTS._carregou && STATE_AGENTS.list.length > 0) return;

  // Se carregou mas lista vazia, tenta de novo (pode ter sido erro de permissГЈo anterior)
  if (STATE_AGENTS._carregou && STATE_AGENTS.list.length === 0) {
    STATE_AGENTS._carregou = false; // forГ§a nova tentativa
  }

  // Listener nГЈo carregou ainda вҖ” faz poll imediato
  clearTimeout(_arEnsureTimer);
  _arEnsureTimer = setTimeout(async () => {
    try {
      console.log('[Agentes] Carregando via poll...');
      const snap = await db.collection('agents').orderBy('lastSeen', 'desc').get();
      STATE_AGENTS._carregou = true;
      STATE_AGENTS.list = snap.docs.map(d => {
        const data = d.data();
        if (data.uptimeH != null) data.uptimeH = Number(data.uptimeH);
        if (data.cpuPct  != null) data.cpuPct  = Number(data.cpuPct);
        if (data.ramPct  != null) data.ramPct  = Number(data.ramPct);
        if (data.memPct  != null) data.memPct  = Number(data.memPct);
        return { id: d.id, ...data };
      });
      console.log('[Agentes] Carregados via poll:', STATE_AGENTS.list.length);
      renderAssistenciaRemota();
      nbUpdate('nb-agentes-online', STATE_AGENTS.list.filter(a => a.status === 'online').length);
    } catch(e) {
      console.warn('[Agentes] poll erro:', e.message);
      STATE_AGENTS._carregou = true; // evita loop infinito
      renderAssistenciaRemota();
    }
  }, 300);
}


// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// MONITOR DE REDE вҖ” todos os dispositivos lГіgicos
// SNMP, ICMP, HTTP вҖ” dados em tempo real do Banco
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

// Monitor de Rede вҖ” filtro KPI ativo
var _monFiltro = '';

function monFiltrar(filtro) {
  // Toggle: clicar no mesmo filtro desliga
  _monFiltro = (_monFiltro === filtro) ? '' : filtro;
  // Sync dropdown
  var sel = document.getElementById('mon-filter-status');
  if (sel) sel.value = _monFiltro;
  // Remove highlight de todos
  ['mon-card-total','mon-card-online','mon-card-offline','mon-card-critico','mon-card-alerta'].forEach(function(id){
    var el = document.getElementById(id);
    if (el) { el.style.outline = 'none'; el.style.boxShadow = ''; }
  });
  // Destaca o ativo
  var colorMap = {ok:'#059669',offline:'#DC2626',critico:'#D97706',alerta:'#F59E0B'};
  var idMap = {ok:'mon-card-online',offline:'mon-card-offline',critico:'mon-card-critico',alerta:'mon-card-alerta'};
  if (_monFiltro && idMap[_monFiltro]) {
    var el = document.getElementById(idMap[_monFiltro]);
    if (el) el.style.outline = '3px solid '+(colorMap[_monFiltro]||'var(--accent)');
  }
  renderMonitorRede();
}

function renderMonChart(todos) {
  var chart = document.getElementById('mon-chart');
  if (!chart) return;
  var byTipo = {};
  todos.forEach(function(d){
    var t = d.tipo||'ativo';
    byTipo[t] = (byTipo[t]||0) + 1;
  });
  var tipoColors = {switch:'#2563EB',router:'#EA580C',ap:'#0891B2','switch-core':'#0F172A',firewall:'#7C3AED',printer:'#D97706',servidor:'#6366F1','server-linux':'#6366F1',workstation:'#64748B',ativo:'#94A3B8'};
  var total = todos.length || 1;
  var barHtml = Object.entries(byTipo).sort(function(a,b){return b[1]-a[1];}).slice(0,8).map(function(e){
    var t=e[0], n=e[1], pct=Math.round(n/total*100);
    var color = tipoColors[t]||'#64748B';
    return '<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">'
      +'<div style="width:80px;font-size:11px;color:var(--g600);text-align:right;flex-shrink:0;text-transform:capitalize">'+escapeHtml(t)+'</div>'
      +'<div style="flex:1;background:var(--g100);border-radius:3px;height:14px;overflow:hidden">'
        +'<div style="background:'+color+';width:'+pct+'%;height:100%;border-radius:3px"></div>'
      +'</div>'
      +'<div style="width:40px;font-size:11px;font-weight:700;color:'+color+'">'+n+'</div>'
    +'</div>';
  }).join('');
  chart.innerHTML = barHtml || '<div style="color:var(--g400);font-size:12px">Sem dados</div>';
}

function renderMonitorRede() {
  const tbody  = document.getElementById('mon-tbody');
  if (!tbody) return;

  const q      = (document.getElementById('mon-search')?.value || '').toLowerCase();
  const fSt    = _monFiltro || document.getElementById('mon-filter-status')?.value || '';
  const fTipo  = document.getElementById('mon-filter-tipo')?.value   || '';
  const fLocal = document.getElementById('mon-filter-local')?.value  || '';
  const agora  = new Date();

  // Agrupa switches + ativos com IP
  const switches = (STATE.switches || []);
  const ativosIP = (STATE.ativos   || []).filter(a => a.ip || a.ipAddress);

  const todos = [
    ...switches.map(s => ({ ...s, _col:'switches' })),
    ...ativosIP.map(a => ({ ...a, _col:'ativos',
      ip: a.ip || a.ipAddress,
      tipo: a.tipo || 'ativo' })),
  ];

  // Stats
  const online   = todos.filter(d => d.reachable || d.status === 'ok').length;
  const offline  = todos.filter(d => d.status === 'offline').length;
  const critico  = todos.filter(d => d.status === 'critico').length;
  const alerta   = todos.filter(d => d.status === 'alerta').length;
  const uptimePct = todos.length ? Math.round(online/todos.length*100) : 0;

  sv('mon-total',   todos.length);
  sv('mon-online',  online);
  sv('mon-offline', offline);
  sv('mon-critico', critico);
  sv('mon-alerta',  alerta);
  sv('mon-uptime',  uptimePct + '%');
  setTimeout(function(){ renderMonChart(todos); }, 0);
  nbUpdate('nb-monitor-critico', critico + offline);
  // Populate localidade dropdown dynamically
  var localSel = document.getElementById('mon-filter-local');
  if (localSel && localSel.options.length <= 1) {
    var locais = [...new Set(todos.map(d => resolverLocal(d)).filter(l => l && l !== 'вҖ”'))].sort();
    locais.forEach(function(loc) {
      var opt = document.createElement('option');
      opt.value = loc; opt.textContent = loc;
      localSel.appendChild(opt);
    });
  }

  document.getElementById('monitor-last-update')
    .textContent = 'Atualizado: ' + agora.toLocaleTimeString('pt-BR');

  // Filtro
  let lista = todos;
  if (q)     lista = lista.filter(d =>
    d.ip?.includes(q) || d.hostname?.toLowerCase().includes(q) ||
    d.desc?.toLowerCase().includes(q) || d.pat?.toLowerCase().includes(q));
  if (fSt)   lista = lista.filter(d => d.status === fSt);
  if (fTipo)  lista = lista.filter(d => d.tipo === fTipo);
  if (fLocal) lista = lista.filter(d => resolverLocal(d) === fLocal);

  // Ordena: crГӯticos primeiro
  // Populate localidade dropdown once
  var localSelMon = document.getElementById('mon-filter-local');
  if (localSelMon && localSelMon.options.length <= 1) {
    var locaisMon = [...new Set(todos.map(function(d){ return resolverLocal(d); }).filter(function(l){ return l && l !== 'вҖ”'; }))].sort();
    locaisMon.forEach(function(loc) {
      var opt = document.createElement('option'); opt.value=loc; opt.textContent=loc; localSelMon.appendChild(opt);
    });
  }

  const ORDER = { offline:0, critico:1, alerta:2, 'sem-snmp':3, ok:4 };
  lista.sort((a,b) => (ORDER[a.status]??5) - (ORDER[b.status]??5));

  if (!lista.length) {
    tbody.innerHTML = '<tr><td colspan="10" style="text-align:center;padding:32px;color:var(--g400)">' +
      (todos.length ? 'Nenhum dispositivo com esses filtros.' :
       'Instale o SYSACK Agent (v2) com suporte SNMP para monitorar dispositivos de rede.') +
      '</td></tr>';
    return;
  }

  tbody.innerHTML = lista.map(d => {
    const dotClass = d.status || (d.reachable ? 'ok' : 'desconhecido');
    const latStr   = d.latencyMs != null ? d.latencyMs.toFixed(1) + 'ms' : 'вҖ”';
    const lastStr  = d.lastSeen
      ? fmtRelative(new Date(d.lastSeen?.seconds ? d.lastSeen.seconds*1000 : d.lastSeen))
      : 'вҖ”';

    // CPU bar
    const cpuBar = d.cpuPct != null
      ? `<div class="mon-bar"><div class="mon-bar-fill ${d.cpuPct>90?'crit':d.cpuPct>70?'warn':'ok'}" style="width:${d.cpuPct}%"></div></div> ${d.cpuPct}%`
      : 'вҖ”';

    // Temp
    const tempStr = d.tempC != null
      ? `<span style="color:${d.tempC>75?'#DC2626':d.tempC>60?'#D97706':'#059669'}">${d.tempC}В°C</span>`
      : 'вҖ”';

    // MГ©tricas extras
    const extras = [];
    if (d.portsUp   != null) extras.push(`${d.portsUp}в–І/${d.portsDown||0}в–ј portas`);
    if (d.battPct   != null) extras.push(`Bat: ${d.battPct}%`);
    if (d.tonerLevels?.length) extras.push(`Toner: ${Math.min(...d.tonerLevels.map(t=>t.pct))}%`);
    if (d.uptime)              extras.push(`Up: ${d.uptime}`);

    return `<tr style="cursor:pointer" onclick="abrirMonitorDetalhe('${d.id}','${d._col}')">
      <td style="text-align:center"><span class="mon-dot ${dotClass}"></span></td>
      <td style="font-weight:600;font-size:13px">${escapeHtml(d.hostname||d.desc||d.pat||'вҖ”')}</td>
      <td style="font-family:monospace;font-size:12px;color:var(--g500)">${escapeHtml(d.ip||'вҖ”')}</td>
      <td><span class="tag">${escapeHtml(d.tipo||'вҖ”')}</span></td>
      <td><span class="badge ${dotClass==='ok'?'badge-success':dotClass==='offline'||dotClass==='critico'?'badge-danger':'badge-warning'}">${dotClass}</span></td>
      <td style="font-size:12px;color:${(d.latencyMs||0)>100?'#D97706':(d.latencyMs||0)>200?'#DC2626':'inherit'}">${latStr}</td>
      <td style="font-size:12px">${cpuBar}</td>
      <td style="font-size:12px">${tempStr}</td>
      <td style="font-size:12px;color:var(--g500)">${extras.join(' В· ')||'вҖ”'}</td>
      <td style="font-size:11.5px;color:var(--g400)">${lastStr}</td>
    </tr>`;
  }).join('');
}

function abrirMonitorDetalhe(id, col) {
  const lista = col === 'switches'
    ? (STATE.switches||[])
    : (STATE.ativos||[]).filter(a => a.ip||a.ipAddress);
  const d = lista.find(x => x.id === id);
  if (!d) return;

  document.getElementById('mon-modal-title').textContent =
    (d.hostname || d.desc || d.pat || d.ip) + ' вҖ” Detalhes';

  const rows = [
    ['IP / Host',    (d.ip||d.ipAddress||'вҖ”') + (d.hostname ? ' ('+d.hostname+')' : '')],
    ['Tipo',         d.tipo||'вҖ”'],
    ['Status',       d.status||'вҖ”'],
    ['LatГӘncia',     d.latencyMs != null ? d.latencyMs.toFixed(1)+'ms' : 'вҖ”'],
    ['CPU',          d.cpuPct    != null ? d.cpuPct+'%' : 'вҖ”'],
    ['Temperatura',  d.tempC     != null ? d.tempC+'В°C' : 'вҖ”'],
    ['Uptime',       d.uptime    || 'вҖ”'],
    ['Portas up/dn', d.portsUp   != null ? d.portsUp+'в–І / '+(d.portsDown||0)+'в–ј' : 'вҖ”'],
    ['Bateria UPS',  d.battPct   != null ? d.battPct+'%' : 'вҖ”'],
    ['Runtime UPS',  d.runtimeMin != null ? d.runtimeMin+'min' : 'вҖ”'],
    ['Гҡltimo online', d.lastSeen ? new Date(d.lastSeen?.seconds ? d.lastSeen.seconds*1000 : d.lastSeen).toLocaleString('pt-BR') : 'вҖ”'],
    ['PAT',          d.pat||'вҖ”'],
    ['ГҒrea',         d.area||'вҖ”'],
  ].filter(([,v]) => v !== 'вҖ”');

  document.getElementById('mon-modal-body').innerHTML =
    '<table style="width:100%;border-collapse:collapse">' +
    rows.map(([k,v]) =>
      '<tr><td style="padding:7px 0;color:var(--g500);font-size:12px;width:140px">'+escapeHtml(k)+'</td>' +
      '<td style="padding:7px 0;font-size:13px;font-weight:500">'+escapeHtml(String(v))+'</td></tr>'
    ).join('') + '</table>' +
    (d.snmpErr ? '<div style="margin-top:12px;padding:10px;background:var(--g50);border-radius:8px;font-size:12px;color:var(--g500)">SNMP: '+escapeHtml(d.snmpErr)+'</div>' : '');

  openModal('modal-monitor-detalhe');
}

function fmtRelative(date) {
  if (!date || isNaN(date)) return 'вҖ”';
  const diff = Date.now() - date.getTime();
  if (diff < 60000)   return 'agora';
  if (diff < 3600000) return Math.floor(diff/60000)+'min atrГЎs';
  if (diff < 86400000) return Math.floor(diff/3600000)+'h atrГЎs';
  return Math.floor(diff/86400000)+'d atrГЎs';
}


// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// APROVAГҮГ•ES вҖ” Fluxo bloqueante com alertas contГӯnuos
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

function renderAprovacoes() {
  const tbody = document.getElementById('aprov-tbody') || document.querySelector('#page-aprovacoes tbody');
  const aprovs = (STATE.aprovacoes || []);

  // Stats
  sv('nb-aprov', aprovs.filter(a => a.status === 'pendente').length);

  if (!tbody) return;

  if (!aprovs.length) {
    tbody.innerHTML = '<tr><td colspan="8" style="text-align:center;padding:32px;color:var(--g400)">Nenhuma aprovaГ§ГЈo pendente</td></tr>';
    return;
  }

  tbody.innerHTML = aprovs.map(a => {
    const dias = a.createdAt ? Math.floor((Date.now() - new Date(a.createdAt).getTime()) / 86400000) : 0;
    const cor  = a.status === 'pendente' ? (dias > 1 ? 'var(--danger)' : 'var(--warning)') : 'var(--success)';
    return `<tr>
      <td class="td-mono" style="color:var(--accent);font-size:12px">${escapeHtml(a.id||'вҖ”')}</td>
      <td style="font-weight:600;font-size:13px">${escapeHtml(a.tipo||'вҖ”')}</td>
      <td style="font-size:12px">${escapeHtml(a.chamadoId||'вҖ”')}</td>
      <td style="font-size:12px">${escapeHtml(a.pat||'вҖ”')}</td>
      <td style="font-size:12px">${escapeHtml(a.solicitante||'вҖ”')}</td>
      <td><span style="font-size:11px;font-weight:700;padding:2px 10px;border-radius:20px;background:${cor}22;color:${cor}">${escapeHtml(a.status||'вҖ”')}</span></td>
      <td style="font-size:12px;color:${dias > 1 ? 'var(--danger)' : 'inherit'}">${dias}d</td>
      <td>
        ${a.status === 'pendente'
          ? `<button class="btn btn-success btn-xs" onclick="aprovarMovimentacao('${a.id}')">вң“ Autorizar</button>
             <button class="btn btn-danger btn-xs"  onclick="recusarMovimentacao('${a.id}')">вң— Recusar</button>`
          : `<span style="font-size:11px;color:var(--g400)">${escapeHtml(a.decidedBy||'')}</span>`
        }
      </td>
    </tr>`;
  }).join('');
}

async function aprovarMovimentacao(aprovId) {
  if (!SESSION_USER?.permissions?.canApprove) {
    showToast('вӣ” Sem permissГЈo para aprovar movimentaГ§ГЈo.', 'error');
    return;
  }

  const aprov = (STATE.aprovacoes || []).find(a => a.id === aprovId);
  if (!aprov) return;

  aprov.status     = 'aprovado';
  aprov.decidedBy  = CURRENT_USER?.nome || 'Gestor';
  aprov.decidedAt  = new Date().toISOString();

  await fsUpdate('aprovacoes', aprovId, {
    status: 'aprovado', decidedBy: aprov.decidedBy, decidedAt: aprov.decidedAt,
  });

  // Atualiza o chamado vinculado para retomar o fluxo
  if (aprov.chamadoId) {
    const ch = (STATE.chamados || []).find(c => c.id === aprov.chamadoId);
    if (ch) {
      ch.status = 'em-atendimento';
      await fsUpdate('chamados', aprov.chamadoId, { status: 'em-atendimento', aprovadoPor: aprov.decidedBy, aprovadoEm: aprov.decidedAt });
    }
  }

  // Executa aГ§ГЈo de movimentaГ§ГЈo aprovada
  if (aprov.detalhes) {
    await executarMovimentacaoAprovada(aprov);
  }

  renderAprovacoes();
  renderChamados();
  showToast('вң… MovimentaГ§ГЈo autorizada вҖ” fluxo retomado!', 'success', 4000);
}

async function recusarMovimentacao(aprovId) {
  const motivo = prompt('Motivo da recusa (obrigatГіrio):');
  if (!motivo?.trim()) return;

  const aprov = (STATE.aprovacoes || []).find(a => a.id === aprovId);
  if (!aprov) return;

  aprov.status    = 'recusado';
  aprov.decidedBy = CURRENT_USER?.nome || 'Gestor';
  aprov.decidedAt = new Date().toISOString();
  aprov.motivoRecusa = motivo.trim();

  await fsUpdate('aprovacoes', aprovId, {
    status: 'recusado', decidedBy: aprov.decidedBy,
    decidedAt: aprov.decidedAt, motivoRecusa: motivo.trim(),
  });

  if (aprov.chamadoId) {
    const ch = (STATE.chamados || []).find(c => c.id === aprov.chamadoId);
    if (ch) {
      ch.status = 'aberto';
      await fsUpdate('chamados', aprov.chamadoId, { status: 'aberto', movimentacaoRecusada: true, motivoRecusa: motivo.trim() });
    }
  }

  renderAprovacoes();
  showToast('MovimentaГ§ГЈo recusada. TГ©cnico serГЎ notificado.', 'warning', 4000);
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// HISTГ“RICO IMUTГҒVEL DO ATIVO
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

// Grava evento imutГЎvel na subcoleГ§ГЈo /ativos/{id}/historico
async function registrarHistoricoAtivo(ativoId, evento, detalhes) {
  if (!ativoId || !evento) return;
  const entry = {
    id:         'h_' + Date.now() + '_' + Math.random().toString(36).slice(2,6),
    evento,     // 'criado' | 'atribuido' | 'transferido' | 'manutencao' | 'retornou'
                // 'santa-clara' | 'reutilizado' | 'descartado' | 'renomeado' | 'observacao'
    detalhes:   detalhes || {},
    usuario:    CURRENT_USER?.nome || 'sistema',
    usuarioId:  CURRENT_USER?.uid  || 'sistema',
    timestamp:  new Date().toISOString(),
  };
  // Salva na subcoleГ§ГЈo вҖ” regras Firestore garantem imutabilidade
  if (FB_READY && db) {
    try {
      await db.collection('ativos').doc(ativoId).collection('historico').add(entry);
    } catch(e) {
      console.warn('[Historico] erro:', e.message);
    }
  }
  return entry;
}

// Busca e exibe linha do tempo de um ativo
async function abrirLinhaDoTempo(ativoId, pat) {
  const modal = document.getElementById('modal-linha-tempo');
  if (!modal) return;
  document.getElementById('lt-titulo').textContent = 'Linha do Tempo вҖ” ' + (pat || ativoId);
  document.getElementById('lt-body').innerHTML = '<div style="text-align:center;padding:32px;color:var(--g400)">Carregando...</div>';
  openModal('modal-linha-tempo');
  try {
    const snap = await db.collection('ativos').doc(ativoId).collection('historico').orderBy('timestamp','desc').limit(100).get();
    const eventos = snap.docs.map(d => d.data());
    if (!eventos.length) {
      document.getElementById('lt-body').innerHTML = '<div style="text-align:center;padding:32px;color:var(--g400)"><div style="font-size:32px;margin-bottom:8px">рҹ“Ӣ</div>Nenhum evento registrado ainda.</div>';
      return;
    }
    const iconMap = {
      'criado':'рҹҹў','atribuido':'рҹ‘Ө','transferido':'рҹ”„','manutencao':'рҹ”§',
      'retornou':'рҹҸӯ','santa-clara':'рҹ“Қ','reutilizado':'вҷ»пёҸ','descartado':'рҹ—‘пёҸ',
      'renomeado':'рҹҸ·пёҸ','observacao':'рҹ’¬','movimentado':'рҹ“Ұ',
    };
    document.getElementById('lt-body').innerHTML = eventos.map(function(ev) {
      var ico = iconMap[ev.evento] || 'рҹ“Ң';
      var data = ev.timestamp ? new Date(ev.timestamp).toLocaleString('pt-BR',{day:'2-digit',month:'2-digit',year:'numeric',hour:'2-digit',minute:'2-digit'}) : 'вҖ”';
      var dets = '';
      if (ev.detalhes) {
        dets = Object.entries(ev.detalhes).filter(function(e){return e[1]&&e[0]!=='id';}).map(function(e){
          return '<span style="font-size:10.5px;color:var(--g500)">'+escapeHtml(e[0])+': <strong>'+escapeHtml(String(e[1]))+'</strong></span>';
        }).join(' В· ');
      }
      return '<div style="display:flex;gap:14px;padding:12px 0;border-bottom:1px solid var(--g100)">'
        +'<div style="font-size:20px;flex-shrink:0;margin-top:2px">'+ico+'</div>'
        +'<div style="flex:1"><div style="font-weight:700;font-size:13px;color:var(--g900)">'+escapeHtml((ev.evento||'').replace(/-/g,' ').replace(/\w/g,function(l){return l.toUpperCase();}))+'</div>'
        +(dets?'<div style="margin-top:4px;display:flex;flex-wrap:wrap;gap:6px">'+dets+'</div>':'')
        +'<div style="font-size:10.5px;color:var(--g400);margin-top:4px">'+escapeHtml(ev.usuario)+' В· '+data+'</div>'
        +'</div></div>';
    }).join('');
  } catch(e) {
    document.getElementById('lt-body').innerHTML = '<div style="text-align:center;padding:32px;color:var(--danger)">Erro ao carregar: '+escapeHtml(e.message)+'</div>';
  }
}

// Adicionar observaГ§ГЈo manual ao histГіrico
async function adicionarObservacaoHistorico(ativoId) {
  var obs = prompt('ObservaГ§ГЈo sobre este ativo (ficarГЎ registrada permanentemente):');
  if (!obs || !obs.trim()) return;
  await registrarHistoricoAtivo(ativoId, 'observacao', { texto: obs.trim() });
  showToast('ObservaГ§ГЈo registrada no histГіrico.', 'success');
}

async function executarMovimentacaoAprovada(aprov) {
  const det = aprov.detalhes || {};

  if (det.destino === 'mindworks') {
    // Registra na lista de terceirizadas com prazo
    const dataRecolh = det.dataRecolhimento || new Date().toISOString().split('T')[0];
    const prazo      = det.prazoTerceirizada || 10;
    const vencimento = calcularDiasUteis(new Date(dataRecolh), prazo);

    // Registra histГіrico imutГЎvel
    const ativoObj = (STATE.ativos||[]).find(a=>a.pat===(det.patAntigo||aprov.pat)||a.id===(det.patAntigo||aprov.pat));
    if (ativoObj) await registrarHistoricoAtivo(ativoObj.id, 'manutencao', {
      destino:'Mindworks', tecnico:det.tecnicoTerceirizada||'вҖ”', chamado:aprov.chamadoId||'вҖ”',
      patAntigo:det.patAntigo||'вҖ”', aprovadoPor:CURRENT_USER?.nome||'вҖ”'
    });

    const tercItem = {
      id:            'TERC-' + Date.now(),
      chamadoId:     aprov.chamadoId,
      pat:           det.patAntigo || aprov.pat,
      ativo:         det.patAntigo || aprov.pat,
      tecnicoId:     det.tecnicoTerceirizada || '',
      dataEnvio:     dataRecolh,
      prazoRetorno:  vencimento.toISOString().split('T')[0],
      prazoUteisTotal: prazo,
      status:        'aguardando-retorno',
      retornado:     false,
      diasUteis:     0,
    };
    if (!STATE.terceirizadaAtivos) STATE.terceirizadaAtivos = [];
    STATE.terceirizadaAtivos.unshift(tercItem);
    await fsAdd('terceirizadaAtivos', tercItem);
    showToast('рҹ“Ұ MГЎquina registrada na Empresa Terceirizada com prazo de ' + prazo + ' dias Гәteis.', 'info', 5000);
  }

  if (det.destino === 'santa-clara') {
    const scItem = {
      id:        'SC-' + Date.now(),
      chamadoId: aprov.chamadoId,
      pat:       det.patAntigo || aprov.pat,
      local:     det.scLocal || '',
      foto:      '', // upload da foto Г© feito separadamente
      dataEntrada: new Date().toISOString().split('T')[0],
      status:    'armazenado',
    };
    if (!STATE.scAtivos) STATE.scAtivos = [];
    STATE.scAtivos.unshift(scItem);
    await fsAdd('scAtivos', scItem);
    showToast('рҹ“Ұ MГЎquina registrada em Santa Clara: ' + det.scLocal, 'info', 5000);
  }

  if (det.destino === 'reutilizada') {
    // Atualiza localizaГ§ГЈo do ativo no sistema
    if (det.patNovo || det.patAntigo) {
      const pat = det.patNovo || det.patAntigo;
      const ativo = (STATE.ativos || []).find(a => a.pat === pat);
      if (ativo) {
        if (det.reutLocal)  ativo.local = det.reutLocal;
        if (det.reutNome)   ativo.desc  = det.reutNome;
        if (det.reutTipoUso) ativo.tipoUso = det.reutTipoUso;
        await fsUpdate('ativos', ativo.id, {
          local: det.reutLocal, desc: det.reutNome || ativo.desc,
          tipoUso: det.reutTipoUso, updatedAt: new Date().toISOString(),
        });
      }
    }
  }
}

function calcularDiasUteis(dataInicio, qtdDias) {
  let data = new Date(dataInicio);
  let count = 0;
  while (count < qtdDias) {
    data.setDate(data.getDate() + 1);
    const dow = data.getDay();
    if (dow !== 0 && dow !== 6) count++; // pula sГЎbado e domingo
  }
  return data;
}

// Alerta de aprovaГ§Гөes pendentes hГЎ mais de 1 dia (roda a cada hora)
function verificarAprovacoesPendentes() {
  const pendentes = (STATE.aprovacoes || []).filter(a => a.status === 'pendente');
  const urgentes  = pendentes.filter(a => {
    const dias = (Date.now() - new Date(a.createdAt).getTime()) / 86400000;
    return dias >= 1;
  });
  if (urgentes.length > 0) {
    nbUpdate('nb-aprov', pendentes.length);
    // Pisca o badge
    const badge = document.getElementById('nb-aprov');
    if (badge) {
      badge.style.background = 'var(--danger)';
      badge.style.animation  = 'pulse 1.5s infinite';
    }
  }
}
setInterval(verificarAprovacoesPendentes, 60 * 60 * 1000);



