    // Detalhes
    '<div style="padding:20px 24px">',
      '<table style="width:100%;font-size:12.5px;border-collapse:collapse">',
        '<tr style="border-bottom:1px solid #F1F5F9"><td style="color:#94A3B8;padding:7px 0;width:120px">Assunto</td>',
