// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// PWA вҖ” Progressive Web App (instalar no celular)
// Atualiza automaticamente quando o sistema web Г© atualizado
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

let _pwaInstallPrompt = null;  // armazena o evento beforeinstallprompt
let _swRegistration   = null;  // registration do service worker

// Intercepta o prompt de instalaГ§ГЈo do navegador
window.addEventListener('beforeinstallprompt', (e) => {
  e.preventDefault();
  _pwaInstallPrompt = e;
  // Mostra botГЈo de instalar no topbar
  const btn = document.getElementById('pwa-install-btn');
  if (btn) {
    btn.style.display = 'flex';
    btn.title = 'Instalar SYSACK no seu dispositivo';
  }
  console.log('[PWA] Prompt de instalaГ§ГЈo disponГӯvel');
});

// Detecta quando o app foi instalado
window.addEventListener('appinstalled', () => {
  _pwaInstallPrompt = null;
  const btn = document.getElementById('pwa-install-btn');
  if (btn) btn.style.display = 'none';
  showToast('вң… SYSACK instalado com sucesso! Procure o Гӯcone na tela inicial.', 'success', 5000);
  console.log('[PWA] App instalado');
});

async function instalarPWA() {
  if (!_pwaInstallPrompt) {
    // Fallback: explica como instalar manualmente
    const isIOS = /iphone|ipad|ipod/i.test(navigator.userAgent);
    if (isIOS) {
      showToast('No iOS: toque em Compartilhar (в¬ҶпёҸ) e depois "Adicionar Г  Tela de InГӯcio"', 'info', 6000);
    } else {
      showToast('Para instalar: no Chrome, toque nos 3 pontos (...) e selecione "Instalar aplicativo"', 'info', 6000);
    }
    return;
  }
  try {
    const result = await _pwaInstallPrompt.prompt();
    console.log('[PWA] Resultado:', result.outcome);
    if (result.outcome === 'accepted') {
      showToast('вң… Instalando SYSACK...', 'success');
    }
  } catch (err) {
    console.warn('[PWA] Erro ao instalar:', err.message);
  }
}

// Registra Service Worker вҖ” permite funcionamento offline e atualizaГ§Гөes automГЎticas
function initPWA() {
  if (!('serviceWorker' in navigator)) {
    console.warn('[PWA] Service Worker nГЈo suportado');
    return;
  }
  navigator.serviceWorker.register('/sw.js')
    .then(reg => {
      _swRegistration = reg;
      console.log('[PWA] вң“ Service Worker registrado:', reg.scope);

      // Verifica atualizaГ§Гөes a cada 60 segundos
      setInterval(() => reg.update(), 60000);

      // Quando hГЎ nova versГЈo disponГӯvel
      reg.addEventListener('updatefound', () => {
        const worker = reg.installing;
        worker.addEventListener('statechange', () => {
          if (worker.state === 'installed' && navigator.serviceWorker.controller) {
            // Nova versГЈo disponГӯvel вҖ” notifica o usuГЎrio
            showUpdateBanner();
          }
        });
      });
    })
    .catch(err => console.warn('[PWA] SW error:', err.message));

  // Recebe comandos FCM do Service Worker (background messages)
  navigator.serviceWorker.addEventListener('message', event => {
    const { type, tipo, data } = event.data || {};
    if (type === 'FCM_CMD') {
      console.log('[FCM SWвҶ’App] Comando:', tipo);
      if (tipo === 'checkin_request')  executarAutoCheckin(data?.smId);
      if (tipo === 'location_request') reportarLocalizacao(data?.smId, data?.requestId);
    }
  });

  // Quando o SW assume o controle (apГіs atualizaГ§ГЈo)
  navigator.serviceWorker.addEventListener('controllerchange', () => {
    console.log('[PWA] Nova versГЈo ativa вҖ” recarregando...');
    window.location.reload();
  });
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
