      term.style.lineHeight = '1.7';
      term.innerHTML =
        '<div style="color:#60A5FA;font-weight:800;font-size:14px;margin-bottom:4px">рҹ–ҘпёҸ Acesso SSH</div>'
        +'<div style="color:#94A3B8;font-size:11px;margin-bottom:16px">'+escapeHtml(sw.hostname||sw.sysName||'вҖ”')+' &nbsp;В·&nbsp; <span style="font-family:monospace;color:#F1F5F9">'+escapeHtml(sw.ip||'вҖ”')+'</span></div>'
        +'<div style="display:flex;flex-direction:column;gap:10px">'

          // в”Җв”Җ OpГ§ГЈo 1: ssh:// (cliente local do OS) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
          +'<div style="background:#1E293B;border:1px solid #334155;border-radius:8px;padding:13px 15px">'
            +'<div style="font-size:10.5px;font-weight:700;color:#60A5FA;text-transform:uppercase;letter-spacing:.5px;margin-bottom:5px">OpГ§ГЈo 1 вҖ” Cliente SSH local</div>'
            +'<div style="font-size:11.5px;color:#94A3B8;margin-bottom:10px">Abre PuTTY, Terminal ou outro cliente SSH instalado no seu computador</div>'
            +'<button onclick="sshAbrirCliente()" style="background:#2563EB;color:#fff;border:none;padding:8px 16px;border-radius:6px;cursor:pointer;font-size:12px;font-weight:700">рҹ”— ssh://'+escapeHtml(sw.ip||'')+'</button>'
            +'<div style="margin-top:8px;font-size:10.5px;color:#475569;font-family:monospace;letter-spacing:.3px">ssh admin@'+escapeHtml(sw.ip||'')+'</div>'
          +'</div>'

          // в”Җв”Җ OpГ§ГЈo 2: WebSSH2 (navegador) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
          +'<div style="background:#1E293B;border:1px solid #334155;border-radius:8px;padding:13px 15px">'
            +'<div style="font-size:10.5px;font-weight:700;color:#34D399;text-transform:uppercase;letter-spacing:.5px;margin-bottom:5px">OpГ§ГЈo 2 вҖ” WebSSH no navegador</div>'
            +'<div style="font-size:11.5px;color:#94A3B8;margin-bottom:10px">Requer servidor WebSSH2 na rede interna CESAN (<code style="font-size:10.5px">npm i -g webssh2</code>)</div>'
            +'<div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap">'
              +'<button onclick="sshAbrirWebSSH()" style="background:#059669;color:#fff;border:none;padding:8px 16px;border-radius:6px;cursor:pointer;font-size:12px;font-weight:700">рҹҢҗ Abrir no navegador</button>'
              +'<button onclick="sshConfigurarWebSSH()" style="background:transparent;color:#34D399;border:1px solid #34D399;padding:7px 12px;border-radius:6px;cursor:pointer;font-size:11.5px">вҡҷпёҸ Configurar endereГ§o</button>'
            +'</div>'
            +'<div style="margin-top:8px;font-size:10.5px;color:#475569">'
              +'Servidor: <span id="ssh-ws-host-lbl" style="color:'+(wsHost?'#34D399':'#F87171')+'">'+(wsHost?escapeHtml(wsHost):'NГЈo configurado')+'</span>'
            +'</div>'
          +'</div>'

          // в”Җв”Җ OpГ§ГЈo 3: Copiar comando в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
          +'<div style="background:#1E293B;border:1px solid #334155;border-radius:8px;padding:13px 15px">'
            +'<div style="font-size:10.5px;font-weight:700;color:#F59E0B;text-transform:uppercase;letter-spacing:.5px;margin-bottom:8px">OpГ§ГЈo 3 вҖ” Copiar comando</div>'
            +'<div style="display:flex;gap:8px;align-items:center">'
