  'show-logs':{title:'рҹ“ң Logs',terminal:true,motivo:false,out:(sw)=>`${sw.hostname}# show logging\n\n*May 8 09:12: %LINK-3-UPDOWN: Gi1/0/1 up\n*May 8 08:45: %SYS-5-CONFIG_I: Configured from console\n*May 7 23:00: %AUTOSAVE: Configuration saved`},
  'backup-config':{title:'рҹ’ҫ Backup Config',terminal:true,motivo:false,out:(sw)=>`Conectando ${sw.ip}...\nBaixando running-config...\n[OK]\nSalvo: ${sw.hostname}_backup_${new Date().toLocaleDateString('pt-BR').replace(/\//g,'-')}.cfg`},
  'update-firmware':{title:'в¬ҶпёҸ AtualizaГ§ГЈo Firmware',terminal:true,motivo:true,out:(sw)=>`VersГЈo atual: ${sw.firmware}\nNova versГЈo detectada.\n[======] 100%\nAguardando janela de manutenГ§ГЈo.`},
