  const LABELS = {
    local:'MudanГ§a de local', estado:'MudanГ§a de estado',
    responsavel:'Troca de responsГЎvel', manutencao:'Enviado para manutenГ§ГЈo',
    retorno:'Retorno de manutenГ§ГЈo', descarte:'Marcado para descarte', outro:'OcorrГӘncia',
  };
  setButtonLoading(btn, true, 'Salvando...');
