// GUIA DE SEGURANГҮA вҖ” exibido apenas para admin no primeiro login
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

function verificarConfigSeguranca() {
  if (CURRENT_USER?.role !== 'admin') return;
  const chave = 'sysack_sec_check_v1';
  // Mostra no mГЎximo 1x por dia
  const ultima = localStorage.getItem(chave);
  if (ultima && (Date.now() - Number(ultima)) < 86400000) return;
  localStorage.setItem(chave, String(Date.now()));

  // Verifica se VAPID e App Check estГЈo configurados
  const semVAPID    = !window.FCM_VAPID_KEY || window.FCM_VAPID_KEY === 'COLE_AQUI_SUA_VAPID_KEY';
  const semAppCheck = false; // App Check desativado intencionalmente вҖ” proteГ§ГЈo via Firestore Rules

  if (!semVAPID && !semAppCheck) return; // tudo OK

  setTimeout(() => {
    const overlay = document.createElement('div');
    overlay.id = 'sysack-security-overlay';
    overlay.style.cssText = 'position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,.7);display:flex;align-items:center;justify-content:center;padding:20px';
    const modal = document.createElement('div');
    modal.style.cssText = 'background:#fff;border-radius:14px;max-width:560px;width:100%;padding:0;overflow:hidden;box-shadow:0 24px 80px rgba(0,0,0,.5)';
    modal.innerHTML = `
      <div style="background:linear-gradient(135deg,#DC2626,#B91C1C);padding:18px 24px">
        <h3 style="color:#fff;margin:0;font-size:16px">рҹ”’ ConfiguraГ§Гөes de SeguranГ§a Pendentes</h3>
        <p style="color:rgba(255,255,255,.7);font-size:12px;margin:4px 0 0">Complete antes de usar em produГ§ГЈo</p>
      </div>
      <div style="padding:20px">
        <div style="display:flex;flex-direction:column;gap:12px">

          ${semVAPID ? `
          <div style="background:#FEF2F2;border:1px solid #FCA5A5;border-radius:8px;padding:12px">
            <div style="font-weight:700;color:#991B1B;margin-bottom:4px">вқҢ FCM VAPID Key nГЈo configurada</div>
            <div style="font-size:12px;color:#7F1D1D;margin-bottom:8px">NotificaГ§Гөes push nГЈo funcionarГЈo.</div>
            <code style="font-size:11px;background:#fff;padding:4px 8px;border-radius:4px;display:block">
              firebase messaging:generate-vapid-key<br>
              # Copie a chave e substitua FCM_VAPID_KEY no index.html
            </code>
          </div>` : ''}

          <div style="background:#F0FDF4;border:1px solid #86EFAC;border-radius:8px;padding:12px">
            <div style="font-weight:700;color:#166534;margin-bottom:4px">вң… ProteГ§Гөes jГЎ ativas</div>
            <div style="font-size:12px;color:#14532D;line-height:1.7">
              вҖў AutenticaГ§ГЈo Firebase obrigatГіria em todas as funГ§Гөes<br>
              вҖў Firestore Rules com controle por role (admin/gestor/tecnico)<br>
              вҖў Notas permanentes: allow delete: if false<br>
              вҖў Audit log imutГЎvel no Firestore<br>
              вҖў Secrets SMTP/API via Firebase Secrets (nГЈo hardcoded)
            </div>
          </div>
        </div>

        <div style="display:flex;gap:10px;justify-content:flex-end;margin-top:16px">
          <button onclick="document.getElementById('sysack-security-overlay')?.remove()" class="btn btn-ghost btn-sm">Fechar</button>
          <a href="https://console.firebase.google.com/project/sysack-829e2/appcheck" target="_blank" class="btn btn-primary btn-sm">Abrir App Check вҶ’</a>
        </div>
      </div>`;
    overlay.appendChild(modal);
    document.body.appendChild(overlay);
    overlay.onclick = e => { if (e.target === overlay) overlay.remove(); };
  }, 3000);
}

// Chama apГіs login
