// MГ“DULO 1 вҖ” GESTГғO PATRIMONIAL AVANГҮADA
// Busca via cГўmera/foto, deduplicaГ§ГЈo, vinculaГ§ГЈo SAP, alertas
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

// в”Җв”Җ Firebase listener para patrimonios (coleГ§ГЈo dedicada) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
(function initPatrimoniosListener() {
  if (!FB_READY || !db) return;
  db.collection('patrimonios').onSnapshot(function(snap) {
    STATE.patrimonios = snap.docs.map(d => ({ id: d.id, ...d.data() }));
    // Alertas automГЎticos: SAP sem vГӯnculo + ativos sem patrimГҙnio
    patVerificarAlertas();
    renderPatrimonio && renderPatrimonio();
  }, function(e) { console.warn('[Banco] patrimonios:', e.message); });

  // Alertas de patrimГҙnio: disparados pelo listener principal de ativos
})();

// в”Җв”Җ Verificar alertas globais de patrimГҙnio в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function patVerificarAlertas() {
  const pats   = STATE.patrimonios || [];
  const ativos = STATE.ativos      || [];

  // PATs SAP sem vГӯnculo
  const semVinculo = pats.filter(p => p.origem === 'sap-import' && !p.ativoId);
  // Ativos computadores/servidores sem PAT
  const ativosSemPat = ativos.filter(a =>
    ['computador','notebook','servidor','desktop'].some(t => (a.tipo||'').toLowerCase().includes(t))
    && !a.pat && !pats.find(p => p.ativoId === a.id));

  const nb = semVinculo.length + ativosSemPat.length;
  nbUpdate('nb-pat-alertas', nb);

  if (semVinculo.length > 0) {
    console.info(`[PAT] ${semVinculo.length} patrimГҙnio(s) SAP sem vГӯnculo вҖ” execute patAutoVincular()`);
  }
}

// в”Җв”Җ Busca por patrimГҙnio: cГўmera OU foto OU texto в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
