// в”Җв”Җ Zoom e impressГЈo do Mapa de Rede в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ


function patMetricasHtml(ativo) {
  const agentes = STATE_AGENTS?.list || [];
  const ativoHn = (ativo.hostname || hostnameFromAtivo(ativo) || '').toLowerCase();
  const ativoIp = ativo.ip || ativo.ipAddress || ativo.ipPrincipal || '';

  // Casa pelo IP, hostname, ou PAT extraГӯdo do hostname do agente
  const ag = agentes.find(a => {
    const agHn = (a.hostname || '').toLowerCase();
    if (ativoIp && a.ip === ativoIp) return true;
    if (ativoHn && agHn === ativoHn) return true;
    // Fallback: PAT numГ©rico no hostname
    const ativoPat = (ativo.pat || '').replace(/\D/g, '');
    const agPat    = agHn.replace(/\D/g, '');
    if (ativoPat && agPat && ativoPat === agPat) return true;
    return false;
  });

  if (!ag) {
    const hasMeta = ativo.disk_total || ativo.mem_total || ativo.cpu_pct != null;
    if (!hasMeta) return '<td style="font-size:11px;color:var(--g300,#CBD5E1);text-align:center">вҖ”</td>';
  }

  const src = ag || ativo;
  // Campos do agente novo (agent-desktop.js)
  const diskPct   = src.discoC_usadoPct ?? src.discoC?.pct ?? null;
  const memPct    = src.ramPct ?? src.memPct ?? null;
  const cpuPct    = src.cpuPct ?? src.cpu_pct ?? null;
  const tipo      = src.tipo_hw || src.tipo || ativo.tipo || '';
  const online    = ag?.status === 'online';

  function bar(pct, color) {
    if (pct == null) return '<span style="color:var(--g300,#cbd5e1)">вҖ”</span>';
    const c = pct > 90 ? '#EF4444' : pct > 70 ? '#F59E0B' : color;
    return `<div style="display:flex;align-items:center;gap:3px">
      <div style="width:36px;height:5px;background:var(--g100,#f1f5f9);border-radius:3px;overflow:hidden">
        <div style="width:${pct}%;height:5px;background:${c};border-radius:3px"></div>
      </div>
      <span style="font-size:10px;color:${c};font-weight:700">${pct}%</span>
    </div>`;
  }

  function fmtBytes(b) {
    if (!b) return 'вҖ”';
    if (b >= 1e12) return (b/1e12).toFixed(1)+'TB';
    if (b >= 1e9)  return (b/1e9).toFixed(0)+'GB';
    if (b >= 1e6)  return (b/1e6).toFixed(0)+'MB';
    return b+'B';
  }

  const uptime   = ag?.uptimeH != null ? Math.round(ag.uptimeH) + 'h' : null;
  const usuario  = ag?.usuarioLogado || null;
  const lastSeen = ag?.lastSeen ? fmtRelative(new Date(ag.lastSeen?.seconds ? ag.lastSeen.seconds*1000 : ag.lastSeen)) : null;

  return `<td style="padding:4px 8px;min-width:200px">
    <div style="background:${online?'#F0FDF4':'var(--g50,#f8fafc)'};border:1px solid ${online?'#BBF7D0':'var(--g200,#e2e8f0)'};border-radius:8px;padding:6px 8px;font-size:10.5px">
      <div style="display:flex;justify-content:space-between;margin-bottom:4px;font-size:10px">
        <span style="font-weight:700;color:${online?'#059669':'var(--g400,#94a3b8)'}">${online?'рҹҹў Online':'вҡ« Offline'}</span>
        ${lastSeen?`<span style="color:var(--g400,#94a3b8)">${escapeHtml(lastSeen)}</span>`:''}
      </div>
      <div style="display:grid;grid-template-columns:30px 1fr;gap:2px 6px;align-items:center">
        <span style="color:var(--g400,#94a3b8)">CPU</span>${bar(cpuPct,'#3B82F6')}
        <span style="color:var(--g400,#94a3b8)">MEM</span>${bar(memPct,'#8B5CF6')}
        <span style="color:var(--g400,#94a3b8)">DSK</span>${bar(diskPct,'#10B981')}
      </div>
    </div>
  </td>`;
}

// MГ©tricas integradas diretamente no renderAtivos() вҖ” patch removido

// Endpoint de recebimento de mГ©tricas do cliente SYSACK Agent
// O agente POST em /api/metrics (ou via Firebase diretamente)
// Formato: { hostname, ip, cpu_pct, mem_total, mem_used, disk_total, disk_used, tipo_hw }
window.sysackReceberMetricas = async function(dados) {
  if (!dados || (!dados.ip && !dados.hostname)) return;
  const ativos = STATE.ativos || [];
  const ativo = ativos.find(a =>
    (dados.ip && a.ip === dados.ip) ||
    (dados.hostname && (a.hostname||'').toLowerCase() === dados.hostname.toLowerCase())
  );
  if (!ativo) return console.warn('[MГ©tricas] Ativo nГЈo encontrado:', dados.hostname || dados.ip);

  const col = ativo._col === 'switches' ? 'switches' : 'ativos';
  await fsUpdate(col, ativo.id, {
    cpu_pct:    dados.cpu_pct,
    mem_total:  dados.mem_total,
    mem_used:   dados.mem_used,
    disk_total: dados.disk_total,
    disk_used:  dados.disk_used,
    tipo_hw:    dados.tipo_hw || '',
    lastMetrica: new Date().toISOString(),
  });
  console.info('[MГ©tricas] Atualizado:', dados.hostname || dados.ip);
};

// в”Җв”Җ Alternar view tabela / mapa de rede в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function monSetView(view) {
  const tabelaWrap = document.getElementById('mon-view-tabela-wrap');
  const mapaWrap   = document.getElementById('mon-view-mapa-wrap');
  const btnTab     = document.getElementById('mon-view-tabela');
  const btnMapa    = document.getElementById('mon-view-mapa');
  if (!tabelaWrap || !mapaWrap) return;
  if (view === 'mapa') {
    tabelaWrap.style.display = 'none';
    mapaWrap.style.display   = '';
    setTimeout(function(){renderMapaRede();}, 100);
    if (btnTab)  { btnTab.style.background='none'; btnTab.style.color='var(--g500,#64748b)'; btnTab.style.boxShadow='none'; }
    if (btnMapa) { btnMapa.style.background='#fff'; btnMapa.style.color='var(--g900,#111827)'; btnMapa.style.boxShadow='0 1px 3px rgba(0,0,0,.1)'; }
    renderMapaRede();
  } else {
    tabelaWrap.style.display = '';
    mapaWrap.style.display   = 'none';
    if (btnTab)  { btnTab.style.background='#fff'; btnTab.style.color='var(--g900,#111827)'; btnTab.style.boxShadow='0 1px 3px rgba(0,0,0,.1)'; }
    if (btnMapa) { btnMapa.style.background='none'; btnMapa.style.color='var(--g500,#64748b)'; btnMapa.style.boxShadow='none'; }
  }
}

// в”Җв”Җ Badge de alertas patrimoniais в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
(function patchNbUpdatePat() {
  const _prev = window.nbUpdate;
  window.nbUpdate = function(id, val) {
    if (id === 'nb-pat-alertas') {
      const el = document.getElementById('nb-pat-alertas');
      if (el) { el.style.display = val > 0 ? '' : 'none'; el.textContent = val; }
      return;
    }
    if (typeof _prev === 'function') return _prev(id, val);
  };
})();

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// CARD: DISPONГҚVEIS PARA REUSO
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
function renderReuso() {
  var grid = document.getElementById('reuso-grid');
  var q    = (document.getElementById('reuso-search')?.value||'').toLowerCase();
  var fTipo = document.getElementById('reuso-filter-tipo')?.value||'';
  if (!grid) return;

  // Ativos em estoque вҖ” inclui todos os tipos (computadores, mobiliГЎrio, switches, etc.)
  var todosAtivos = (STATE.ativos||[]).concat(STATE.mobiliario||[]);
  var lista = todosAtivos.filter(function(a) {
    var s = (a.status||'').toLowerCase();
    return s==='estoque'||s==='disponivel'||s==='disponГӯvel';
  });
  if (fTipo) lista = lista.filter(function(a){return (a.tipo||'').toLowerCase().includes(fTipo);});
  if (q) lista = lista.filter(function(a){
    return ['hostname','ip','desc','pat','area','osNome'].some(function(f){return (a[f]||'').toLowerCase().includes(q);});
  });

  var sv = function(id,v){var el=document.getElementById(id);if(el)el.textContent=v;};
  var todos = (STATE.ativos||[]).filter(function(a){var s=(a.status||'').toLowerCase();return s==='estoque'||s==='disponivel'||s==='disponГӯvel';});
  sv('reuso-kpi-total', todos.length);
  sv('reuso-kpi-notebook', todos.filter(function(a){return(a.tipo||'').toLowerCase()==='notebook';}).length);
  sv('reuso-kpi-desktop', todos.filter(function(a){var t=(a.tipo||'').toLowerCase();return t==='workstation'||t==='computador'||t==='desktop';}).length);
  sv('reuso-kpi-servidor', todos.filter(function(a){return(a.tipo||'').toLowerCase().includes('serv');}).length);

  if (!lista.length) {
    grid.innerHTML = '<div style="grid-column:1/-1;text-align:center;padding:56px;color:var(--g400)"><div style="font-size:48px;margin-bottom:12px">рҹ“Ұ</div><div style="font-size:15px;font-weight:600">Nenhum ativo disponГӯvel para reuso</div><div style="font-size:12px;margin-top:8px;color:var(--g300)">Ativos entram aqui quando retornam de manutenГ§ГЈo ou sГЈo devolvidos ao estoque</div></div>';
    return;
  }

  lista.sort(function(a,b) {
    // Mais antigo em estoque primeiro (prioridade de saГӯda)
    var da = a.dataEstoque||a.updatedAt||a.createdAt||'';
    var db_ = b.dataEstoque||b.updatedAt||b.createdAt||'';
    return da < db_ ? -1 : da > db_ ? 1 : 0;
  });

  grid.innerHTML = lista.map(function(a) {
    var hn   = a.hostname||a.desc||a.pat||a.ip||'вҖ”';
    var tipo = (a.tipo||'workstation').toLowerCase();
    var ico  = {notebook:'рҹ’»',workstation:'рҹ–ҘпёҸ',desktop:'рҹ–ҘпёҸ',servidor:'рҹ–ҘпёҸ','server-linux':'рҹ–ҘпёҸ',monitor:'рҹ–ҘпёҸ'}[tipo]||'рҹ’»';
    var age  = a.dataEstoque ? contarDiasUteis(a.dataEstoque, new Date()) : null;
    var ageCor = !age ? '#6B7280' : age > 90 ? '#DC2626' : age > 30 ? '#D97706' : '#059669';
    var ageLabel = age ? age + ' dias em estoque' : 'Data de entrada nГЈo registrada';
    return '<div style="background:var(--panel,#fff);border:0.5px solid var(--line,#e2e8f0);border-radius:12px;overflow:hidden;border-top:4px solid #059669">'
      +'<div style="padding:16px 18px">'
        +'<div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:12px">'
          +'<div style="display:flex;gap:10px;align-items:flex-start;min-width:0">'
            +'<span style="font-size:24px;flex-shrink:0">'+ico+'</span>'
            +'<div style="min-width:0"><div style="font-family:monospace;font-weight:800;font-size:13px;color:var(--g900);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+escapeHtml(hn)+'</div>'
            +'<div style="font-size:10.5px;color:var(--g500);margin-top:2px">PAT: '+escapeHtml(a.pat||'вҖ”')+' В· '+escapeHtml(tipo)+'</div></div>'
          +'</div>'
          +'<span style="background:#F0FDF4;color:#059669;border:1px solid #05966944;font-size:10px;font-weight:700;padding:2px 8px;border-radius:10px;flex-shrink:0;margin-left:8px">DisponГӯvel</span>'
        +'</div>'
        +'<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;font-size:11.5px;margin-bottom:10px">'
          +'<div><span style="color:var(--g400)">OS:</span> <span>'+escapeHtml((a.osNome||'вҖ”').slice(0,24))+'</span></div>'
          +'<div><span style="color:var(--g400)">Local:</span> <span>'+escapeHtml(resolverLocal(a)||'вҖ”')+'</span></div>'
          +'<div><span style="color:var(--g400)">CPU:</span> <span>'+escapeHtml((a.cpuModelo||'вҖ”').slice(0,22))+'</span></div>'
          +'<div><span style="color:var(--g400)">RAM:</span> <span>'+(a.ramGb?a.ramGb+'GB':'вҖ”')+'</span></div>'
        +'</div>'
        +'<div style="background:var(--g50);border-radius:8px;padding:6px 10px;display:flex;align-items:center;justify-content:space-between">'
          +'<span style="font-size:11px;color:'+ageCor+';font-weight:700">вҸұ '+escapeHtml(ageLabel)+'</span>'
          +(age>90?'<span style="font-size:10px;background:#FEF2F2;color:#DC2626;padding:2px 6px;border-radius:6px;font-weight:700">Prioridade Alta</span>':'')
        +'</div>'
      +'</div>'
      +'<div style="display:flex;border-top:0.5px solid var(--g100)">'
        +'<button data-aid="'+escapeHtml(a.id)+'" data-pat="'+escapeHtml(a.pat||'')+'" onclick="abrirLinhaDoTempo(this.dataset.aid,this.dataset.pat)" style="flex:1;border:none;background:none;padding:10px;font-size:11.5px;font-weight:600;color:var(--g500);cursor:pointer;border-right:0.5px solid var(--g100)">рҹ“Ӣ HistГіrico</button>'
        +'<button data-aid="'+escapeHtml(a.id)+'" onclick="abrirAtribuirAtivo(this.dataset.aid)" style="flex:1;border:none;background:none;padding:10px;font-size:11.5px;font-weight:600;color:#059669;cursor:pointer;border-right:0.5px solid var(--g100)">рҹ‘Ө Atribuir</button>'
        +'<button onclick="openModal(\'modal-novo-chamado\')" style="flex:1;border:none;background:none;padding:10px;font-size:11.5px;font-weight:600;color:var(--g500);cursor:pointer">рҹҺ« Chamado</button>'
      +'</div>'
    +'</div>';
  }).join('');
}

function abrirAtribuirAtivo(ativoId) {
  var a = (STATE.ativos||[]).find(function(x){return x.id===ativoId;});
  if (!a) return;
  var usuario = prompt('Nome do usuГЎrio ou ГЎrea de destino:');
  if (!usuario||!usuario.trim()) return;
  var local = prompt('Nova localidade/setor:');
  if (!local||!local.trim()) return;
  var obs = { novoUsuario: usuario.trim(), novaLocalidade: local.trim(), patAntigo: a.pat };
  fsUpdate('ativos', ativoId, { status:'em-uso', usuario:usuario.trim(), local:local.trim(), dataEstoque:null });
  registrarHistoricoAtivo(ativoId, 'atribuido', obs);
  a.status = 'em-uso'; a.usuario = usuario.trim(); a.local = local.trim();
  showToast('Ativo atribuГӯdo a '+usuario+' em '+local, 'success', 4000);
  renderReuso();
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// CARD: DESCARTE
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
function renderDescarte() {
  var grid = document.getElementById('descarte-grid');
  var q    = (document.getElementById('descarte-search')?.value||'').toLowerCase();
  var fSub = document.getElementById('descarte-filter-sub')?.value||'';
  if (!grid) return;

  var lista = (STATE.ativos||[]).filter(function(a){return (a.status||'').toLowerCase()==='descarte';});
  if (fSub) lista = lista.filter(function(a){return (a.substatusDescarte||'').toLowerCase()===fSub;});
  if (q) lista = lista.filter(function(a){return (a.pat+' '+(a.hostname||'')+' '+(a.desc||'')).toLowerCase().includes(q);});

  var sv = function(id,v){var el=document.getElementById(id);if(el)el.textContent=v;};
  var todos = (STATE.ativos||[]).filter(function(a){return (a.status||'').toLowerCase()==='descarte';});
  sv('descarte-kpi-total',   todos.length);
  sv('descarte-kpi-leilao',  todos.filter(function(a){return a.substatusDescarte==='leilao';}).length);
  sv('descarte-kpi-doacao',  todos.filter(function(a){return a.substatusDescarte==='doacao';}).length);
  sv('descarte-kpi-inutilizado', todos.filter(function(a){return a.substatusDescarte==='inutilizado';}).length);

  if (!lista.length) {
    grid.innerHTML = '<div style="grid-column:1/-1;text-align:center;padding:56px;color:var(--g400)"><div style="font-size:48px;margin-bottom:12px">рҹ—‘пёҸ</div><div style="font-size:15px;font-weight:600">Nenhum ativo em processo de descarte</div></div>';
    return;
  }

  var subMap = {leilao:['LeilГЈo/PregГЈo','#D97706','#FFFBEB'],doacao:['DoaГ§ГЈo','#2563EB','#EFF6FF'],inutilizado:['Inutilizado','#DC2626','#FEF2F2'],'em-analise':['Em AnГЎlise','#475569','#F8FAFC']};

  grid.innerHTML = lista.map(function(a) {
    var hn = a.hostname||a.desc||a.pat||'вҖ”';
    var sub = a.substatusDescarte||'em-analise';
    var sm = subMap[sub]||['Descarte','#DC2626','#FEF2F2'];
    return '<div style="background:var(--panel,#fff);border:0.5px solid var(--line,#e2e8f0);border-radius:12px;overflow:hidden;border-top:4px solid #DC2626">'
      +'<div style="padding:16px 18px">'
        +'<div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:12px">'
          +'<div><div style="font-family:monospace;font-weight:800;font-size:13px;color:var(--g900)">'+escapeHtml(hn)+'</div>'
          +'<div style="font-size:10.5px;color:var(--g500);margin-top:2px">PAT: '+escapeHtml(a.pat||'вҖ”')+' В· '+escapeHtml(a.tipo||'вҖ”')+'</div></div>'
          +'<span style="background:'+sm[2]+';color:'+sm[1]+';border:1px solid '+sm[1]+'44;font-size:10px;font-weight:700;padding:2px 8px;border-radius:10px;white-space:nowrap">'+escapeHtml(sm[0])+'</span>'
        +'</div>'
        +'<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;font-size:11.5px;margin-bottom:10px">'
          +'<div><span style="color:var(--g400)">AutorizaГ§ГЈo:</span> <span>'+escapeHtml(a.descarteAutorizadoPor||'вҖ”')+'</span></div>'
          +'<div><span style="color:var(--g400)">Data:</span> <span>'+escapeHtml(a.descarteData||'вҖ”')+'</span></div>'
          +'<div><span style="color:var(--g400)">Processo SAP:</span> <span style="font-family:monospace;font-weight:600">'+escapeHtml(a.descarteSAP||'вҖ”')+'</span></div>'
          +'<div><span style="color:var(--g400)">Local anterior:</span> <span>'+escapeHtml(resolverLocal(a)||'вҖ”')+'</span></div>'
        +'</div>'
        +(a.descarteObs?'<div style="font-size:11px;color:var(--g500);background:var(--g50);border-radius:6px;padding:6px 10px">'+escapeHtml(a.descarteObs)+'</div>':'')
      +'</div>'
      +'<div style="display:flex;border-top:0.5px solid var(--g100)">'
        +'<button data-aid="'+escapeHtml(a.id)+'" data-pat="'+escapeHtml(a.pat||'')+'" onclick="abrirLinhaDoTempo(this.dataset.aid,this.dataset.pat)" style="flex:1;border:none;background:none;padding:10px;font-size:11.5px;font-weight:600;color:var(--g500);cursor:pointer;border-right:0.5px solid var(--g100)">рҹ“Ӣ HistГіrico</button>'
        +(isAdmin()?'<button data-aid="'+escapeHtml(a.id)+'" onclick="abrirAtualizarDescarte(this.dataset.aid)" style="flex:1;border:none;background:none;padding:10px;font-size:11.5px;font-weight:600;color:var(--accent);cursor:pointer;border-right:0.5px solid var(--g100)">вңҸпёҸ Atualizar</button>':'')
        +'<button data-aid="'+escapeHtml(a.id)+'" data-pat="'+escapeHtml(a.pat||'')+'" onclick="abrirLinhaDoTempo(this.dataset.aid,this.dataset.pat)" style="flex:1;border:none;background:none;padding:10px;font-size:11.5px;font-weight:600;color:var(--danger);cursor:pointer">рҹ—‘пёҸ Ver Descarte</button>'
      +'</div>'
    +'</div>';
  }).join('');
}

function abrirEnviarDescarte(ativoId) {
  if (!isAdmin()) return showToast('Apenas administradores podem mover para descarte.','danger');
  var a = (STATE.ativos||[]).find(function(x){return x.id===ativoId;});
  if (!a) return;
  var modal = document.getElementById('modal-descarte');
  if (modal) { document.getElementById('desc-ativo-id').value = ativoId; document.getElementById('desc-pat').textContent = a.pat||a.id; openModal('modal-descarte'); }
}

async function salvarDescarte() {
  var ativoId = document.getElementById('desc-ativo-id').value;
  var modalidade = document.getElementById('desc-modalidade').value;
  var sap  = document.getElementById('desc-sap').value.trim();
  var obs  = document.getElementById('desc-obs').value.trim();
  if (!modalidade) return showToast('Selecione a modalidade de descarte','warning');
  var updates = { status:'descarte', substatusDescarte: modalidade, descarteSAP: sap, descarteObs: obs, descarteData: new Date().toISOString().split('T')[0], descarteAutorizadoPor: CURRENT_USER?.nome||'' };
  await fsUpdate('ativos', ativoId, updates);
  Object.assign((STATE.ativos||[]).find(function(a){return a.id===ativoId;})||{}, updates);
  await registrarHistoricoAtivo(ativoId,'descartado',{modalidade, sap, obs, por: CURRENT_USER?.nome||''});
  closeModal('modal-descarte');
  showToast('Ativo movido para descarte ('+modalidade+')','success');
  renderDescarte();
}

function abrirAtualizarDescarte(ativoId) {
  var novoSub = prompt('Novo subestatus: leilao | doacao | inutilizado | em-analise');
  if (!novoSub) return;
  var sap = prompt('NГәmero do processo SAP (opcional):');
  fsUpdate('ativos', ativoId, { substatusDescarte: novoSub, descarteSAP: sap||'' });
  var a = (STATE.ativos||[]).find(function(x){return x.id===ativoId;});
  if (a) { a.substatusDescarte = novoSub; if(sap) a.descarteSAP = sap; }
  showToast('Descarte atualizado','success');
  renderDescarte();
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// CARD: MINDWORKS (painel de controle SLA)
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
function renderMindworks() {
  var grid = document.getElementById('mindworks-grid');
  if (!grid) return;
  var q = (document.getElementById('mindworks-search')?.value||'').toLowerCase();

  var lista = (STATE.terceirizadaAtivos||[]).filter(function(t){return !t.retornado;});
  // Atualiza diasUteis em tempo real
  lista.forEach(function(t) {
    if (t.dataEnvio) t.diasUteis = contarDiasUteis(t.dataEnvio, new Date());
  });
  if (q) lista = lista.filter(function(t){return (t.pat+' '+(t.ativo||'')+(t.tecnicoId||'')).toLowerCase().includes(q);});

  lista.sort(function(a,b){return (b.diasUteis||0)-(a.diasUteis||0);}); // mais atrasados primeiro

  var sv = function(id,v){var el=document.getElementById(id);if(el)el.textContent=v;};
  var todos = lista;
  sv('mw-kpi-total',   todos.length);
  sv('mw-kpi-ok',      todos.filter(function(t){return(t.diasUteis||0)<=5;}).length);
  sv('mw-kpi-alerta',  todos.filter(function(t){return(t.diasUteis||0)>5&&(t.diasUteis||0)<=10;}).length);
  sv('mw-kpi-critico', todos.filter(function(t){return(t.diasUteis||0)>10;}).length);

  if (!lista.length) {
    grid.innerHTML = '<div style="grid-column:1/-1;text-align:center;padding:56px;color:var(--g400)"><div style="font-size:48px;margin-bottom:12px">рҹ”§</div><div style="font-size:15px;font-weight:600">Nenhuma mГЎquina com empresa terceirizada no momento</div></div>';
    return;
  }

  grid.innerHTML = lista.map(function(t) {
    var du = t.diasUteis||0;
    var cor = du>10?'#DC2626':du>5?'#D97706':'#059669';
    var bg  = du>10?'#FEF2F2':du>5?'#FFFBEB':'#F0FDF4';
    var pct = Math.min(Math.round(du/10*100),100);
    var venc = t.prazoRetorno ? new Date(t.prazoRetorno).toLocaleDateString('pt-BR') : 'вҖ”';
    var tecnico = (STATE.tecnicos||[]).find(function(tk){return tk.id===t.tecnicoId;});
    var tecNome = tecnico?tecnico.nome:(t.tecnicoId||'вҖ”');
    return '<div style="background:var(--panel,#fff);border:0.5px solid var(--line,#e2e8f0);border-radius:12px;overflow:hidden;border-left:4px solid '+cor+'">'
      +'<div style="background:linear-gradient(135deg,#0F172A,#1E293B);padding:14px 16px;display:flex;align-items:flex-start;justify-content:space-between">'
        +'<div><div style="font-family:monospace;font-weight:800;font-size:14px;color:#F1F5F9">'+escapeHtml(t.pat||t.ativo||'вҖ”')+'</div>'
        +'<div style="font-size:10.5px;color:#94A3B8;margin-top:2px">TГ©cnico: '+escapeHtml(tecNome)+'</div></div>'
        +'<div style="background:'+bg+';color:'+cor+';font-size:11px;font-weight:800;padding:4px 10px;border-radius:8px;text-align:center;flex-shrink:0;margin-left:8px">'
          +du+'<div style="font-size:9px;font-weight:600">dias Гәteis</div></div>'
      +'</div>'
      +'<div style="padding:14px 16px">'
        +'<div style="margin-bottom:10px"><div style="display:flex;justify-content:space-between;font-size:10.5px;color:var(--g500);margin-bottom:4px"><span>SLA (prazo: 10 dias Гәteis)</span><span style="font-weight:700;color:'+cor+'">'+pct+'%</span></div>'
          +'<div style="background:var(--g200);border-radius:4px;height:6px;overflow:hidden"><div style="background:'+cor+';width:'+pct+'%;height:100%;border-radius:4px;transition:width .3s"></div></div></div>'
        +'<div style="display:grid;grid-template-columns:1fr 1fr;gap:5px;font-size:11.5px">'
          +'<div><span style="color:var(--g400)">Enviado:</span> <span>'+escapeHtml(t.dataEnvio||'вҖ”')+'</span></div>'
          +'<div><span style="color:var(--g400)">Vence:</span> <span style="font-weight:600;color:'+cor+'">'+venc+'</span></div>'
          +'<div><span style="color:var(--g400)">Chamado:</span> <span style="font-family:monospace">'+escapeHtml(t.chamadoId||'вҖ”')+'</span></div>'
          +'<div><span style="color:var(--g400)">Status:</span> <span>'+escapeHtml(t.status||'aguardando')+'</span></div>'
        +'</div>'
        +(du>10?'<div style="margin-top:10px;background:#FEF2F2;border-radius:8px;padding:8px 12px;font-size:11.5px;color:#DC2626;font-weight:600">вҡ пёҸ SLA vencido hГЎ '+(du-10)+' dias Гәteis вҖ” escalaГ§ГЈo ativada</div>':'')
        +(du>5&&du<=10?'<div style="margin-top:10px;background:#FFFBEB;border-radius:8px;padding:8px 12px;font-size:11.5px;color:#D97706;font-weight:600">вҸ° Faltam '+(10-du)+' dias Гәteis para o prazo</div>':'')
      +'</div>'
      +'<div style="display:flex;border-top:0.5px solid var(--g100)">'
        +'<button data-tid="'+escapeHtml(t.id)+'" onclick="marcarRetornoMindworks(this.dataset.tid)" style="flex:1;border:none;background:none;padding:10px;font-size:11.5px;font-weight:600;color:#059669;cursor:pointer;border-right:0.5px solid var(--g100)">вң… Marcar Retorno</button>'
        +'<button onclick="openModal(\'modal-novo-chamado\')" style="flex:1;border:none;background:none;padding:10px;font-size:11.5px;font-weight:600;color:var(--g500);cursor:pointer">рҹҺ« Chamado</button>'
      +'</div>'
    +'</div>';
  }).join('');
}

async function marcarRetornoMindworks(tercId) {
  var t = (STATE.terceirizadaAtivos||[]).find(function(x){return x.id===tercId;});
  if (!t) return;
  var confirm_ = window.confirm('Confirmar retorno de '+t.pat+' da empresa terceirizada?\n\nApГіs isso, o tГ©cnico A-DSI deverГЎ confirmar o recebimento fГӯsico.');
  if (!confirm_) return;
  var updates = { status:'retornando', dataMarcouRetorno: new Date().toISOString(), marcouRetornoPor: CURRENT_USER?.nome||'' };
  await fsUpdate('terceirizadaAtivos', tercId, updates);
  Object.assign(t, updates);
  showToast('Retorno marcado вҖ” aguardando confirmaГ§ГЈo do tГ©cnico A-DSI','info',5000);
  renderMindworks();
}

async function confirmarRecebimentoADSI(tercId) {
  var t = (STATE.terceirizadaAtivos||[]).find(function(x){return x.id===tercId;});
  if (!t) return;
  var updates = { retornado:true, dataRetorno: new Date().toISOString(), recebidoPor: CURRENT_USER?.nome||'' };
  await fsUpdate('terceirizadaAtivos', tercId, updates);
  Object.assign(t, updates);
  // Registra histГіrico no ativo
  var ativo = (STATE.ativos||[]).find(function(a){return a.pat===t.pat;});
  if (ativo) {
    await registrarHistoricoAtivo(ativo.id,'retornou',{de:'Mindworks',tecnicoMW:t.tecnicoId||'вҖ”',recebidoPor:CURRENT_USER?.nome||'вҖ”',diasUteis:t.diasUteis||0});
    // Abre decisГЈo pГіs-retorno
    abrirDecisaoPosRetorno(ativo.id, t.pat);
  }
  showToast('Recebimento confirmado вҖ” escolha o destino da mГЎquina','success',5000);
  renderMindworks();
}

function abrirDecisaoPosRetorno(ativoId, pat) {
  var modal = document.getElementById('modal-pos-retorno');
  if (!modal) return;
  document.getElementById('pr-ativo-id').value  = ativoId;
  document.getElementById('pr-ativo-pat').textContent = pat;
  openModal('modal-pos-retorno');
}

async function salvarDecisaoPosRetorno() {
  var ativoId = document.getElementById('pr-ativo-id').value;
  var destino = document.getElementById('pr-destino').value;
  var local   = document.getElementById('pr-local').value.trim();
  var renomear = document.getElementById('pr-renomear').checked;
  var novoNome = document.getElementById('pr-novo-nome').value.trim();
  var tipoUso  = document.getElementById('pr-tipo-uso').value;
  if (!destino) return showToast('Selecione o destino da mГЎquina','warning');
  if (destino==='reutilizar'&&!local) return showToast('Informe a nova localidade','warning');
  if (destino==='santa-clara'&&!local) return showToast('Informe a localizaГ§ГЈo em Santa Clara','warning');
  var newStatus = destino==='santa-clara'?'santa-clara':(tipoUso==='estoque'?'estoque':'em-uso');
  var updates = { status:newStatus, local:local||'' };
  if (renomear&&novoNome) updates.hostname = novoNome;
  if (tipoUso) updates.tipoUso = tipoUso;
  if (destino==='santa-clara') { updates.scLocal = local; updates.dataEntradaSC = new Date().toISOString().split('T')[0]; }
  if (destino==='reutilizar'&&newStatus==='estoque') updates.dataEstoque = new Date().toISOString().split('T')[0];
  await fsUpdate('ativos', ativoId, updates);
  Object.assign((STATE.ativos||[]).find(function(a){return a.id===ativoId;})||{}, updates);
  await registrarHistoricoAtivo(ativoId,
    destino==='santa-clara'?'santa-clara':'reutilizado',
    {destino, local, novoNome:novoNome||'вҖ”', tipoUso:tipoUso||'вҖ”', por:CURRENT_USER?.nome||'вҖ”'});
  closeModal('modal-pos-retorno');
  showToast('MГЎquina direcionada: '+destino,'success',4000);
  if (destino==='santa-clara') renderSantaClara(); else renderReuso();
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// MOTOR DE EVENTOS (Event Engine)
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
var _motorEventosTimer = null;

function iniciarMotorEventos() {
  if (_motorEventosTimer) clearInterval(_motorEventosTimer);
  _motorEventosTimer = setInterval(detectarEventos, 5 * 60 * 1000); // a cada 5 min
  detectarEventos(); // roda imediatamente ao carregar
}

async function detectarEventos() {
  var ativos = STATE.ativos||[];
  var agora  = new Date();
  var alertas = [];

  ativos.forEach(function(a) {
    if (!a.id) return;
    var hn  = a.hostname||a.sysName||'';
    var status = (a.status||'').toLowerCase();

    // 1. MГЎquina offline > 5 dias
    if (a.lastSeen) {
      var ls = new Date(a.lastSeen.seconds?a.lastSeen.seconds*1000:a.lastSeen);
      var diffDias = Math.floor((agora-ls)/(1000*60*60*24));
      if (diffDias > 5 && status==='em-uso') {
        alertas.push({tipo:'offline',ativo:a,diffDias,msg:hn+' estГЎ offline hГЎ '+diffDias+' dias'});
      }
    }

    // 2. IP mudou vs cadastrado
    if (a.ip && a.ipAnterior && a.ip !== a.ipAnterior) {
      alertas.push({tipo:'ip-mudou',ativo:a,msg:hn+': IP mudou de '+a.ipAnterior+' para '+a.ip});
    }

    // 3. Hostname mudou
    if (a.hostname && a.hostnameAnterior && a.hostname !== a.hostnameAnterior) {
      alertas.push({tipo:'hostname-mudou',ativo:a,msg:hn+': hostname mudou de '+a.hostnameAnterior+' para '+a.hostname});
    }

    // 4. Ativo sem PAT
    if (!a.pat && status==='em-uso') {
      alertas.push({tipo:'sem-pat',ativo:a,msg:(hn||a.ip||a.id)+' nГЈo tem nГәmero patrimonial'});
    }
  });

  // 5. SLA Mindworks
  (STATE.terceirizadaAtivos||[]).filter(function(t){return !t.retornado;}).forEach(function(t) {
    var du = contarDiasUteis(t.dataEnvio, agora);
    t.diasUteis = du;
    if (du === 5) alertas.push({tipo:'sla-d5',ativo:t,msg:'[SLA D-5] '+t.pat+' вҖ” faltam 5 dias Гәteis para retorno da Mindworks'});
    if (du > 10)  alertas.push({tipo:'sla-vencido',ativo:t,urgente:true,msg:'[SLA VENCIDO] '+t.pat+' вҖ” '+du+' dias Гәteis sem retorno da Mindworks'});
  });

  // 6. AprovaГ§Гөes pendentes > 24h
  (STATE.aprovacoes||[]).filter(function(a){return a.status==='pendente';}).forEach(function(ap) {
    var criado = new Date(ap.createdAt||0);
    var diffH  = Math.floor((agora-criado)/3600000);
    if (diffH > 24) alertas.push({tipo:'aprov-pendente',ativo:ap,urgente:diffH>48,msg:'AprovaГ§ГЈo pendente hГЎ '+diffH+'h: '+ap.descricao});
  });

  // Registra alertas novos no STATE e exibe badge
  if (alertas.length) {
    STATE.alertasEventos = alertas;
    nbUpdate('nb-alertas-eventos', alertas.length);
    // Mostra alerta bloqueante para itens urgentes
    var urgentes = alertas.filter(function(a){return a.urgente;});
    if (urgentes.length && isPageActive('dashboard')) {
      showToast(urgentes[0].msg, 'danger', 8000);
    }
    // Atualiza painel se estiver aberto
    if (isPageActive('alertas')) renderAlertas();
  } else {
    STATE.alertasEventos = [];
    nbUpdate('nb-alertas-eventos', 0);
  }
}

// в”Җв”Җ Renderiza painel de alertas do motor de eventos в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
var _renderAletasOriginal = typeof renderAlertas === 'function' ? renderAlertas : null;
function renderAlertas() {
  if (_renderAletasOriginal) _renderAletasOriginal();
  var panel = document.getElementById('eventos-alertas-grid');
  if (!panel) return;
  var alertas = STATE.alertasEventos||[];
  if (!alertas.length) {
    panel.innerHTML = '<div style="text-align:center;padding:40px;color:var(--g400)"><div style="font-size:40px;margin-bottom:8px">вң…</div><div style="font-weight:600">Nenhum evento detectado</div></div>';
    return;
  }
  var corMap = {'offline':'#DC2626','ip-mudou':'#D97706','hostname-mudou':'#D97706','sem-pat':'#D97706','sla-d5':'#D97706','sla-vencido':'#DC2626','aprov-pendente':'#2563EB'};
  panel.innerHTML = alertas.map(function(al) {
    var cor = corMap[al.tipo]||'#64748B';
    return '<div style="background:var(--panel,#fff);border:0.5px solid var(--line);border-radius:10px;padding:14px 16px;border-left:4px solid '+cor+';display:flex;align-items:center;gap:12px">'
      +'<div style="flex:1"><div style="font-size:12.5px;font-weight:700;color:var(--g900)">'+escapeHtml(al.msg)+'</div>'
      +'<div style="font-size:10.5px;color:var(--g400);margin-top:3px">'+escapeHtml(al.tipo.replace(/-/g,' ').toUpperCase())+(al.urgente?' В· вҡ пёҸ URGENTE':'')+'</div></div>'
      +(al.urgente?'<span style="background:#FEF2F2;color:#DC2626;font-size:10px;font-weight:700;padding:2px 8px;border-radius:8px;flex-shrink:0">CRГҚTICO</span>':'')
    +'</div>';
  }).join('');
}

