function resolverLocal(sw){
  if(sw.local&&sw.local!=='undefined'&&sw.local!=='вҖ”'&&sw.local!=='')return sw.local;
  if(sw.area&&sw.area!=='undefined'&&sw.area!=='вҖ”'&&sw.area!=='')return sw.area;
  if(sw.ip){var pts=sw.ip.split('.');var p24=pts.slice(0,3).join('.');if(REDES_PREFIX[p24])return REDES_PREFIX[p24].nome;}
  if(sw.hostname||sw.sysName){var hn=(sw.hostname||sw.sysName||'').toUpperCase();var m=hn.match(/^([A-Z]{2,4})-/);if(m){var s=m[1].toLowerCase();if(REDES_SIGLA[s])return REDES_SIGLA[s];}}
  return 'вҖ”';
}

// в”Җв”Җ renderSwitches в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function renderSwitches(){
  var sws=STATE.switches||[];
  var q=(document.getElementById('sw-search-input')?.value||'').toLowerCase();
  var fSt=document.getElementById('sw-filter-status')?.value||'';
  var fTp=document.getElementById('sw-filter-tipo')?.value||'';
  var fLo=document.getElementById('sw-filter-local')?.value||'';
  var lista=sws.filter(function(s){var t=(s.tipo||'').toLowerCase();if(t==='firewall'||t==='impressora'||t==='printer')return false;if(fSt&&(s.status||'')!==fSt)return false;if(fTp&&t!==fTp)return false;if(fLo&&!resolverLocal(s).toLowerCase().includes(fLo.toLowerCase()))return false;if(q&&!((s.ip||'')+' '+(s.hostname||'')+' '+(s.sysName||'')+' '+resolverLocal(s)).toLowerCase().includes(q))return false;return true;});
  var total=sws.filter(function(s){var t=(s.tipo||'').toLowerCase();return t!=='firewall'&&t!=='impressora'&&t!=='printer';});
  var sv=function(id,v){var el=document.getElementById(id);if(el)el.textContent=v;};
  sv('sw-total',total.length);sv('sw-online',total.filter(function(s){return s.reachable||(s.status||'')==='online';}).length);sv('sw-offline',total.filter(function(s){return(s.status||'')==='offline';}).length);sv('sw-alertas',total.filter(function(s){return(s.status||'')==='alerta'||(s.status||'')==='critico';}).length);sv('sw-portas-total',total.reduce(function(a,s){return a+(s.totalPortas||0);},0));sv('sw-portas-uso',total.reduce(function(a,s){return a+(s.portasUso||0);},0));
  var cont=document.getElementById('sw-cards-grid')||document.getElementById('sw-grid');if(!cont)return;
  if(!lista.length){cont.innerHTML='<div style="grid-column:1/-1;text-align:center;padding:48px;color:var(--g400)"><div style="font-size:40px">рҹ”Җ</div><div style="font-weight:600;margin-top:8px">Nenhum dispositivo encontrado</div></div>';return;}
  cont.innerHTML=lista.map(function(s){
    var t=(s.tipo||'switch').toLowerCase(),bg={switch:'#2563EB',router:'#EA580C',ap:'#0891B2','switch-core':'#0F172A','switch-acesso':'#1D4ED8'}[t]||'#64748B',ico={switch:'рҹ”Җ',router:'рҹҢҗ',ap:'рҹ“Ў','switch-core':'рҹ”Җ'}[t]||'рҹ”Ң';
    var online=s.reachable||(s.status||'')==='online'||(s.status||'')==='ativo',sc=online?'#059669':(s.status||'')==='offline'?'#6B7280':(s.status||'')==='critico'?'#DC2626':'#D97706',sl=online?'Online':((s.status||'?').charAt(0).toUpperCase()+(s.status||'?').slice(1));
    var hn=s.hostname||s.sysName||s.ip||'вҖ”',mm=[s.marca,s.modelo].filter(function(v){return v&&v!=='undefined';}).join(' ')||(s.sysDescr?s.sysDescr.split(',')[0].trim().slice(0,40):'вҖ”');
    var loc=resolverLocal(s),up=s.uptimeH!=null?(s.uptimeH>=24?Math.floor(s.uptimeH/24)+'d '+Math.round(s.uptimeH%24)+'h':Math.round(s.uptimeH)+'h'):(s.uptime||'вҖ”');
    var pct=s.totalPortas?Math.round((s.portasUso||0)/s.totalPortas*100):0,pl=s.totalPortas&&s.totalPortas!=='undefined'?(s.portasUso||0)+'/'+s.totalPortas:'вҖ”';
    var lat='вҖ”';if(s.latencyMs!=null){var lc=s.latencyMs>20?'#DC2626':s.latencyMs>5?'#D97706':'#059669';lat='<div style="display:flex;align-items:center;gap:6px"><div style="flex:1;background:var(--g200);border-radius:3px;height:4px;overflow:hidden"><div style="background:'+lc+';width:'+Math.min(Math.round(s.latencyMs/50*100),100)+'%;height:100%;border-radius:3px"></div></div><span style="font-size:11px;color:var(--g500)">'+s.latencyMs.toFixed(1)+'ms</span></div>';}
    var pb='';if(s.totalPortas&&t!=='ap'&&t!=='firewall'){var pc=pct>85?'#DC2626':pct>70?'#D97706':'#059669';pb='<div style="margin-top:8px"><div style="display:flex;justify-content:space-between;font-size:10.5px;color:var(--g500);margin-bottom:3px"><span>Portas: '+pl+'</span><span>'+pct+'%</span></div><div style="background:var(--g200);border-radius:4px;height:5px;overflow:hidden"><div style="background:'+pc+';width:'+pct+'%;height:100%;border-radius:4px"></div></div></div>';}
    return '<div style="background:var(--panel,#fff);border:0.5px solid var(--line,#e2e8f0);border-radius:12px;overflow:hidden"><div style="background:linear-gradient(135deg,#0F172A,#1E293B);border-radius:10px 10px 0 0;padding:12px 14px;display:flex;align-items:center;gap:10px"><div style="width:36px;height:36px;border-radius:8px;background:'+bg+';display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0">'+ico+'</div><div style="flex:1;min-width:0"><div style="font-weight:700;font-size:13px;font-family:monospace;color:#F1F5F9;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+escapeHtml(hn)+'</div><div style="font-size:10.5px;color:#94A3B8;margin-top:1px">'+escapeHtml(mm)+'</div></div><span style="background:'+sc+'22;color:'+sc+';border:1px solid '+sc+'44;font-size:10px;font-weight:700;padding:2px 7px;border-radius:10px;flex-shrink:0">'+sl+'</span></div><div style="padding:12px 14px"><div style="display:grid;grid-template-columns:1fr 1fr;gap:5px;font-size:11.5px;margin-bottom:10px"><div><span style="color:var(--g400)">IP</span> <span style="font-family:monospace;font-weight:600">'+escapeHtml(s.ip||'вҖ”')+'</span></div><div><span style="color:var(--g400)">Local</span> <span style="font-weight:600">'+escapeHtml(loc)+'</span></div><div><span style="color:var(--g400)">Uptime</span> <span style="font-weight:600">'+escapeHtml(String(up))+'</span></div><div><span style="color:var(--g400)">Tipo</span> <span>'+escapeHtml(t)+'</span></div></div><div style="margin-bottom:8px"><div style="display:flex;justify-content:space-between;font-size:10.5px;color:var(--g500);margin-bottom:3px"><span>LatГӘncia</span>'+(s.hasSnmp?'<span style="background:#EFF6FF;color:#2563EB;font-size:9px;padding:1px 5px;border-radius:8px">SNMP</span>':'')+'</div>'+lat+'</div>'+pb+'</div><div style="display:flex;border-top:0.5px solid var(--g100)"><button data-sid="'+escapeHtml(s.id)+'" onclick="abrirGerenciarSwitch(this.dataset.sid)" style="flex:1;border:none;background:none;padding:8px;font-size:11px;font-weight:600;color:var(--g500);cursor:pointer;border-right:0.5px solid var(--g100)">Gerenciar</button><button data-sid="'+escapeHtml(s.id)+'" onclick="abrirHistSwitch(this.dataset.sid)" style="flex:1;border:none;background:none;padding:8px;font-size:11px;font-weight:600;color:var(--g500);cursor:pointer;border-right:0.5px solid var(--g100)">Historico</button><button data-sid="'+escapeHtml(s.id)+'" onclick="swActionDirect(&quot;ping&quot;,this.dataset.sid)" style="flex:1;border:none;background:none;padding:8px;font-size:11px;font-weight:600;color:var(--g500);cursor:pointer;border-right:0.5px solid var(--g100)">Ping</button><button data-sid="'+escapeHtml(s.id)+'" onclick="swActionDirect(&quot;ssh&quot;,this.dataset.sid)" style="flex:1;border:none;background:none;padding:8px;font-size:11px;font-weight:600;color:var(--g500);cursor:pointer">SSH</button></div></div>';
  }).join('');
}
function _sn(a){var cs=[a.hostname,a.sysName,a.nome,a.desc,a.name,a.pat];for(var i=0;i<cs.length;i++){var s=(cs[i]||'').trim();if(s&&s!==a.ip&&s.length>2)return s;}return '';}
function isVirtualServidor(a){return /vserv|vmserver|vm-/i.test(_sn(a))||(a.tipo||'').toLowerCase()==='server-linux';}
function isFisicoServidor(a){var h=_sn(a),t=(a.tipo||'').toLowerCase();return(/serv/i.test(h)&&!isVirtualServidor(a))||(t==='servidor'&&!isVirtualServidor(a));}
function isServidor(a){return /serv/i.test(_sn(a))||(a.tipo||'').toLowerCase()==='servidor'||(a.tipo||'').toLowerCase()==='server-linux';}
var _srvTab='todos';
function srvTab(tab,el){_srvTab=tab;document.querySelectorAll('.srv-tab-btn').forEach(function(b){b.style.background='transparent';b.style.color='var(--g500)';b.style.boxShadow='none';});if(el){el.style.background='#fff';el.style.color='var(--g900)';el.style.boxShadow='0 1px 3px rgba(0,0,0,.1)';}renderServidores();}
function renderServidores(filtroKpi) {
  // filtroKpi: 'online' | 'offline' | undefined (todos)
  if (filtroKpi !== undefined) window._srvFiltroKpi = filtroKpi;
  var fKpi  = window._srvFiltroKpi || '';
  var q     = (document.getElementById('srv-search')?.value||'').toLowerCase();
  var fSt   = document.getElementById('srv-filter-status')?.value || fKpi || '';

  var todos = (STATE.ativos||[]).filter(isServidor);
  var lista = todos.slice();
  if (_srvTab==='fisico')   lista = lista.filter(isFisicoServidor);
  if (_srvTab==='virtual')  lista = lista.filter(isVirtualServidor);
  if (fSt === 'online')     lista = lista.filter(function(a){return a.reachable||(a.status||'')==='ok'||(a.status||'').toLowerCase()==='online'||(a.status||'').toLowerCase()==='ativo';});
  if (fSt === 'offline')    lista = lista.filter(function(a){return !a.reachable&&(a.status||'').toLowerCase()==='offline';});
  if (q) lista = lista.filter(function(a){return ['hostname','ip','desc','area','pat','osNome','sysDescr'].some(function(f){return (a[f]||'').toLowerCase().includes(q);});});

  var sv = function(id,v){var el=document.getElementById(id);if(el)el.textContent=v;};
  var onlineCount  = todos.filter(function(a){return a.reachable||(a.status||'')==='ok'||(a.status||'').toLowerCase()==='online'||(a.status||'').toLowerCase()==='ativo';}).length;
  var offlineCount = todos.filter(function(a){return !a.reachable&&(a.status||'').toLowerCase()==='offline';}).length;
  sv('srv-kpi-total',   todos.length);
  sv('srv-kpi-fisicos', todos.filter(isFisicoServidor).length);
  sv('srv-kpi-virtuais',todos.filter(isVirtualServidor).length);
  sv('srv-kpi-online',  onlineCount);
  sv('srv-kpi-offline', offlineCount);

  // Highlight KPI clicado
  ['srv-kpi-total-card','srv-kpi-fisicos-card','srv-kpi-virtuais-card','srv-kpi-online-card','srv-kpi-offline-card'].forEach(function(id){
    var el=document.getElementById(id);if(el)el.style.outline='none';
  });
  if (fSt==='online')  { var el=document.getElementById('srv-kpi-online-card');  if(el)el.style.outline='2px solid var(--success)'; }
  if (fSt==='offline') { var el=document.getElementById('srv-kpi-offline-card'); if(el)el.style.outline='2px solid var(--danger)'; }
  if (_srvTab==='fisico')  { var el=document.getElementById('srv-kpi-fisicos-card');  if(el)el.style.outline='2px solid #2563EB'; }
  if (_srvTab==='virtual') { var el=document.getElementById('srv-kpi-virtuais-card'); if(el)el.style.outline='2px solid #7C3AED'; }

  var grid = document.getElementById('srv-grid'); if(!grid) return;

  if (!lista.length) {
    grid.innerHTML = '<div style="grid-column:1/-1;text-align:center;padding:56px;color:var(--g400)"><div style="font-size:48px">рҹ–ҘпёҸ</div><div style="font-weight:600;margin-top:8px">Nenhum servidor encontrado</div>'
      + (fSt?'<div style="margin-top:8px"><button onclick="renderServidores(\'\')" class="btn btn-secondary btn-sm">Ver todos</button></div>':'')
      + '</div>';
    return;
  }

  lista.sort(function(a,b){
    var ord={offline:0,critico:1,alerta:2,online:3,ok:3,ativo:4};
    return (ord[(a.status||'').toLowerCase()]??5) - (ord[(b.status||'').toLowerCase()]??5)
        || (_sn(a)||'').localeCompare(_sn(b)||'');
  });

  function mb(l,v,d,w){
    if(v==null||v===undefined)return '';
    var co=v>=d?'#DC2626':v>=w?'#D97706':'#059669';
    return '<div style="margin-bottom:5px"><div style="display:flex;justify-content:space-between;font-size:10.5px;color:var(--g500);margin-bottom:2px"><span>'+l+'</span><span style="color:'+co+';font-weight:700">'+Math.round(v)+'%</span></div><div style="background:var(--g200);border-radius:3px;height:4px"><div style="background:'+co+';width:'+Math.min(Math.round(v),100)+'%;height:100%;border-radius:3px"></div></div></div>';
  }

  grid.innerHTML = lista.map(function(a) {
    var hn = _sn(a) || a.ip || 'вҖ”';
    var iv = isVirtualServidor(a), tc = iv?'#7C3AED':'#2563EB';
    var st = (a.status||'').toLowerCase();
    var online = a.reachable || st==='ok' || st==='online' || st==='ativo';
    var sc = online?'#059669':st==='critico'?'#DC2626':st==='offline'?'#6B7280':'#D97706';
    var slabel = online ? 'Online' : (st.charAt(0).toUpperCase()+st.slice(1)||'Offline');

    // uptimeH (discover) ou uptimeHoras (agente) вҖ” aceita ambos
    var uptimeH = a.uptimeH != null ? a.uptimeH : (a.uptimeHoras != null ? a.uptimeHoras : null);
    var upStr   = uptimeH != null
      ? (uptimeH >= 24 ? Math.floor(uptimeH/24)+'d '+Math.round(uptimeH%24)+'h' : Math.round(uptimeH)+'h')
      : 'вҖ”';

    // latГӘncia (discover salva latencyMs)
    var latStr = a.latencyMs != null
      ? '<span style="font-size:11px;color:var(--g500)">'+a.latencyMs.toFixed(1)+'ms latГӘncia</span>'
      : '';

    // CPU/RAM do agente Windows
    var metricas = (a.cpuPct!=null||a.memPct!=null)
      ? mb('CPU',a.cpuPct,90,70) + mb('RAM',a.memPct,90,80)
      : '<div style="font-size:11px;color:var(--g400);margin-bottom:10px">Agente nГЈo instalado В· descoberto via SNMP/ping</div>';

    // OS: prefer osNome (agente) вҶ’ sysDescr (SNMP)
    var osStr = a.osNome || (a.sysDescr ? a.sysDescr.split(',')[0].trim().slice(0,40) : 'вҖ”');
    var local  = resolverLocal(a);

    return '<div style="background:var(--panel,#fff);border:0.5px solid var(--line,#e2e8f0);border-radius:12px;overflow:hidden;border-left:4px solid '+tc+'">'
      +'<div style="background:linear-gradient(135deg,#0F172A,#1E293B);padding:14px 16px;display:flex;align-items:flex-start;justify-content:space-between">'
        +'<div style="display:flex;gap:10px;min-width:0">'
          +'<span style="font-size:22px;flex-shrink:0">'+(iv?'вҳҒпёҸ':'рҹ–ҘпёҸ')+'</span>'
          +'<div style="min-width:0">'
            +'<div style="font-family:monospace;font-size:13px;font-weight:800;color:#F1F5F9;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+escapeHtml(hn)+'</div>'
            +'<div style="font-size:10.5px;color:#94A3B8;margin-top:2px">'+escapeHtml(a.ip||'вҖ”')+' В· '+escapeHtml(local)+'</div>'
          +'</div>'
        +'</div>'
        +'<div style="display:flex;flex-direction:column;gap:4px;align-items:flex-end;flex-shrink:0;margin-left:8px">'
          +'<span style="background:'+sc+'22;color:'+sc+';border:1px solid '+sc+'44;font-size:10px;font-weight:700;padding:2px 8px;border-radius:10px">'+slabel+'</span>'
          +'<span style="background:'+tc+'22;color:'+tc+';font-size:10px;font-weight:600;padding:1px 6px;border-radius:8px">'+(iv?'Virtual':'FГӯsico')+'</span>'
        +'</div>'
      +'</div>'
      +'<div style="padding:14px 16px">'
        + metricas
        +'<div style="display:grid;grid-template-columns:1fr 1fr;gap:5px;font-size:11.5px;margin-top:4px">'
          +'<div><span style="color:var(--g400)">OS:</span> <span>'+escapeHtml(osStr.slice(0,28))+'</span></div>'
          +'<div><span style="color:var(--g400)">Uptime:</span> <span style="font-weight:600">'+upStr+'</span></div>'
          +(a.cpuModelo?'<div><span style="color:var(--g400)">CPU:</span> <span>'+escapeHtml(a.cpuModelo.slice(0,22))+'</span></div>':'')
          +(latStr?'<div>'+latStr+'</div>':'')
          +(a.hasSnmp?'<div><span style="background:#EFF6FF;color:#2563EB;font-size:9px;padding:1px 5px;border-radius:6px;font-weight:700">SNMP вң“</span></div>':'')
        +'</div>'
      +'</div>'
      +'<div style="display:flex;border-top:0.5px solid var(--g100)">'
        +'<button data-aid="'+escapeHtml(a.id)+'" data-pat="'+escapeHtml(a.pat||'')+'" onclick="abrirLinhaDoTempo(this.dataset.aid,this.dataset.pat)" style="flex:1;border:none;background:none;padding:9px;font-size:11.5px;font-weight:600;color:var(--g500);cursor:pointer;border-right:0.5px solid var(--g100)">рҹ“Ӣ HistГіrico</button>'
        +'<button onclick="openModal(\'modal-novo-chamado\')" style="flex:1;border:none;background:none;padding:9px;font-size:11.5px;font-weight:600;color:var(--g500);cursor:pointer;border-right:0.5px solid var(--g100)">рҹҺ« Chamado</button>'
        +'<button data-ip="'+escapeHtml(a.ip||'')+'" data-aid="'+escapeHtml(a.id)+'" onclick="pingAtivo(this.dataset.ip,this.dataset.aid)" style="flex:1;border:none;background:none;padding:9px;font-size:11.5px;font-weight:600;color:var(--g500);cursor:pointer">рҹ“¶ Ping</button>'
      +'</div>'
    +'</div>';
  }).join('');
  // actualiza grГЎfico
  if (typeof renderSrvCharts === 'function') renderSrvCharts();
}

// в”Җв”Җ GrГЎfico de servidores (barras inline SVG) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function renderSrvCharts() {
  var todos   = (STATE.ativos||[]).filter(isServidor);
  if (!todos.length) return;

  var onlineN  = todos.filter(function(a){return a.reachable||(a.status||'')==='ok'||(a.status||'').toLowerCase()==='online'||(a.status||'').toLowerCase()==='ativo';}).length;
  var offlineN = todos.length - onlineN;
  var fisicoN  = todos.filter(isFisicoServidor).length;
  var virtualN = todos.filter(isVirtualServidor).length;

  function bar(label, val, total, color, onclick_) {
    var pct = total ? Math.round(val/total*100) : 0;
    return '<div style="display:flex;align-items:center;gap:10px;cursor:'+(onclick_?'pointer':'default')+'" '+(onclick_?'onclick="'+onclick_+'"':'')+' title="'+label+': '+val+'">'
      +'<div style="width:90px;font-size:11.5px;color:var(--g600);text-align:right;flex-shrink:0">'+escapeHtml(label)+'</div>'
      +'<div style="flex:1;background:var(--g100);border-radius:4px;height:18px;overflow:hidden;position:relative">'
        +'<div style="background:'+color+';width:'+pct+'%;height:100%;border-radius:4px;transition:width .4s ease"></div>'
      +'</div>'
      +'<div style="width:48px;font-size:12px;font-weight:700;color:'+color+';flex-shrink:0">'+val+' <span style="font-weight:400;color:var(--g400);font-size:10px">('+pct+'%)</span></div>'
    +'</div>';
  }

  var statusEl = document.getElementById('srv-chart-status');
  if (statusEl) {
    statusEl.innerHTML = bar('Online', onlineN, todos.length, '#059669', "window._srvFiltroKpi='online';document.getElementById('srv-filter-status').value='online';renderServidores()")
      + bar('Offline', offlineN, todos.length, '#DC2626', "window._srvFiltroKpi='offline';document.getElementById('srv-filter-status').value='offline';renderServidores()");
  }

  var tipoEl = document.getElementById('srv-chart-tipo');
  if (tipoEl) {
    tipoEl.innerHTML = bar('Virtuais', virtualN, todos.length, '#7C3AED', "srvTab('virtual',document.querySelector('.srv-tab-btn:nth-child(3)'));renderServidores()")
      + bar('FГӯsicos', fisicoN, todos.length, '#2563EB', "srvTab('fisico',document.querySelector('.srv-tab-btn:nth-child(2)'));renderServidores()");
  }
}

function getFirewalls(){
  function isFw(s){
    var t    = (s.tipo||'').toLowerCase();
    var desc = (s.sysDescr||s.desc||'').toLowerCase();
    var oid  = (s.sysOid||'').toLowerCase();
    var hn   = (s.hostname||s.sysName||s.name||'').toLowerCase();
    return t==='firewall'
      || oid.includes('1.3.6.1.4.1.12356.')   // Fortinet
      || oid.includes('1.3.6.1.4.1.25461.')   // Palo Alto
      || oid.includes('1.3.6.1.4.1.2620.')    // Check Point
      || oid.includes('1.3.6.1.4.1.3076.')    // Cisco ASA
      || desc.includes('fortigate')
      || desc.includes('fortinet')
      || desc.includes('pfsense')
      || desc.includes('opnsense')
      || desc.includes('firewall')
      || desc.includes('cisco asa')
      || /^fw-|^fwl-|-fw\d|-fwl\d|firewall|-fw$/.test(hn);
  }
  var visto = new Set();
  var lista = [];
  // Fonte principal: coleГ§ГЈo 'firewalls'
  // Fallback: switches e ativos (dados legados ainda nГЈo migrados)
  [...(STATE.firewallsDisc||[]),
   ...(STATE.switches||[]),
   ...(STATE.ativos||[]),
  ].forEach(function(s){
    var key = s.ip||s.hostname||s.id||'';
    if(isFw(s) && key && !visto.has(key)){ visto.add(key); lista.push(s); }
  });
  return lista;
}
function renderFirewalls(){var q=(document.getElementById('fw-search')?.value||'').toLowerCase(),fSt=document.getElementById('fw-filter-status')?.value||'';var todos=getFirewalls(),lista=todos.filter(function(f){return(!fSt||(f.status||'').toLowerCase()===fSt)&&(!q||(f.hostname||f.sysName||f.ip||'').toLowerCase().includes(q));});var sv=function(id,v){var el=document.getElementById(id);if(el)el.textContent=v;};sv('fw-kpi-total',todos.length);sv('fw-kpi-online',todos.filter(function(f){return f.reachable||(f.status||'').toLowerCase()==='online';}).length);sv('fw-kpi-offline',todos.filter(function(f){return(f.status||'').toLowerCase()==='offline';}).length);sv('fw-kpi-sem-snmp',todos.filter(function(f){return!f.hasSnmp;}).length);var grid=document.getElementById('fw-grid');if(!grid)return;if(!lista.length){grid.innerHTML='<div style="grid-column:1/-1;text-align:center;padding:56px;color:var(--g400)"><div style="font-size:40px">рҹ”Ҙ</div><div style="font-weight:600;margin-top:8px">Nenhum firewall detectado</div></div>';return;}grid.innerHTML=lista.map(function(f){var hn=f.hostname||f.sysName||f.ip||'вҖ”',st=(f.status||'?').toLowerCase(),online=f.reachable||st==='online'||st==='ativo',sc=online?'#059669':st==='alerta'?'#D97706':st==='offline'?'#DC2626':'#6B7280';var lat='вҖ”';if(f.latencyMs!=null){var lc=f.latencyMs>20?'#DC2626':f.latencyMs>5?'#D97706':'#059669';lat='<div style="display:flex;align-items:center;gap:6px"><div style="flex:1;background:var(--g200);border-radius:3px;height:4px;overflow:hidden"><div style="background:'+lc+';width:'+Math.min(Math.round(f.latencyMs/50*100),100)+'%;height:100%;border-radius:3px"></div></div><span style="font-size:11px;color:var(--g500)">'+f.latencyMs.toFixed(1)+'ms</span></div>';}var up=f.uptimeH!=null?(f.uptimeH>=24?Math.floor(f.uptimeH/24)+'d '+Math.round(f.uptimeH%24)+'h':Math.round(f.uptimeH)+'h'):'вҖ”';return '<div style="background:var(--panel,#fff);border:0.5px solid var(--line,#e2e8f0);border-radius:12px;overflow:hidden;border-left:4px solid '+sc+'"><div style="background:linear-gradient(135deg,#0F172A,#1E293B);padding:14px 16px;display:flex;align-items:flex-start;justify-content:space-between"><div style="display:flex;gap:10px;min-width:0"><span style="font-size:22px;flex-shrink:0">рҹ”Ҙ</span><div style="min-width:0"><div style="font-family:monospace;font-size:13px;font-weight:800;color:#F1F5F9;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+escapeHtml(hn)+'</div><div style="font-size:10.5px;color:#94A3B8;margin-top:2px">'+escapeHtml(f.ip||'вҖ”')+' В· '+escapeHtml(resolverLocal(f))+'</div></div></div><span style="background:'+sc+'22;color:'+sc+';border:1px solid '+sc+'44;font-size:10px;font-weight:700;padding:2px 8px;border-radius:10px;flex-shrink:0;margin-left:8px">'+(online?'Online':st.charAt(0).toUpperCase()+st.slice(1))+'</span></div><div style="padding:14px 16px"><div style="margin-bottom:8px"><div style="display:flex;justify-content:space-between;font-size:10.5px;color:var(--g500);margin-bottom:3px"><span>LatГӘncia</span>'+(f.hasSnmp?'<span style="background:#EFF6FF;color:#2563EB;font-size:9px;padding:1px 5px;border-radius:8px">SNMP</span>':'')+'</div>'+lat+'</div><div style="display:grid;grid-template-columns:1fr 1fr;gap:5px;font-size:11.5px"><div><span style="color:var(--g400)">Local:</span> <span>'+escapeHtml(resolverLocal(f))+'</span></div><div><span style="color:var(--g400)">Uptime:</span> <span style="font-weight:600">'+escapeHtml(up)+'</span></div></div></div><div style="display:flex;border-top:0.5px solid var(--g100)"><button onclick="openModal(&quot;modal-novo-chamado&quot;)" style="flex:1;border:none;background:none;padding:9px;font-size:11.5px;font-weight:600;color:var(--g500);cursor:pointer;border-right:0.5px solid var(--g100)">Chamado</button><button data-aid="'+escapeHtml(f.id)+'" onclick="swActionDirect(&quot;ping&quot;,this.dataset.aid)" style="flex:1;border:none;background:none;padding:9px;font-size:11.5px;font-weight:600;color:var(--g500);cursor:pointer;border-right:0.5px solid var(--g100)">Ping</button><button data-aid="'+escapeHtml(f.id)+'" onclick="swActionDirect(&quot;ssh&quot;,this.dataset.aid)" style="flex:1;border:none;background:none;padding:9px;font-size:11.5px;font-weight:600;color:var(--g500);cursor:pointer">SSH</button></div></div>';}).join('');}




function coletarTodosMonitores(){var r=[];(STATE.ativos||[]).forEach(function(av){var ms=[];try{
  // Tenta monitores (campo do agente) e monitoresConectados (campo legado)
  var raw = av.monitores || av.monitoresConectados;
  ms = typeof raw==='string' ? JSON.parse(raw) : (Array.isArray(raw) ? raw : []);
  }catch(e){}
  // TambГ©m busca nos agentes desktop
  if(!ms.length){var ag=(STATE_AGENTS?.list||[]).find(function(a){return a.ip===av.ip||(a.hostname&&a.hostname===av.hostname);});if(ag&&Array.isArray(ag.monitores))ms=ag.monitores;}ms.forEach(function(m){if(!m.serial)return;var c=(STATE.monitoresCadastrados||[]).find(function(x){return x.serial===m.serial;});r.push({serial:m.serial,fabricante:m.fabricante||'',modelo:m.modelo||'',pat:(c&&c.pat)||m.pat||'',pcAtual:av.hostname||av.ip||'вҖ”',area:resolverLocal(av),qtdMovimentos:0});});});(STATE.monitoresCadastrados||[]).forEach(function(c){if(r.find(function(m){return m.serial===c.serial;}))return;r.push({serial:c.serial||'',fabricante:c.fabricante||'',modelo:c.modelo||'',pat:c.pat||'',pcAtual:c.pcVinculado||'вҖ”',area:c.area||'',qtdMovimentos:0});});return r;}
function renderMonitores(){var q=(document.getElementById('mon-search-monitores')?.value||'').toLowerCase(),fSt=document.getElementById('mon-filter-status-monitores')?.value||'';var grid=document.getElementById('mon-grid'),todos=coletarTodosMonitores();var sv=function(id,v){var el=document.getElementById(id);if(el)el.textContent=v;};sv('mon-kpi-total',todos.length);sv('mon-kpi-sem-pat',todos.filter(function(m){return!m.pat;}).length);sv('mon-kpi-com-pat',todos.filter(function(m){return!!m.pat;}).length);sv('mon-kpi-movidos',todos.filter(function(m){return m.qtdMovimentos>1;}).length);if(!grid)return;var lista=todos;if(q)lista=lista.filter(function(m){return(m.serial+m.pat+m.modelo+m.fabricante+m.pcAtual).toLowerCase().includes(q);});if(fSt==='sem-pat')lista=lista.filter(function(m){return!m.pat;});if(fSt==='com-pat')lista=lista.filter(function(m){return!!m.pat;});if(!lista.length){grid.innerHTML='<div style="grid-column:1/-1;text-align:center;padding:48px;color:var(--g400)"><div style="font-size:40px">рҹ–ҘпёҸ</div><div style="font-weight:600;margin-top:8px">Nenhum monitor encontrado</div></div>';return;}grid.innerHTML=lista.map(function(m){var tp=!!m.pat;return'<div style="background:var(--panel,#fff);border:0.5px solid var(--line,#e2e8f0);border-radius:12px;overflow:hidden;border-top:3px solid '+(tp?'var(--success)':'#F59E0B')+'"><div style="padding:14px 16px 10px"><div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:10px"><div style="display:flex;align-items:center;gap:10px"><div style="font-size:28px">рҹ–ҘпёҸ</div><div><div style="font-size:14px;font-weight:700">'+escapeHtml((m.fabricante||'')+' '+(m.modelo||'Monitor'))+'</div><div style="font-size:11px;font-family:monospace;color:var(--g500)">S/N: '+escapeHtml(m.serial||'вҖ”')+'</div></div></div>'+(tp?'<span style="background:#eaf3de;color:#3b6d11;font-size:11px;font-weight:700;padding:2px 8px;border-radius:10px">PAT: '+escapeHtml(m.pat)+'</span>':'<span style="background:#FEF3C7;color:#92400E;font-size:11px;font-weight:700;padding:2px 8px;border-radius:10px">Sem PatrimГҙnio</span>')+'</div><div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;font-size:12px"><div><span style="color:var(--g400)">PC:</span> <span style="font-weight:600">'+escapeHtml(m.pcAtual)+'</span></div><div><span style="color:var(--g400)">Local:</span> <span>'+escapeHtml(m.area||'вҖ”')+'</span></div></div></div><div style="display:flex;border-top:0.5px solid var(--g100)"><button onclick="abrirAtribuirPatMonitor(\''+escapeHtml(m.serial||'')+'\',' +'\''+escapeHtml((m.fabricante||'')+' '+(m.modelo||'Monitor'))+'\',' +'\''+escapeHtml(m.pat||'')+'\')" style="flex:1;border:none;background:none;padding:10px;font-size:12px;font-weight:600;color:'+(tp?'var(--g500)':'var(--accent)')+';cursor:pointer;border-right:0.5px solid var(--g100)">'+(tp?'Alterar PAT':'Atribuir PAT')+'</button><button onclick="openModal(\'modal-novo-chamado\')" style="flex:1;border:none;background:none;padding:10px;font-size:12px;font-weight:600;color:var(--g500);cursor:pointer">Chamado</button></div></div>';}).join('');}

// в”Җв”Җ Faixas de Rede в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
var STATE_REDES=null;
function renderRedes() {
  var grid    = document.getElementById('redes-grid');
  if (!grid) return;

  var q       = (document.getElementById('redes-search')?.value||'').toLowerCase();
  var fSigla  = document.getElementById('redes-filter-sigla')?.value||'';
  var fView   = window._redesFiltroKpi || ''; // 'total'|'personalizada'|''

  var redesList  = buildRedesList();
  var totalFaixas= redesList.length;
  var siglasUnicas = new Set(redesList.map(function(r){return r.sigla;})).size;

  // KPI highlights
  ['redes-kpi-total-card','redes-kpi-loc-card','redes-kpi-custom-card'].forEach(function(id){
    var el=document.getElementById(id);if(el)el.style.outline='none';
  });
  if(fView==='total'){var el=document.getElementById('redes-kpi-total-card');if(el)el.style.outline='3px solid #2563EB';}

  var sv = function(id,v){var el=document.getElementById(id);if(el)el.textContent=v;};
  sv('redes-kpi-total',       totalFaixas);
  sv('redes-kpi-localidades', siglasUnicas);

  // Populate sigla dropdown once
  var fSiglaEl = document.getElementById('redes-filter-sigla');
  if (fSiglaEl && fSiglaEl.options.length <= 1) {
    var siglas = [...new Set(redesList.map(function(r){return r.sigla;}).filter(Boolean))].sort();
    siglas.forEach(function(s) {
      var opt = document.createElement('option');
      opt.value = s;
      opt.textContent = s.toUpperCase() + ' вҖ” ' + (REDES_SIGLA[s]||s);
      fSiglaEl.appendChild(opt);
    });
  }

  // BotГЈo admin
  var addBtn = document.getElementById('redes-add-btn');
  if (addBtn) addBtn.style.display = isAdmin() ? '' : 'none';

  // Filtra lista base
  var lista = redesList;
  if (fSigla) lista = lista.filter(function(r){return r.sigla===fSigla;});
  if (q)      lista = lista.filter(function(r){return (r.prefix+' '+r.sigla+' '+r.nome+' '+(r.desc||'')).toLowerCase().includes(q);});

  if (!lista.length) {
    grid.innerHTML = '<div style="grid-column:1/-1;text-align:center;padding:48px;color:var(--g400)"><div style="font-size:40px">рҹҢҗ</div><div style="font-weight:600;margin-top:8px">'+(fView==='personalizada'?'Nenhuma rede personalizada':'Nenhuma rede encontrada')+'</div>'+(fView?'<div style="margin-top:8px"><button onclick="window._redesFiltroKpi=\'\';renderRedes()" class="btn btn-secondary btn-sm">Ver todas</button></div>':'')+'</div>';
    return;
  }

  // Agrupa por localidade
  var byLocal = {};
  lista.forEach(function(r) {
    var key = r.sigla;
    if (!byLocal[key]) byLocal[key] = {sigla:r.sigla, nome:r.nome, redes:[]};
    byLocal[key].redes.push(r);
  });

  grid.innerHTML = Object.values(byLocal)
    .sort(function(a,b){return a.nome.localeCompare(b.nome);})
    .map(function(loc) {
      var redesHtml = loc.redes
        .sort(function(a,b){return a.prefix.localeCompare(b.prefix);})
        .map(function(r) {
          var isCustom = r.custom;
          return '<div style="display:flex;align-items:center;justify-content:space-between;padding:6px 10px;border-radius:6px;background:var(--g50);margin-bottom:4px">'
            +'<div style="display:flex;align-items:center;gap:10px;min-width:0">'
              +'<span style="font-family:monospace;font-size:12px;font-weight:600;color:var(--accent);flex-shrink:0">'+escapeHtml(r.prefix)+'.0/24</span>'
              +'<span style="font-size:11px;color:var(--g500);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+escapeHtml(r.desc||r.nome)+'</span>'
              +(isCustom?'<span style="font-size:9px;background:#EFF6FF;color:#2563EB;padding:1px 5px;border-radius:6px;font-weight:700;flex-shrink:0">editado</span>':'')
            +'</div>'
            +(isAdmin()
              ? '<div style="display:flex;gap:4px;flex-shrink:0;margin-left:8px">'
                  +'<button data-prefix="'+escapeHtml(r.prefix)+'" data-sigla="'+escapeHtml(r.sigla)+'" data-nome="'+escapeHtml(r.desc||r.nome)+'" data-id="'+escapeHtml(r.id||'')+'" onclick="abrirEditarRede(this.dataset)" style="border:none;background:none;padding:3px 6px;cursor:pointer;color:var(--g400);font-size:12px" title="Editar faixa">вңҸпёҸ</button>'
                  +(isCustom?'<button data-id="'+escapeHtml(r.id||'')+'" onclick="excluirRede(this.dataset.id)" style="border:none;background:none;padding:3px 6px;cursor:pointer;color:var(--danger);font-size:12px" title="Remover override">рҹ—‘пёҸ</button>':'')
                +'</div>'
              : '')
          +'</div>';
        }).join('');

      return '<div style="background:var(--panel,#fff);border:0.5px solid var(--line,#e2e8f0);border-radius:12px;overflow:hidden">'
        // Card header вҖ” clicГЎvel filtra por essa sigla
        +'<div style="padding:12px 16px;background:linear-gradient(90deg,#0F172A,#1E293B);display:flex;align-items:center;justify-content:space-between;cursor:pointer" onclick="filtrarRedePorSigla(\''+escapeHtml(loc.sigla)+'\')" title="Filtrar por '+escapeHtml(loc.nome)+'">'
          +'<div>'
            // в”Җв”Җ SIGLA em destaque + Nome
            +'<div style="display:flex;align-items:center;gap:10px">'
              +'<span style="font-family:monospace;font-size:15px;font-weight:900;color:#60A5FA;letter-spacing:1px">'+escapeHtml(loc.sigla.toUpperCase())+'</span>'
              +'<span style="font-weight:700;font-size:13px;color:#F1F5F9">'+escapeHtml(loc.nome)+'</span>'
            +'</div>'
            +'<div style="font-size:10.5px;color:#94A3B8;margin-top:3px">'+loc.redes.length+' faixa'+(loc.redes.length>1?'s':'')+' В· clique para filtrar</div>'
          +'</div>'
          +(isAdmin()
            ? '<button onclick="event.stopPropagation();abrirAddRede(\''+escapeHtml(loc.sigla)+'\',\''+escapeHtml(loc.nome)+'\')" style="border:1px solid #ffffff22;background:#ffffff11;color:#94A3B8;border-radius:6px;padding:4px 10px;cursor:pointer;font-size:11px" title="Adicionar faixa a esta localidade">+ Faixa</button>'
            : '')
        +'</div>'
        +'<div style="padding:12px 16px">'+redesHtml+'</div>'
      +'</div>';
    }).join('');
}

function filtrarRedePorSigla(sigla) {
  var sel = document.getElementById('redes-filter-sigla');
  if (!sel) return;
  // Toggle: clicar na mesma sigla desfaz o filtro
  sel.value = sel.value === sigla ? '' : sigla;
  window._redesFiltroKpi = '';
  renderRedes();
}


function buildRedesList(){var lista=Object.entries(REDES_PREFIX).map(function(e){return{prefix:e[0],sigla:e[1].sigla,nome:REDES_SIGLA[e[1].sigla]||e[1].nome,desc:e[1].nome,custom:false,id:''};});if(STATE_REDES&&STATE_REDES.length){STATE_REDES.forEach(function(r){var idx=lista.findIndex(function(x){return x.prefix===r.prefix;});if(idx>=0)lista[idx]=Object.assign({},lista[idx],r,{custom:true});else lista.push(Object.assign({},r,{custom:true}));});}return lista;}
function abrirAddRede(sigla,nome){if(!isAdmin())return;document.getElementById('rede-modal-title').textContent='Adicionar Faixa de Rede';document.getElementById('rede-id').value='';document.getElementById('rede-prefix').value='';document.getElementById('rede-sigla').value=sigla||'';document.getElementById('rede-nome').value=nome||(sigla?(REDES_SIGLA[sigla]||''):'');document.getElementById('rede-desc').value='';openModal('modal-rede');}
function abrirEditarRede(dataset){if(!isAdmin())return;document.getElementById('rede-modal-title').textContent='Editar Faixa de Rede';document.getElementById('rede-id').value=dataset.id||'';document.getElementById('rede-prefix').value=dataset.prefix||'';document.getElementById('rede-sigla').value=dataset.sigla||'';document.getElementById('rede-nome').value=REDES_SIGLA[dataset.sigla]||dataset.nome||'';document.getElementById('rede-desc').value=dataset.nome||'';openModal('modal-rede');}
async function salvarRede(){if(!isAdmin())return;var id=document.getElementById('rede-id').value.trim(),prefix=document.getElementById('rede-prefix').value.trim().replace(/\.0\/24$/,'').replace(/\.$/,''),sigla=document.getElementById('rede-sigla').value.trim().toLowerCase(),nome=document.getElementById('rede-nome').value.trim(),desc=document.getElementById('rede-desc').value.trim();if(!prefix||!sigla||!nome)return showToast('Preencha todos os campos obrigatГіrios','danger',3000);var data={prefix,sigla,nome,desc:desc||nome,atualizadoEm:new Date().toISOString(),atualizadoPor:CURRENT_USER?.email||''};var col=db.collection('config_redes');var prom=id?col.doc(id).set(data,{merge:true}):col.add(data);prom.then(function(){showToast('Rede salva','success',2000);closeModal('modal-rede');}).catch(function(e){showToast('Erro: '+e.message,'danger',4000);});}
async function excluirRede(id){if(!isAdmin()||!id)return;if(!confirm('Remover override? A faixa original serГЎ restaurada.'))return;db.collection('config_redes').doc(id).delete().then(function(){showToast('Override removido','success',2000);}).catch(function(e){showToast('Erro: '+e.message,'danger',4000);});}
function iniciarListenerRedes(){if(!db)return;db.collection('config_redes').onSnapshot(function(snap){STATE_REDES=snap.docs.map(function(d){return Object.assign({id:d.id},d.data());});if(isPageActive('redes'))renderRedes();},function(e){console.warn('[Redes] erro listener:',e.message);});}
function isAdmin(){return CURRENT_USER&&(CURRENT_USER.role==='admin'||CURRENT_USER.perfil==='admin');}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// DESCARTE вҖ” Busca, SeleГ§ГЈo e MovimentaГ§ГЈo
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

var _descarteAtivoSel = null;

function abrirBuscaDescarte() {
  _descarteAtivoSel = null;
  // Reset form
  ['desc-busca-q','desc-busca-area','desc-sap-busca','desc-obs-busca'].forEach(function(id){
    var el = document.getElementById(id); if(el) el.value = '';
  });
  var sel = document.getElementById('desc-busca-tipo'); if(sel) sel.value = '';
  var sel2 = document.getElementById('desc-modalidade-busca'); if(sel2) sel2.value = '';
  document.getElementById('desc-busca-lista').innerHTML = '<div style="text-align:center;padding:40px;color:var(--g400)"><div style="font-size:32px;margin-bottom:8px">рҹ”Қ</div><div>Busque um ativo acima para selecionГЎ-lo</div></div>';
  document.getElementById('desc-busca-count').textContent = 'Digite para buscar ativos...';
  document.getElementById('desc-selecionado-wrap').style.display = 'none';
  document.getElementById('desc-form-wrap').style.display = 'none';
  var btn = document.getElementById('desc-confirmar-btn');
  if (btn) { btn.disabled = true; btn.style.opacity = '.5'; btn.style.cursor = 'not-allowed'; }
  openModal('modal-busca-descarte');
  setTimeout(function(){ var el = document.getElementById('desc-busca-q'); if(el) el.focus(); }, 300);
}

function buscarAtivosDescarte() {
  var q     = (document.getElementById('desc-busca-q')?.value || '').toLowerCase().trim();
  var area  = (document.getElementById('desc-busca-area')?.value || '').toLowerCase().trim();
  var tipo  = (document.getElementById('desc-busca-tipo')?.value || '').toLowerCase();

  // Precisa de pelo menos 2 chars para buscar
  if (!q && !area && !tipo) {
    document.getElementById('desc-busca-lista').innerHTML = '<div style="text-align:center;padding:40px;color:var(--g400)"><div style="font-size:32px;margin-bottom:8px">рҹ”Қ</div><div>Busque um ativo acima para selecionГЎ-lo</div></div>';
    document.getElementById('desc-busca-count').textContent = 'Digite para buscar ativos...';
    return;
  }

  // Filtra ativos вҖ” exclui os jГЎ em descarte
  // Inclui todos os tipos: ativos, mobiliГЎrio, etc.
  var _todosDesc = (STATE.ativos||[]).concat(STATE.mobiliario||[]);
  var lista = _todosDesc.filter(function(a) {
    if ((a.status || '').toLowerCase() === 'descarte') return false;
    var matchQ    = !q    || (a.pat||'').toLowerCase().includes(q) || (a.hostname||'').toLowerCase().includes(q) || (a.ip||'').toLowerCase().includes(q) || (a.desc||'').toLowerCase().includes(q);
    var matchArea = !area || resolverLocal(a).toLowerCase().includes(area) || (a.area||'').toLowerCase().includes(area);
    var matchTipo = !tipo || (a.tipo||'').toLowerCase().includes(tipo);
    return matchQ && matchArea && matchTipo;
  });

  document.getElementById('desc-busca-count').textContent = lista.length + ' ativo(s) encontrado(s)' + (lista.length > 50 ? ' вҖ” refine a busca' : '');

  if (!lista.length) {
    document.getElementById('desc-busca-lista').innerHTML = '<div style="text-align:center;padding:40px;color:var(--g400)"><div style="font-size:32px;margin-bottom:8px">рҹ“ӯ</div><div>Nenhum ativo encontrado</div></div>';
    return;
  }

  // Limita a 80 resultados para performance
  var exibir = lista.slice(0, 80);
  var tipoColors = {notebook:'#7C3AED',workstation:'#2563EB',desktop:'#2563EB',servidor:'#0891B2','server-linux':'#0891B2',switch:'#EA580C',impressora:'#059669',printer:'#059669',monitor:'#475569'};

  document.getElementById('desc-busca-lista').innerHTML = exibir.map(function(a) {
    var hn    = a.hostname || a.desc || a.ip || 'вҖ”';
    var tipo  = (a.tipo || 'workstation').toLowerCase();
    var cor   = tipoColors[tipo] || '#64748B';
    var local = resolverLocal(a);
    var st    = (a.status || 'ativo').toLowerCase();
    var stCor = st === 'em-uso' || st === 'ativo' ? '#059669' : st === 'manutencao' ? '#D97706' : '#64748B';
    var sel   = _descarteAtivoSel && _descarteAtivoSel.id === a.id;

    return '<div onclick="selecionarAtivoDescarte(\'' + escapeHtml(a.id) + '\')" style="display:flex;align-items:center;gap:12px;padding:10px 20px;border-bottom:0.5px solid var(--g100);cursor:pointer;transition:background .12s;background:' + (sel ? '#FEF2F2' : 'var(--panel)') + '" onmouseenter="this.style.background=\'#FFF7F7\'" onmouseleave="this.style.background=\'' + (sel ? '#FEF2F2' : 'var(--panel)') + '\'">'
      + '<div style="width:36px;height:36px;border-radius:8px;background:' + cor + '22;border:1px solid ' + cor + '44;display:flex;align-items:center;justify-content:center;font-size:16px;flex-shrink:0">'
        + (tipo==='notebook'?'рҹ’»':tipo==='switch'||tipo==='router'?'рҹ”Җ':tipo==='servidor'||tipo==='server-linux'?'рҹ–ҘпёҸ':tipo==='impressora'||tipo==='printer'?'рҹ–ЁпёҸ':'рҹ–ҘпёҸ')
      + '</div>'
      + '<div style="flex:1;min-width:0">'
        + '<div style="font-weight:700;font-size:13px;font-family:monospace;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + escapeHtml(hn) + '</div>'
        + '<div style="font-size:11px;color:var(--g500);margin-top:2px;display:flex;gap:10px;flex-wrap:wrap">'
          + '<span>PAT: <strong>' + escapeHtml(a.pat || 'вҖ”') + '</strong></span>'
          + '<span>IP: <span style="font-family:monospace">' + escapeHtml(a.ip || 'вҖ”') + '</span></span>'
          + '<span>рҹ“Қ ' + escapeHtml(local) + '</span>'
          + '<span style="color:' + cor + ';font-weight:600">' + escapeHtml(tipo) + '</span>'
        + '</div>'
      + '</div>'
      + '<div style="text-align:right;flex-shrink:0">'
        + '<span style="font-size:10px;font-weight:700;color:' + stCor + ';background:' + stCor + '15;padding:2px 8px;border-radius:8px">' + escapeHtml(st) + '</span>'
        + (sel ? '<div style="font-size:18px;margin-top:4px">вң…</div>' : '')
      + '</div>'
    + '</div>';
  }).join('')
  + (lista.length > 80 ? '<div style="text-align:center;padding:12px;font-size:11.5px;color:var(--g400)">... e mais ' + (lista.length-80) + ' ativos. Refine a busca.</div>' : '');
}

function selecionarAtivoDescarte(ativoId) {
  var a = (STATE.ativos || []).find(function(x){ return x.id === ativoId; });
  if (!a) return;

  _descarteAtivoSel = a;
  document.getElementById('desc-busca-ativo-id').value = ativoId;

  // Atualiza info do selecionado
  var hn    = a.hostname || a.desc || a.ip || 'вҖ”';
  var local = resolverLocal(a);
  document.getElementById('desc-selecionado-info').innerHTML =
    'рҹ–ҘпёҸ <strong>' + escapeHtml(hn) + '</strong>'
    + ' &nbsp;В·&nbsp; PAT: <strong>' + escapeHtml(a.pat || 'вҖ”') + '</strong>'
    + ' &nbsp;В·&nbsp; ' + escapeHtml(a.tipo || '?')
    + ' &nbsp;В·&nbsp; рҹ“Қ ' + escapeHtml(local);

  document.getElementById('desc-selecionado-wrap').style.display = '';
  document.getElementById('desc-form-wrap').style.display = '';

  // Habilita botГЈo confirmar
  var btn = document.getElementById('desc-confirmar-btn');
  if (btn) { btn.disabled = false; btn.style.opacity = '1'; btn.style.cursor = 'pointer'; }

  // Re-render lista para mostrar selecionado
  buscarAtivosDescarte();

  // Scroll para o formulГЎrio
  var fw = document.getElementById('desc-form-wrap');
  if (fw) fw.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
}

async function confirmarMoverDescarte() {
  var ativoId    = document.getElementById('desc-busca-ativo-id').value;
  var modalidade = document.getElementById('desc-modalidade-busca').value;
  var sap        = document.getElementById('desc-sap-busca').value.trim();
  var obs        = document.getElementById('desc-obs-busca').value.trim();

  if (!ativoId)    return showToast('Selecione um ativo da lista', 'warning');
  if (!modalidade) return showToast('Selecione a modalidade de descarte', 'warning');
  if (!obs)        return showToast('Informe o motivo do descarte', 'warning');

  var a = (STATE.ativos || []).find(function(x){ return x.id === ativoId; });
  if (!a) return;

  var btn = document.getElementById('desc-confirmar-btn');
  if (btn) { btn.disabled = true; btn.textContent = 'вҸі Processando...'; }

  try {
    var updates = {
      status:               'descarte',
      substatusDescarte:    modalidade,
      descarteSAP:          sap,
      descarteObs:          obs,
      descarteData:         new Date().toISOString().split('T')[0],
      descarteAutorizadoPor: CURRENT_USER?.nome || '',
      updatedAt:            new Date().toISOString(),
    };

    await fsUpdate('ativos', ativoId, updates);
    Object.assign(a, updates);

    // HistГіrico imutГЎvel
    await registrarHistoricoAtivo(ativoId, 'descartado', {
      modalidade,
      sap:          sap || 'вҖ”',
      obs,
      por:          CURRENT_USER?.nome || 'вҖ”',
      dataDescarte: updates.descarteData,
    });

    // Cria aprovaГ§ГЈo pendente para o gestor
    var aprov = {
      id:           'APROV-DESC-' + Date.now(),
      tipo:         'Descarte de Ativo',
      pat:          a.pat || ativoId,
      descricao:    'Descarte: ' + (a.hostname||a.pat||'вҖ”') + ' вҶ’ ' + modalidade,
      destino:      'descarte',
      modalidade,
      sap,
      obs,
      ativoId,
      solicitante:  CURRENT_USER?.nome || '',
      status:       'pendente',
      createdAt:    new Date().toISOString(),
    };
    if (!STATE.aprovacoes) STATE.aprovacoes = [];
    STATE.aprovacoes.unshift(aprov);
    await fsAdd('aprovacoes', aprov);
    nbUpdate('nb-aprov', STATE.aprovacoes.filter(function(x){return x.status==='pendente';}).length);

    closeModal('modal-busca-descarte');
    showToast('вң… ' + (a.hostname||a.pat||'Ativo') + ' movido para Descarte вҖ” aguardando aprovaГ§ГЈo do gestor', 'success', 6000);
    renderDescarte();
    if (typeof renderDashboard === 'function') renderDashboard();
  } catch(e) {
    showToast('Erro: ' + e.message, 'danger', 5000);
    if (btn) { btn.disabled = false; btn.textContent = 'рҹ—‘пёҸ Confirmar Descarte'; }
  }
}

