// в”Җв”Җ Busca histГіrico por ativo в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function relBuscarHistorico() {
  var q = (document.getElementById('rel-historico-q')?.value||'').toLowerCase().trim();
  var lista = document.getElementById('rel-historico-lista');
  if (!lista) return;
  if (!q) { lista.innerHTML = ''; return; }

  var ativos = (STATE.ativos||[]).filter(function(a){
    return (a.pat||'').toLowerCase().includes(q) || (a.hostname||'').toLowerCase().includes(q) || (a.ip||'').toLowerCase().includes(q);
  }).slice(0,10);

  if (!ativos.length) {
    lista.innerHTML = '<div style="font-size:12px;color:var(--g400);padding:8px 0">Nenhum ativo encontrado</div>';
    return;
  }
  lista.innerHTML = ativos.map(function(a){
    var hn = a.hostname||a.desc||a.ip||'вҖ”';
    return '<button onclick="relAbrirHistoricoAtivo(\''+escapeHtml(a.id||'')+'\',\''+escapeHtml(a.pat||'')+'\',\''+escapeHtml(hn)+'\')" style="margin:3px;padding:5px 12px;border:1px solid var(--g200);border-radius:8px;background:var(--panel);cursor:pointer;font-size:12px;font-weight:600">рҹ–ҘпёҸ '+escapeHtml(hn)+' <span style="color:var(--g400);font-weight:400">PAT:'+escapeHtml(a.pat||'вҖ”')+'</span></button>';
  }).join('');
}

async function relAbrirHistoricoAtivo(ativoId, pat, nome) {
  var tbody = document.getElementById('rel-tbody');
  var sumEl = document.getElementById('rel-summary');
  if (!tbody) return;
  tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;color:var(--g400);padding:24px">вҸі Carregando histГіrico de '+escapeHtml(nome)+'...</td></tr>';
  if (sumEl) sumEl.textContent = '';
  try {
    var snap = await db.collection('ativos').doc(ativoId).collection('historico').orderBy('timestamp','desc').limit(200).get();
    var eventos = snap.docs.map(function(d){return d.data();});
    var iconMap = {criado:'рҹҹў',atribuido:'рҹ‘Ө',transferido:'рҹ”„',manutencao:'рҹ”§',retornou:'рҹҸӯ','santa-clara':'рҹ“Қ',reutilizado:'вҷ»пёҸ',descartado:'рҹ—‘пёҸ',renomeado:'рҹҸ·пёҸ',observacao:'рҹ’¬',movimentado:'рҹ“Ұ'};
    tbody.innerHTML = eventos.map(function(ev){
      var ico  = iconMap[ev.evento]||'рҹ“Ң';
      var data = ev.timestamp ? new Date(ev.timestamp).toLocaleString('pt-BR',{day:'2-digit',month:'2-digit',year:'numeric',hour:'2-digit',minute:'2-digit'}) : 'вҖ”';
      var dets = ev.detalhes ? Object.entries(ev.detalhes).filter(function(e){return e[1]&&e[0]!=='id';}).map(function(e){return escapeHtml(e[0])+': '+escapeHtml(String(e[1]));}).join(' В· ') : 'вҖ”';
      return '<tr><td>'+ico+' <strong>'+escapeHtml((ev.evento||'').replace(/-/g,' '))+'</strong></td><td style="font-family:monospace">'+escapeHtml(pat)+'</td><td style="font-size:11.5px;color:var(--g600)">'+dets+'</td><td>'+escapeHtml(ev.usuario||'вҖ”')+'</td><td style="font-size:11.5px">'+data+'</td></tr>';
    }).join('') || '<tr><td colspan="5" style="text-align:center;color:var(--g400)">Nenhum evento registrado para este ativo</td></tr>';
    if (sumEl) sumEl.textContent = eventos.length + ' eventos no histГіrico de ' + nome + ' (PAT: ' + pat + ')';
    _relDadosAtual = eventos;
  } catch(e) {
    tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;color:var(--danger)">Erro: '+escapeHtml(e.message)+'</td></tr>';
  }
}

// в”Җв”Җ Exportar CSV в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function relExportarCSV() {
  if (!_relDadosAtual || !_relDadosAtual.length) return showToast('Nenhum dado para exportar','warning');
  var cols = Object.keys(_relDadosAtual[0]).filter(function(k){return typeof _relDadosAtual[0][k]!=='object'||_relDadosAtual[0][k]===null;});
  var csv  = cols.join(';') + '\n';
  csv += _relDadosAtual.map(function(row){
    return cols.map(function(c){
      var v = row[c];
      if (v == null) return '';
      return '"' + String(v).replace(/"/g,'""') + '"';
    }).join(';');
  }).join('\n');
  var blob = new Blob(['\uFEFF'+csv], {type:'text/csv;charset=utf-8'});
  var url  = URL.createObjectURL(blob);
  var a    = document.createElement('a');
  a.href   = url;
  a.download = 'sysack-relatorio-'+_relTipoAtual+'-'+new Date().toISOString().split('T')[0]+'.csv';
  a.click();
  URL.revokeObjectURL(url);
  showToast('CSV exportado com sucesso','success');
}

// в”Җв”Җ Inicializa relatГіrios ao entrar na pГЎgina в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function renderRelatorios() {
  // Carrega dados lazy sob demanda ao entrar na pГЎgina
  ['_load_vistorias','_load_baixasPatrimoniais','_load_notasFiscais'].forEach(function(fn){
    if(window[fn]) window[fn]();
  });
  relAtualizarCards();
  // Marca MГӘs como padrГЈo visualmente
  var btns = document.querySelectorAll('.rel-per-btn, .rel-per-btn2');
  btns.forEach(function(b){
    if (b.textContent.trim() === 'MГӘs') {
      b.style.background = '#fff'; b.style.color='var(--g900)'; b.style.boxShadow='0 1px 3px rgba(0,0,0,.1)';
    }
  });
  var el = document.getElementById('rel-periodo-label');
  if (el) el.textContent = 'вҶ’ ' + new Date().toLocaleDateString('pt-BR',{month:'long',year:'numeric'});
}

