// в”Җв”Җ Tab switchers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function descarteSetTab(tab, btn) {
  document.getElementById('desc-panel-manual').style.display  = tab==='manual'  ? '' : 'none';
  document.getElementById('desc-panel-arquivo').style.display = tab==='arquivo' ? '' : 'none';
  ['desc-tab-manual','desc-tab-arquivo'].forEach(function(id){
    var el = document.getElementById(id);
    if(!el)return;
    el.style.color         = 'var(--g500)';
    el.style.borderBottom  = '2px solid transparent';
    el.style.fontWeight    = '600';
  });
  if(btn){btn.style.color='#991B1B';btn.style.borderBottom='2px solid #991B1B';btn.style.fontWeight='700';}
}

function reusoSetTab(tab, btn) {
  document.getElementById('reuso-panel-manual').style.display  = tab==='manual'  ? '' : 'none';
  document.getElementById('reuso-panel-arquivo').style.display = tab==='arquivo' ? '' : 'none';
  ['reuso-tab-manual','reuso-tab-arquivo'].forEach(function(id){
    var el = document.getElementById(id);
    if(!el)return;
    el.style.color        = 'var(--g500)';
    el.style.borderBottom = '2px solid transparent';
    el.style.fontWeight   = '600';
  });
  if(btn){btn.style.color='#065F46';btn.style.borderBottom='2px solid #065F46';btn.style.fontWeight='700';}
}

// в”Җв”Җ Drag & Drop handlers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function descarteHandleDrop(e) {
  e.preventDefault();
  document.getElementById('desc-drop-zone').style.background = '#FFF5F5';
  var file = e.dataTransfer.files[0];
  if (file) processarArquivoLista(file, 'descarte');
}
function reusoHandleDrop(e) {
  e.preventDefault();
  document.getElementById('reuso-drop-zone').style.background = '#F0FDF4';
  var file = e.dataTransfer.files[0];
  if (file) processarArquivoLista(file, 'reuso');
}
function descarteProcessarArquivo(input) {
  if (input.files[0]) processarArquivoLista(input.files[0], 'descarte');
}
function reusoProcessarArquivo(input) {
  if (input.files[0]) processarArquivoLista(input.files[0], 'reuso');
}

// в”Җв”Җ Core: processa o arquivo e cruza com STATE.ativos в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
async function processarArquivoLista(file, modo) {
  var statusEl = document.getElementById(modo+'-import-status');
  if (statusEl) { statusEl.style.display=''; statusEl.innerHTML='<div style="text-align:center;padding:20px;color:var(--g500)">вҸі Lendo arquivo...</div>'; }

  var ext = file.name.split('.').pop().toLowerCase();

  try {
    var linhas = [];

    if (ext === 'txt' || ext === 'csv') {
      // в”Җв”Җ TXT / CSV в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
      var texto = await lerArquivoTexto(file);
      linhas = texto.split(/[\r\n]+/).map(function(l){ return l.replace(/[";,\t]+/g,' ').trim(); }).filter(Boolean);

    } else if (ext === 'xlsx' || ext === 'xls') {
      // в”Җв”Җ Excel вҖ” usa SheetJS (XLSX) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
      if (typeof XLSX === 'undefined') {
        // Carrega SheetJS dinamicamente
        await carregarScript('https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js');
      }
      var data = await lerArquivoBinario(file);
      var wb   = XLSX.read(data, {type:'array'});
      var ws   = wb.Sheets[wb.SheetNames[0]];
      var rows = XLSX.utils.sheet_to_json(ws, {header:1, raw:false});
      // Pega todas as cГ©lulas nГЈo vazias de todas as linhas
      rows.forEach(function(row) {
        row.forEach(function(cell) {
          var v = String(cell||'').trim();
          if (v) linhas.push(v);
        });
      });
    } else {
      if (statusEl) statusEl.innerHTML = '<div style="color:#DC2626;padding:12px;background:#FEF2F2;border-radius:8px">вқҢ Formato nГЈo suportado. Use .xlsx, .xls, .txt ou .csv</div>';
      return;
    }

    // Remove duplicatas e linhas vazias / cabeГ§alhos comuns
    var stopWords = new Set(['pat','patrimonio','patrimГҙnio','hostname','nome','maquina','mГЎquina','ativo','asset','computador','equipamento','device','name','number','id']);
    linhas = linhas.filter(function(l){ return l.length > 1 && !stopWords.has(l.toLowerCase()); });
    linhas = [...new Set(linhas)];

    if (!linhas.length) {
      if (statusEl) statusEl.innerHTML = '<div style="color:#DC2626;padding:12px;background:#FEF2F2;border-radius:8px">вқҢ Nenhum item encontrado no arquivo.</div>';
      return;
    }

    renderizarResultadoImport(linhas, modo, statusEl);

  } catch(e) {
    if (statusEl) statusEl.innerHTML = '<div style="color:#DC2626;padding:12px;background:#FEF2F2;border-radius:8px">вқҢ Erro ao ler arquivo: '+escapeHtml(e.message)+'</div>';
  }
}

function lerArquivoTexto(file) {
  return new Promise(function(resolve, reject) {
    var r = new FileReader();
    r.onload  = function(e){ resolve(e.target.result); };
    r.onerror = reject;
    r.readAsText(file, 'UTF-8');
  });
}

function lerArquivoBinario(file) {
  return new Promise(function(resolve, reject) {
    var r = new FileReader();
    r.onload  = function(e){ resolve(new Uint8Array(e.target.result)); };
    r.onerror = reject;
    r.readAsArrayBuffer(file);
  });
}

function carregarScript(url) {
  return new Promise(function(resolve, reject) {
    if (document.querySelector('script[src="'+url+'"]')) { resolve(); return; }
    var s = document.createElement('script');
    s.src = url; s.onload = resolve; s.onerror = reject;
    document.head.appendChild(s);
  });
}

// в”Җв”Җ Cruza lista com STATE.ativos e exibe resultado в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function renderizarResultadoImport(linhas, modo, statusEl) {
  var todos  = (STATE.ativos||[]).concat(STATE.mobiliario||[]);
  var cor    = modo==='descarte' ? '#991B1B' : '#065F46';
  var corBg  = modo==='descarte' ? '#FFF5F5' : '#F0FDF4';

  var encontrados  = []; // {termo, ativo}
  var naoEncontrados = []; // {termo, candidatos:[]}

  linhas.forEach(function(termo) {
    var t = termo.toLowerCase().trim();

    // 1. Match exato por PAT
    var byPat = todos.find(function(a){ return (a.pat||'').toLowerCase() === t; });
    if (byPat) { encontrados.push({termo:termo, ativo:byPat, metodo:'PAT exato'}); return; }

    // 2. Match exato por hostname
    var byHost = todos.find(function(a){ return (a.hostname||a.sysName||'').toLowerCase() === t; });
    if (byHost) { encontrados.push({termo:termo, ativo:byHost, metodo:'Hostname exato'}); return; }

    // 3. Match parcial por hostname (contГ©m)
    var byHostParcial = todos.filter(function(a){ return (a.hostname||a.sysName||'').toLowerCase().includes(t) && t.length >= 4; });
    if (byHostParcial.length === 1) { encontrados.push({termo:termo, ativo:byHostParcial[0], metodo:'Hostname parcial'}); return; }
    if (byHostParcial.length > 1)   { naoEncontrados.push({termo:termo, candidatos:byHostParcial.slice(0,5), motivo:'mГәltiplos resultados'}); return; }

    // 4. Match por desc/nome
    var byDesc = todos.find(function(a){ return (a.desc||a.nome||'').toLowerCase().includes(t) && t.length >= 5; });
    if (byDesc) { encontrados.push({termo:termo, ativo:byDesc, metodo:'Nome/Desc'}); return; }

    // 5. NГЈo encontrado
    naoEncontrados.push({termo:termo, candidatos:[], motivo:'nГЈo encontrado'});
  });

  // Render resultado
  var html = '<div style="margin-bottom:12px;display:flex;gap:10px;flex-wrap:wrap;align-items:center">';
  html += '<span style="font-size:12px;font-weight:700;color:'+cor+'">'+linhas.length+' itens na lista</span>';
  html += '<span style="font-size:11px;background:#F0FDF4;color:#059669;padding:3px 10px;border-radius:8px;font-weight:700">вң… '+encontrados.length+' identificados</span>';
  if (naoEncontrados.length) {
    html += '<span style="font-size:11px;background:#FEF2F2;color:#DC2626;padding:3px 10px;border-radius:8px;font-weight:700">вҡ пёҸ '+naoEncontrados.length+' nГЈo identificados</span>';
  }
  html += '</div>';

  // Tabela de encontrados
  if (encontrados.length) {
    html += '<div style="background:#fff;border:1px solid var(--g200);border-radius:8px;overflow:hidden;margin-bottom:12px">';
    html += '<div style="padding:8px 14px;background:'+corBg+';font-size:11px;font-weight:700;color:'+cor+'">вң… IDENTIFICADOS вҖ” serГЈo movimentados</div>';
    html += '<div style="max-height:180px;overflow-y:auto">';
    html += encontrados.map(function(r){
      var a = r.ativo;
      var hn = a.hostname||a.nome||a.desc||a.ip||'вҖ”';
      return '<div style="display:flex;align-items:center;gap:10px;padding:7px 14px;border-bottom:0.5px solid var(--g100)">'
        +'<div style="flex:1;min-width:0"><span style="font-family:monospace;font-size:12px;font-weight:600">'+escapeHtml(hn)+'</span> <span style="font-size:10.5px;color:var(--g400)">PAT: '+escapeHtml(a.pat||'вҖ”')+'</span></div>'
        +'<span style="font-size:10px;background:#EFF6FF;color:#2563EB;padding:1px 7px;border-radius:6px">'+escapeHtml(r.metodo)+'</span>'
        +'<span style="font-size:10.5px;color:var(--g400)">'+escapeHtml(r.termo)+'</span>'
        +'</div>';
    }).join('');
    html += '</div></div>';
  }

  // Tabela de nГЈo encontrados (com inputs de confirmaГ§ГЈo)
  if (naoEncontrados.length) {
    html += '<div style="background:#fff;border:1px solid #FCA5A5;border-radius:8px;overflow:hidden;margin-bottom:12px">';
    html += '<div style="padding:8px 14px;background:#FEF2F2;font-size:11px;font-weight:700;color:#DC2626">вҡ пёҸ CONFIRME MANUALMENTE вҖ” nГЈo identificados automaticamente</div>';
    html += '<div id="import-confirm-area-'+modo+'" style="max-height:220px;overflow-y:auto">';
    html += naoEncontrados.map(function(r, i) {
      var candidatosHtml = '';
      if (r.candidatos.length > 0) {
        candidatosHtml = '<div style="margin-top:6px"><span style="font-size:10.5px;color:var(--g500)">PossГӯveis matches:</span> '
          + r.candidatos.map(function(c){
            var cn = c.hostname||c.desc||c.ip||'вҖ”';
            return '<button onclick="importConfirmarCandidato(\''+modo+'\','+i+',\''+escapeHtml(c.id||'')+'\',\''+escapeHtml(cn)+'\')" style="margin:2px;padding:3px 8px;border:1px solid var(--g300);border-radius:6px;background:#fff;cursor:pointer;font-size:11px">'+escapeHtml(cn)+'<span style="color:var(--g400);margin-left:4px">'+escapeHtml(c.pat||'')+'</span></button>';
          }).join('')
          + '</div>';
      }
      return '<div id="import-nr-'+modo+'-'+i+'" style="padding:10px 14px;border-bottom:0.5px solid var(--g100)">'
        +'<div style="display:flex;align-items:flex-start;gap:10px;flex-wrap:wrap">'
          +'<div style="flex:1">'
            +'<span style="font-family:monospace;font-size:12.5px;font-weight:700;color:#991B1B">'+escapeHtml(r.termo)+'</span>'
            +' <span style="font-size:10.5px;color:var(--g400)">('+escapeHtml(r.motivo)+')</span>'
            + candidatosHtml
          +'</div>'
          +'<div style="display:flex;gap:6px;align-items:center;flex-shrink:0">'
            +'<input id="import-manual-'+modo+'-'+i+'" placeholder="PAT ou hostname correto..." style="border:1px solid var(--g300);border-radius:6px;padding:4px 8px;font-size:11.5px;width:180px" onkeyup="importBuscarManual(this,\''+modo+'\','+i+')">'
            +'<button onclick="importConfirmarManual(\''+modo+'\','+i+')" style="padding:4px 10px;background:'+cor+';color:#fff;border:none;border-radius:6px;cursor:pointer;font-size:11.5px;font-weight:600">Confirmar</button>'
            +'<button onclick="importIgnorar(\''+modo+'\','+i+')" style="padding:4px 8px;background:var(--g100);color:var(--g600);border:none;border-radius:6px;cursor:pointer;font-size:11.5px">Ignorar</button>'
          +'</div>'
        +'</div>'
        +'<div id="import-manual-result-'+modo+'-'+i+'" style="margin-top:6px;font-size:11px;color:var(--g500)"></div>'
      +'</div>';
    }).join('');
    html += '</div></div>';
  }

  // BotГЈo de aplicar
  if (encontrados.length) {
    // Guarda lista encontrados para uso no botГЈo
    window['_importLista_'+modo] = encontrados;
    html += '<button onclick="aplicarImportacao(\''+modo+'\')" style="width:100%;padding:10px;background:'+cor+';color:#fff;border:none;border-radius:8px;cursor:pointer;font-size:13px;font-weight:700">'
      +(modo==='descarte'?'рҹ—‘пёҸ':'вҷ»пёҸ')+' Aplicar movimentaГ§ГЈo em lote ('+encontrados.length+' ativo'+(encontrados.length>1?'s':'')+')</button>';
  }

  if (statusEl) statusEl.innerHTML = html;
}

// в”Җв”Җ Busca manual para item nГЈo identificado в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function importBuscarManual(input, modo, idx) {
  var q   = input.value.toLowerCase().trim();
  var res = document.getElementById('import-manual-result-'+modo+'-'+idx);
  if (!res) return;
  if (q.length < 2) { res.textContent = ''; return; }
  var todos = (STATE.ativos||[]).concat(STATE.mobiliario||[]);
  var matches = todos.filter(function(a){
    return (a.pat||'').toLowerCase().includes(q) || (a.hostname||'').toLowerCase().includes(q) || (a.desc||'').toLowerCase().includes(q);
  }).slice(0,4);
  if (!matches.length) { res.textContent = 'Nenhum resultado.'; return; }
  res.innerHTML = matches.map(function(a){
    var hn = a.hostname||a.desc||a.ip||'вҖ”';
    return '<button onclick="importConfirmarCandidato(\''+modo+'\','+idx+',\''+escapeHtml(a.id||'')+'\',\''+escapeHtml(hn)+'\')" style="margin:2px;padding:3px 8px;border:1px solid #059669;border-radius:6px;background:#F0FDF4;cursor:pointer;font-size:11px">'+escapeHtml(hn)+' <span style="color:var(--g400)">'+escapeHtml(a.pat||'вҖ”')+'</span></button>';
  }).join('');
}

function importConfirmarCandidato(modo, idx, ativoId, nome) {
  var todos = (STATE.ativos||[]).concat(STATE.mobiliario||[]);
  var a = todos.find(function(x){return x.id===ativoId;});
  if (!a) return;
  // Add to found list
  if (!window['_importLista_'+modo]) window['_importLista_'+modo] = [];
  window['_importLista_'+modo].push({termo:nome, ativo:a, metodo:'Confirmado manualmente'});
  // Mark row as confirmed
  var row = document.getElementById('import-nr-'+modo+'-'+idx);
  if (row) row.innerHTML = '<div style="padding:6px 0;color:#059669;font-size:12px;font-weight:700">вң… Confirmado: '+escapeHtml(a.hostname||a.desc||a.ip||'вҖ”')+' (PAT: '+escapeHtml(a.pat||'вҖ”')+')</div>';
  // Update apply button
  var btn = document.querySelector('[onclick="aplicarImportacao(\''+modo+'\')"]');
  if (btn) {
    var count = (window['_importLista_'+modo]||[]).length;
    btn.textContent = (modo==='descarte'?'рҹ—‘пёҸ':'вҷ»пёҸ')+' Aplicar movimentaГ§ГЈo em lote ('+count+' ativo'+(count>1?'s':'')+')';
  }
}

function importConfirmarManual(modo, idx) {
  var input = document.getElementById('import-manual-'+modo+'-'+idx);
  if (!input || !input.value.trim()) return;
  var q     = input.value.toLowerCase().trim();
  var todos = (STATE.ativos||[]).concat(STATE.mobiliario||[]);
  var a     = todos.find(function(x){
    return (x.pat||'').toLowerCase()===q || (x.hostname||'').toLowerCase()===q;
  });
  if (!a) { showToast('Ativo nГЈo encontrado: '+input.value,'warning'); return; }
  importConfirmarCandidato(modo, idx, a.id, a.hostname||a.desc||a.ip||'вҖ”');
}

function importIgnorar(modo, idx) {
  var row = document.getElementById('import-nr-'+modo+'-'+idx);
  if (row) row.innerHTML = '<div style="padding:4px 0;color:var(--g400);font-size:11.5px;font-style:italic">Ignorado</div>';
}

// в”Җв”Җ Aplica movimentaГ§ГЈo em lote в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
async function aplicarImportacao(modo) {
  var lista = window['_importLista_'+modo] || [];
  if (!lista.length) return showToast('Nenhum ativo para mover', 'warning');

  var cor    = modo === 'descarte' ? '#991B1B' : '#065F46';
  var corBg  = modo === 'descarte' ? '#FFF5F5' : '#F0FDF4';
  var emoji  = modo === 'descarte' ? 'рҹ—‘пёҸ' : 'вҷ»пёҸ';

  // Valida campos do formulГЎrio antes de processar
  if (modo === 'descarte') {
    var modalidade = document.getElementById('desc-modalidade-busca').value;
    var sap        = document.getElementById('desc-sap-busca').value.trim();
    var obs        = document.getElementById('desc-obs-busca').value.trim();
    if (!modalidade) return showToast('Preencha a modalidade antes de aplicar', 'warning');
    if (!obs)        return showToast('Informe o motivo do descarte', 'warning');
  } else {
    var local    = document.getElementById('reuso-local-estoque').value.trim();
    var condicao = document.getElementById('reuso-condicao').value;
    var motivo   = document.getElementById('reuso-motivo').value.trim();
    if (!local)  return showToast('Informe o local de armazenamento', 'warning');
    if (!motivo) return showToast('Informe o motivo da devoluГ§ГЈo ao estoque', 'warning');
  }

  // Mostra progresso no status
  var statusEl = document.getElementById(modo + '-import-status');
  if (statusEl) {
    statusEl.style.display = '';
    statusEl.innerHTML = '<div style="text-align:center;padding:16px;color:var(--g500)">вҸі Processando '+lista.length+' ativo'+(lista.length>1?'s':'')+'...</div>';
  }

  // Desabilita botГЈo durante o processamento
  var applyBtn = document.getElementById(modo+'-apply-btn');
  if (applyBtn) { applyBtn.disabled = true; applyBtn.style.opacity = '.6'; applyBtn.textContent = 'вҸі Processando...'; }

  var resultados = []; // {ativo, termo, ok, erro}

  for (var i = 0; i < lista.length; i++) {
    var item = lista[i];
    var a    = item.ativo;
    var hn   = a.hostname || a.nome || a.desc || a.ip || 'вҖ”';

    // Atualiza progresso
    if (statusEl) {
      statusEl.innerHTML = '<div style="text-align:center;padding:12px;color:var(--g500)">вҸі Processando '+emoji+' '+(i+1)+'/'+lista.length+' вҖ” '+escapeHtml(hn)+'</div>';
    }

    try {
      if (modo === 'descarte') {
        var upd = {
          status: 'descarte', substatusDescarte: modalidade, descarteSAP: sap,
          descarteObs: obs, descarteData: new Date().toISOString().split('T')[0],
          descarteAutorizadoPor: CURRENT_USER?.nome || '', updatedAt: new Date().toISOString()
        };
        await fsUpdate('ativos', a.id, upd);
        Object.assign(a, upd);
        await registrarHistoricoAtivo(a.id, 'descartado', {
          modalidade, sap: sap||'вҖ”', obs, por: CURRENT_USER?.nome||'вҖ”', importacao: 'lote'
        });
      } else {
        var upd2 = {
          status: 'estoque', local: local, area: local, condicao: condicao,
          dataEstoque: new Date().toISOString().split('T')[0], updatedAt: new Date().toISOString()
        };
        var col2 = (STATE.mobiliario||[]).find(function(x){return x.id===a.id;}) ? 'mobiliario' : 'ativos';
        await fsUpdate(col2, a.id, upd2);
        Object.assign(a, upd2);
        await registrarHistoricoAtivo(a.id, 'movimentado', {
          para: 'Estoque (Reuso)', local: local, condicao: condicao,
          motivo: motivo, por: CURRENT_USER?.nome||'вҖ”', importacao: 'lote'
        });
      }
      resultados.push({ativo: a, termo: item.termo, ok: true});
    } catch(e) {
      resultados.push({ativo: a, termo: item.termo, ok: false, erro: e.message});
    }
  }

  // в”Җв”Җ Monta relatГіrio final item a item в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  var sucesso = resultados.filter(function(r){return r.ok;});
  var falhas  = resultados.filter(function(r){return !r.ok;});

  var html = '<div style="margin-bottom:10px;display:flex;gap:10px;flex-wrap:wrap;align-items:center">'
    + '<span style="font-size:13px;font-weight:800;color:'+cor+'">'+emoji+' Resultado do lote</span>'
    + '<span style="font-size:11px;background:#F0FDF4;color:#059669;padding:3px 10px;border-radius:8px;font-weight:700">вң… '+sucesso.length+' concluГӯdo'+(sucesso.length!==1?'s':'')+'</span>'
    + (falhas.length ? '<span style="font-size:11px;background:#FEF2F2;color:#DC2626;padding:3px 10px;border-radius:8px;font-weight:700">вқҢ '+falhas.length+' com erro</span>' : '')
    + '</div>';

  // Tabela de sucesso
  if (sucesso.length) {
    html += '<div style="background:#fff;border:1px solid #BBF7D0;border-radius:8px;overflow:hidden;margin-bottom:10px">'
      + '<div style="padding:7px 12px;background:#F0FDF4;font-size:11px;font-weight:700;color:#065F46">вң… CONCLUГҚDOS COM SUCESSO</div>'
      + '<div style="max-height:160px;overflow-y:auto">'
      + sucesso.map(function(r) {
          var hn = r.ativo.hostname||r.ativo.nome||r.ativo.desc||r.ativo.ip||'вҖ”';
          return '<div style="display:flex;align-items:center;gap:10px;padding:6px 12px;border-bottom:0.5px solid var(--g100)">'
            + '<span style="color:#059669;font-size:14px;flex-shrink:0">вң…</span>'
            + '<div style="flex:1;min-width:0">'
              + '<span style="font-family:monospace;font-size:12px;font-weight:600">'+escapeHtml(hn)+'</span>'
              + ' <span style="font-size:10.5px;color:var(--g400)">PAT: '+escapeHtml(r.ativo.pat||'вҖ”')+'</span>'
            + '</div>'
            + '<span style="font-size:10px;color:var(--g400)">'+escapeHtml(r.termo)+'</span>'
          + '</div>';
        }).join('')
      + '</div></div>';
  }

  // Tabela de erros вҖ” item a item com mensagem
  if (falhas.length) {
    html += '<div style="background:#fff;border:1px solid #FCA5A5;border-radius:8px;overflow:hidden;margin-bottom:10px">'
      + '<div style="padding:7px 12px;background:#FEF2F2;font-size:11px;font-weight:700;color:#DC2626">вқҢ ERROS вҖ” NГғO MOVIMENTADOS</div>'
      + '<div style="max-height:160px;overflow-y:auto">'
      + falhas.map(function(r) {
          var hn = r.ativo.hostname||r.ativo.nome||r.ativo.desc||r.ativo.ip||'вҖ”';
          return '<div style="padding:8px 12px;border-bottom:0.5px solid var(--g100)">'
            + '<div style="display:flex;align-items:center;gap:10px">'
              + '<span style="color:#DC2626;font-size:14px;flex-shrink:0">вқҢ</span>'
              + '<div style="flex:1;min-width:0">'
                + '<span style="font-family:monospace;font-size:12px;font-weight:600">'+escapeHtml(hn)+'</span>'
                + ' <span style="font-size:10.5px;color:var(--g400)">PAT: '+escapeHtml(r.ativo.pat||'вҖ”')+'</span>'
              + '</div>'
              + '<span style="font-size:10px;color:var(--g400)">'+escapeHtml(r.termo)+'</span>'
            + '</div>'
            + '<div style="margin-top:4px;margin-left:24px;font-size:11px;color:#DC2626;background:#FEF2F2;padding:3px 8px;border-radius:5px">'
              + 'вҡ  '+escapeHtml(r.erro||'Erro desconhecido')
            + '</div>'
          + '</div>';
        }).join('')
      + '</div>'
      // BotГЈo de retry para os que falharam
      + (falhas.length ? '<div style="padding:10px 12px;background:#FEF2F2;border-top:1px solid #FCA5A5">'
          + '<button data-modo="'+modo+'" onclick="reprocessarFalhas(this.dataset.modo)" style="padding:6px 14px;background:#DC2626;color:#fff;border:none;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600">рҹ”„ Tentar novamente os '+falhas.length+' com erro</button>'
          + '</div>' : '')
      + '</div>';

    // Guarda lista de falhas para retry
    window['_importFalhas_'+modo] = falhas;
  }

  if (statusEl) statusEl.innerHTML = html;
  if (applyBtn) { applyBtn.disabled = false; applyBtn.style.opacity = '1'; }

  // Atualiza o card correspondente
  if (modo === 'descarte') renderDescarte(); else renderReuso();
  if (typeof renderDashboard === 'function') renderDashboard();

  // SГі fecha o modal se TUDO funcionou
  if (!falhas.length) {
    setTimeout(function(){
      closeModal('modal-busca-'+modo);
      showToast(emoji+' Todos os '+sucesso.length+' ativos movidos com sucesso!', 'success', 5000);
    }, 1500);
  } else {
    showToast(sucesso.length+' movidos, '+falhas.length+' com erro вҖ” veja o relatГіrio', 'warning', 6000);
  }
}

// в”Җв”Җ Retry: tenta novamente sГі os que falharam в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
async function reprocessarFalhas(modo) {
  var falhas = window['_importFalhas_'+modo] || [];
  if (!falhas.length) return;
  // Recarrega a lista com sГі as falhas e tenta de novo
  window['_importLista_'+modo] = falhas.map(function(f){return {ativo:f.ativo,termo:f.termo};});
  await aplicarImportacao(modo);
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// MAPA DE REDE вҖ” Layout por Localidade (legГӯvel, imprimГӯvel)
// Agrupa os 2578 dispositivos por ГЎrea geogrГЎfica (87 localidades)
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ


// в”Җв”Җ Zoom в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ




// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// MAPA DE REDE вҖ” MODO DUPLO
//   Modo 1: VisГЈo Geral  вҖ” grafico SVG subnet/switch tree
//   Modo 2: Por Localidade вҖ” cards agrupados + ao selecionar
//           uma ГЎrea mostra o grafico filtrado daquela ГЎrea
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

var _mapaMode     = 'geral';    // 'geral' | 'areas'
var _mapaScale    = 1;
var _maPan        = {x:0, y:0};
var _mapaFiltros  = {status:'', tipo:'', local:''};
var _mapaExpanded = {};
var _mapaAreaSel  = null;       // localidade selecionada para ver grГЎfico

// в”Җв”Җ Zoom в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function mapaZoom(f) {
  if (f === 1) { _mapaScale = 1; _maPan = {x:0, y:0}; }
  else _mapaScale = Math.max(0.15, Math.min(3, _mapaScale * f));
  var inner = document.getElementById('mapa-rede-inner');
  if (inner) {
    inner.style.transform = 'translate('+_maPan.x+'px,'+_maPan.y+'px) scale('+_mapaScale+')';
    inner.style.transformOrigin = 'top left';
  }
}

// в”Җв”Җ Mudar modo в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function mapaSetMode(mode, btn) {
  _mapaMode    = mode;
  _mapaAreaSel = null;
  // Highlight active tab button
  document.querySelectorAll('.mapa-mode-btn').forEach(function(b) {
    b.style.background = 'transparent';
    b.style.color      = 'var(--g500)';
    b.style.borderBottom = '2px solid transparent';
    b.style.fontWeight = '500';
  });
  if (btn) {
    btn.style.background   = 'transparent';
    btn.style.color        = 'var(--accent,#2563EB)';
    btn.style.borderBottom = '2px solid var(--accent,#2563EB)';
    btn.style.fontWeight   = '700';
  }
  renderMapaRede();
}

// в”Җв”Җ Main render dispatcher в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function renderMapaRede() {
  var container = document.getElementById('mapa-rede-svg');
  if (!container) return;

  var todos = (STATE.switches||[]).concat(
    (STATE.ativos||[]).filter(function(a){
      return a.ip && !(STATE.switches||[]).find(function(s){return s.id===a.id;});
    })
  );

  if (!todos.length) {
    container.innerHTML = '<div style="text-align:center;padding:60px;color:var(--g400)">'
      + '<div style="font-size:48px;margin-bottom:12px">рҹҢҗ</div>'
      + '<div style="font-weight:600">Nenhum dispositivo no monitor de rede</div>'
      + '<div style="font-size:12px;margin-top:8px">Execute o discover.js na rede CESAN</div></div>';
    _mapaAtualizarBotoesModo();
    return;
  }

  // Update localidade filter dropdown
  var selLocal = document.getElementById('mon-filter-local');
  if (selLocal && selLocal.options.length <= 1) {
    var locais = [...new Set(todos.map(function(d){return resolverLocal(d);}).filter(function(l){return l&&l!=='вҖ”';}))].sort();
    locais.forEach(function(loc){
      var opt = document.createElement('option'); opt.value=loc; opt.textContent=loc; selLocal.appendChild(opt);
    });
  }

  _mapaAtualizarBotoesModo();

  if (_mapaMode === 'geral' || _mapaAreaSel) {
    _renderMapaGrafico(todos, container);
  } else {
    _renderMapaAreas(todos, container);
  }
}

function _mapaAtualizarBotoesModo() {
  // Sync mode buttons visual state on render
  var btnGeral = document.getElementById('mapa-btn-geral');
  var btnAreas = document.getElementById('mapa-btn-areas');
  if (btnGeral) {
    var gActive = _mapaMode === 'geral' || _mapaAreaSel;
    btnGeral.style.color       = gActive ? 'var(--accent,#2563EB)' : 'var(--g500)';
    btnGeral.style.borderBottom= gActive ? '2px solid var(--accent,#2563EB)' : '2px solid transparent';
    btnGeral.style.fontWeight  = gActive ? '700' : '500';
  }
  if (btnAreas) {
    var aActive = _mapaMode === 'areas' && !_mapaAreaSel;
    btnAreas.style.color       = aActive ? 'var(--accent,#2563EB)' : 'var(--g500)';
    btnAreas.style.borderBottom= aActive ? '2px solid var(--accent,#2563EB)' : '2px solid transparent';
    btnAreas.style.fontWeight  = aActive ? '700' : '500';
  }
}

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// MODO 1 вҖ” GRГҒFICO SVG (VisГЈo Geral ou ГҒrea EspecГӯfica)
// Layout: switches no centro, ativos ao redor por subnet
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function _mapaFiltBtn(campo, valor, label, cor) {
  var ativo = (_mapaFiltros||{})[campo] === valor;
  return '<button onclick="_mapaFiltros=_mapaFiltros||{};_mapaFiltros.'+campo+'=(_mapaFiltros.'+campo+'===\''+valor+'\'?\'\':\''+valor+'\');renderMapaRede()" '
    +'style="border:1px solid '+(ativo?cor:'var(--g200)')+';background:'+(ativo?cor+'22':'transparent')+';color:'+(ativo?cor:'var(--g500)')+';padding:3px 10px;border-radius:16px;cursor:pointer;'
    +'font-size:11px;font-weight:'+(ativo?'700':'400')+';cursor:pointer;white-space:nowrap">'+label+'</button>';
}

function _renderMapaGrafico(todosAll, container) {
  var todos = _mapaAreaSel
    ? todosAll.filter(function(d){ return resolverLocal(d) === _mapaAreaSel; })
    : todosAll;

  if (_mapaFiltros.status) {
    todos = todos.filter(function(d){
      var ok = d.reachable || (d.status||'').match(/^(ok|ativo|online)$/i);
      if (_mapaFiltros.status==='ok')      return ok;
      if (_mapaFiltros.status==='offline') return !ok;
      if (_mapaFiltros.status==='alerta')  return (d.status||'').toLowerCase()==='alerta';
      return true;
    });
  }
  if (_mapaFiltros.tipo) {
    todos = todos.filter(function(d){ return (d.tipo||'').toLowerCase() === _mapaFiltros.tipo; });
  }

  // в”Җв”Җ Tipos e cores в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  var SW_TIPOS = ['switch','switch-core','switch-distribuicao','switch-acesso','router','firewall','ap'];
  var switches = todos.filter(function(d){ return SW_TIPOS.includes((d.tipo||'').toLowerCase()); });
  var hosts    = todos.filter(function(d){ return !SW_TIPOS.includes((d.tipo||'').toLowerCase()); });

  function getSubnet(ip)  { var p=(ip||'').split('.'); return p.length>=3?p.slice(0,3).join('.'):''; }
  function get24(ip)      { var p=(ip||'').split('.'); return p.length>=4?p.slice(0,3).join('.'):''; }

  // ГҚcone e cor por tipo de equipamento
  function tipoIcon(tipo) {
    var t = (tipo||'').toLowerCase();
    if (t==='switch'||t==='switch-core'||t==='switch-distribuicao'||t==='switch-acesso') return {icon:'вҮҢ', cor:'#1E40AF', bg:'#1E3A8A', label:'SWITCH'};
    if (t==='router'||t==='roteador')   return {icon:'рҹҢҗ', cor:'#EA580C', bg:'#7C2D12', label:'ROUTER'};
    if (t==='firewall')                 return {icon:'рҹӣЎ', cor:'#7C3AED', bg:'#4C1D95', label:'FIREWALL'};
    if (t==='ap'||t==='access-point')   return {icon:'рҹ“Ў', cor:'#0891B2', bg:'#164E63', label:'AP'};
    if (t==='servidor'||t==='server')   return {icon:'рҹ–і', cor:'#059669', bg:'#064E3B', label:'SERVIDOR'};
    if (t==='impressora'||t==='printer')return {icon:'рҹ–Ё', cor:'#D97706', bg:'#78350F', label:'IMPRESSORA'};
    if (t==='notebook'||t==='laptop')   return {icon:'рҹ’»', cor:'#0284C7', bg:'#0C4A6E', label:'NOTEBOOK'};
    if (t==='computador'||t==='desktop'||t==='workstation') return {icon:'рҹ–Ҙ', cor:'#475569', bg:'#1E293B', label:'PC'};
    if (t==='telefone'||t==='voip')     return {icon:'рҹ“һ', cor:'#BE185D', bg:'#831843', label:'VOIP'};
    if (t==='camera'||t==='cГўmera')     return {icon:'рҹ“·', cor:'#92400E', bg:'#451A03', label:'CГӮMERA'};
    if (t==='ups'||t==='nobreak')       return {icon:'рҹ”Ӣ', cor:'#15803D', bg:'#14532D', label:'UPS'};
    return {icon:'рҹ“Ұ', cor:'#64748B', bg:'#334155', label:(tipo||'DISPOSITIVO').toUpperCase().slice(0,12)};
  }

  var statusClr = function(d){
    var s=(d.status||'').toLowerCase();
    if(d.reachable===true||s==='ok'||s==='ativo'||s==='online') return '#10B981';
    if(s==='offline') return '#EF4444';
    if(s==='alerta')  return '#F59E0B';
    return '#94A3B8';
  };

  // в”Җв”Җ Agrupamento inteligente: subnet /24 + fallback por localidade в”Җ
  var groups = [];
  var usedHosts = new Set();

  switches.sort(function(a,b){ return (a.ip||'').localeCompare(b.ip||''); });

  switches.forEach(function(sw) {
    var snSw = getSubnet(sw.ip);
    var swHosts = hosts.filter(function(h){
      // Match por /24 subnet
      if (snSw && getSubnet(h.ip) === snSw) return true;
      // Match por localidade/hostname prefix
      var swLoc = (sw.sysName||sw.hostname||'').replace(/-SW\d+$/i,'').toLowerCase();
      var hLoc  = (h.hostname||'').toLowerCase();
      if (swLoc.length > 3 && hLoc.includes(swLoc)) return true;
      return false;
    });
    swHosts.forEach(function(h){ usedHosts.add(h.id||h.ip); });
    groups.push({ sw: sw, hosts: swHosts });
  });

  // Hosts sem switch (realmente ГіrfГЈos)
  var orphans = hosts.filter(function(h){ return !usedHosts.has(h.id||h.ip); });

  // Agrupa ГіrfГЈos por /24 subnet
  if (orphans.length) {
    var orphanSubnets = {};
    orphans.forEach(function(h){
      var sn = getSubnet(h.ip) || 'sem-ip';
      if (!orphanSubnets[sn]) orphanSubnets[sn] = [];
      orphanSubnets[sn].push(h);
    });
    Object.keys(orphanSubnets).sort().forEach(function(sn){
      groups.push({ sw: null, subnet: sn, hosts: orphanSubnets[sn] });
    });
  }

  // в”Җв”Җ Layout в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  var COL_W   = 200;
  var COL_GAP = 20;
  var SW_H    = 76;
  var HOST_H  = 38;
  var HOST_GAP= 4;
  var TOP_PAD = 20;
  var SW_PAD  = 28;

  var maxHosts = Math.max.apply(null, groups.map(function(g){ return g.hosts.length; })) || 0;
  var totalH   = TOP_PAD + SW_H + SW_PAD + maxHosts * (HOST_H + HOST_GAP) + 80;
  var totalW   = Math.max(groups.length * (COL_W + COL_GAP) + 24, 900);

  // в”Җв”Җ HTML/SVG в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  var html = '';

  // Legenda de Гӯcones
  html += '<div style="display:flex;gap:12px;flex-wrap:wrap;padding:8px 14px;background:var(--g50);'
        + 'border-bottom:1px solid var(--g100);font-size:11px;color:var(--g500);align-items:center">'
        + '<span style="font-weight:700;color:var(--g700)">Legenda:</span>'
        + '<span>вҮҢ Switch</span><span>рҹҢҗ Router</span><span>рҹӣЎ Firewall</span><span>рҹ“Ў AP</span>'
        + '<span>рҹ–і Servidor</span><span>рҹ–Ё Impressora</span><span>рҹ–Ҙ PC/Desktop</span>'
        + '<span>рҹ’» Notebook</span><span>рҹ“һ VoIP</span><span>рҹ“Ұ Outro</span>'
        + '<span style="margin-left:auto;display:flex;gap:8px">'
        + '<span style="display:flex;align-items:center;gap:3px"><span style="width:8px;height:8px;border-radius:50%;background:#10B981;display:inline-block"></span>Online</span>'
        + '<span style="display:flex;align-items:center;gap:3px"><span style="width:8px;height:8px;border-radius:50%;background:#EF4444;display:inline-block"></span>Offline</span>'
        + '<span style="display:flex;align-items:center;gap:3px"><span style="width:8px;height:8px;border-radius:50%;background:#F59E0B;display:inline-block"></span>Alerta</span>'
        + '<span style="display:flex;align-items:center;gap:3px"><span style="width:8px;height:8px;border-radius:50%;background:#94A3B8;display:inline-block"></span>Sem dados</span>'
        + '</span></div>';

  html += '<div style="overflow-x:auto;overflow-y:auto;position:relative;max-height:calc(70vh - 40px)">'
        + '<svg xmlns="http://www.w3.org/2000/svg" width="'+(totalW+40)+'" height="'+totalH
        + '" style="display:block;padding:12px;min-width:'+(totalW+40)+'px">';

  groups.forEach(function(g, gi) {
    var x   = gi * (COL_W + COL_GAP) + 12;
    var sw  = g.sw;
    var swY = TOP_PAD;

    // в”Җв”Җ Switch / Gateway node в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    if (sw) {
      var ti      = tipoIcon(sw.tipo);
      var swSt    = statusClr(sw);
      var swLabel = (sw.sysName || sw.hostname || sw.ip || '?').slice(0,20);
      var latMs   = sw.latencyMs != null ? sw.latencyMs+'ms' : '';

      // Background gradient rect
      html += '<defs><linearGradient id="swg'+gi+'" x1="0" y1="0" x2="0" y2="1">'
            + '<stop offset="0%" stop-color="'+ti.bg+'"/>'
            + '<stop offset="100%" stop-color="'+ti.cor+'" stop-opacity="0.85"/>'
            + '</linearGradient></defs>';
      html += '<rect x="'+x+'" y="'+swY+'" width="'+COL_W+'" height="'+SW_H+'" rx="10" fill="url(#swg'+gi+')"/>';
      // Borda status
      html += '<rect x="'+x+'" y="'+swY+'" width="'+COL_W+'" height="'+SW_H+'" rx="10" fill="none" stroke="'+swSt+'" stroke-width="2" stroke-opacity="0.6"/>';
      // Status dot
      html += '<circle cx="'+(x+COL_W-12)+'" cy="'+(swY+12)+'" r="5" fill="'+swSt+'"/>';
      // ГҚcone tipo
      html += '<text x="'+(x+12)+'" y="'+(swY+38)+'" font-size="20">'+ti.icon+'</text>';
      // Label tipo
      html += '<text x="'+(x+38)+'" y="'+(swY+16)+'" font-size="8" font-weight="700" fill="rgba(255,255,255,.55)" letter-spacing="0.5">'+ti.label+'</text>';
      // Hostname
      html += '<text x="'+(x+38)+'" y="'+(swY+30)+'" font-size="10" font-weight="700" fill="#fff" font-family="monospace">'+escapeHtml(swLabel)+'</text>';
      // IP
      html += '<text x="'+(x+38)+'" y="'+(swY+44)+'" font-size="8.5" fill="rgba(255,255,255,.65)" font-family="monospace">'+escapeHtml(sw.ip||'')+'</text>';
      // LatГӘncia
      if (latMs) html += '<text x="'+(x+12)+'" y="'+(swY+58)+'" font-size="8" fill="rgba(255,255,255,.5)">'+escapeHtml(latMs)+'</text>';
      // NВә de hosts
      html += '<text x="'+(x+COL_W-12)+'" y="'+(swY+54)+'" font-size="8" fill="rgba(255,255,255,.5)" text-anchor="end">'+g.hosts.length+' hosts</text>';

      // Linha vertical do switch вҶ’ hosts
      if (g.hosts.length) {
        var lx  = x + COL_W/2;
        var ly1 = swY + SW_H;
        var ly2 = TOP_PAD + SW_H + SW_PAD + (g.hosts.length-1)*(HOST_H+HOST_GAP) + HOST_H/2;
        html += '<line x1="'+lx+'" y1="'+ly1+'" x2="'+lx+'" y2="'+ly2+'" stroke="#CBD5E1" stroke-width="1.5" stroke-dasharray="4 3"/>';
        g.hosts.forEach(function(h,hi){
          var hy2 = TOP_PAD + SW_H + SW_PAD + hi*(HOST_H+HOST_GAP) + HOST_H/2;
          html += '<line x1="'+lx+'" y1="'+hy2+'" x2="'+(x+6)+'" y2="'+hy2+'" stroke="#CBD5E1" stroke-width="1"/>';
        });
      }
    } else {
      // Grupo sem switch вҖ” cabeГ§alho de subnet
      var subnet = g.subnet || 'Sem rede';
      html += '<rect x="'+x+'" y="'+swY+'" width="'+COL_W+'" height="'+SW_H+'" rx="10" fill="#334155" stroke="#475569" stroke-width="1.5"/>';
      html += '<text x="'+(x+COL_W/2)+'" y="'+(swY+22)+'" text-anchor="middle" font-size="9" font-weight="700" fill="rgba(255,255,255,.4)" letter-spacing="0.5">SEM SWITCH</text>';
      html += '<text x="'+(x+COL_W/2)+'" y="'+(swY+38)+'" text-anchor="middle" font-size="11" fill="rgba(255,255,255,.7)" font-family="monospace">'+escapeHtml(subnet)+'.*</text>';
      html += '<text x="'+(x+COL_W/2)+'" y="'+(swY+54)+'" text-anchor="middle" font-size="8" fill="rgba(255,255,255,.4)">'+g.hosts.length+' dispositivos</text>';
      // Linha tracejada para hosts
      if (g.hosts.length) {
        var lx  = x + COL_W/2;
        var ly1 = swY + SW_H;
        var ly2 = TOP_PAD + SW_H + SW_PAD + (g.hosts.length-1)*(HOST_H+HOST_GAP) + HOST_H/2;
        html += '<line x1="'+lx+'" y1="'+ly1+'" x2="'+lx+'" y2="'+ly2+'" stroke="#475569" stroke-width="1.5" stroke-dasharray="3 4"/>';
        g.hosts.forEach(function(h,hi){
          var hy2 = TOP_PAD + SW_H + SW_PAD + hi*(HOST_H+HOST_GAP) + HOST_H/2;
          html += '<line x1="'+lx+'" y1="'+hy2+'" x2="'+(x+6)+'" y2="'+hy2+'" stroke="#475569" stroke-width="1"/>';
        });
      }
    }

    // в”Җв”Җ Hosts в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    var hostStartY = TOP_PAD + SW_H + SW_PAD;
    g.hosts.forEach(function(h, hi) {
      var hy     = hostStartY + hi * (HOST_H + HOST_GAP);
      var hSt    = statusClr(h);
      var hTi    = tipoIcon(h.tipo);
      var hLabel = (h.hostname || h.sysName || h.ip || '?').slice(0,22);
      var hIp    = h.ip || '';

      // Cor de fundo baseada em status
      var hBg     = hSt==='#10B981'?'#F0FDF4' : hSt==='#EF4444'?'#FEF2F2' : hSt==='#F59E0B'?'#FFFBEB' : '#F8FAFC';
      var hBorder = hSt;

      html += '<rect x="'+x+'" y="'+hy+'" width="'+COL_W+'" height="'+HOST_H+'" rx="6" fill="'+hBg+'" stroke="'+hBorder+'" stroke-width="0.8" stroke-opacity="0.5"/>';

      // Faixa colorida Г  esquerda indicando tipo
      html += '<rect x="'+x+'" y="'+hy+'" width="4" height="'+HOST_H+'" rx="3" fill="'+hTi.cor+'"/>';

      // Status dot
      html += '<circle cx="'+(x+14)+'" cy="'+(hy+HOST_H/2)+'" r="4" fill="'+hSt+'"/>';

      // ГҚcone tipo
      html += '<text x="'+(x+25)+'" y="'+(hy+HOST_H/2+4)+'" font-size="11">'+hTi.icon+'</text>';

      // Label hostname
      html += '<text x="'+(x+40)+'" y="'+(hy+HOST_H/2-2)+'" font-size="8.5" fill="#1E293B" font-family="monospace" font-weight="600">'+escapeHtml(hLabel)+'</text>';

      // IP menor embaixo
      if (hIp && hIp !== hLabel) {
        html += '<text x="'+(x+40)+'" y="'+(hy+HOST_H/2+9)+'" font-size="7.5" fill="#94A3B8" font-family="monospace">'+escapeHtml(hIp)+'</text>';
      }

      // LatГӘncia (se disponГӯvel)
      if (h.latencyMs != null) {
        var latCor = h.latencyMs < 5 ? '#10B981' : h.latencyMs < 30 ? '#F59E0B' : '#EF4444';
        html += '<text x="'+(x+COL_W-5)+'" y="'+(hy+HOST_H/2+4)+'" font-size="7.5" fill="'+latCor+'" text-anchor="end">'+h.latencyMs+'ms</text>';
      }
    });
  });

  html += '</svg></div>';
  container.innerHTML = html;
}


// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// MODO 2 вҖ” CARDS POR LOCALIDADE
// Cards agrupados. Ao clicar numa localidade вҶ’ abre grГЎfico SVG filtrado
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function _renderMapaAreas(todos, container) {
  // Group by area
  var grupos = {};
  todos.forEach(function(d) {
    var local = resolverLocal(d) || 'Sem localidade';
    if (!grupos[local]) grupos[local] = {nome:local, devs:[]};
    grupos[local].devs.push(d);
  });
  var locais = Object.values(grupos).sort(function(a,b){return a.nome.localeCompare(b.nome);});

  var totalOnline  = todos.filter(function(d){return d.reachable||(d.status||'').match(/^(ok|ativo|online)$/i);}).length;
  var totalOffline = todos.filter(function(d){return (d.status||'').toLowerCase()==='offline';}).length;

  var tipoIco = {switch:'вҮҢ',router:'рҹҢҗ',firewall:'рҹ”Ҙ',ap:'рҹ“Ў','switch-core':'вҳ…','switch-distribuicao':'вҮҢ','switch-acesso':'вҮҢ',servidor:'рҹ–Ҙ',workstation:'рҹ’»',notebook:'рҹ’»',impressora:'рҹ–Ё',printer:'рҹ–Ё'};

  var html = '';

  // Stats bar
  html += '<div style="display:flex;gap:16px;align-items:center;padding:10px 14px;background:var(--g50);border-bottom:0.5px solid var(--g100);font-size:12px">'
    +'<span style="font-weight:700;color:var(--g900)">'+locais.length+' localidades В· '+todos.length+' dispositivos</span>'
    +'<span style="color:#059669">рҹҹў '+totalOnline+' online</span>'
    +'<span style="color:#EF4444">рҹ”ҙ '+totalOffline+' offline</span>'
    +'<div style="margin-left:auto;display:flex;gap:6px">'
      +'<button onclick="Object.keys(_mapaExpanded).forEach(function(k){_mapaExpanded[k]=true});renderMapaRede()" style="border:1px solid var(--g200);background:var(--panel);padding:3px 9px;border-radius:6px;cursor:pointer;font-size:11px">вҠһ Tudo</button>'
      +'<button onclick="Object.keys(_mapaExpanded).forEach(function(k){_mapaExpanded[k]=false});renderMapaRede()" style="border:1px solid var(--g200);background:var(--panel);padding:3px 9px;border-radius:6px;cursor:pointer;font-size:11px">вҠҹ Recolher</button>'
    +'</div>'
  +'</div>';

  // Grid
  html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:10px;padding:12px">';

  locais.forEach(function(grp) {
    var devs     = grp.devs;
    var onL      = devs.filter(function(d){return d.reachable||(d.status||'').match(/^(ok|ativo|online)$/i);}).length;
    var offL     = devs.filter(function(d){return (d.status||'').toLowerCase()==='offline';}).length;
    var alertaL  = devs.filter(function(d){return (d.status||'').toLowerCase()==='alerta';}).length;
    var expanded = _mapaExpanded[grp.nome];
    var pct      = devs.length ? Math.round(onL/devs.length*100) : 0;
    var barC     = pct===100?'#059669':pct>=80?'#D97706':'#DC2626';

    html += '<div style="background:var(--panel);border:0.5px solid var(--line,#e2e8f0);border-radius:10px;overflow:hidden">';

    // Header вҖ” clique expande ou abre grГЎfico via botГЈo
    html += '<div onclick="mapaToggleLocal(\''+escapeHtml(grp.nome)+'\')" style="background:linear-gradient(90deg,#0F172A,#1E293B);padding:10px 12px;cursor:pointer;display:flex;align-items:center;gap:8px">'
      +'<div style="flex:1;min-width:0">'
        +'<div style="font-weight:800;font-size:12.5px;color:#F1F5F9;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+escapeHtml(grp.nome)+'</div>'
        +'<div style="font-size:10px;color:#94A3B8;margin-top:2px">'+devs.length+' dispositivos</div>'
      +'</div>'
      +'<div style="display:flex;gap:4px;align-items:center;flex-shrink:0">'
        +(onL?'<span style="font-size:10px;background:#05966930;color:#34D399;padding:1px 5px;border-radius:5px;font-weight:700">'+onL+'вң“</span>':'')
        +(offL?'<span style="font-size:10px;background:#DC262625;color:#F87171;padding:1px 5px;border-radius:5px;font-weight:700">'+offL+'вң—</span>':'')
        +(alertaL?'<span style="font-size:10px;background:#D9770630;color:#FCD34D;padding:1px 5px;border-radius:5px;font-weight:700">'+alertaL+'!</span>':'')
      +'</div>'
      // BotГЈo para abrir grГЎfico SVG desta ГЎrea
      +'<button onclick="event.stopPropagation();mapaAbrirGraficoArea(\''+escapeHtml(grp.nome)+'\')" '
        +'style="border:1px solid #ffffff22;background:#ffffff11;color:#94A3B8;border-radius:5px;padding:3px 8px;cursor:pointer;font-size:10px;flex-shrink:0" title="Ver grГЎfico desta ГЎrea">рҹ“Ҡ</button>'
      +'<span style="color:#94A3B8;font-size:11px;flex-shrink:0">'+(expanded?'в–ҫ':'в–ё')+'</span>'
    +'</div>';

    // Barra de saГәde
    html += '<div style="height:3px;background:#1E293B"><div style="height:100%;width:'+pct+'%;background:'+barC+'"></div></div>';

    if (expanded) {
      // Lista completa
      html += '<div style="padding:8px 10px;max-height:260px;overflow-y:auto">';
      devs.forEach(function(d) {
        var hn  = d.hostname||d.sysName||d.desc||d.ip||'вҖ”';
        var ico = tipoIco[(d.tipo||'').toLowerCase()]||'рҹ“Ұ';
        var sc  = (d.reachable||(d.status||'').match(/^(ok|ativo|online)$/i)) ? '#10B981'
                   : (d.status||'').toLowerCase()==='alerta' ? '#F59E0B' : '#EF4444';
        var lat = d.latencyMs!=null ? d.latencyMs.toFixed(1)+'ms' : '';
        html += '<div style="display:flex;align-items:center;gap:7px;padding:4px 0;border-bottom:0.5px solid var(--g50)">'
          +'<span style="font-size:12px">'+ico+'</span>'
          +'<div style="flex:1;min-width:0">'
            +'<div style="font-size:11.5px;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;font-family:monospace">'+escapeHtml(hn.slice(0,24))+'</div>'
            +'<div style="font-size:10px;color:var(--g400)">'+escapeHtml(d.ip||'вҖ”')+'</div>'
          +'</div>'
          +'<div style="display:flex;align-items:center;gap:4px;flex-shrink:0">'
            +(lat?'<span style="font-size:9px;color:var(--g400);font-family:monospace">'+lat+'</span>':'')
            +'<div style="width:7px;height:7px;border-radius:50%;background:'+sc+'"></div>'
          +'</div>'
        +'</div>';
      });
      html += '</div>';
    } else {
      // Mini dots grid
      html += '<div style="padding:8px 10px 10px">';
      // Tipo summary badges
      var byTipo = {};
      devs.forEach(function(d){var t=(d.tipo||'ativo').toLowerCase();byTipo[t]=(byTipo[t]||0)+1;});
      html += '<div style="display:flex;flex-wrap:wrap;gap:4px;margin-bottom:7px">';
      Object.entries(byTipo).sort(function(a,b){return b[1]-a[1];}).slice(0,5).forEach(function(e){
        html += '<span style="font-size:10px;background:var(--g100);padding:1px 7px;border-radius:5px;color:var(--g600)">'+(tipoIco[e[0]]||'рҹ“Ұ')+' '+e[1]+' '+e[0]+'</span>';
      });
      html += '</div>';
      // Dots
      html += '<div style="display:flex;flex-wrap:wrap;gap:2px">';
      devs.forEach(function(d){
        var sc2 = (d.reachable||(d.status||'').match(/^(ok|ativo|online)$/i)) ? '#10B981'
                  : (d.status||'').toLowerCase()==='alerta' ? '#F59E0B' : '#94A3B8';
        html += '<div title="'+escapeHtml(d.hostname||d.ip||'вҖ”')+'" style="width:9px;height:9px;border-radius:2px;background:'+sc2+'"></div>';
      });
      html += '</div></div>';
    }
    html += '</div>';
  });

  html += '</div>';
  container.innerHTML = html;
}

function mapaToggleLocal(nome) {
  _mapaExpanded[nome] = !_mapaExpanded[nome];
  renderMapaRede();
}

function mapaAbrirGraficoArea(nome) {
  _mapaAreaSel = nome;
  _mapaScale   = 1;
  _maPan       = {x:0, y:0};
  renderMapaRede();
}

// в”Җв”Җ ImpressГЈo PDF в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function mapaImprimir() {
  var todos = (STATE.switches||[]).concat(
    (STATE.ativos||[]).filter(function(a){return a.ip&&!(STATE.switches||[]).find(function(s){return s.id===a.id;});})
  );
  var grupos = {};
  todos.forEach(function(d){
    var local = resolverLocal(d)||'Sem localidade';
    if (!grupos[local]) grupos[local]={nome:local,devs:[]};
    grupos[local].devs.push(d);
  });
  var locais = Object.values(grupos).sort(function(a,b){return a.nome.localeCompare(b.nome);});
  var onAll  = todos.filter(function(d){return d.reachable||(d.status||'').match(/^(ok|ativo|online)$/i);}).length;

  var win = window.open('','_blank','width=1400,height=900');
  win.document.write('<!DOCTYPE html><html><head><title>Mapa de Rede CESAN</title><meta charset="UTF-8"><style>'
    +'@page{size:A3 landscape;margin:10mm}*{box-sizing:border-box;margin:0;padding:0}'
    +'body{font-family:Arial,sans-serif;font-size:10px;background:#fff;color:#111}'
    +'.header{display:flex;justify-content:space-between;align-items:flex-end;padding-bottom:6px;border-bottom:2px solid #0F172A;margin-bottom:10px}'
    +'.header h1{font-size:17px;font-weight:900;color:#0F172A}'
    +'.stats{display:flex;gap:12px;margin-bottom:10px}'
    +'.stat{background:#F1F5F9;border-radius:5px;padding:5px 10px;font-size:10px}'
    +'.stat strong{font-size:15px;display:block;font-weight:900}'
    +'.grid{display:grid;grid-template-columns:repeat(4,1fr);gap:7px}'
    +'.card{border:1px solid #E2E8F0;border-radius:7px;overflow:hidden;page-break-inside:avoid}'
    +'.card-head{background:#0F172A;color:#F1F5F9;padding:6px 9px}'
    +'.card-head .nome{font-weight:800;font-size:11px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}'
    +'.badges{display:flex;gap:3px;margin-top:2px}'
    +'.b{font-size:9px;padding:1px 4px;border-radius:3px;font-weight:700}'
    +'.b-ok{background:#05966930;color:#059669}.b-off{background:#DC262625;color:#DC2626}'
    +'.bar{height:3px;background:#1E293B}'
    +'.devs{padding:5px 7px}'
    +'.dev{display:flex;align-items:center;gap:4px;padding:2px 0;border-bottom:0.5px solid #F1F5F9;font-size:9px}'
    +'.dev:last-child{border:none}'
    +'.dot{width:5px;height:5px;border-radius:50%;flex-shrink:0}'
    +'.dn{background:#10B981}.df{background:#EF4444}.da{background:#F59E0B}.dd{background:#94A3B8}'
    +'.hn{font-family:monospace;font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;flex:1}'
    +'.ip{color:#94A3B8;font-family:monospace;flex-shrink:0;font-size:8px}'
    +'.lat{color:#94A3B8;flex-shrink:0;min-width:28px;text-align:right;font-size:8px}'
    +'</style></head><body>');

  win.document.write('<div class="header"><div><h1>рҹҢҗ Mapa de Rede вҖ” CESAN</h1>'
    +'<div style="font-size:10px;color:#475569;margin-top:2px">SYSACK В· A-DSI В· '+new Date().toLocaleString('pt-BR')+'</div></div>'
    +'<div style="text-align:right;font-size:10px;color:#475569">'+todos.length+' dispositivos В· '+locais.length+' localidades</div></div>');

  win.document.write('<div class="stats">'
    +'<div class="stat"><strong style="color:#059669">'+onAll+'</strong>Online</div>'
    +'<div class="stat"><strong style="color:#DC2626">'+(todos.length-onAll)+'</strong>Offline/Alerta</div>'
    +'<div class="stat"><strong>'+locais.length+'</strong>Localidades</div>'
    +'<div class="stat"><strong>'+todos.length+'</strong>Total</div>'
    +'</div>');

  win.document.write('<div class="grid">');
  locais.forEach(function(grp) {
    var devs    = grp.devs;
    var onL     = devs.filter(function(d){return d.reachable||(d.status||'').match(/^(ok|ativo|online)$/i);}).length;
    var offL    = devs.filter(function(d){return (d.status||'').toLowerCase()==='offline';}).length;
    var pct     = devs.length?Math.round(onL/devs.length*100):0;
    var barC    = pct===100?'#059669':pct>=80?'#D97706':'#DC2626';
    win.document.write('<div class="card"><div class="card-head"><div class="nome">'+grp.nome+'</div>'
      +'<div class="badges">'
        +(onL?'<span class="b b-ok">'+onL+'вң“</span>':'')
        +(offL?'<span class="b b-off">'+offL+'вң—</span>':'')
        +'<span style="font-size:8px;color:#94A3B8;margin-left:auto">'+devs.length+'</span>'
      +'</div></div>'
      +'<div class="bar"><div style="height:100%;width:'+pct+'%;background:'+barC+'"></div></div>'
      +'<div class="devs">');
    devs.forEach(function(d){
      var hn  = (d.hostname||d.sysName||d.desc||d.ip||'вҖ”').slice(0,20);
      var st  = (d.status||'').toLowerCase();
      var ok  = d.reachable||st.match(/^(ok|ativo|online)$/);
      var dc  = ok?'dn':st==='alerta'?'da':st==='offline'?'df':'dd';
      var lat = d.latencyMs!=null?d.latencyMs.toFixed(0)+'ms':'';
      var ip  = (d.ip||'').replace(/^172\.\d+\./,'172.*.');
      win.document.write('<div class="dev"><div class="dot '+dc+'"></div><span class="hn">'+hn+'</span><span class="ip">'+ip+'</span><span class="lat">'+lat+'</span></div>');
    });
    win.document.write('</div></div>');
  });
  win.document.write('</div></body></html>');
  win.document.close();
  setTimeout(function(){win.print();},700);
}


// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// MDM вҖ” Cadastrar Smartphone
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

// в”Җв”Җ Busca de empregado com dropdown (campo responsГЎvel smartphone) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
let _smEmpTimer = null;

function smBuscarEmpregadoLista(q) {
  clearTimeout(_smEmpTimer);
  const res = document.getElementById('sm-emp-resultados');
  if (!q || q.length < 2) { if (res) res.style.display = 'none'; return; }
  _smEmpTimer = setTimeout(() => _smExecBusca(q), 200);
}

function _smExecBusca(q) {
  const res = document.getElementById('sm-emp-resultados');
  if (!res) return;

  const qLow = q.toLowerCase();
  const emps = (STATE.empregados || []).filter(e =>
    (e.nome   || '').toLowerCase().includes(qLow) ||
    (e.mat    || '').toLowerCase().includes(qLow) ||
    (e.login  || '').toLowerCase().includes(qLow) ||
    (e.email  || '').toLowerCase().includes(qLow) ||
    (e.setor  || '').toLowerCase().includes(qLow)
  ).slice(0, 10);

  if (!emps.length) {
    res.innerHTML = '<div style="padding:10px 14px;font-size:12px;color:var(--g400)">Nenhum empregado encontrado</div>';
    res.style.display = '';
    return;
  }

  res.innerHTML = emps.map((e, i) => {
    const iniciais = (e.nome || '?').split(' ').slice(0,2).map(p => p[0]).join('').toUpperCase();
    return `<div data-idx="${i}"
      onclick="smSelecionarEmpregado(${JSON.stringify(e).replace(/"/g,'&quot;')})"
      style="padding:9px 14px;cursor:pointer;border-bottom:1px solid var(--g100);display:flex;gap:10px;align-items:center"
      onmouseover="this.style.background='var(--g50)'" onmouseout="this.style.background=''">
      <div style="width:32px;height:32px;border-radius:50%;background:var(--accent);color:#fff;
                  display:flex;align-items:center;justify-content:center;font-size:11px;
                  font-weight:700;flex-shrink:0">${iniciais}</div>
      <div style="flex:1;min-width:0">
        <div style="font-weight:600;font-size:12.5px;color:var(--g900)">${escapeHtml(e.nome || 'вҖ”')}</div>
        <div style="font-size:11px;color:var(--g400)">${escapeHtml(e.mat || '')} В· ${escapeHtml(e.setor || e.lotacao || '')}</div>
      </div>
      <div style="font-size:11px;color:var(--g500);flex-shrink:0">${escapeHtml(e.login || '')}</div>
    </div>`;
  }).join('');

  res.style.display = '';
}

function smSelecionarEmpregado(emp) {
  // Preenche campos hidden
  const setH = (id, val) => { const el = document.getElementById(id); if (el) el.value = val || ''; };
  setH('sm-emp-id',    emp.id    || '');
  setH('sm-emp-mat',   emp.mat   || emp.matricula || '');
  setH('sm-emp-nome',  emp.nome  || '');
  setH('sm-emp-login', emp.login || emp.empLogin  || '');
  setH('sm-emp-setor', emp.setor || emp.lotacao   || '');

  // Mostra card do empregado
  const card = document.getElementById('sm-emp-selecionado');
  const av   = document.getElementById('sm-emp-avatar');
  const nm   = document.getElementById('sm-emp-nome-card');
  const inf  = document.getElementById('sm-emp-info-card');
  if (card) card.style.display = '';
  if (av)   av.textContent  = (emp.nome || '?').split(' ').slice(0,2).map(p=>p[0]).join('').toUpperCase();
  if (nm)   nm.textContent  = emp.nome || 'вҖ”';
  if (inf)  inf.textContent = [emp.mat, emp.setor || emp.lotacao, emp.login].filter(Boolean).join(' В· ');

  // Limpa busca e fecha dropdown
  const busca = document.getElementById('sm-emp-busca');
  const res   = document.getElementById('sm-emp-resultados');
  if (busca) busca.value = '';
  if (res)   res.style.display = 'none';
}

function smLimparEmpregado() {
  ['sm-emp-id','sm-emp-mat','sm-emp-nome','sm-emp-login','sm-emp-setor'].forEach(id => {
    const el = document.getElementById(id); if (el) el.value = '';
  });
  const card = document.getElementById('sm-emp-selecionado');
  if (card) card.style.display = 'none';
  const busca = document.getElementById('sm-emp-busca');
  if (busca) { busca.value = ''; busca.focus(); }
}

function smBuscaKeyDown(e) {
  if (e.key === 'Escape') {
    document.getElementById('sm-emp-resultados').style.display = 'none';
  }
}

// Fecha dropdown ao clicar fora
document.addEventListener('click', e => {
  if (!e.target.closest('#sm-emp-busca') && !e.target.closest('#sm-emp-resultados')) {
    const res = document.getElementById('sm-emp-resultados');
    if (res) res.style.display = 'none';
  }
});

// MantГ©m compatibilidade com chamadas antigas
function smBuscarEmpregado(mat) { smBuscarEmpregadoLista(mat); }

// в”Җв”Җ CГўmera para capturar IMEI в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
let _smCameraStream = null;
let _smOcrTimer     = null;
let _smTargetField  = null;

async function smAbrirCamera(targetFieldId) {
  _smTargetField = targetFieldId;
  const overlay = document.getElementById('sm-camera-overlay');
  if (!overlay) return;
  overlay.style.display = 'flex';

  try {
    _smCameraStream = await navigator.mediaDevices.getUserMedia({
      video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } }
    });
    const video = document.getElementById('sm-camera-video');
    video.srcObject = _smCameraStream;
    await video.play();
    _smIniciarOCR();
  } catch(e) {
    smFecharCamera();
    showToast('CГўmera nГЈo disponГӯvel: ' + e.message, 'danger');
  }
}

function smFecharCamera() {
  clearInterval(_smOcrTimer);
  if (_smCameraStream) {
    _smCameraStream.getTracks().forEach(t => t.stop());
    _smCameraStream = null;
  }
  const overlay = document.getElementById('sm-camera-overlay');
  if (overlay) overlay.style.display = 'none';
  const video = document.getElementById('sm-camera-video');
  if (video) video.srcObject = null;
}

function _smIniciarOCR() {
  clearInterval(_smOcrTimer);
  _smOcrTimer = setInterval(async () => {
    const video   = document.getElementById('sm-camera-video');
    const status  = document.getElementById('sm-camera-status');
    if (!video || video.readyState < 2) return;

    // Captura frame atual
    const canvas  = document.createElement('canvas');
    canvas.width  = video.videoWidth;
    canvas.height = video.videoHeight;
    canvas.getContext('2d').drawImage(video, 0, 0);
    const base64  = canvas.toDataURL('image/jpeg', 0.85).split(',')[1];

    if (status) status.textContent = 'рҹ”Қ Analisando...';

    try {
      const resp = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: 'claude-sonnet-4-20250514',
          max_tokens: 100,
          messages: [{
            role: 'user',
            content: [
              { type: 'image', source: { type: 'base64', media_type: 'image/jpeg', data: base64 } },
              { type: 'text',  text: 'Esta imagem mostra um IMEI de celular. Extraia APENAS o nГәmero do IMEI (15 dГӯgitos). Responda SOMENTE com os 15 dГӯgitos, sem espaГ§os, traГ§os ou qualquer outro texto. Se nГЈo houver IMEI visГӯvel, responda com a palavra NONE.' }
            ]
          }]
        })
      });

      const data  = await resp.json();
      const texto = (data.content?.[0]?.text || '').trim().replace(/\D/g, '');

      if (texto.length === 15) {
        clearInterval(_smOcrTimer);
        // Vibra (se mobile)
        navigator.vibrate?.(200);
        if (status) status.textContent = `вң“ IMEI detectado: ${texto}`;
        // Preenche campo alvo
        const campo = document.getElementById(_smTargetField);
        if (campo) {
          campo.value = texto;
          campo.dispatchEvent(new Event('input'));
        }
        // Fecha cГўmera apГіs 1.5s
        setTimeout(smFecharCamera, 1500);
      } else {
        if (status) status.textContent = 'рҹ“· Aponte para o IMEI...';
      }
    } catch(e) {
      if (status) status.textContent = 'вҡ  Erro OCR вҖ” tentando novamente...';
    }
  }, 1800); // analisa a cada 1.8s
}

function smUploadFotoImei(targetFieldId) {
  _smTargetField = targetFieldId;
  const input = document.createElement('input');
  input.type = 'file';
  input.accept = 'image/*';
  input.onchange = async e => {
    const file = e.target.files[0];
    if (!file) return;
    const status = document.getElementById('sm-imei1-status') || document.getElementById('sm-imei2-status');
    if (status) status.textContent = 'рҹӨ– Extraindo IMEI da foto...';

    const base64 = await new Promise((res, rej) => {
      const r = new FileReader();
      r.onload = () => res(r.result.split(',')[1]);
      r.onerror = rej;
      r.readAsDataURL(file);
    });

    try {
      const resp = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: 'claude-sonnet-4-20250514',
          max_tokens: 100,
          messages: [{
            role: 'user',
            content: [
              { type: 'image', source: { type: 'base64', media_type: file.type || 'image/jpeg', data: base64 } },
              { type: 'text',  text: 'Esta imagem mostra um IMEI de celular. Extraia APENAS o nГәmero do IMEI (15 dГӯgitos). Responda SOMENTE com os 15 dГӯgitos, sem espaГ§os, traГ§os ou qualquer outro texto. Se nГЈo houver IMEI visГӯvel ou for ilegГӯvel, responda com a palavra NONE.' }
            ]
          }]
        })
      });
      const data  = await resp.json();
      const texto = (data.content?.[0]?.text || '').trim().replace(/\D/g, '');
      if (texto.length === 15) {
        const campo = document.getElementById(_smTargetField);
        if (campo) { campo.value = texto; campo.dispatchEvent(new Event('input')); }
        showToast(`вң“ IMEI ${texto} extraГӯdo da foto!`, 'success');
        if (status) status.textContent = `вң“ ${texto}`;
      } else {
        showToast('IMEI nГЈo encontrado na foto. Tente com melhor iluminaГ§ГЈo.', 'warning');
        if (status) status.textContent = '';
      }
    } catch(e) {
      showToast('Erro ao processar foto: ' + e.message, 'danger');
    }
  };
  input.click();
}

// в”Җв”Җ Salvar Smartphone в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
async function salvarSmartphone() {
  const marca  = document.getElementById('sm-marca')?.value;
  const modelo = document.getElementById('sm-modelo')?.value?.trim();
  const imei1  = document.getElementById('sm-imei1')?.value?.trim();

  if (!marca)  return showToast('Selecione a marca', 'danger');
  if (!modelo) return showToast('Informe o modelo', 'danger');
  if (!imei1 || imei1.length !== 15) return showToast('IMEI 1 invГЎlido вҖ” deve ter 15 dГӯgitos', 'danger');

  // Verifica Firebase disponГӯvel
  if (!FB_READY || !db) {
    return showToast('Banco de dados nГЈo disponГӯvel. Verifique a conexГЈo.', 'danger');
  }

  // Verifica duplicata pelo IMEI direto no Firestore
  const jaExiste = (STATE.smartphones || []).find(s => s.imei1 === imei1);
  if (jaExiste) return showToast(`IMEI jГЎ cadastrado: ${jaExiste.marca} ${jaExiste.modelo}`, 'danger');

  // Coleta dados do empregado (campos hidden preenchidos por smSelecionarEmpregado)
  const empId    = document.getElementById('sm-emp-id')?.value?.trim()    || '';
  const empMat   = document.getElementById('sm-emp-mat')?.value?.trim()   || '';
  const empNome  = document.getElementById('sm-emp-nome')?.value?.trim()  || '';
  const empLogin = document.getElementById('sm-emp-login')?.value?.trim() || '';
  const empSetor = document.getElementById('sm-emp-setor')?.value?.trim() || '';
  const linha    = (document.getElementById('sm-linha')?.value?.trim() || '').replace(/\D/g, '');

  const agora = new Date();
  const novo = {
    marca,
    modelo,
    so:             document.getElementById('sm-so')?.value || 'Android',
    versao:         document.getElementById('sm-versao')?.value?.trim() || '',
    imei1,
    imei2:          document.getElementById('sm-imei2')?.value?.trim() || '',
    serie:          document.getElementById('sm-serie')?.value?.trim() || '',
    linha,
    operadora:      document.getElementById('sm-operadora')?.value || '',
    // VГӯnculo com empregado
    empId,
    empMat,
    empNome,
    empLogin,
    empSetor,
    // Status
    status:         document.getElementById('sm-status')?.value || 'estoque',
    ultimaTroca:    document.getElementById('sm-ultima-troca')?.value || null,
    obs:            document.getElementById('sm-obs')?.value?.trim() || '',
    mdmCompliant:   false,
    origemCadastro: 'manual',
    createdAt:      agora,
    criadoPor:      CURRENT_USER?.nome || CURRENT_USER?.uid || '',
  };

  // Feedback visual no botГЈo
  const btn = document.querySelector('#modal-novo-smartphone .btn-primary');
  if (btn) { btn.disabled = true; btn.textContent = 'вҸі Salvando...'; }

  try {
    // 1. Salva o smartphone no Firestore
    const ref = await db.collection('smartphones').add(novo);
    novo.id = ref.id;

    // 2. Registra no histГіrico do smartphone
    await ref.collection('historico').add({
      evento:    'cadastro-manual',
      data:      agora,
      usuario:   CURRENT_USER?.nome || CURRENT_USER?.uid || 'Sistema',
      userRole:  CURRENT_USER?.role || '',
      obs:       `Smartphone cadastrado manualmente вҖ” ${marca} ${modelo} В· IMEI: ${imei1}` +
                 (empNome ? ` В· ResponsГЎvel: ${empNome} (${empMat})` : ''),
    });

    // 3. Se vinculou a um empregado, registra no histГіrico do empregado tambГ©m
    if (empId) {
      await db.collection('empregados').doc(empId).collection('historico').add({
        evento:     'smartphone-vinculado',
        data:       agora,
        usuario:    CURRENT_USER?.nome || 'Sistema',
        smId:       ref.id,
        smModelo:   `${marca} ${modelo}`,
        smImei:     imei1,
        obs:        `Smartphone ${marca} ${modelo} (IMEI: ${imei1}) vinculado como comodato`,
      }).catch(() => {}); // nГЈo bloqueia se empregado nГЈo tiver subcoleГ§ГЈo
    }

    // 4. Atualiza STATE local
    if (!STATE.smartphones) STATE.smartphones = [];
    STATE.smartphones.unshift(novo);

    // 5. Fecha modal, limpa e atualiza tela
    closeModal('modal-novo-smartphone');
    smLimparModal();
    renderMDM?.();

    showToast(`вң“ ${marca} ${modelo} cadastrado no sistema! ID: ${ref.id.slice(0,8)}`, 'success', 5000);
    console.log(`[MDM] Smartphone cadastrado вҖ” Firestore ID: ${ref.id} В· IMEI: ${imei1}`);

  } catch(e) {
    console.error('[MDM] Erro ao cadastrar smartphone:', e);
    showToast('Erro ao salvar no banco: ' + e.message, 'danger', 6000);
  } finally {
    if (btn) { btn.disabled = false; btn.textContent = 'рҹ“ұ Cadastrar Smartphone'; }
  }
}

function smLimparModal() {
  ['sm-modelo','sm-imei1','sm-imei2','sm-serie','sm-versao','sm-linha',
   'sm-emp-id','sm-emp-mat','sm-emp-nome','sm-emp-login','sm-emp-setor',
   'sm-emp-busca','sm-ultima-troca','sm-obs'].forEach(id => {
    const el = document.getElementById(id); if (el) el.value = '';
  });
  ['sm-marca','sm-so','sm-status','sm-operadora'].forEach(id => {
    const el = document.getElementById(id); if (el) el.selectedIndex = 0;
  });
  ['sm-imei1-status','sm-imei2-status'].forEach(id => {
    const el = document.getElementById(id); if (el) el.textContent = '';
  });
  const card = document.getElementById('sm-emp-selecionado');
  if (card) card.style.display = 'none';
  const res = document.getElementById('sm-emp-resultados');
  if (res) res.style.display = 'none';
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
