// в”Җв”Җ Motor de verificaГ§ГЈo de cobranГ§a в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function tcVerificarFatura(fatura) {
  const alertas = [];
  const linhas  = fatura.linhas || [];
  const mes     = fatura.competencia;

  linhas.forEach(linha => {
    const planoId = linha.tipoPlano || _tcInferirPlano(linha);
    const plano   = CONTRATO_VIVO_CESAN.planos[planoId];
    const alertasLinha = [];

    // 1. Verifica valor da mensalidade
    if (plano && linha.valorMensalidade) {
      const esperado = plano.valorUnitario;
      const cobrado  = parseFloat(linha.valorMensalidade);
      if (cobrado > esperado * 1.001) { // tolerГўncia 0.1%
        alertasLinha.push({
          tipo:     'valor_incorreto',
          gravidade:'alta',
          msg:      `Mensalidade cobrada R$ ${cobrado.toFixed(2)} вҖ” contrato prevГӘ R$ ${esperado.toFixed(2)}`,
          diferenca: cobrado - esperado,
        });
      }
    }

    // 2. Verifica cobranГ§as indevidas
    (linha.itens || []).forEach(item => {
      const descUpper = (item.descricao || '').toUpperCase();
      const indevido  = CONTRATO_VIVO_CESAN.cobranГ§as_indevidas.some(c =>
        descUpper.includes(c.toUpperCase())
      );
      if (indevido && parseFloat(item.valor || 0) > 0) {
        alertasLinha.push({
          tipo:     'cobranca_indevida',
          gravidade:'alta',
          msg:      `CobranГ§a indevida pelo contrato: "${item.descricao}" вҖ” R$ ${parseFloat(item.valor).toFixed(2)}`,
          diferenca: parseFloat(item.valor),
          item,
        });
      }
    });

    // 3. Verifica excedente de dados
    if (plano && linha.dadosUsadosGB != null) {
      const franquia = plano.franquiaDadosGB;
      const usado    = parseFloat(linha.dadosUsadosGB);
      if (usado > franquia) {
        const exc = (usado - franquia).toFixed(2);
        alertasLinha.push({
          tipo:     'excedente_dados',
          gravidade:'media',
          msg:      `Dados: ${usado}GB usados, franquia ${franquia}GB вҖ” excedente ${exc}GB`,
          excedente: exc,
        });
      }
    }

    // 4. Verifica excedente de voz
    if (plano && linha.vozUsadoMin != null) {
      const franquia = plano.franquiaVozMin;
      const usado    = parseInt(linha.vozUsadoMin);
      if (usado > franquia) {
        const exc = usado - franquia;
        alertasLinha.push({
          tipo:     'excedente_voz',
          gravidade:'media',
          msg:      `Voz: ${usado.toLocaleString('pt-BR')} min usados, franquia ${franquia.toLocaleString('pt-BR')} min вҖ” excedente ${exc.toLocaleString('pt-BR')} min`,
          excedente: exc,
        });
      }
    }

    // 5. Verifica roaming internacional sem pacote
    (linha.itens || []).forEach(item => {
      const desc = (item.descricao || '').toUpperCase();
      const val  = parseFloat(item.valor || 0);
      if (val > 0 && (desc.includes('ROAMING') || desc.includes('INTERNACIONAL'))) {
        // Verifica se a tarifa estГЎ dentro do previsto
        const tarifa = desc.includes('MRIF') || desc.includes('FIXO') ? CONTRATO_VIVO_CESAN.tarifas.roamingIntlFixo
                     : desc.includes('MRIM') || desc.includes('MГ“VEL') ? CONTRATO_VIVO_CESAN.tarifas.roamingIntlMovel
                     : desc.includes('CRRI') || desc.includes('RECEBIDA') ? CONTRATO_VIVO_CESAN.tarifas.roamingIntlRecebido
                     : null;
        if (tarifa) {
          const minutos = parseFloat(item.quantidade || 0);
          const esperado = tarifa * minutos;
          if (val > esperado * 1.01) {
            alertasLinha.push({
              tipo:     'tarifa_roaming_incorreta',
              gravidade:'alta',
              msg:      `Roaming: tarifa cobrada R$ ${(val/minutos).toFixed(2)}/min, contrato prevГӘ R$ ${tarifa.toFixed(2)}/min`,
              diferenca: val - esperado,
            });
          }
        }
      }
    });

    // 6. Linha sem uso
    if (linha.dadosUsadosGB === 0 && linha.vozUsadoMin === 0) {
      alertasLinha.push({
        tipo:     'sem_uso',
        gravidade:'baixa',
        msg:      'Linha sem nenhum uso no perГӯodo вҖ” avaliar suspensГЈo ou cancelamento',
      });
    }

    if (alertasLinha.length) {
      alertas.push({ numero: linha.numero, empNome: linha.empNome, planoId, alertas: alertasLinha });
    }
  });

  return alertas;
}

function _tcInferirPlano(linha) {
  const val = parseFloat(linha.valorMensalidade || 0);
  if (val >= 230) return 'smartphone-a';
  if (val >= 150) return 'smartphone-b';
  if (val >= 90)  return 'smartphone-c';
  if (val >= 20)  return 'sim-modem';
  return 'sim-pabx';
}

function initTelecomListeners() {
  if (!FB_READY || !db || STATE._telecomInit) return;
  STATE._telecomInit = true;
  // Inicia listener de comodatos junto
  initTelecomComodatos();

  db.collection('planos_telecom').onSnapshot(snap => {
    STATE.planosTelecom = snap2arr(snap);
    if (isPageActive('telecom')) renderTelecom();
  }, e => console.warn('[Telecom] planos:', e.message));

  db.collection('faturas_telecom').orderBy('competencia', 'desc').limit(24).onSnapshot(snap => {
    STATE.faturasTelecom = snap2arr(snap);
    if (isPageActive('telecom')) renderTelecom();
  }, e => console.warn('[Telecom] faturas:', e.message));
}

// Dispara ao entrar na pГЎgina
document.addEventListener('sysack-login', () => setTimeout(initTelecomListeners, 3000));

// в”Җв”Җ Render principal в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function renderTelecom() {
  initTelecomListeners();
  renderTelecomKpis();
  renderTelecomLinhas();
  renderTelecomFaturas();
  renderTelecomAlertas();
  _tcPopularFiltroMes();
}

// в”Җв”Җ KPIs в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function renderTelecomKpis() {
  const sms = (STATE.smartphones || []).filter(s => s.linha);
  const planos = STATE.planosTelecom || [];
  const faturas = STATE.faturasTelecom || [];

  sv('tc-total-linhas', sms.length);

  // Custo do mГӘs mais recente
  const faturaRecente = faturas[0];
  const _tcTotal = faturaRecente?.totalGeral || faturaRecente?.totalCalculado || 0;
  if (_tcTotal > 0) {
    sv('tc-custo-mes', 'R$ ' + Number(_tcTotal).toLocaleString('pt-BR', {minimumFractionDigits:2}));
  } else {
    sv('tc-custo-mes', 'вҖ”');
  }

  // Alertas: linhas com excedente ou fora expediente na Гәltima fatura
  const alertas = _tcLinhasComAlerta();
  sv('tc-alertas', alertas.length);

  // Sem uso: linhas sem registro de chamada/dado em 30 dias (baseado na Гәltima fatura)
  const semUso = sms.filter(s => {
    const p = planos.find(p => p.linha === s.linha);
    return p && p.semUso;
  });
  sv('tc-sem-uso', semUso.length);
}

// в”Җв”Җ Linhas + Planos в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function renderTelecomLinhas() {
  const tbody = document.getElementById('tc-linhas-body');
  if (!tbody) return;

  const q      = (document.getElementById('tc-busca')?.value || '').toLowerCase();
  const filtro = document.getElementById('tc-filtro-alerta')?.value || '';
  const sms    = (STATE.smartphones || []).filter(s => s.linha || s.operadora === 'Vivo');
  const planos = STATE.planosTelecom || [];

  const rows = sms.map(s => {
    const plano   = planos.find(p => p.linha === s.linha) || null;
    const alertas = _tcAlertasLinha(s.linha, plano);
    const status  = !plano ? 'sem-plano' : alertas.length ? 'alerta' : plano.semUso ? 'sem-uso' : 'ok';

    return { s, plano, alertas, status };
  }).filter(({ s, status }) => {
    const matchQ = !q
      || (s.linha    || '').includes(q)
      || (s.empNome  || '').toLowerCase().includes(q)
      || (s.empMat   || '').toLowerCase().includes(q)
      || (s.empSetor || '').toLowerCase().includes(q);
    const matchF = !filtro || status === filtro;
    return matchQ && matchF;
  });

  if (!rows.length) {
    tbody.innerHTML = '<tr><td colspan="10" style="text-align:center;padding:32px;color:var(--g400)">Nenhuma linha encontrada</td></tr>';
    return;
  }

  const statusBadge = st => ({
    ok:         '<span class="tag tag-success">вң“ OK</span>',
    alerta:     '<span class="tag tag-danger">вҡ  Alerta</span>',
    'sem-uso':  '<span class="tag tag-warning">рҹ“ө Sem uso</span>',
    'sem-plano':'<span class="tag" style="background:var(--g100);color:var(--g600)">Sem plano</span>',
  }[st] || 'вҖ”');

  tbody.innerHTML = rows.map(({ s, plano, alertas, status }) => `
    <tr>
      <td class="td-mono" style="color:var(--accent);font-weight:700">${escapeHtml(s.linha || 'вҖ”')}</td>
      <td>
        <div style="font-weight:600">${escapeHtml(s.empNome || 'вҖ”')}</div>
        <div style="font-size:10.5px;color:var(--g400)">${escapeHtml(s.empMat || '')}</div>
      </td>
      <td style="font-size:12px">${escapeHtml(s.empSetor || 'вҖ”')}</td>
      <td>
        ${plano
          ? `<div style="font-weight:600;font-size:12.5px">${escapeHtml(plano.nomePlano || 'Plano')}</div>
             <div style="font-size:10.5px;color:var(--g400)">${escapeHtml(plano.descricao || '')}</div>`
          : '<span style="color:var(--g400);font-size:12px;font-style:italic">NГЈo cadastrado</span>'}
      </td>
      <td class="td-mono">${plano?.franquiaDados ? plano.franquiaDados + ' GB' : 'вҖ”'}</td>
      <td class="td-mono">${plano?.franquiaVoz  ? plano.franquiaVoz  + ' min' : 'вҖ”'}</td>
      <td class="td-mono" style="font-weight:600">${plano?.valor ? 'R$ ' + Number(plano.valor).toFixed(2).replace('.',',') : 'вҖ”'}</td>
      <td class="td-mono" style="font-size:11px">${plano?.ultimaFaturaRef || 'вҖ”'}</td>
      <td>${statusBadge(status)}
        ${alertas.length ? `<div style="font-size:10px;color:var(--danger);margin-top:2px">${alertas.slice(0,2).map(escapeHtml).join(' В· ')}</div>` : ''}
      </td>
      <td>
        <div class="flex gap-4">
          <button class="btn btn-ghost btn-xs" onclick="abrirCadastrarPlano('${escapeHtml(s.id)}','${escapeHtml(s.linha||'')}')">
            ${plano ? 'вңҸпёҸ Plano' : '+ Plano'}
          </button>
          <button class="btn btn-ghost btn-xs" onclick="tcVerDetalhe('${escapeHtml(s.id)}')">рҹ“Ҡ</button>
        </div>
      </td>
    </tr>`).join('');
}

// в”Җв”Җ Faturas importadas в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function renderTelecomFaturas() {
  const tbody = document.getElementById('tc-faturas-body');
  if (!tbody) return;

  const mes    = document.getElementById('tc-filtro-mes')?.value || '';
  const fats   = (STATE.faturasTelecom || []).filter(f => !mes || f.competencia === mes);

  if (!fats.length) {
    tbody.innerHTML = '<tr><td colspan="8" style="text-align:center;padding:32px;color:var(--g400)">Nenhuma fatura importada</td></tr>';
    return;
  }

  // Calcula totais e variaГ§Гөes
  const fatsOrdenadas = [...fats].sort((a,b) => (a.competencia||'').localeCompare(b.competencia||''));
  tbody.innerHTML = fats.map((f, idx) => {
    const total = f.totalGeral || f.totalCalculado || 0;
    const linhas = f.totalLinhas || 1;
    const custoMedio = total / linhas;

    // VariaГ§ГЈo vs mГӘs anterior (fatura anterior na lista ordenada)
    const fatAnterior = fatsOrdenadas[fatsOrdenadas.indexOf(f) - 1];
    const totalAnt = fatAnterior ? (fatAnterior.totalGeral || fatAnterior.totalCalculado || 0) : null;
    let variacaoHtml = 'вҖ”';
    if (totalAnt !== null && totalAnt > 0) {
      const pct  = ((total - totalAnt) / totalAnt * 100).toFixed(1);
      const sobe = total > totalAnt;
      variacaoHtml = `<span style="color:${sobe?'var(--danger)':'var(--success)'};font-weight:700;font-size:12px">
        ${sobe?'в–І':'в–ј'} ${Math.abs(pct)}%</span>
        <div style="font-size:10px;color:var(--g400)">vs ${fatAnterior.competencia}</div>`;
    }

    // Alertas crГӯticos
    const alertasCrit = f.alertasCriticos || f.qtdExcedentes || 0;
    const totalAlertas = f.alertas || 0;

    return `<tr>
      <td class="td-mono" style="font-weight:700">${escapeHtml(f.competencia || 'вҖ”')}</td>
      <td class="td-mono">${linhas.toLocaleString('pt-BR')}</td>
      <td class="td-mono" style="font-weight:700;color:var(--accent)">R$ ${Number(total).toLocaleString('pt-BR',{minimumFractionDigits:2})}</td>
      <td style="font-size:12px;color:var(--g600)">R$ ${custoMedio.toLocaleString('pt-BR',{minimumFractionDigits:2})}</td>
      <td>${variacaoHtml}</td>
      <td>${alertasCrit > 0
        ? `<span class="tag tag-danger" title="${totalAlertas} alertas total">${alertasCrit} crГӯticos</span>`
        : '<span class="tag tag-success">Nenhum</span>'}</td>
      <td>${f.qtdExcedentes ? `<span class="tag tag-warning">${f.qtdExcedentes} linhas</span>` : 'вҖ”'}</td>
      <td style="font-size:11px;color:var(--g400)">${f.importadaEm ? new Date(f.importadaEm.seconds ? f.importadaEm.seconds*1000 : f.importadaEm).toLocaleDateString('pt-BR') : 'вҖ”'}</td>
      <td>
        <div class="flex gap-4">
          <button class="btn btn-ghost btn-xs" onclick="tcAbrirDetalhesFatura('${escapeHtml(f.id)}','${escapeHtml(f.competencia||'')}')">рҹ“Ӣ Linhas</button>
          <button class="btn btn-ghost btn-xs" onclick="tcVerRelatorioFatura('${escapeHtml(f.id)}')">рҹ“Ҡ Ver</button>
          <button class="btn btn-ghost btn-xs" onclick="tcExcluirFatura('${escapeHtml(f.id)}')" style="color:var(--danger)">рҹ—‘</button>
        </div>
      </td>
    </tr>`;
  }).join('');
}

// в”Җв”Җ Alertas в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function renderTelecomAlertas() {
  const el = document.getElementById('tc-alertas-lista');
  if (!el) return;

  const todos = _tcLinhasComAlerta();
  if (!todos.length) {
    el.innerHTML = '<div style="text-align:center;padding:32px;color:var(--g400)">вң“ Nenhum alerta no momento</div>';
    return;
  }

  el.innerHTML = todos.map(a => `
    <div style="display:flex;align-items:flex-start;gap:14px;padding:14px 16px;border:1px solid var(--g200);border-radius:10px;background:var(--g50)">
      <div style="font-size:22px;flex-shrink:0">${a.tipo === 'excedente' ? 'вҡ пёҸ' : a.tipo === 'fora-expediente' ? 'рҹҢҷ' : 'рҹ“ө'}</div>
      <div style="flex:1">
        <div style="font-weight:700;font-size:13px">${escapeHtml(a.linha)} вҖ” ${escapeHtml(a.empNome || 'Sem empregado')}</div>
        <div style="font-size:12px;color:var(--g600);margin-top:2px">${escapeHtml(a.mensagem)}</div>
        <div style="font-size:11px;color:var(--g400);margin-top:4px">${escapeHtml(a.unidade || '')}</div>
      </div>
      <span class="tag ${a.tipo === 'excedente' ? 'tag-danger' : a.tipo === 'fora-expediente' ? 'tag-warning' : ''}" style="flex-shrink:0">${
        a.tipo === 'excedente' ? 'Excedente' : a.tipo === 'fora-expediente' ? 'Fora expediente' : 'Sem uso'
      }</span>
    </div>`).join('');
}

// в”Җв”Җ Helpers de alerta в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function _tcAlertasLinha(linha, plano) {
  if (!linha || !plano) return [];
  const alertas = [];
  if (plano.excedenteDados)      alertas.push(`Dados excedidos: ${plano.excedenteDados} GB extra`);
  if (plano.excedenteVoz)        alertas.push(`Voz excedida: ${plano.excedenteVoz} min extra`);
  if (plano.foraExpediente)      alertas.push('Uso fora do expediente detectado');
  if (plano.semUso)              alertas.push('Sem uso nos Гәltimos 30 dias');
  return alertas;
}

function _tcLinhasComAlerta() {
  const sms    = (STATE.smartphones || []).filter(s => s.linha);
  const planos = STATE.planosTelecom || [];
  const result = [];

  for (const s of sms) {
    const plano = planos.find(p => p.linha === s.linha);
    if (!plano) continue;
    const checks = [
      plano.excedenteDados  && { tipo:'excedente',        linha:s.linha, empNome:s.empNome, unidade:s.empSetor, mensagem:`Dados excedidos em ${plano.excedenteDados} GB` },
      plano.excedenteVoz    && { tipo:'excedente',        linha:s.linha, empNome:s.empNome, unidade:s.empSetor, mensagem:`Voz excedida em ${plano.excedenteVoz} min` },
      plano.foraExpediente  && { tipo:'fora-expediente',  linha:s.linha, empNome:s.empNome, unidade:s.empSetor, mensagem:'Chamadas/dados registrados fora do expediente' },
      plano.semUso          && { tipo:'sem-uso',          linha:s.linha, empNome:s.empNome, unidade:s.empSetor, mensagem:'Linha sem uso nos Гәltimos 30 dias' },
    ].filter(Boolean);
    result.push(...checks);
  }
  return result;
}

function _tcPopularFiltroMes() {
  const sel = document.getElementById('tc-filtro-mes');
  if (!sel) return;
  const meses = [...new Set((STATE.faturasTelecom || []).map(f => f.competencia).filter(Boolean))];
  sel.innerHTML = '<option value="">Todas as competГӘncias</option>' +
    meses.map(m => `<option value="${escapeHtml(m)}">${escapeHtml(m)}</option>`).join('');
}

// в”Җв”Җ Abas в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function tcTab(tab) {
  ['linhas','comodato','faturas','alertas','relatorio'].forEach(t => {
    const el = document.getElementById(`tc-view-${t}`);
    const bt = document.getElementById(`tc-tab-${t}`);
    if (el) el.style.display = t === tab ? '' : 'none';
    if (bt) bt.classList.toggle('active', t === tab);
  });
}

// в”Җв”Җ Modal: Cadastrar / Editar Plano в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function abrirCadastrarPlano(smId, linha) {
  const planos = STATE.planosTelecom || [];
  const plano  = linha ? planos.find(p => p.linha === linha) : null;
  const sms    = STATE.smartphones || [];

  // Monta select de linhas sem plano (+ a linha atual se ediГ§ГЈo)
  const linhasDisp = sms
    .filter(s => s.linha && (!planos.find(p => p.linha === s.linha) || s.linha === linha))
    .map(s => `<option value="${escapeHtml(s.linha)}" ${s.linha===linha?'selected':''}>${escapeHtml(s.linha)} вҖ” ${escapeHtml(s.empNome||s.pat||'')}</option>`)
    .join('');

  // OpГ§Гөes de tipo de plano do contrato Vivo
  const tiposContrato = Object.entries(CONTRATO_VIVO_CESAN.planos).map(([k,p]) =>
    `<option value="${k}" ${plano?.tipoPlano===k?'selected':''}>
      ${p.nome} вҖ” R$ ${p.valorUnitario.toFixed(2)}/mГӘs (${p.franquiaDadosGB}GB + ${p.franquiaVozMin.toLocaleString('pt-BR')} min)
    </option>`
  ).join('');

  const html = `
  <div class="modal-overlay open" id="modal-plano-telecom" onclick="if(event.target===this)document.getElementById('modal-plano-telecom').remove()">
    <div class="modal" style="max-width:600px">
      <div class="modal-header">
        <div>
          <h3>${plano ? 'вңҸпёҸ Editar Plano' : '+ Cadastrar Plano'}</h3>
          <div style="font-size:11px;color:var(--g400);margin-top:2px">Contrato Vivo вҖ” PregГЈo 158/2021 В· R$ 101.475,93/mГӘs</div>
        </div>
        <button class="close-btn" onclick="document.getElementById('modal-plano-telecom').remove()">вң•</button>
      </div>
      <div class="modal-body">
        <input type="hidden" id="tc-plano-id" value="${plano?.id || ''}">

        <!-- Tipo do contrato (auto-preenche campos) -->
        <div class="form-group">
          <label class="form-label req">Tipo de plano contratado (PregГЈo 158/2021)</label>
          <select class="form-control" id="tc-plano-tipo" onchange="tcAutoPreencherPlano(this.value)">
            <option value="">вҖ” Selecione o tipo conforme contrato вҖ”</option>
            ${tiposContrato}
            <option value="custom" ${plano?.tipoPlano==='custom'?'selected':''}>Outro / Personalizado</option>
          </select>
        </div>

        <div class="form-row c2">
          <div class="form-group">
            <label class="form-label req">Linha (nГәmero)</label>
            <select class="form-control" id="tc-plano-linha" ${plano ? 'disabled' : ''}>
              <option value="">Selecione a linha...</option>
              ${linhasDisp}
            </select>
            ${!linhasDisp ? '<div style="font-size:11px;color:var(--warning);margin-top:4px">Todas as linhas jГЎ tГӘm plano</div>' : ''}
          </div>
          <div class="form-group">
            <label class="form-label req">Nome do plano</label>
            <input class="form-control" id="tc-plano-nome" placeholder="Ex: Smartphone C вҖ” Vivo" value="${escapeHtml(plano?.nomePlano||'')}">
          </div>
        </div>

        <div class="form-row c2">
          <div class="form-group">
            <label class="form-label req">Valor mensal (R$)</label>
            <input class="form-control" id="tc-plano-valor" type="number" step="0.01" placeholder="0,00" value="${plano?.valor||''}">
          </div>
          <div class="form-group">
            <label class="form-label">Franquia de dados (GB)</label>
            <input class="form-control" id="tc-plano-dados" type="number" step="0.5" placeholder="Ex: 15" value="${plano?.franquiaDados||''}">
          </div>
        </div>

        <div class="form-row c2">
          <div class="form-group">
            <label class="form-label">Franquia de voz (min/mГӘs)</label>
            <input class="form-control" id="tc-plano-voz" type="number" placeholder="Ex: 300" value="${plano?.franquiaVoz||''}">
            <div style="font-size:11px;color:var(--g400);margin-top:4px">0 = ilimitado</div>
          </div>
          <div class="form-group">
            <label class="form-label">SMS incluso</label>
            <select class="form-control" id="tc-plano-sms">
              <option value="sim" ${plano?.smsIncluso!==false?'selected':''}>Sim вҖ” ilimitado</option>
              <option value="nao" ${plano?.smsIncluso===false?'selected':''}>NГЈo incluso</option>
            </select>
          </div>
        </div>

        <div class="form-group">
          <label class="form-label">DescriГ§ГЈo / observaГ§Гөes</label>
          <input class="form-control" id="tc-plano-desc" placeholder="Ex: Roaming nacional incluso, portabilidade de 2023..." value="${escapeHtml(plano?.descricao||'')}">
        </div>

        <div class="form-row c2">
          <div class="form-group">
            <label class="form-label">Vencimento fatura (dia)</label>
            <input class="form-control" id="tc-plano-venc" type="number" min="1" max="31" placeholder="Ex: 15" value="${plano?.diaVencimento||''}">
          </div>
          <div class="form-group">
            <label class="form-label">Data inГӯcio contrato</label>
            <input class="form-control" id="tc-plano-inicio" type="date" value="${plano?.dataInicio||''}">
          </div>
        </div>

        <div style="background:var(--g50);border-radius:8px;padding:12px 14px;font-size:12px;color:var(--g600)">
          рҹ’Ў Os campos de alerta (excedente, fora expediente, sem uso) sГЈo preenchidos automaticamente ao importar a fatura da Vivo.
        </div>
      </div>
      <div class="modal-footer">
        <button class="btn btn-ghost" onclick="document.getElementById('modal-plano-telecom').remove()">Cancelar</button>
        <button class="btn btn-primary" onclick="salvarPlanoTelecom()">рҹ’ҫ Salvar Plano</button>
      </div>
    </div>
  </div>`;

  // Remove modal anterior se existir
  document.getElementById('modal-plano-telecom')?.remove();
  document.body.insertAdjacentHTML('beforeend', html);

  // Pre-seleciona linha se veio do botГЈo da tabela
  if (linha) {
    const sel = document.getElementById('tc-plano-linha');
    if (sel) sel.value = linha;
  }
}

async function salvarPlanoTelecom() {
  const id    = document.getElementById('tc-plano-id')?.value?.trim();
  const linha = document.getElementById('tc-plano-linha')?.value?.trim();
  const nome  = document.getElementById('tc-plano-nome')?.value?.trim();
  const valor = parseFloat(document.getElementById('tc-plano-valor')?.value || '0');

  if (!linha) return showToast('Selecione a linha', 'danger');
  if (!nome)  return showToast('Informe o nome do plano', 'danger');
  if (!valor) return showToast('Informe o valor mensal', 'danger');

  const tipoPlano = document.getElementById('tc-plano-tipo')?.value || '';
  const contratoRef = CONTRATO_VIVO_CESAN.planos[tipoPlano];

  const dados = {
    linha,
    nomePlano:    nome,
    tipoPlano,
    contratoPreg: '158/2021',
    valor,
    // Franquias do contrato (ou customizadas)
    franquiaDados: contratoRef?.franquiaDadosGB || parseFloat(document.getElementById('tc-plano-dados')?.value || '0') || null,
    franquiaVoz:   contratoRef?.franquiaVozMin  || parseInt(document.getElementById('tc-plano-voz')?.value || '0')    || null,
    franquiaSMS:   contratoRef?.franquiaSMS     || 0,
    valorContrato: contratoRef?.valorUnitario   || valor,
    smsIncluso:    document.getElementById('tc-plano-sms')?.value !== 'nao',
    descricao:     document.getElementById('tc-plano-desc')?.value?.trim() || (contratoRef?.descricao || ''),
    diaVencimento: parseInt(document.getElementById('tc-plano-venc')?.value || '0') || null,
    dataInicio:    document.getElementById('tc-plano-inicio')?.value || null,
    roamingNacional: contratoRef?.roamingNacional ?? true,
    coberturaAD:   true, // isenГ§ГЈo AD1/AD2 prevista em contrato
    coberturaD:    true, // isenГ§ГЈo D1/D2 prevista em contrato
    atualizadoEm:  new Date(),
    atualizadoPor: CURRENT_USER?.nome || CURRENT_USER?.uid || '',
  };

  try {
    if (id) {
      await db.collection('planos_telecom').doc(id).update(dados);
    } else {
      dados.criadoEm = new Date();
      await db.collection('planos_telecom').add(dados);
    }
    showToast(`вң“ Plano ${nome} salvo!`, 'success');
    document.getElementById('modal-plano-telecom')?.remove();
    document.getElementById('modal-plano-telecom')?.remove();
  } catch(e) {
    showToast('Erro ao salvar: ' + e.message, 'danger');
  }
}

// в”Җв”Җ Modal: Importar fatura (CSV ou PDF) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function abrirImportarFatura() {
  document.getElementById('modal-importar-fatura')?.remove();
  const html = `
  <div class="modal-overlay open" id="modal-importar-fatura" onclick="if(event.target===this)document.getElementById('modal-importar-fatura').remove()">
    <div class="modal" style="max-width:520px">
      <div class="modal-header">
        <h3>рҹ“„ Importar Fatura Vivo</h3>
        <button class="close-btn" onclick="document.getElementById('modal-importar-fatura').remove()">вң•</button>
      </div>
      <div class="modal-body">
        <div class="form-group">
          <label class="form-label req">CompetГӘncia (mГӘs/ano)</label>
          <input class="form-control" id="tc-imp-mes" type="month" value="${new Date().toISOString().slice(0,7)}">
        </div>

        <div style="border:2px dashed var(--g300);border-radius:10px;padding:28px;text-align:center;margin-bottom:16px">
          <div style="font-size:32px;margin-bottom:8px">рҹ“Ғ</div>
          <div style="font-size:13px;font-weight:600;margin-bottom:6px">Selecione o arquivo da fatura</div>
          <div style="font-size:11.5px;color:var(--g400);margin-bottom:14px">Arquivo TXT, CSV ou PDF da Vivo Empresas</div>
          <input type="file" id="tc-imp-file" accept=".txt,.csv,.pdf" style="display:none" onchange="tcPreviewArquivo(this)">
          <button class="btn btn-secondary btn-sm" onclick="document.getElementById('tc-imp-file').click()">Escolher arquivo</button>
          <div id="tc-imp-preview" style="margin-top:12px;font-size:12px;color:var(--g600)"></div>
        </div>

        <div style="background:var(--accent-l);border-radius:8px;padding:12px 14px;font-size:12px;color:var(--accent)">
          <strong>Para TXT:</strong> arquivo de fatura eletrГҙnica Vivo (formato proprietГЎrio) вҖ” processado automaticamente.<br>
          <strong>Para CSV:</strong> exporte do portal Vivo Empresas вҶ’ RelatГіrios вҶ’ Detalhamento por linha.<br>
          <strong>Para PDF:</strong> a IA (Gemini) extrai os dados automaticamente вҖ” pode levar alguns segundos.
        </div>

        <div id="tc-imp-status" style="margin-top:12px;display:none"></div>
      </div>
      <div class="modal-footer">
        <button class="btn btn-ghost" onclick="document.getElementById('modal-importar-fatura').remove()">Cancelar</button>
        <button class="btn btn-primary" id="tc-imp-btn" onclick="tcProcessarFatura()" disabled>рҹ“Ҙ Importar</button>
      </div>
    </div>
  </div>`;
  document.body.insertAdjacentHTML('beforeend', html);
}

function tcPreviewArquivo(input) {
  const file = input.files[0];
  if (!file) return;
  const prev = document.getElementById('tc-imp-preview');
  const btn  = document.getElementById('tc-imp-btn');
  const ext  = file.name.split('.').pop().toLowerCase();

  prev.innerHTML = `<span style="color:var(--success)">вң“ ${escapeHtml(file.name)}</span> вҖ” ${(file.size/1024).toFixed(1)} KB В· ${ext.toUpperCase()}`;
  btn.disabled = false;
  btn.dataset.ext = ext;
}

async function tcProcessarFatura() {
  const fileInput = document.getElementById('tc-imp-file');
  const mes       = document.getElementById('tc-imp-mes')?.value;
  const statusEl  = document.getElementById('tc-imp-status');
  const file      = fileInput?.files?.[0];

  if (!file) return showToast('Selecione um arquivo', 'danger');
  if (!mes)  return showToast('Selecione a competГӘncia', 'danger');

  const ext = file.name.split('.').pop().toLowerCase();
  statusEl.style.display = '';
  statusEl.innerHTML = '<div style="color:var(--accent)">вҸі Processando arquivo...</div>';

  try {
    if (ext === 'txt') {
      await _tcParseTXTVivo(file, mes);
    } else if (ext === 'csv') {
      await _tcParseCSV(file, mes);
    } else {
      // PDF via Gemini IA
      await _tcParsePDFGemini(file, mes);
    }
  } catch(e) {
    statusEl.innerHTML = '<div style="color:var(--danger)">вқҢ Erro: ' + escapeHtml(e.message) + '</div>';
  }
}

// в”Җв”Җ Parser TXT Vivo (formato proprietГЎrio fixo) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Formato: arquivo posicional ISO-8859-1, registros de largura fixa
// Conta: 0120692821 (CESAN)
// Registros-chave:
//   110D = Гӯndice de assinantes (telefone formatado + plano + valor/linha)
//   200D = dados do assinante (plano, datas vigГӘncia)
//   201Z = dados do aparelho (marca/modelo)
//   215D = valores cobrados
//   225D = itens do plano com valores
async function _tcParseTXTVivo(file, mes) {
  const statusEl = document.getElementById('tc-imp-status');

  // в”Җв”Җ Leitura como latin-1 в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  const buffer = await file.arrayBuffer();
  const bytes  = new Uint8Array(buffer);
  let txt = '';
  for (let i = 0; i < bytes.length; i++) txt += String.fromCharCode(bytes[i]);
  const linhas = txt.split('\r\n');

  statusEl.style.display = '';
  statusEl.innerHTML = `<div style="color:var(--accent)">вҸі ${linhas.length.toLocaleString('pt-BR')} linhas вҖ” extraindo assinantes...</div>`;
  await new Promise(r => setTimeout(r, 50));

  // в”Җв”Җ PASSO 1: Monta Гӯndice de assinantes via registros 110D в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  // Estes registros tГӘm telefone formatado (27-XXXXX-XXXX) e valor ao final
  const phoneIndex = {};

  for (const linha of linhas) {
    if (!linha.includes('110D')) continue;
    if (!linha.includes('0120692821')) continue;

    const phoneM = linha.match(/(27-\d{5}-\d{4})/);
    const valM   = linha.match(/(\d+\.\d{2})A?\s*$/);
    if (!phoneM) continue;

    const phoneFmt = phoneM[1];
    const phoneNum = phoneFmt.replace(/-/g, '');
    const valor    = valM ? parseFloat(valM[1]) : 0;

    // Nome do plano вҖ” texto apГіs o telefone
    let plano = '';
    const afterPhone = linha.substring(linha.indexOf(phoneFmt) + 12);
    if      (afterPhone.includes('SMART EMPRESAS 20GB')) plano = 'SMART EMPRESAS 20GB';
    else if (afterPhone.includes('SMART EMPRESAS 10GB')) plano = 'SMART EMPRESAS 10GB';
    else if (afterPhone.includes('SMART EMPRESAS 3GB'))  plano = 'SMART EMPRESAS 3GB';
    else if (afterPhone.includes('PLANO BASE INTERNET')) plano = 'PLANO BASE INTERNET PJ';
    else {
      const planoM = afterPhone.match(/([A-Z][A-Z0-9 ]{5,30}[A-Z0-9])/);
      if (planoM) plano = planoM[1].trim();
    }

    if (!phoneIndex[phoneNum]) {
      phoneIndex[phoneNum] = {
        telefone:    phoneNum,
        telefoneFmt: phoneFmt,
        plano,
        valor,
        aparelho:    '',
        itens:       [],
      };
    }
  }

  statusEl.innerHTML = `<div style="color:var(--accent)">вҸі ${Object.keys(phoneIndex).length} assinantes encontrados вҖ” enriquecendo dados...</div>`;
  await new Promise(r => setTimeout(r, 50));

  // в”Җв”Җ PASSO 2: Enriquece com registros de detalhe por assinante в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  let currentPhone = null;

  for (const linha of linhas) {
    if (linha.length < 50) continue;
    if (!linha.includes('0120692821')) continue;

    // Telefone na posiГ§ГЈo 29-41 (com possГӯvel espaГ§o antes)
    const chunkPhone = linha.substring(28, 42).trim();
    const phoneM2 = chunkPhone.match(/^(27\d{9,10})/);
    if (phoneM2) currentPhone = phoneM2[1];

    if (!currentPhone || !phoneIndex[currentPhone]) continue;
    const a = phoneIndex[currentPhone];

    // Identifica tipo de registro pelo conteГәdo
    const seg = linha.substring(95, 125);

    // 201Z = aparelho (Samsung, Motorola etc.) вҖ” pos 350+
    if (seg.includes('201') && linha.length > 400) {
      const ap = linha.substring(350, 430).trim().replace(/\s+/g, ' ');
      if (ap && !a.aparelho) a.aparelho = ap.substring(0, 40);
    }

    // 215D = valores de mensalidade вҖ” pos 155+
    else if (seg.includes('215') && linha.length > 170) {
      const valsStr = linha.substring(150, 210);
      const vals = valsStr.match(/(\d+\.\d{2})/g);
      if (vals && parseFloat(vals[0]) > 0 && a.valor === 0) {
        a.valor = parseFloat(vals[0]);
      }
    }

    // 225D = itens do plano вҖ” verifica cobranГ§as indevidas
    else if (seg.includes('225') && linha.length > 200) {
      const desc    = linha.substring(190, 260).trim();
      const valPart = linha.substring(140, 200);
      const vals    = valPart.match(/(\d+\.\d{2})/g);
      if (desc && desc.length > 3) {
        const v = vals ? parseFloat(vals[0]) : 0;
        const dU = desc.toUpperCase();
        const indevido = ['AD1','AD2',' D1 ',' D2 ','ASSINATURA BASICA','ASSINATURA BГҒSICA']
          .some(x => dU.includes(x));
        a.itens.push({ descricao: desc.substring(0, 50), valor: v, _indevido: indevido });
      }
    }
  }

  // в”Җв”Җ PASSO 3: Classifica plano pelo contrato e detecta irregularidades в”Җ
  const PLANOS_CONTRATO = CONTRATO_VIVO_CESAN.planos;

  const listaFinal = Object.values(phoneIndex).map(a => {
    const v = a.valor;

    // Classifica tipo do contrato pelo valor
    let tipoPlano = 'custom';
    let valorContrato = 0;
    if      (v >= 230 && v <= 240)  { tipoPlano = 'smartphone-a'; valorContrato = 236.47; }
    else if (v >= 150 && v <= 165)  { tipoPlano = 'smartphone-b'; valorContrato = 154.40; }
    else if (v >= 90  && v <= 100)  { tipoPlano = 'smartphone-c'; valorContrato = 96.00;  }
    else if (v >= 20  && v <= 30)   { tipoPlano = 'sim-modem';    valorContrato = 25.00;  }
    else if (v >  0   && v <= 20)   { tipoPlano = 'sim-pabx';     valorContrato = 15.00;  }

    // Detecta valor divergente do contrato
    const alertasLinha = [];
    if (valorContrato > 0 && Math.abs(v - valorContrato) > 0.01) {
      alertasLinha.push({
        tipo:      'valor_incorreto',
        gravidade: 'alta',
        msg:       `Mensalidade cobrada R$ ${v.toFixed(2)} вҖ” contrato prevГӘ R$ ${valorContrato.toFixed(2)}`,
        diferenca:  +(v - valorContrato).toFixed(2),
      });
    }

    // Plano nГЈo reconhecido pelo contrato
    if (tipoPlano === 'custom' && v > 0) {
      alertasLinha.push({
        tipo:      'plano_nao_contratado',
        gravidade: 'alta',
        msg:       `Plano "${a.plano}" com valor R$ ${v.toFixed(2)} nГЈo consta no PregГЈo 158/2021`,
        diferenca:  v,
      });
    }

    // CobranГ§as indevidas (AD1, AD2, D1, D2, assinatura)
    a.itens.forEach(item => {
      if (item._indevido && item.valor > 0) {
        alertasLinha.push({
          tipo:      'cobranca_indevida',
          gravidade: 'alta',
          msg:       `CobranГ§a indevida pelo contrato: "${item.descricao}" вҖ” R$ ${item.valor.toFixed(2)}`,
          diferenca:  item.valor,
          item,
        });
      }
    });

    return {
      numero:           a.telefoneFmt,
      empNome:          '',
      tipoPlano,
      valorMensalidade: v,
      valorContrato,
      plano:            a.plano,
      aparelho:         a.aparelho,
      dadosUsadosGB:    null,
      vozUsadoMin:      null,
      itens:            a.itens,
      alertasLinha,
    };
  });

  // в”Җв”Җ PASSO 4: VerificaГ§ГЈo contratual в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  statusEl.innerHTML = `<div style="color:var(--accent)">вң… ${listaFinal.length} linhas extraГӯdas вҖ” verificando contrato...</div>`;
  await new Promise(r => setTimeout(r, 80));

  // Monta alertas no formato esperado por tcMostrarResultadoVerificacao
  const alertasContrato = listaFinal
    .filter(l => l.alertasLinha.length > 0)
    .map(l => ({ numero: l.numero, empNome: l.empNome, planoId: l.tipoPlano, alertas: l.alertasLinha }));

  const totalCalc = listaFinal.reduce((s, l) => s + (l.valorMensalidade || 0), 0);

  // в”Җв”Җ PASSO 5: Grava no Firestore в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  if (FB_READY && db) {
    statusEl.innerHTML = `<div style="color:var(--accent)">рҹ’ҫ Gravando fatura no banco...</div>`;
    await new Promise(r => setTimeout(r, 30));

    // Documento principal
    const faturaRef = await db.collection('faturas_telecom').add({
      competencia:     mes,
      conta:           '0120692821',
      totalGeral:      +totalCalc.toFixed(2),   // campo lido por renderTelecomKpis/Faturas
      totalCalculado:  +totalCalc.toFixed(2),
      totalLinhas:     listaFinal.length,
      alertas:         alertasContrato.reduce((s,l) => s + l.alertas.length, 0),
      alertasCriticos: alertasContrato.reduce((s,l) => s + l.alertas.filter(a=>a.gravidade==='alta').length, 0),
      importadaEm:     new Date(),
      importadaPor:    CURRENT_USER?.nome || '',
      formato:         'txt-vivo',
      resumoPlanos: listaFinal.reduce((acc, l) => {
        const tp = l.tipoPlano || 'outros';
        if (!acc[tp]) acc[tp] = { qtd: 0, total: 0 };
        acc[tp].qtd++;
        acc[tp].total = +(acc[tp].total + l.valorMensalidade).toFixed(2);
        return acc;
      }, {}),
      resumoAlertas: alertasContrato.reduce((acc, l) => {
        l.alertas.forEach(a => { acc[a.tipo] = (acc[a.tipo]||0) + 1; });
        return acc;
      }, {}),
    });

    // SubcoleГ§ГЈo: 1 doc por assinante (batches de 490)
    const BATCH = 490;
    for (let i = 0; i < listaFinal.length; i += BATCH) {
      const batch = db.batch();
      listaFinal.slice(i, i + BATCH).forEach(l => {
        const docId   = l.numero.replace(/\D/g, '') || `linha_${i}`;
        const alerLinha = alertasContrato.find(a =>
          a.numero === l.numero || a.numero?.replace(/\D/g,'') === docId
        );
        batch.set(faturaRef.collection('linhas').doc(docId), {
          ...l,
          alertas:         alerLinha?.alertas || l.alertasLinha || [],
          temAlerta:       (alerLinha?.alertas?.length || l.alertasLinha?.length || 0) > 0,
          alertasCriticos: (alerLinha?.alertas || l.alertasLinha || []).filter(a=>a.gravidade==='alta').length,
          faturaId:        faturaRef.id,
          competencia:     mes,
          gravadoEm:       new Date(),
        });
      });
      await batch.commit();
      const pct = Math.min(100, Math.round((i + BATCH) / listaFinal.length * 100));
      statusEl.innerHTML = `<div style="color:var(--accent)">рҹ’ҫ Gravando... ${pct}% (${Math.min(i+BATCH, listaFinal.length)}/${listaFinal.length} linhas)</div>`;
      await new Promise(r => setTimeout(r, 10));
    }
  }

  document.getElementById('modal-importar-fatura')?.remove();
  tcMostrarResultadoVerificacao(alertasContrato, mes, totalCalc);
  showToast(`вң… Fatura ${mes} вҖ” ${listaFinal.length} linhas В· R$ ${totalCalc.toLocaleString('pt-BR',{minimumFractionDigits:2})} В· ${alertasContrato.length} alertas`, 'success', 7000);
}

// в”Җв”Җ Parser CSV Vivo в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
async function _tcParseCsv(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = e => {
      try {
        const text  = e.target.result;
        const lines = text.split('\n').map(l => l.trim()).filter(Boolean);
        if (lines.length < 2) return reject(new Error('CSV vazio ou sem dados'));

        // Detecta separador
        const sep = lines[0].includes(';') ? ';' : ',';
        const headers = lines[0].split(sep).map(h => h.replace(/"/g,'').trim().toLowerCase());

        // Mapeia colunas Vivo (nomes podem variar ligeiramente)
        const col = name => {
          const idx = headers.findIndex(h => h.includes(name));
          return idx;
        };

        const iLinha = col('nГәmero') >= 0 ? col('nГәmero') : col('linha') >= 0 ? col('linha') : col('msisdn');
        const iTotal = col('total') >= 0 ? col('total') : col('valor');
        const iDados = col('dado') >= 0 ? col('dado') : col('data');
        const iVoz   = col('voz') >= 0 ? col('voz') : col('minuto');
        const iSms   = col('sms');
        const iNome  = col('nome') >= 0 ? col('nome') : col('usuГЎrio') >= 0 ? col('usuГЎrio') : col('usuario');

        const parsed = lines.slice(1).map(line => {
          const cols = line.split(sep).map(c => c.replace(/"/g,'').trim());
          if (cols.length < 2) return null;
          return {
            linha: iLinha >= 0 ? cols[iLinha]?.replace(/\D/g,'') : '',
            nome:  iNome  >= 0 ? cols[iNome]  : '',
            total: iTotal >= 0 ? parseFloat(cols[iTotal]?.replace(',','.')) || 0 : 0,
            dados: iDados >= 0 ? parseFloat(cols[iDados]?.replace(',','.')) || 0 : 0,
            voz:   iVoz   >= 0 ? parseInt(cols[iVoz])   || 0 : 0,
            sms:   iSms   >= 0 ? parseInt(cols[iSms])   || 0 : 0,
          };
        }).filter(r => r && r.linha);

        resolve(parsed);
      } catch(e) { reject(e); }
    };
    reader.onerror = () => reject(new Error('Falha ao ler arquivo'));
    reader.readAsText(file, 'UTF-8');
  });
}

// в”Җв”Җ Parser PDF via Gemini в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
async function _tcParsePdfGemini(file, mes) {
  const base64 = await new Promise((res, rej) => {
    const r = new FileReader();
    r.onload = () => res(r.result.split(',')[1]);
    r.onerror = () => rej(new Error('Falha ao ler PDF'));
    r.readAsDataURL(file);
  });

  const resp = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model: 'claude-sonnet-4-20250514',
      max_tokens: 4000,
      messages: [{
        role: 'user',
        content: [
          {
            type: 'document',
            source: { type: 'base64', media_type: 'application/pdf', data: base64 }
          },
          {
            type: 'text',
            text: `Esta Г© uma fatura da Vivo Empresas referente a ${mes}. Extraia os dados de cada linha telefГҙnica e retorne APENAS um JSON vГЎlido sem nenhum texto adicional, no formato:
[
  {
    "linha": "27999998888",
    "nome": "Nome do usuГЎrio",
    "total": 89.90,
    "dados": 12.5,
    "dadosExtra": 0,
    "voz": 240,
    "vozExtra": 0,
    "sms": 0,
    "foraExpediente": false,
    "semUso": false
  }
]
Se nГЈo conseguir extrair um campo, use null. Linha deve ter apenas dГӯgitos. Total e dados em nГәmero decimal. Voz em minutos inteiros.`
          }
        ]
      }]
    })
  });

  if (!resp.ok) throw new Error('Erro na API: ' + resp.status);
  const data = await resp.json();
  const text = data.content?.find(c => c.type === 'text')?.text || '[]';

  try {
    const clean = text.replace(/```json|```/g, '').trim();
    return JSON.parse(clean);
  } catch {
    throw new Error('NГЈo foi possГӯvel interpretar a resposta da IA. Tente com CSV.');
  }
}

// в”Җв”Җ AnГЎlise e persistГӘncia в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
async function _tcAnalisarEPersistir(linhas, mes) {
  const planos  = STATE.planosTelecom || [];
  const agora   = new Date();
  const expedInicio = 7, expedFim = 19; // 07hвҖ“19h Гәtil (configurГЎvel futuramente)

  let totalGeral = 0, qtdExcedentes = 0, qtdForaExp = 0, qtdSemUso = 0;
  const alertas  = [];
  const batch    = [];

  for (const l of linhas) {
    if (!l.linha) continue;
    const plano = planos.find(p => p.linha === l.linha);
    totalGeral += l.total || 0;

    const excedenteDados = plano?.franquiaDados && l.dados > plano.franquiaDados
      ? +(l.dados - plano.franquiaDados).toFixed(2) : 0;
    const excedenteVoz = plano?.franquiaVoz && plano.franquiaVoz > 0 && l.voz > plano.franquiaVoz
      ? l.voz - plano.franquiaVoz : 0;
    const foraExp  = l.foraExpediente || false;
    const semUso   = l.semUso || (l.total === 0 && !l.dados && !l.voz);

    if (excedenteDados) { qtdExcedentes++; alertas.push({ tipo:'excedente', linha:l.linha, mensagem:`Dados excedidos: +${excedenteDados} GB` }); }
    if (excedenteVoz)   { qtdExcedentes++; alertas.push({ tipo:'excedente', linha:l.linha, mensagem:`Voz excedida: +${excedenteVoz} min` }); }
    if (foraExp)        { qtdForaExp++;    alertas.push({ tipo:'fora-expediente', linha:l.linha, mensagem:'Uso fora do expediente' }); }
    if (semUso)         { qtdSemUso++;     alertas.push({ tipo:'sem-uso', linha:l.linha, mensagem:'Linha sem uso no perГӯodo' }); }

    // Atualiza plano com dados de alerta da fatura
    if (plano && FB_READY && db) {
      batch.push(db.collection('planos_telecom').doc(plano.id).update({
        excedenteDados:   excedenteDados || null,
        excedenteVoz:     excedenteVoz   || null,
        foraExpediente:   foraExp || null,
        semUso:           semUso  || null,
        ultimaFaturaRef:  mes,
        ultimaFaturaTotal: l.total,
        ultimaFaturaEm:   agora,
      }));
    }
  }

  // Persiste fatura consolidada
  if (FB_READY && db) {
    batch.push(db.collection('faturas_telecom').add({
      competencia:       mes,
      totalLinhas:       linhas.length,
      totalGeral:        +totalGeral.toFixed(2),
      qtdExcedentes,
      qtdForaExpediente: qtdForaExp,
      qtdSemUso,
      alertas,
      importadaEm:       agora,
      importadaPor:      CURRENT_USER?.nome || CURRENT_USER?.uid || '',
    }));

    await Promise.allSettled(batch);
  }

  // в”Җв”Җ VerificaГ§ГЈo contratual (PregГЈo 158/2021) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  const faturaObj = {
    competencia: mes,
    linhas: linhas.map(l => ({
      numero:           l.linha,
      empNome:          l.empNome || '',
      tipoPlano:        (planos.find(p => p.linha === l.linha))?.tipoPlano || '',
      valorMensalidade: l.total || 0,
      dadosUsadosGB:    l.dados ?? null,
      vozUsadoMin:      l.voz   ?? null,
      foraExpediente:   l.foraExpediente || false,
      itens:            l.itens || [],
    })),
  };
  const alertasContrato = tcVerificarFatura(faturaObj);

  // Mostra resultado da verificaГ§ГЈo contratual
  if (alertasContrato.length > 0 || alertas.length > 0) {
    setTimeout(() => {
      tcMostrarResultadoVerificacao(alertasContrato, mes, +totalGeral.toFixed(2));
    }, 500);
  } else {
    showToast(`вң… Fatura ${mes} verificada вҖ” sem irregularidades em relaГ§ГЈo ao contrato PregГЈo 158/2021`, 'success', 7000);
  }

  return { total: linhas.length, alertas: alertas.length, alertasContrato: alertasContrato.length };
}

