// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// ALERTAS DE MГҒQUINAS DESLIGADAS вҖ” Regras de negГіcio:
// вҖў MГЎquina offline > 5 dias consecutivos вҶ’ alerta para TI
// вҖў Alerta se repete a cada 5 dias enquanto nГЈo houver justificativa
// вҖў Se responsГЎvel estiver em ausГӘncia (fГ©rias/licenГ§a) вҶ’ alerta suprimido
// вҖў TГ©cnico pode inserir justificativa para suprimir atГ© prГіxima verificaГ§ГЈo
// ColeГ§ГЈo Firestore: alertas_maquina_offline
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

const ALERTA_OFFLINE_DIAS      = 5;   // dias offline para disparar 1Вә alerta
const ALERTA_OFFLINE_CICLO     = 5;   // dias entre alertas recorrentes
const ALERTA_OFFLINE_COLECAO   = 'alertas_maquina_offline';

// в”Җв”Җ Inicializa listener de alertas в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function initAlertasMaquinaOffline() {
  if (!FB_READY || !db || STATE._alertasOfflineInit) return;
  STATE._alertasOfflineInit = true;

  db.collection(ALERTA_OFFLINE_COLECAO)
    .where('status', 'in', ['ativo', 'suprimido'])
    .onSnapshot(snap => {
      STATE.alertasOffline = snap2arr(snap).sort((a,b) =>
        (b.criadoEm?.seconds || 0) - (a.criadoEm?.seconds || 0)
      );
      _renderAlertasOfflineBadge();
    }, e => console.warn('[AlertasOffline]', e.message));
}

document.addEventListener('sysack-login', () => {
  setTimeout(initAlertasMaquinaOffline, 4000);
  // Verifica mГЎquinas offline periodicamente (a cada 30min enquanto app aberto)
  setTimeout(_verificarMaquinasOffline, 10000);
  setInterval(_verificarMaquinasOffline, 30 * 60 * 1000);
});

// в”Җв”Җ VerificaГ§ГЈo principal в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
async function _verificarMaquinasOffline() {
  if (!FB_READY || !db) return;

  const agora     = Date.now();
  const limiteMs  = ALERTA_OFFLINE_DIAS * 24 * 60 * 60 * 1000;
  const cicloMs   = ALERTA_OFFLINE_CICLO * 24 * 60 * 60 * 1000;
  const agentes   = STATE_AGENTS?.list || [];
  const empregados = STATE.empregados  || [];

  // Carrega alertas ativos existentes
  let alertasExistentes = {};
  try {
    const snap = await db.collection(ALERTA_OFFLINE_COLECAO)
      .where('status', 'in', ['ativo', 'suprimido']).get();
    snap.docs.forEach(d => { alertasExistentes[d.data().agentId] = { id: d.id, ...d.data() }; });
  } catch(e) { console.warn('[AlertasOffline] load:', e.message); return; }

  const batch = [];

  for (const ag of agentes) {
    if (!ag.lastSeen) continue;

    const lastSeenMs  = ag.lastSeen?.seconds ? ag.lastSeen.seconds * 1000
                        : new Date(ag.lastSeen).getTime();
    const offlineMs   = agora - lastSeenMs;

    // Ainda estГЎ online ou offline recente вҖ” limpa alerta se existia
    if (offlineMs < limiteMs) {
      const existente = alertasExistentes[ag.id];
      if (existente && existente.status === 'ativo') {
        batch.push(
          db.collection(ALERTA_OFFLINE_COLECAO).doc(existente.id)
            .update({ status: 'resolvido', resolvidoEm: new Date(),
                      obs: 'MГЎquina voltou a ficar online automaticamente.' })
        );
        console.log(`[AlertasOffline] вң“ ${ag.hostname} voltou online вҖ” alerta encerrado`);
      }
      continue;
    }

    // Busca empregado responsГЎvel pela mГЎquina
    // Tenta vГЎrias chaves: login do agente, matrГӯcula, e-mail
    // TambГ©m tenta via ativo vinculado (campo resp = login do responsГЎvel)
    const ativoVinculado = (STATE.ativos || []).find(a =>
      a.pat === ag.pat || a.hostname === ag.hostname
    );
    const respLogin = ag.empLogin || ativoVinculado?.resp || '';
    const respMat   = ag.empMat   || '';

    const emp = empregados.find(e =>
      (respLogin && e.login === respLogin)       ||
      (respMat   && e.mat   === respMat)         ||
      (ag.empEmail && e.email === ag.empEmail)
    );

    // Suprime se empregado estiver em qualquer tipo de ausГӘncia
    const responsavelAusente = emp?.emAusencia === true;

    const existente = alertasExistentes[ag.id];

    if (!existente) {
      // Primeiro alerta
      const novoAlerta = {
        agentId:           ag.id,
        hostname:          ag.hostname  || ag.id,
        empNome:           ag.empNome   || emp?.nome  || 'вҖ”',
        empMat:            ag.empMat    || emp?.mat   || '',
        empLogin:          ag.empLogin  || '',
        area:              ag.area      || ag.empSetor || emp?.setor || emp?.lotacao || '',
        pat:               ag.pat       || '',
        offlineDias:       Math.floor(offlineMs / (24*60*60*1000)),
        lastSeen:          new Date(lastSeenMs),
        status:            responsavelAusente ? 'suprimido' : 'ativo',
        suprimidoMotivo:   responsavelAusente ? `ResponsГЎvel em ausГӘncia: ${emp?.ausencia || 'ausГӘncia'}` : '',
        criadoEm:          new Date(),
        ultimoAlertaEm:    responsavelAusente ? null : new Date(),
        ciclosEnviados:    responsavelAusente ? 0 : 1,
        justificativa:     '',
        justificativaEm:   null,
        justificativaPor:  '',
      };
      batch.push(db.collection(ALERTA_OFFLINE_COLECAO).add(novoAlerta));
      if (!responsavelAusente) {
        console.log(`[AlertasOffline] вҡ  Novo alerta: ${ag.hostname} вҖ” ${Math.floor(offlineMs/86400000)} dias offline`);
        _notificarAlertaOffline(novoAlerta);
      }

    } else {
      // Alerta jГЎ existe
      const updates = { offlineDias: Math.floor(offlineMs / (24*60*60*1000)) };

      if (responsavelAusente && existente.status === 'ativo') {
        // Suprimir вҖ” responsГЎvel entrou em ausГӘncia
        updates.status         = 'suprimido';
        updates.suprimidoMotivo = `ResponsГЎvel em ausГӘncia: ${emp?.ausencia || 'ausГӘncia'}`;
        batch.push(db.collection(ALERTA_OFFLINE_COLECAO).doc(existente.id).update(updates));

      } else if (!responsavelAusente && existente.status === 'suprimido' && !existente.justificativa) {
        // Reativar вҖ” responsГЎvel voltou
        updates.status         = 'ativo';
        updates.suprimidoMotivo = '';
        updates.ultimoAlertaEm = new Date();
        updates.ciclosEnviados = (existente.ciclosEnviados || 0) + 1;
        batch.push(db.collection(ALERTA_OFFLINE_COLECAO).doc(existente.id).update(updates));
        _notificarAlertaOffline({ ...existente, ...updates });

      } else if (existente.status === 'ativo' && !existente.justificativa) {
        // Verifica se Г© hora de enviar alerta recorrente
        const ultimoEnvioMs = existente.ultimoAlertaEm?.seconds
          ? existente.ultimoAlertaEm.seconds * 1000
          : existente.ultimoAlertaEm ? new Date(existente.ultimoAlertaEm).getTime() : 0;

        if (agora - ultimoEnvioMs >= cicloMs) {
          updates.ultimoAlertaEm = new Date();
          updates.ciclosEnviados = (existente.ciclosEnviados || 0) + 1;
          batch.push(db.collection(ALERTA_OFFLINE_COLECAO).doc(existente.id).update(updates));
          _notificarAlertaOffline({ ...existente, ...updates });
          console.log(`[AlertasOffline] рҹ”Ғ Ciclo ${updates.ciclosEnviados}: ${existente.hostname}`);
        } else {
          // SГі atualiza dias offline
          batch.push(db.collection(ALERTA_OFFLINE_COLECAO).doc(existente.id).update(updates));
        }
      }
    }
  }

  if (batch.length) await Promise.allSettled(batch);
}

// в”Җв”Җ NotificaГ§ГЈo (toast + e-mail) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function _notificarAlertaOffline(alerta) {
  const dias = alerta.offlineDias || ALERTA_OFFLINE_DIAS;
  const ciclo = alerta.ciclosEnviados > 1 ? ` (${alerta.ciclosEnviados}Вә aviso)` : '';
  showToast(
    `вҡ пёҸ ${alerta.hostname} desligada hГЎ ${dias} dias${ciclo} вҖ” ${alerta.empNome}`,
    'warning', 8000
  );

  // Envia e-mail via fila
  if (FB_READY && db) {
    const assunto = `[SYSACK] MГЎquina offline: ${alerta.hostname} вҖ” ${dias} dias${ciclo}`;
    const html = `<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;background:#F1F5F9;padding:20px">
<div style="background:#fff;border-radius:12px;max-width:600px;margin:0 auto;overflow:hidden;box-shadow:0 4px 16px rgba(0,0,0,.08)">
  <div style="background:#D97706;color:#fff;padding:20px 28px">
    <h1 style="margin:0;font-size:18px">вҡ пёҸ MГЎquina Offline вҖ” SYSACK</h1>
    <p style="margin:4px 0 0;font-size:12px;opacity:.85">${ciclo ? 'Aviso recorrente' : 'Primeiro aviso'}</p>
  </div>
  <div style="padding:24px 28px">
    <p>A mГЎquina abaixo estГЎ <strong>desligada hГЎ ${dias} dias consecutivos</strong>${ciclo}.</p>
    <table style="width:100%;border-collapse:collapse;margin:16px 0">
      <tr><th style="text-align:left;padding:8px 12px;background:#F8FAFC;font-size:11px;text-transform:uppercase;color:#64748B">MГЎquina</th><td style="padding:8px 12px;font-weight:700">${alerta.hostname}</td></tr>
      <tr><th style="text-align:left;padding:8px 12px;background:#F8FAFC;font-size:11px;text-transform:uppercase;color:#64748B">PatrimГҙnio</th><td style="padding:8px 12px">${alerta.pat || 'вҖ”'}</td></tr>
      <tr><th style="text-align:left;padding:8px 12px;background:#F8FAFC;font-size:11px;text-transform:uppercase;color:#64748B">ResponsГЎvel</th><td style="padding:8px 12px">${alerta.empNome}</td></tr>
      <tr><th style="text-align:left;padding:8px 12px;background:#F8FAFC;font-size:11px;text-transform:uppercase;color:#64748B">ГҒrea</th><td style="padding:8px 12px">${alerta.area || 'вҖ”'}</td></tr>
      <tr><th style="text-align:left;padding:8px 12px;background:#F8FAFC;font-size:11px;text-transform:uppercase;color:#64748B">Гҡltimo online</th><td style="padding:8px 12px">${alerta.lastSeen ? new Date(alerta.lastSeen?.seconds ? alerta.lastSeen.seconds*1000 : alerta.lastSeen).toLocaleString('pt-BR') : 'вҖ”'}</td></tr>
    </table>
    <p style="font-size:13px;color:#64748B">Acesse o SYSACK para verificar a situaГ§ГЈo e inserir uma justificativa caso necessГЎrio.</p>
    <a href="https://sysack.vercel.app/" style="display:inline-block;background:#D97706;color:#fff;padding:10px 20px;border-radius:8px;text-decoration:none;font-weight:600;margin-top:8px">Ver no SYSACK вҶ’</a>
  </div>
</div></body></html>`;

    db.collection('emails_pendentes').add({
      para:      CURRENT_USER?.email || 'ti@cesan.com.br',
      assunto,
      htmlBody:  html,
      criadoEm:  new Date(),
      enviado:   false,
      tipo:      'alerta-offline',
      agentId:   alerta.agentId || alerta.id || '',
    }).catch(() => {});
  }
}

// в”Җв”Җ Reavalia supressГЈo quando lista de empregados muda в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Chamado sempre que o STATE.empregados Г© atualizado pelo listener
async function _reavaliarSupressaoAlertas(empregados) {
  const alertas = STATE.alertasOffline || [];
  if (!alertas.length || !FB_READY || !db) return;

  const ativos    = alertas.filter(a => a.status === 'ativo');
  const suprimidos = alertas.filter(a => a.status === 'suprimido');
  const batch = [];

  // Ativos: verifica se o responsГЎvel entrou em ausГӘncia вҶ’ suprimir
  for (const al of ativos) {
    const emp = empregados.find(e =>
      (al.empLogin && e.login === al.empLogin) ||
      (al.empMat   && e.mat   === al.empMat)
    );
    if (emp?.emAusencia) {
      batch.push(
        db.collection(ALERTA_OFFLINE_COLECAO).doc(al.id).update({
          status:          'suprimido',
          suprimidoMotivo: `ResponsГЎvel em ${emp.ausencia || 'ausГӘncia'} вҖ” alertas suspensos automaticamente`,
          suprimidoEm:     new Date(),
        })
      );
      console.log(`[AlertasOffline] вҸё ${al.hostname} suprimido вҖ” ${emp.nome} em ${emp.ausencia||'ausГӘncia'}`);
    }
  }

  // Suprimidos: verifica se o responsГЎvel voltou вҶ’ reativar
  for (const al of suprimidos) {
    if (al.justificativa) continue; // suprimido por justificativa manual вҖ” nГЈo reativa automГЎtico
    const emp = empregados.find(e =>
      (al.empLogin && e.login === al.empLogin) ||
      (al.empMat   && e.mat   === al.empMat)
    );
    if (emp && !emp.emAusencia) {
      batch.push(
        db.collection(ALERTA_OFFLINE_COLECAO).doc(al.id).update({
          status:          'ativo',
          suprimidoMotivo: '',
          reativadoEm:     new Date(),
          ultimoAlertaEm:  new Date(),
          ciclosEnviados:  (al.ciclosEnviados || 0) + 1,
        })
      );
      console.log(`[AlertasOffline] рҹ”” ${al.hostname} reativado вҖ” ${emp.nome} voltou de ${al.suprimidoMotivo||'ausГӘncia'}`);
      _notificarAlertaOffline({ ...al, status:'ativo', ciclosEnviados:(al.ciclosEnviados||0)+1 });
    }
  }

  if (batch.length) await Promise.allSettled(batch);
}

// в”Җв”Җ Badge de alertas no menu в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function _renderAlertasOfflineBadge() {
  const ativos = (STATE.alertasOffline || []).filter(a => a.status === 'ativo').length;
  // Mostra/esconde botГЈo na topbar
  const btn = document.getElementById('btn-alertas-offline');
  if (btn) btn.style.display = ativos > 0 ? '' : 'none';
  const badge = document.getElementById('nb-alertas-offline');
  if (badge) {
    badge.textContent = ativos;
    badge.style.display = ativos > 0 ? '' : 'none';
  }
}

// в”Җв”Җ Modal: painel de alertas de mГЎquinas offline в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function abrirPainelAlertasOffline() {
  const alertas = STATE.alertasOffline || [];
  const ativos    = alertas.filter(a => a.status === 'ativo');
  const suprimidos = alertas.filter(a => a.status === 'suprimido');

  const renderCard = (a) => {
    const dias = a.offlineDias || '?';
    const lastStr = a.lastSeen
      ? new Date(a.lastSeen?.seconds ? a.lastSeen.seconds*1000 : a.lastSeen).toLocaleDateString('pt-BR')
      : 'вҖ”';
    const corBorda = a.status === 'suprimido' ? 'var(--g300)' : dias >= 15 ? 'var(--danger)' : 'var(--warning)';
    return `
    <div style="border-left:4px solid ${corBorda};background:var(--g50);border-radius:0 10px 10px 0;
                padding:12px 16px;margin-bottom:10px;display:flex;gap:12px;align-items:flex-start">
      <div style="flex:1;min-width:0">
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:4px">
          <span style="font-weight:700;font-size:13px;color:var(--g900)">${escapeHtml(a.hostname)}</span>
          ${a.pat ? `<span class="tag" style="font-size:10px">${escapeHtml(a.pat)}</span>` : ''}
          ${a.ciclosEnviados > 1 ? `<span class="tag tag-warning" style="font-size:10px">${a.ciclosEnviados}Вә aviso</span>` : ''}
          ${a.status === 'suprimido' ? `<span class="tag" style="background:var(--g100);font-size:10px">рҹҳҙ Suprimido</span>` : ''}
        </div>
        <div style="font-size:12px;color:var(--g600)">
          рҹ‘Ө ${escapeHtml(a.empNome || 'вҖ”')}
          ${a.area ? ` В· ${escapeHtml(a.area)}` : ''}
        </div>
        <div style="font-size:11.5px;color:var(--danger);font-weight:600;margin-top:4px">
          ${a.status !== 'suprimido' ? `вҸұ Desligada hГЎ <strong>${dias} dias</strong> В· Гҡltimo online: ${lastStr}` : ''}
          ${a.status === 'suprimido' ? `<span style="color:var(--g500)">вҸё ${escapeHtml(a.suprimidoMotivo||'Suprimido')}</span>` : ''}
        </div>
        ${a.justificativa ? `<div style="font-size:11.5px;color:var(--success);margin-top:4px">вң“ Justificativa: ${escapeHtml(a.justificativa)}</div>` : ''}
      </div>
      <div style="display:flex;flex-direction:column;gap:6px;flex-shrink:0">
        ${a.status === 'ativo' && !a.justificativa ? `
          <button class="btn btn-secondary btn-xs" onclick="abrirJustificativaOffline('${a.id}')">вңҸпёҸ Justificar</button>
        ` : ''}
        <button class="btn btn-ghost btn-xs" style="color:var(--danger)" onclick="encerrarAlertaOffline('${a.id}')">вң•</button>
      </div>
    </div>`;
  };

  const html = `
  <div class="modal-overlay open" id="modal-alertas-offline" onclick="if(event.target===this)this.remove()">
    <div class="modal" style="max-width:620px">
      <div class="modal-header">
        <h3>вҡ пёҸ MГЎquinas Offline (${ativos.length} ativo${ativos.length!==1?'s':''})</h3>
        <button class="close-btn" onclick="document.getElementById('modal-alertas-offline').remove()">вң•</button>
      </div>
      <div class="modal-body" style="max-height:70vh;overflow-y:auto">
        ${ativos.length ? `
          <div style="font-size:11px;font-weight:700;color:var(--g500);text-transform:uppercase;letter-spacing:.5px;margin-bottom:10px">
            Alertas ativos (${ativos.length})
          </div>
          ${ativos.map(renderCard).join('')}
        ` : `
          <div style="text-align:center;padding:32px;color:var(--g400)">
            вң“ Nenhum alerta ativo no momento
          </div>
        `}
        ${suprimidos.length ? `
          <div style="font-size:11px;font-weight:700;color:var(--g500);text-transform:uppercase;letter-spacing:.5px;margin:16px 0 10px">
            Suprimidos por ausГӘncia (${suprimidos.length})
          </div>
          ${suprimidos.map(renderCard).join('')}
        ` : ''}
      </div>
      <div class="modal-footer">
        <button class="btn btn-ghost" onclick="document.getElementById('modal-alertas-offline').remove()">Fechar</button>
        <button class="btn btn-secondary" onclick="_verificarMaquinasOffline().then(()=>showToast('вң“ VerificaГ§ГЈo concluГӯda'))">рҹ”„ Verificar agora</button>
      </div>
    </div>
  </div>`;

  document.getElementById('modal-alertas-offline')?.remove();
  document.body.insertAdjacentHTML('beforeend', html);
}

function abrirJustificativaOffline(alertaId) {
  const alerta = (STATE.alertasOffline || []).find(a => a.id === alertaId);
  if (!alerta) return;

  const html = `
  <div class="modal-overlay open" id="modal-justif-offline" onclick="if(event.target===this)this.remove()">
    <div class="modal" style="max-width:460px">
      <div class="modal-header">
        <h3>вңҸпёҸ Justificativa вҖ” ${escapeHtml(alerta.hostname)}</h3>
        <button class="close-btn" onclick="document.getElementById('modal-justif-offline').remove()">вң•</button>
      </div>
      <div class="modal-body">
        <p style="font-size:13px;color:var(--g600);margin-bottom:14px">
          Explique o motivo da mГЎquina estar desligada. O alerta ficarГЎ suspenso atГ© o prГіximo ciclo de ${ALERTA_OFFLINE_CICLO} dias.
        </p>
        <div class="form-group">
          <label class="form-label req">Justificativa</label>
          <textarea class="form-control" id="justif-offline-texto" rows="3"
            placeholder="Ex: Empregado em fГ©rias, mГЎquina aguardando manutenГ§ГЈo, transferГӘncia em andamento..."></textarea>
        </div>
      </div>
      <div class="modal-footer">
        <button class="btn btn-ghost" onclick="document.getElementById('modal-justif-offline').remove()">Cancelar</button>
        <button class="btn btn-primary" onclick="salvarJustificativaOffline('${alertaId}')">рҹ’ҫ Salvar Justificativa</button>
      </div>
    </div>
  </div>`;

  document.getElementById('modal-justif-offline')?.remove();
  document.body.insertAdjacentHTML('beforeend', html);
  setTimeout(() => document.getElementById('justif-offline-texto')?.focus(), 100);
}

async function salvarJustificativaOffline(alertaId) {
  const texto = document.getElementById('justif-offline-texto')?.value?.trim();
  if (!texto) return showToast('Informe a justificativa', 'danger');

  try {
    const agora = new Date();
    await db.collection(ALERTA_OFFLINE_COLECAO).doc(alertaId).update({
      justificativa:    texto,
      justificativaEm:  agora,
      justificativaPor: CURRENT_USER?.nome || CURRENT_USER?.uid || '',
      // Reseta o ciclo вҖ” prГіximo alerta sГі em CICLO dias
      ultimoAlertaEm:   agora,
    });
    document.getElementById('modal-justif-offline')?.remove();
    showToast('вң“ Justificativa registrada. Alerta suspenso por mais ' + ALERTA_OFFLINE_CICLO + ' dias.', 'success');
  } catch(e) {
    showToast('Erro: ' + e.message, 'danger');
  }
}

async function encerrarAlertaOffline(alertaId) {
  if (!confirm('Encerrar este alerta manualmente?')) return;
  try {
    await db.collection(ALERTA_OFFLINE_COLECAO).doc(alertaId).update({
      status:       'resolvido',
      resolvidoEm:  new Date(),
      resolvidoPor: CURRENT_USER?.nome || '',
    });
    showToast('Alerta encerrado', 'success');
  } catch(e) {
    showToast('Erro: ' + e.message, 'danger');
  }
}


